def atlas_route_entry_artifact_identity() -> dict[str, Any]:
    return {
        "artifact_class": "session_memory_atlas_route_entry",
        "surface_state": "portable_generated_session_route_packet",
        "owner_repo": "aoa-session-memory",
        "authority_ref": "maps/README.md",
        "producer": (
            "scripts/aoa_session_memory.py atlas build from session manifests, "
            "segment indexes, route signals, diagnostics, search state, and "
            "source atlas axes"
        ),
        "consumer_expectation": (
            "Verify schema_version, artifact_identity, axis, route_key, "
            "truth_status, evidence refs, atlas schema, and atlas build or "
            "route-readiness status before using this as a route packet; open "
            "session, segment, or raw refs before promoting any claim."
        ),
        "privacy_boundary": (
            "Portable local route signals and evidence refs only; no raw "
            "transcript bodies, prompt text, secrets, credentials, or reviewed "
            "memory claims."
        ),
        "content_identity": (
            "maps/by-*/entries/*.json generated by build_agent_atlas() and "
            "validated against schemas/atlas-route-entry.schema.json."
        ),
        "abi_epoch": "aoa_session_memory_atlas_route_entry_v1",
        "contract_version": (
            "schemas/atlas-route-entry.schema.json@"
            "aoa_session_memory_atlas_route_entry_v1#artifact_identity"
        ),
        "trust_layer": list(ATLAS_ROUTE_ENTRY_TRUST_LAYER),
        "verification": [
            "python3 -m py_compile scripts/aoa_session_memory.py",
            "PYTHONDONTWRITEBYTECODE=1 python3 -m pytest -q -p no:cacheprovider tests/test_session_memory.py",
            "python3 scripts/aoa_session_memory.py audit --portable-bundle",
        ],
        "action": "ADD_CONSUMER_EXPECTATION",
    }


