def named_entity_candidates_from_text(text: str) -> set[str]:
    source = str(text or "")
    entities = {match.group(0) for match in NAMED_ENTITY_PATTERN.finditer(source)}
    entities.update(match.group(1) for match in SKILL_PATH_ENTITY_PATTERN.finditer(source))
    entities.update(match.group(0) for match in ENV_ENTITY_PATTERN.finditer(source) if env_entity_candidate(match.group(0)))
    return entities


def mcp_service_shape_key(value: str, *, path_source: bool = False) -> str | None:
    key = route_key_slug(value, fallback="")
    parts = [part for part in key.split("_") if part]
    if len(parts) < 2 or parts[-1] != "mcp":
        return None
    if "mcp" in parts[:-1]:
        return None
    if path_source:
        return key if len(parts) <= 6 else None
    if parts[0] == "aoa":
        return key if len(parts) <= 5 else None
    if parts[0] == "abyss":
        return key if len(parts) <= 4 else None
    return key if len(parts) <= 6 else None


def canonical_mcp_service_key(value: str, *, path_source: bool = False) -> str | None:
    key = mcp_service_shape_key(value, path_source=path_source)
    if not key:
        return None
    return key


def mcp_service_text_mention_key(value: str) -> str | None:
    key = canonical_mcp_service_key(value, path_source=False)
    if not key:
        return None
    if key.startswith(MCP_SERVICE_TEXT_NOISE_PREFIXES):
        return None
    return key


def mcp_service_identity_suggestion(value: str, *, path_source: bool = False) -> str:
    key = mcp_service_shape_key(value, path_source=path_source)
    if not key or key in CANONICAL_MCP_SERVICE_KEYS:
        return ""
    matches = difflib.get_close_matches(key, sorted(CANONICAL_MCP_SERVICE_KEYS), n=1, cutoff=0.72)
    return matches[0] if matches else ""


def is_unknown_mcp_service_identity(value: str, *, path_source: bool = False) -> bool:
    key = mcp_service_shape_key(value, path_source=path_source)
    return bool(key and key not in CANONICAL_MCP_SERVICE_KEYS)


def mcp_config_service_key(value: str) -> str | None:
    key = route_key_slug(value, fallback="")
    for prefix in ("mcp_servers_", "mcp_server_", "mcp__"):
        if not key.startswith(prefix):
            continue
        suffix = key[len(prefix) :].strip("_")
        if not suffix or suffix.startswith("codex_apps_"):
            return None
        service_key = suffix if suffix.endswith("_mcp") else f"{suffix}_mcp"
        return canonical_mcp_service_key(service_key, path_source=False)
    return None


def mcp_route_candidates_from_texts(texts: list[str]) -> set[str]:
    source = " ".join(str(text or "") for text in texts)
    candidates: set[str] = set()
    for match in MCP_SERVICE_ENTITY_PATTERN.finditer(source):
        key = mcp_service_text_mention_key(match.group(1))
        if key:
            candidates.add(key)
    for match in MCP_SERVICE_PATH_PATTERN.finditer(source):
        key = canonical_mcp_service_key(match.group(1), path_source=True)
        if key:
            candidates.add(key)
    return candidates


def operational_entity_key(value: str, *, allow_plain: bool = False, max_chars: int = 96) -> str | None:
    key = route_key_slug(value, fallback="", max_chars=max_chars)
    if not key or key in OPERATIONAL_ENTITY_STOPWORDS or len(key) < 2:
        return None
    if allow_plain or "_" in key or key in {
        "pytest",
        "inspect_ai",
        "lighteval",
        "graphql",
        "rest",
        "http",
        "websocket",
        "graphrag",
        "codex",
        "github",
        "gmail",
        "openai",
        "git",
        "gh",
    }:
        return key
    return None


def skill_entity_key(value: str, *, explicit: bool = False, path_source: bool = False) -> str | None:
    key = operational_entity_key(value, allow_plain=explicit or path_source, max_chars=96)
    if not key:
        return None
    raw = str(value or "").strip()
    raw_core = raw.strip(":;,.").replace("\\", "/")
    if raw_core.count(":") >= 2:
        return None
    if CODE_LOCATION_KEY_PATTERN.search(key):
        return None
    if re.search(r"\.(?:py|sh|js|ts|tsx|go|rs)(?::\d+)?$", raw_core, flags=re.IGNORECASE):
        return None
    if key in KNOWN_TOOL_ENTITY_KEYS:
        return None
    if key in {"agents_md", "readme", "readme_md", "skill_md", "github_com"}:
        return None
    if key in NON_SKILL_ENTITY_KEYS:
        return None
    if TECHNIQUE_ID_KEY_PATTERN.match(key):
        return None
    if DOCUMENT_LOCATION_VALUE_PATTERN.search(raw_core):
        return None
    if path_source:
        return key
    if key in KNOWN_SKILL_ENTITY_KEYS:
        return key
    if raw.rstrip().endswith(":"):
        return None
    if any(key.startswith(prefix) for prefix in KNOWN_SKILL_ENTITY_PREFIXES):
        return key
    if explicit and ("-" in raw_core or "_" in raw_core or ":" in raw_core):
        return key
    return None


def plugin_entity_key(value: str, *, explicit: bool = False, declaration_source: bool = False) -> str | None:
    raw = str(value or "").strip().strip("/")
    raw_core = raw.strip(":;,.").replace("\\", "/")
    if raw_core.count(":") >= 2:
        return None
    if "@" in raw_core:
        plugin_name, plugin_source = raw_core.split("@", 1)
        source_key = route_key_slug(plugin_source, fallback="", max_chars=64)
        if source_key not in KNOWN_PLUGIN_SOURCE_KEYS:
            return None
        raw = f"{plugin_name}_{source_key}"
    if raw.startswith("openai-curated/"):
        raw = raw.split("/", 1)[1]
    key = operational_entity_key(raw, allow_plain=True, max_chars=96)
    if not key:
        return None
    if key.isdigit():
        return None
    if CODE_LOCATION_KEY_PATTERN.search(key):
        return None
    if DOCUMENT_ARTIFACT_KEY_PATTERN.search(key):
        return None
    if DOCUMENT_LOCATION_VALUE_PATTERN.search(raw_core):
        return None
    if re.search(r"(?:^|_)(?:zip|tar|tgz|gz|xz|7z)$", key, flags=re.IGNORECASE):
        return None
    if key in KNOWN_PLUGIN_ENTITY_KEYS:
        return key
    if declaration_source and not any(key.startswith(prefix) for prefix in KNOWN_PLUGIN_ENTITY_PREFIXES):
        return None
    structured = any(marker in raw for marker in ("-", "_", "@", ":", "/"))
    if explicit and structured:
        return key
    return None


def path_stem_entity_key(value: str) -> str | None:
    text = str(value or "").replace("\\", "/").strip()
    if not text:
        return None
    name = text.rsplit("/", 1)[-1]
    stem = re.sub(r"\.(?:py|sh|js|ts|tsx|go|rs|md|json|ya?ml|toml)$", "", name, flags=re.IGNORECASE)
    return operational_entity_key(stem, allow_plain=True)


def skill_entity_candidates_from_texts(texts: list[str]) -> set[str]:
    source = " ".join(str(text or "") for text in texts)
    lowered = source.lower()
    if "skill" not in lowered and "скил" not in lowered and "/skills/" not in lowered and "skills/" not in lowered:
        return set()
    candidates: set[str] = set()
    for match in SKILL_PATH_ENTITY_PATTERN.finditer(source):
        key = skill_entity_key(match.group(1), explicit=True, path_source=True)
        if key:
            candidates.add(key)
    for match in SKILL_DECL_ENTITY_PATTERN.finditer(source):
        key = skill_entity_key(match.group(1) or match.group(2) or "", explicit=True)
        if key:
            candidates.add(key)
    for match in KNOWN_SKILL_FORWARD_PATTERN.finditer(source):
        key = skill_entity_key(match.group(1), explicit=True)
        if key:
            candidates.add(key)
    for match in KNOWN_SKILL_REVERSE_PATTERN.finditer(source):
        key = skill_entity_key(match.group(1), explicit=True)
        if key:
            candidates.add(key)
    return candidates


def tool_entity_candidates_from_texts(texts: list[str]) -> set[str]:
    source = " ".join(str(text or "") for text in texts)
    candidates: set[str] = set()
    for tool in KNOWN_TOOL_ENTITY_KEYS:
        if re.search(fr"(?<![A-Za-z0-9_]){re.escape(tool)}(?![A-Za-z0-9_])", source, flags=re.IGNORECASE):
            candidates.add(tool)
    for match in re.finditer(r"(?<![A-Za-z0-9_])(mcp__[A-Za-z0-9_]+__[A-Za-z0-9_]+)(?![A-Za-z0-9_])", source):
        key = operational_entity_key(match.group(1), allow_plain=True)
        if key:
            candidates.add(key)
    return candidates


def api_entity_candidates_from_texts(texts: list[str]) -> set[str]:
    source = " ".join(str(text or "") for text in texts)
    lowered = source.lower()
    if not any(
        marker in lowered
        for marker in (
            "api",
            "graphql",
            "rest",
            "http",
            "websocket",
            "openai",
            "responses",
            "github",
            "gmail",
            "google",
            "hugging",
            "notion",
            "canva",
            "mcp",
        )
    ):
        return set()
    candidates: set[str] = set()

    def add_api_candidate(value: str) -> None:
        key = operational_entity_key(value, allow_plain=True)
        if not key:
            return
        parts = [part for part in key.split("_") if part]
        if key in API_ENTITY_ALIASES:
            candidates.add(API_ENTITY_ALIASES[key])
            return
        if key in API_PROVIDER_KEYS:
            candidates.add(key)
            return
        if key.endswith("_api"):
            provider = key[: -len("_api")].strip("_")
            if provider in API_PROVIDER_KEYS:
                candidates.add(provider)
                return
        if key.startswith("api_"):
            provider = key[len("api_") :].strip("_")
            if provider in API_PROVIDER_KEYS:
                candidates.add(provider)
                return
        if "openai" in parts and "api" in parts:
            if "platform" in parts:
                candidates.add("openai_platform")
            elif "responses" in parts:
                candidates.add("openai_responses")
            else:
                candidates.add("openai")

    for text in texts:
        add_api_candidate(str(text or ""))
    for match in API_ENTITY_PATTERN.finditer(source):
        add_api_candidate(match.group(1))
    if "openai_api_key" in lowered or "api.openai.com" in lowered:
        candidates.add("openai")
    if "responses api" in lowered and "openai" in lowered:
        candidates.add("openai_responses")
    if "graphql" in lowered:
        candidates.add("graphql")
    if re.search(r"\brest[-_ ]?api\b", lowered):
        candidates.add("rest")
    return candidates


