def search_provider_config(aoa_root: Path) -> dict[str, Any]:
    config = default_search_provider_config()
    configured = read_json(aoa_root / SEARCH_PROVIDER_CONFIG_PATH, {})
    if not isinstance(configured, dict):
        return config
    for key in ("default_provider", "authority_law"):
        if configured.get(key):
            config[key] = configured[key]
    if isinstance(configured.get("providers"), dict):
        providers = config["providers"]
        for name, value in configured["providers"].items():
            if not isinstance(value, dict):
                continue
            base = providers.get(str(name), {})
            merged = dict(base)
            merged.update(value)
            providers[str(name)] = merged
    return config


def run_json_command(command: list[str], *, timeout: int = 30, cwd: Path | None = None) -> dict[str, Any]:
    if not command:
        return {"ok": False, "status": "invalid_command", "error": "empty command", "command": command}
    executable = shutil.which(command[0])
    if executable is None:
        return {"ok": False, "status": "command_missing", "error": f"command not found: {command[0]}", "command": command}
    try:
        completed = subprocess.run(
            command,
            check=False,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            timeout=timeout,
            cwd=str(cwd) if cwd else None,
        )
    except subprocess.TimeoutExpired:
        return {"ok": False, "status": "timeout", "error": f"timed out after {timeout}s", "command": command}
    except Exception as exc:
        return {"ok": False, "status": "error", "error": f"{exc.__class__.__name__}: {exc}", "command": command}
    stdout = completed.stdout.strip()
    stderr = completed.stderr.strip()
    payload: Any = None
    parse_error = ""
    if stdout:
        try:
            payload = json.loads(stdout)
        except json.JSONDecodeError as exc:
            parse_error = f"{exc.__class__.__name__}: {exc}"
    if not isinstance(payload, dict):
        return {
            "ok": False,
            "status": "invalid_json" if completed.returncode == 0 else "failed",
            "returncode": completed.returncode,
            "command": command,
            "stderr": short_text(stderr, max_chars=1200),
            "stdout": short_text(stdout, max_chars=1200),
            "parse_error": parse_error,
        }
    return {
        "ok": completed.returncode == 0 and bool(payload.get("ok", True)),
        "status": "ok" if completed.returncode == 0 else "failed",
        "returncode": completed.returncode,
        "command": command,
        "payload": payload,
        "stderr": short_text(stderr, max_chars=1200),
    }


def run_json_url(
    url: str,
    *,
    method: str = "GET",
    payload: dict[str, Any] | None = None,
    timeout: int = 30,
) -> dict[str, Any]:
    if not url:
        return {"ok": False, "status": "invalid_url", "error": "empty url", "url": url}
    data: bytes | None = None
    headers = {"Accept": "application/json"}
    if payload is not None:
        data = json.dumps(payload, ensure_ascii=False).encode("utf-8")
        headers["Content-Type"] = "application/json"
    request = urllib.request.Request(url, data=data, headers=headers, method=method)
    try:
        with urllib.request.urlopen(request, timeout=timeout) as response:
            body = response.read().decode("utf-8", errors="replace").strip()
            status_code = int(getattr(response, "status", 0) or 0)
    except urllib.error.HTTPError as exc:
        body = exc.read().decode("utf-8", errors="replace").strip()
        return {
            "ok": False,
            "status": "http_error",
            "status_code": exc.code,
            "url": url,
            "body": short_text(body, max_chars=1200),
            "error": str(exc),
        }
    except Exception as exc:
        return {"ok": False, "status": "error", "url": url, "error": f"{exc.__class__.__name__}: {exc}"}
    parsed: Any = None
    parse_error = ""
    if body:
        try:
            parsed = json.loads(body)
        except json.JSONDecodeError as exc:
            parse_error = f"{exc.__class__.__name__}: {exc}"
    if not isinstance(parsed, dict):
        return {
            "ok": False,
            "status": "invalid_json",
            "status_code": status_code,
            "url": url,
            "body": short_text(body, max_chars=1200),
            "parse_error": parse_error,
        }
    return {
        "ok": 200 <= status_code < 300 and bool(parsed.get("ok", True)),
        "status": "ok" if 200 <= status_code < 300 else "http_error",
        "status_code": status_code,
        "url": url,
        "payload": parsed,
    }


def summary_warning_count(payload: dict[str, Any]) -> int:
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    return int_value(summary.get("warnings"), 0)


def summary_fail_count(payload: dict[str, Any]) -> int:
    summary = payload.get("summary") if isinstance(payload.get("summary"), dict) else {}
    return int_value(summary.get("fails"), 0)


def compact_gate_result(result: dict[str, Any]) -> dict[str, Any]:
    payload = result.get("payload") if isinstance(result.get("payload"), dict) else {}
    return {
        "ok": bool(result.get("ok")),
        "status": result.get("status"),
        "returncode": result.get("returncode"),
        "command": result.get("command"),
        "schema": payload.get("schema") or payload.get("schema_version"),
        "generated_at": payload.get("generated_at"),
        "summary": payload.get("summary"),
        "warnings": summary_warning_count(payload),
        "fails": summary_fail_count(payload),
        "error": result.get("error"),
        "stderr": result.get("stderr"),
    }


def compact_semantic_status_result(result: dict[str, Any]) -> dict[str, Any]:
    payload = result.get("payload") if isinstance(result.get("payload"), dict) else {}
    embedding = payload.get("embedding") if isinstance(payload.get("embedding"), dict) else {}
    counts = payload.get("counts") if isinstance(payload.get("counts"), dict) else {}
    count_meta = counts.get("meta") if isinstance(counts.get("meta"), dict) else {}
    freshness = payload.get("freshness") if isinstance(payload.get("freshness"), dict) else {}
    warnings = payload.get("warnings") if isinstance(payload.get("warnings"), list) else []
    notices = payload.get("notices") if isinstance(payload.get("notices"), list) else []
    ready = bool(result.get("ok")) and bool(payload.get("ready", payload.get("ok", False)))
    stale = bool(freshness.get("stale"))
    status = "ready"
    if not ready:
        status = str(result.get("status") or "unavailable")
    elif stale:
        status = "stale"
    return {
        "ok": ready and not stale,
        "status": status,
        "returncode": result.get("returncode"),
        "command": result.get("command"),
        "schema": payload.get("schema") or payload.get("schema_version"),
        "generated_at": payload.get("generated_at"),
        "model_dir": embedding.get("model_dir"),
        "model_exists": embedding.get("model_exists"),
        "device": embedding.get("device"),
        "dimension": embedding.get("dimension"),
        "vectors": counts.get("vectors"),
        "source_chunks": freshness.get("source_chunks") or count_meta.get("source_chunks"),
        "delta_chunks": freshness.get("delta_chunks"),
        "partial": freshness.get("partial"),
        "stale": stale,
        "freshness": {
            "source_index_changed": freshness.get("source_index_changed"),
            "bounded_source_drift": freshness.get("bounded_source_drift"),
            "stale_by_delta": freshness.get("stale_by_delta"),
            "stale_by_age": freshness.get("stale_by_age"),
            "embedding_config_stale": freshness.get("embedding_config_stale"),
        },
        "warning_count": len(warnings) + (1 if stale else 0),
        "notice_count": len(notices),
        "error": result.get("error"),
        "stderr": result.get("stderr"),
    }


def compact_rerank_health_result(result: dict[str, Any]) -> dict[str, Any]:
    payload = result.get("payload") if isinstance(result.get("payload"), dict) else {}
    ok = bool(result.get("ok")) and bool(payload.get("ok", True))
    return {
        "ok": ok,
        "status": "ready" if ok else str(result.get("status") or "unavailable"),
        "url": result.get("url"),
        "status_code": result.get("status_code"),
        "service": payload.get("service"),
        "model": payload.get("model"),
        "backend": payload.get("backend"),
        "device": payload.get("device"),
        "model_dir": payload.get("model_dir"),
        "model_dir_exists": payload.get("model_dir_exists"),
        "max_length": payload.get("max_length"),
        "batch_size": payload.get("batch_size"),
        "loaded": payload.get("loaded"),
        "idle_unload_sec": payload.get("idle_unload_sec"),
        "fake_mode": payload.get("fake_mode"),
        "error": result.get("error"),
    }


def sqlite_provider_status(
    aoa_root: Path,
    *,
    check_freshness: bool = True,
    freshness_mode: str = "deep",
    record_freshness_state: bool = False,
    freshness_records: list[dict[str, Any]] | None = None,
    projection_fingerprints: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    db_path = search_db_path(aoa_root)
    effective_freshness_mode = "deep" if freshness_records is not None or projection_fingerprints is not None else freshness_mode
    if not db_path.exists():
        return {
            "provider": "portable_sqlite",
            "ok": False,
            "status": "missing",
            "db_path": str(db_path),
            "diagnostics": ["search index missing; run search-index"],
        }
    try:
        conn = connect_existing_search_db(db_path)
        metadata = search_index_metadata(conn)
        schema_diagnostics = search_schema_diagnostics(conn)
        if effective_freshness_mode == "hot":
            rows = []
            counts: dict[str, int] = {}
            total: int | None = None
            has_documents = bool(conn.execute("SELECT 1 FROM documents LIMIT 1").fetchone())
            has_routes = sqlite_table_exists(conn, "document_routes") and bool(conn.execute("SELECT 1 FROM document_routes LIMIT 1").fetchone())
            has_route_terms = sqlite_table_exists(conn, "route_terms") and bool(conn.execute("SELECT 1 FROM route_terms LIMIT 1").fetchone())
            route_counts: dict[str, Any] = {
                "route_index_count": None,
                "route_index_document_count": None,
                "route_term_count": None,
                "has_route_index": has_routes,
                "has_route_terms": has_route_terms,
            }
            indexed_session_states = {}
            hot_freshness = sqlite_search_freshness_summary(conn, db_path=db_path) if check_freshness else None
        else:
            rows = conn.execute("SELECT doc_type, COUNT(*) AS count FROM documents GROUP BY doc_type").fetchall()
            counts = {str(row["doc_type"]): int(row["count"]) for row in rows}
            total = sum(counts.values())
            has_documents = total > 0
            route_counts = search_route_storage_counts(conn)
            has_routes = int_value(route_counts.get("route_index_count")) > 0
            has_route_terms = int_value(route_counts.get("route_term_count")) > 0
            indexed_session_states = sqlite_search_session_states(conn) if check_freshness else {}
            hot_freshness = None
        conn.close()
    except sqlite3.Error as exc:
        status = sqlite_error_status(exc)
        return {
            "provider": "portable_sqlite",
            "ok": False,
            "status": status,
            "db_path": str(db_path),
            "diagnostics": [sqlite_error_diagnostic(exc)],
        }
    schema_version = str(metadata.get("schema_version") or "")
    diagnostics: list[str] = list(schema_diagnostics)
    if not has_documents:
        diagnostics.append("search index has no documents")
    if schema_version != str(SEARCH_SCHEMA_VERSION):
        diagnostics.append("search_schema_mismatch")
    if has_documents and not has_routes:
        diagnostics.append("search_route_index_empty")
    if has_routes and not has_route_terms:
        diagnostics.append("search_route_terms_empty")
    freshness: dict[str, Any] = {"status": "unchecked", "checked": False}
    if check_freshness:
        if hot_freshness is not None:
            freshness = hot_freshness
            diagnostics.extend(
                reason
                for reason in freshness.get("reasons", [])
                if reason not in diagnostics and reason != "recent_live_projection_updates_deferred"
            )
        else:
            try:
                scoped_freshness = freshness_records is not None or projection_fingerprints is not None
                records = freshness_records if freshness_records is not None else chronological_session_records(aoa_root)
                projection_fingerprints = projection_fingerprints if projection_fingerprints is not None else search_projection_fingerprints_for_records(records)
                dirty_sessions = search_dirty_projection_states(projection_fingerprints, indexed_session_states)
                live_defer_summary = projection_recent_live_session_summary(dirty_sessions)
                actionable_dirty_sessions = (
                    live_defer_summary.get("actionable_dirty_sessions")
                    if isinstance(live_defer_summary.get("actionable_dirty_sessions"), list)
                    else dirty_sessions
                )
                latest_source_mtime = max(
                    (float(item.get("latest_source_mtime") or 0.0) for item in projection_fingerprints),
                    default=0.0,
                )
                db_mtime = path_mtime(db_path)
                freshness_reasons: list[str] = []
                if actionable_dirty_sessions:
                    freshness_reasons.append("session_projection_dirty")
                elif dirty_sessions:
                    freshness_reasons.append("recent_live_projection_updates_deferred")
                elif latest_source_mtime > 0 and db_mtime < latest_source_mtime:
                    freshness_reasons.append("source_newer_than_search_index")
                diagnostics.extend(
                    reason
                    for reason in freshness_reasons
                    if reason not in diagnostics and reason != "recent_live_projection_updates_deferred"
                )
                freshness_status = "current"
                if actionable_dirty_sessions or "source_newer_than_search_index" in freshness_reasons:
                    freshness_status = "stale"
                elif dirty_sessions:
                    freshness_status = "current_with_deferred_live_updates"
                state_refresh: dict[str, Any] | None = None
                if record_freshness_state:
                    state_refresh = write_search_freshness_probe_state(
                        aoa_root,
                        projection_fingerprints=projection_fingerprints,
                        dirty_sessions=dirty_sessions,
                        live_defer_summary=live_defer_summary,
                        checked_at=utc_now(),
                    )
                    if state_refresh.get("diagnostics"):
                        diagnostics.extend(str(item) for item in state_refresh.get("diagnostics", []) if item)
                freshness = {
                    "status": freshness_status,
                    "checked": True,
                    "mode": "deep_projection_scan",
                    "scope": "selected_records" if scoped_freshness else "all_sessions",
                    "source_scan": True,
                    "selected_session_state_count": len(projection_fingerprints),
                    "indexed_session_state_count": len(indexed_session_states),
                    "dirty_session_count": len(dirty_sessions),
                    "actionable_dirty_session_count": len(actionable_dirty_sessions),
                    "deferred_live_session_count": int_value(live_defer_summary.get("deferred_live_session_count")),
                    "dirty_session_ids": [str(item.get("session_id") or "") for item in dirty_sessions if item.get("session_id")],
                    "actionable_dirty_session_ids": [
                        str(item.get("session_id") or "") for item in actionable_dirty_sessions if item.get("session_id")
                    ],
                    "dirty_sessions": dirty_sessions[:8],
                    "actionable_dirty_sessions": actionable_dirty_sessions[:8],
                    "deferred_live_sessions": (
                        live_defer_summary.get("deferred_live_sessions", [])[:8]
                        if isinstance(live_defer_summary.get("deferred_live_sessions"), list)
                        else []
                    ),
                    "live_defer_quiet_seconds": live_defer_summary.get("quiet_seconds"),
                    "latest_source_mtime": latest_source_mtime,
                    "db_mtime": db_mtime,
                    "reasons": freshness_reasons,
                    "state_refresh": state_refresh,
                }
            except Exception as exc:
                diagnostics.append(f"search_freshness_probe_failed:{exc.__class__.__name__}")
                freshness = {
                    "status": "unknown",
                    "checked": False,
                    "mode": "deep_projection_scan",
                    "source_scan": True,
                    "error": short_text(str(exc), max_chars=300),
                }
    ok = has_documents and not diagnostics
    status = (
        "ready_with_deferred_live_updates"
        if ok and freshness.get("status") == "current_with_deferred_live_updates"
        else ("ready" if ok else ("empty" if not has_documents else "stale"))
    )
    return {
        "provider": "portable_sqlite",
        "ok": ok,
        "status": status,
        "db_path": str(db_path),
        "index_generated_at": metadata.get("generated_at"),
        "metadata": metadata,
        "raw_lexical_policy": search_raw_lexical_policy_from_metadata(metadata),
        "search_schema_version": schema_version,
        "expected_search_schema_version": SEARCH_SCHEMA_VERSION,
        "document_count": total,
        "document_counts": counts,
        "count_mode": "not_counted_hot" if effective_freshness_mode == "hot" else "counted_deep",
        "has_documents": has_documents,
        **route_counts,
        "freshness": freshness,
        "diagnostics": diagnostics,
    }


def sqlite_provider_status_fast(aoa_root: Path) -> dict[str, Any]:
    db_path = search_db_path(aoa_root)
    if not db_path.exists():
        return {
            "provider": "portable_sqlite",
            "ok": False,
            "status": "missing",
            "db_path": str(db_path),
            "diagnostics": ["search index missing; run search-index"],
            "count_mode": "not_counted_fast",
        }
    try:
        conn = connect_existing_search_db(db_path)
        metadata = search_index_metadata(conn)
        schema_diagnostics = search_schema_diagnostics(conn)
        has_documents = bool(conn.execute("SELECT 1 FROM documents LIMIT 1").fetchone())
        has_routes = sqlite_table_exists(conn, "document_routes") and bool(conn.execute("SELECT 1 FROM document_routes LIMIT 1").fetchone())
        has_route_terms = sqlite_table_exists(conn, "route_terms") and bool(conn.execute("SELECT 1 FROM route_terms LIMIT 1").fetchone())
        freshness = sqlite_search_freshness_summary(conn, db_path=db_path)
        conn.close()
    except sqlite3.Error as exc:
        status = sqlite_error_status(exc)
        return {
            "provider": "portable_sqlite",
            "ok": False,
            "status": status,
            "db_path": str(db_path),
            "diagnostics": [sqlite_error_diagnostic(exc)],
            "count_mode": "not_counted_fast",
        }
    schema_version = str(metadata.get("schema_version") or "")
    diagnostics: list[str] = list(schema_diagnostics)
    if not has_documents:
        diagnostics.append("search index has no documents")
    if schema_version != str(SEARCH_SCHEMA_VERSION):
        diagnostics.append("search_schema_mismatch")
    if has_documents and not has_routes:
        diagnostics.append("search_route_index_empty")
    if has_routes and not has_route_terms:
        diagnostics.append("search_route_terms_empty")
    diagnostics.extend(
        reason
        for reason in freshness.get("reasons", [])
        if reason not in diagnostics and reason != "recent_live_projection_updates_deferred"
    )
    ok = has_documents and not diagnostics
    status = (
        "ready_with_deferred_live_updates"
        if ok and freshness.get("status") == "current_with_deferred_live_updates"
        else ("ready" if ok else ("empty" if not has_documents else "stale"))
    )
    return {
        "provider": "portable_sqlite",
        "ok": ok,
        "status": status,
        "db_path": str(db_path),
        "index_generated_at": metadata.get("generated_at"),
        "metadata": metadata,
        "raw_lexical_policy": search_raw_lexical_policy_from_metadata(metadata),
        "search_schema_version": schema_version,
        "expected_search_schema_version": SEARCH_SCHEMA_VERSION,
        "has_documents": has_documents,
        "has_route_index": has_routes,
        "has_route_terms": has_route_terms,
        "count_mode": "not_counted_fast",
        "freshness": freshness,
        "diagnostics": diagnostics,
    }


def search_provider_status_fast(
    *,
    aoa_root: Path,
    provider_name: str = "portable_sqlite",
) -> dict[str, Any]:
    now = utc_now()
    config = search_provider_config(aoa_root)
    default_provider = str(config.get("default_provider") or "portable_sqlite")
    if provider_name != "portable_sqlite":
        return search_provider_status(aoa_root=aoa_root, provider_name=provider_name)
    provider = sqlite_provider_status_fast(aoa_root)
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "search_provider_status",
        "provider_schema_version": SEARCH_PROVIDER_SCHEMA_VERSION,
        "generated_at": now,
        "ok": bool(provider.get("ok")),
        "aoa_root": str(aoa_root),
        "config_path": str(aoa_root / SEARCH_PROVIDER_CONFIG_PATH),
        "default_provider": default_provider,
        "authority_law": config.get("authority_law"),
        "selected_provider": provider_name,
        "status_mode": "fast_presence_probe",
        "providers": {"portable_sqlite": provider},
        "diagnostics": [] if provider.get("ok") else [f"portable_sqlite:{provider.get('status')}"],
    }


def host_provider_status(
    *,
    config: dict[str, Any],
    provider_name: str,
    force_probe: bool = False,
    refresh_host: bool = False,
    refresh_host_index: bool = False,
    timeout: int = 45,
) -> dict[str, Any]:
    provider = config.get("providers", {}).get(provider_name, {}) if isinstance(config.get("providers"), dict) else {}
    if not isinstance(provider, dict):
        return {"provider": provider_name, "ok": False, "status": "unknown_provider", "diagnostics": ["provider is not configured"]}
    if provider.get("write_policy") == "not_implemented_in_portable_bundle":
        return {
            "provider": provider_name,
            "ok": True,
            "status": "declared_future_optional",
            "portable": bool(provider.get("portable")),
            "role": provider.get("role"),
            "truth_level": provider.get("truth_level"),
            "write_policy": provider.get("write_policy"),
            "host_write_requires_operator_enablement": bool(provider.get("host_write_requires_operator_enablement")),
            "diagnostics": ["provider is declared for future runtime integration and is not used by portable search"],
        }
    if not provider.get("enabled") and not force_probe:
        return {
            "provider": provider_name,
            "ok": True,
            "status": "disabled_by_default",
            "portable": bool(provider.get("portable")),
            "role": provider.get("role"),
            "truth_level": provider.get("truth_level"),
            "diagnostics": ["provider disabled in config; use explicit host probing before relying on it"],
        }
    gates: dict[str, Any] = {}
    diagnostics: list[str] = []
    capability_command = provider.get("capability_gate") if isinstance(provider.get("capability_gate"), list) else []
    capability = run_json_command([str(part) for part in capability_command], timeout=timeout) if capability_command else {"ok": False, "status": "missing_gate", "error": "capability gate missing"}
    gates["capability_gate"] = compact_gate_result(capability)
    if not capability.get("ok"):
        diagnostics.append("capability_gate_failed")

    quality_key = "quality_gate"
    if refresh_host_index and isinstance(provider.get("refresh_index_quality_gate"), list):
        quality_key = "refresh_index_quality_gate"
    elif refresh_host and isinstance(provider.get("refresh_quality_gate"), list):
        quality_key = "refresh_quality_gate"
    quality_command = provider.get(quality_key) if isinstance(provider.get(quality_key), list) else provider.get("quality_gate")
    quality = run_json_command([str(part) for part in quality_command], timeout=timeout) if isinstance(quality_command, list) else {"ok": False, "status": "missing_gate", "error": "quality gate missing"}
    gates["quality_gate"] = compact_gate_result(quality)
    if not quality.get("ok"):
        diagnostics.append("quality_gate_failed")

    models: dict[str, Any] = {}
    model_warning_count = 0
    semantic_command = provider.get("semantic_status_gate") if isinstance(provider.get("semantic_status_gate"), list) else []
    if semantic_command:
        semantic_status = run_json_command([str(part) for part in semantic_command], timeout=timeout)
        models["embedding"] = compact_semantic_status_result(semantic_status)
        if not models["embedding"].get("ok"):
            model_warning_count += 1
            diagnostics.append(f"embedding_status:{models['embedding'].get('status')}")
    rerank_health_url = str(provider.get("rerank_api_health_url") or "")
    if rerank_health_url:
        rerank_health = run_json_url(rerank_health_url, timeout=min(timeout, 15))
        models["reranker"] = compact_rerank_health_result(rerank_health)
        if not models["reranker"].get("ok"):
            model_warning_count += 1
            diagnostics.append(f"reranker_status:{models['reranker'].get('status')}")

    warning_count = (
        int(gates["capability_gate"].get("warnings") or 0)
        + int(gates["quality_gate"].get("warnings") or 0)
        + model_warning_count
    )
    fail_count = int(gates["capability_gate"].get("fails") or 0) + int(gates["quality_gate"].get("fails") or 0)
    if warning_count:
        diagnostics.append("host_backend_has_warnings")
    status = "ready"
    ok = bool(capability.get("ok")) and bool(quality.get("ok")) and fail_count == 0
    if not ok:
        status = "unavailable"
    elif warning_count:
        status = "ready_with_warnings"
    return {
        "provider": provider_name,
        "ok": ok,
        "status": status,
        "portable": bool(provider.get("portable")),
        "role": provider.get("role"),
        "truth_level": provider.get("truth_level"),
        "write_policy": provider.get("write_policy"),
        "host_write_requires_operator_enablement": bool(provider.get("host_write_requires_operator_enablement")),
        "warning_count": warning_count,
        "fail_count": fail_count,
        "gates": gates,
        "models": models,
        "diagnostics": diagnostics,
    }


def search_provider_status(
    *,
    aoa_root: Path,
    provider_name: str = "all",
    include_host: bool = False,
    refresh_host: bool = False,
    refresh_host_index: bool = False,
    freshness_records: list[dict[str, Any]] | None = None,
    projection_fingerprints: list[dict[str, Any]] | None = None,
    timeout: int = 45,
    freshness_mode: str = "hot",
    record_freshness_state: bool = False,
    write_report: bool = False,
) -> dict[str, Any]:
    now = utc_now()
    config = search_provider_config(aoa_root)
    providers = config.get("providers") if isinstance(config.get("providers"), dict) else {}
    selected = sorted(providers) if provider_name == "all" else [provider_name]
    results: dict[str, Any] = {}
    diagnostics: list[str] = []
    effective_freshness_mode = "deep" if freshness_records is not None or projection_fingerprints is not None else freshness_mode
    for name in selected:
        if name == "portable_sqlite":
            results[name] = sqlite_provider_status(
                aoa_root,
                freshness_mode=effective_freshness_mode,
                record_freshness_state=record_freshness_state,
                freshness_records=freshness_records,
                projection_fingerprints=projection_fingerprints,
            )
        elif name in providers:
            if include_host or bool(providers.get(name, {}).get("enabled")):
                results[name] = host_provider_status(
                    config=config,
                    provider_name=name,
                    force_probe=include_host,
                    refresh_host=refresh_host,
                    refresh_host_index=refresh_host_index,
                    timeout=timeout,
                )
            else:
                provider = providers.get(name, {})
                results[name] = {
                    "provider": name,
                    "ok": True,
                    "status": "disabled_by_default",
                    "portable": bool(provider.get("portable")),
                    "role": provider.get("role"),
                    "truth_level": provider.get("truth_level"),
                    "diagnostics": ["host provider not probed; pass --include-host to run host gates"],
                }
        else:
            results[name] = {"provider": name, "ok": False, "status": "unknown_provider", "diagnostics": ["provider is not configured"]}
    for name, result in results.items():
        if not result.get("ok"):
            diagnostics.append(f"{name}:{result.get('status')}")
    default_provider = str(config.get("default_provider") or "portable_sqlite")
    default_status = results.get(default_provider) or sqlite_provider_status(
        aoa_root,
        freshness_mode=effective_freshness_mode,
        record_freshness_state=record_freshness_state,
        freshness_records=freshness_records,
        projection_fingerprints=projection_fingerprints,
    )
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "search_provider_status",
        "provider_schema_version": SEARCH_PROVIDER_SCHEMA_VERSION,
        "generated_at": now,
        "ok": bool(default_status.get("ok")) and not any(
            not result.get("ok") and result.get("status") != "disabled_by_default"
            for result in results.values()
            if provider_name != "all" or result.get("provider") == default_provider
        ),
        "aoa_root": str(aoa_root),
        "config_path": str(aoa_root / SEARCH_PROVIDER_CONFIG_PATH),
        "default_provider": default_provider,
        "authority_law": config.get("authority_law"),
        "selected_provider": provider_name,
        "freshness_mode": effective_freshness_mode,
        "record_freshness_state": record_freshness_state,
        "providers": results,
        "diagnostics": diagnostics,
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__search-provider-status"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, search_provider_status_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def compact_search_provider_session_sample(item: Any) -> dict[str, Any]:
    if not isinstance(item, dict):
        return {"value": str(item)}
    keys = (
        "session_id",
        "session_label",
        "session_dir",
        "latest_source_mtime",
        "indexed_mtime",
        "reason",
    )
    return {key: item.get(key) for key in keys if item.get(key) is not None}


def compact_search_provider_freshness_for_route(
    freshness: Any,
    *,
    sample_limit: int = 3,
) -> dict[str, Any]:
    if not isinstance(freshness, dict):
        return {"status": "unknown", "checked": False}
    keys = (
        "status",
        "checked",
        "mode",
        "scope",
        "source_scan",
        "selected_session_state_count",
        "indexed_session_state_count",
        "dirty_session_count",
        "actionable_dirty_session_count",
        "deferred_live_session_count",
        "live_defer_quiet_seconds",
        "latest_source_mtime",
        "db_mtime",
        "reasons",
    )
    compact = {key: freshness.get(key) for key in keys if key in freshness}
    dirty_sessions = freshness.get("dirty_sessions")
    if isinstance(dirty_sessions, list) and dirty_sessions:
        compact["dirty_session_samples"] = [
            compact_search_provider_session_sample(item)
            for item in dirty_sessions[:sample_limit]
        ]
        compact["dirty_session_sample_count"] = min(len(dirty_sessions), sample_limit)
        compact["omitted_dirty_session_count"] = max(0, int_value(freshness.get("dirty_session_count") or len(dirty_sessions)) - sample_limit)
    actionable_sessions = freshness.get("actionable_dirty_sessions")
    if isinstance(actionable_sessions, list) and actionable_sessions:
        compact["actionable_dirty_session_samples"] = [
            compact_search_provider_session_sample(item)
            for item in actionable_sessions[:sample_limit]
        ]
        compact["actionable_dirty_session_sample_count"] = min(len(actionable_sessions), sample_limit)
    deferred_sessions = freshness.get("deferred_live_sessions")
    if isinstance(deferred_sessions, list) and deferred_sessions:
        compact["deferred_live_session_samples"] = [
            compact_search_provider_session_sample(item)
            for item in deferred_sessions[:sample_limit]
        ]
        compact["deferred_live_session_sample_count"] = min(len(deferred_sessions), sample_limit)
    omitted_fields = [
        key
        for key in (
            "dirty_session_ids",
            "dirty_sessions",
            "actionable_dirty_session_ids",
            "actionable_dirty_sessions",
            "deferred_live_sessions",
        )
        if key in freshness
    ]
    if omitted_fields:
        compact["omitted_fields"] = omitted_fields
    return compact


def compact_search_provider_status_for_route(
    provider_status: dict[str, Any],
    *,
    provider_name: str = "portable_sqlite",
) -> dict[str, Any]:
    top_keys = (
        "schema_version",
        "artifact_type",
        "provider_schema_version",
        "generated_at",
        "ok",
        "aoa_root",
        "default_provider",
        "authority_law",
        "selected_provider",
        "freshness_mode",
        "status_mode",
        "diagnostics",
    )
    provider_keys = (
        "provider",
        "ok",
        "status",
        "db_path",
        "index_generated_at",
        "search_schema_version",
        "expected_search_schema_version",
        "document_count",
        "route_index_count",
        "route_term_count",
        "has_documents",
        "has_route_index",
        "has_route_terms",
        "count_mode",
        "diagnostics",
    )
    compact = {key: provider_status.get(key) for key in top_keys if key in provider_status}
    providers = provider_status.get("providers") if isinstance(provider_status.get("providers"), dict) else {}
    compact_providers: dict[str, Any] = {}
    selected_names = [provider_name] if provider_name in providers else list(providers)
    for name in selected_names:
        value = providers.get(name)
        if not isinstance(value, dict):
            compact_providers[str(name)] = value
            continue
        compact_provider = {key: value.get(key) for key in provider_keys if key in value}
        compact_provider["freshness"] = compact_search_provider_freshness_for_route(value.get("freshness"))
        compact_providers[str(name)] = compact_provider
    compact["providers"] = compact_providers
    compact["full_status_route"] = f"search-provider-status --provider {provider_name}"
    compact["response_compacted"] = True
    return compact


def search_provider_status_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Search Provider Status",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- default_provider: `{payload.get('default_provider')}`",
        f"- selected_provider: `{payload.get('selected_provider')}`",
        "",
        "## Providers",
        "",
        "| provider | status | ok | role | diagnostics |",
        "| --- | --- | --- | --- | --- |",
    ]
    providers = payload.get("providers") if isinstance(payload.get("providers"), dict) else {}
    for name, item in providers.items():
        if not isinstance(item, dict):
            continue
        diagnostics = ", ".join(str(value) for value in item.get("diagnostics", []) if value) if isinstance(item.get("diagnostics"), list) else ""
        lines.append(f"| `{name}` | `{item.get('status')}` | `{item.get('ok')}` | `{item.get('role')}` | {diagnostics or 'none'} |")
    model_rows: list[str] = []
    for name, item in providers.items():
        if not isinstance(item, dict) or not isinstance(item.get("models"), dict):
            continue
        for model_name, model in item["models"].items():
            if not isinstance(model, dict):
                continue
            model_rows.append(
                f"| `{name}` | `{model_name}` | `{model.get('status')}` | `{model.get('ok')}` | `{model.get('model') or model.get('model_dir') or ''}` | `{model.get('device') or ''}` |"
            )
    if model_rows:
        lines.extend(["", "## Local Model Gates", "", "| provider | model gate | status | ok | model | device |", "| --- | --- | --- | --- | --- | --- |"])
        lines.extend(model_rows)
    lines.extend(["", "## Authority Law", "", str(payload.get("authority_law") or "")])
    return "\n".join(lines)


def compact_host_recall_payload(result: dict[str, Any]) -> dict[str, Any]:
    payload = result.get("payload") if isinstance(result.get("payload"), dict) else {}
    evidence = payload.get("evidence") if isinstance(payload.get("evidence"), list) else []
    return {
        "ok": bool(result.get("ok")),
        "status": result.get("status"),
        "command": result.get("command"),
        "schema": payload.get("schema") or payload.get("schema_version"),
        "generated_at": payload.get("generated_at"),
        "mode": payload.get("mode"),
        "query": payload.get("query"),
        "summary": payload.get("summary"),
        "evidence_count": len(evidence),
        "paths": payload.get("paths") if isinstance(payload.get("paths"), dict) else {},
        "truth_level": "host_context_only_not_aoa_authority",
    }


def compact_host_semantic_payload(result: dict[str, Any], *, sample_limit: int = 5) -> dict[str, Any]:
    payload = result.get("payload") if isinstance(result.get("payload"), dict) else {}
    hits: list[dict[str, Any]] = []
    for item in payload.get("results", []) if isinstance(payload.get("results"), list) else []:
        if not isinstance(item, dict):
            continue
        hits.append(
            {
                "source_id": item.get("source_id"),
                "document_schema": item.get("document_schema"),
                "title": item.get("title"),
                "score": item.get("score") or item.get("semantic_score"),
                "generated_at": item.get("generated_at"),
                "indexed_at": item.get("indexed_at"),
                "snippet": short_text(item.get("snippet") or item.get("body_preview"), max_chars=360),
            }
        )
        if len(hits) >= sample_limit:
            break
    embedding_status = payload.get("embedding_status") if isinstance(payload.get("embedding_status"), dict) else {}
    return {
        "ok": bool(result.get("ok")),
        "status": result.get("status"),
        "command": result.get("command"),
        "schema": payload.get("schema") or payload.get("schema_version"),
        "generated_at": payload.get("generated_at"),
        "query": payload.get("query"),
        "result_count": len(payload.get("results", [])) if isinstance(payload.get("results"), list) else 0,
        "summary": payload.get("summary") if isinstance(payload.get("summary"), dict) else {},
        "embedding": {
            "ok": embedding_status.get("ok"),
            "dim": embedding_status.get("dim"),
            "device": embedding_status.get("device"),
            "model_dir": embedding_status.get("model_dir"),
        },
        "hits": hits,
        "truth_level": "host_semantic_context_only_not_aoa_authority",
    }


def host_context_overlay(
    *,
    config: dict[str, Any],
    provider_name: str,
    query: str,
    limit: int,
    timeout: int,
) -> dict[str, Any]:
    provider = config.get("providers", {}).get(provider_name, {}) if isinstance(config.get("providers"), dict) else {}
    command = provider.get("recall_command") if isinstance(provider, dict) else None
    if not isinstance(command, list):
        return {"ok": False, "status": "not_supported", "diagnostics": ["provider has no recall_command"]}
    rendered = [
        str(part).replace("{query}", query).replace("{limit}", str(max(1, min(limit, 10))))
        for part in command
    ]
    result = run_json_command(rendered, timeout=timeout)
    return compact_host_recall_payload(result)


def host_semantic_overlay(
    *,
    config: dict[str, Any],
    provider_name: str,
    query: str,
    limit: int,
    timeout: int,
) -> dict[str, Any]:
    provider = config.get("providers", {}).get(provider_name, {}) if isinstance(config.get("providers"), dict) else {}
    command = provider.get("semantic_search_command") if isinstance(provider, dict) else None
    if not isinstance(command, list):
        return {"ok": False, "status": "not_supported", "diagnostics": ["provider has no semantic_search_command"]}
    rendered = [
        str(part).replace("{query}", query).replace("{limit}", str(max(1, min(limit, 10))))
        for part in command
    ]
    result = run_json_command(rendered, timeout=timeout)
    return compact_host_semantic_payload(result)


def rerank_document_for_search_hit(hit: dict[str, Any]) -> str:
    parts = [
        f"title: {hit.get('title') or ''}",
        f"session: {hit.get('session_label') or ''}",
        f"event_type: {hit.get('event_type') or ''}",
        f"conversation_act: {hit.get('conversation_act') or ''}",
        f"session_act: {hit.get('session_act') or ''}",
        f"route_layers: {hit.get('route_layers') or ''}",
        f"route_signals: {hit.get('route_signals') or ''}",
        f"snippet: {hit.get('snippet') or ''}",
    ]
    return short_text("\n".join(part for part in parts if part.strip()), max_chars=2000)


def local_rerank_search_results(
    *,
    config: dict[str, Any],
    provider_name: str,
    query: str,
    results: list[dict[str, Any]],
    timeout: int,
    candidate_limit: int | None = None,
) -> dict[str, Any]:
    provider = config.get("providers", {}).get(provider_name, {}) if isinstance(config.get("providers"), dict) else {}
    url = str(provider.get("rerank_api_url") or "")
    if not url:
        return {"ok": False, "status": "not_supported", "diagnostics": ["provider has no rerank_api_url"], "results": results}
    if not query.strip():
        return {"ok": False, "status": "empty_query", "diagnostics": ["rerank requires a non-empty query"], "results": results}
    configured_limit = int_value(provider.get("rerank_candidate_limit"), 24)
    effective_limit = max(1, min(candidate_limit or configured_limit or 24, len(results)))
    candidates = results[:effective_limit]
    documents = [rerank_document_for_search_hit(hit) for hit in candidates]
    response = run_json_url(
        url,
        method="POST",
        payload={"query": query, "documents": documents},
        timeout=min(timeout, 60),
    )
    payload = response.get("payload") if isinstance(response.get("payload"), dict) else {}
    ranked_items = payload.get("results") if isinstance(payload.get("results"), list) else []
    if not response.get("ok") or not ranked_items:
        return {
            "ok": False,
            "status": response.get("status") or "empty_rerank",
            "url": url,
            "diagnostics": [str(response.get("error") or response.get("status") or "rerank failed")],
            "results": results,
        }
    by_index: dict[int, dict[str, Any]] = {}
    for item in ranked_items:
        if not isinstance(item, dict):
            continue
        idx = int_value(item.get("index"), -1)
        if 0 <= idx < len(candidates):
            by_index[idx] = item
    annotated: list[dict[str, Any]] = []
    for idx, hit in enumerate(candidates):
        clone = dict(hit)
        refs = hit.get("refs") if isinstance(hit.get("refs"), dict) else {}
        if refs:
            clone["refs"] = dict(refs)
        item = by_index.get(idx, {})
        score = item.get("relevance_score")
        clone["host_rerank"] = {
            "provider": provider_name,
            "model": payload.get("model"),
            "score": score,
            "raw_logit_diff": item.get("raw_logit_diff"),
            "original_position": idx + 1,
            "truth_level": "local_rerank_ordering_not_aoa_authority",
        }
        annotated.append(clone)
    annotated.sort(
        key=lambda hit: (
            hit.get("host_rerank", {}).get("score") is None,
            -(float(hit.get("host_rerank", {}).get("score") or 0.0)),
            int_value(hit.get("host_rerank", {}).get("original_position"), 999999),
        )
    )
    for idx, hit in enumerate(annotated, start=1):
        if isinstance(hit.get("host_rerank"), dict):
            hit["host_rerank"]["reranked_position"] = idx
    final_results = annotated + results[effective_limit:]
    meta = payload.get("meta") if isinstance(payload.get("meta"), dict) else {}
    return {
        "ok": True,
        "status": "applied",
        "url": url,
        "model": payload.get("model"),
        "candidate_count": len(candidates),
        "returned_count": len(ranked_items),
        "meta": {
            "backend": meta.get("backend"),
            "device": meta.get("device"),
            "documents": meta.get("documents"),
            "returned": meta.get("returned"),
            "total_ms": meta.get("total_ms"),
            "fake_mode": meta.get("fake_mode"),
        },
        "truth_level": "local_rerank_ordering_not_aoa_authority",
        "results": final_results,
    }


SEARCH_DB_INDEX_STATEMENTS = [
    "CREATE INDEX IF NOT EXISTS idx_documents_session ON documents(session_label)",
    "CREATE INDEX IF NOT EXISTS idx_documents_session_id ON documents(session_id)",
    "CREATE INDEX IF NOT EXISTS idx_documents_type ON documents(doc_type, event_type)",
    "CREATE INDEX IF NOT EXISTS idx_documents_doc_type_date ON documents(doc_type, session_date DESC, rowid DESC)",
    "CREATE INDEX IF NOT EXISTS idx_documents_usage_role_date ON documents(usage_role, session_date DESC, rowid DESC)",
    "CREATE INDEX IF NOT EXISTS idx_documents_doc_type_usage_role_date ON documents(doc_type, usage_role, session_date DESC, rowid DESC)",
    "CREATE INDEX IF NOT EXISTS idx_documents_session_act_date ON documents(session_act, session_date DESC, rowid DESC)",
    "CREATE INDEX IF NOT EXISTS idx_documents_doc_type_session_act_date ON documents(doc_type, session_act, session_date DESC, rowid DESC)",
    "CREATE INDEX IF NOT EXISTS idx_documents_agent_event_date ON documents(agent_event, session_date DESC, rowid DESC)",
    "CREATE INDEX IF NOT EXISTS idx_documents_task_episode_date ON documents(task_episode_id, session_date DESC, rowid DESC)",
    "CREATE INDEX IF NOT EXISTS idx_documents_status ON documents(archive_status, freshness_status)",
    "CREATE INDEX IF NOT EXISTS idx_route_terms_signal ON route_terms(route_signal)",
    "CREATE INDEX IF NOT EXISTS idx_route_terms_layer_key ON route_terms(layer, key)",
    "CREATE INDEX IF NOT EXISTS idx_document_routes_route ON document_routes(route_id, doc_rowid)",
    "CREATE INDEX IF NOT EXISTS idx_session_index_state_label ON session_index_state(session_label)",
    "CREATE INDEX IF NOT EXISTS idx_search_freshness_state_status ON search_freshness_state(status, session_label)",
    "CREATE INDEX IF NOT EXISTS idx_omitted_context_tail_route_refs_layer_key ON omitted_context_tail_route_refs(layer, key)",
    "CREATE INDEX IF NOT EXISTS idx_omitted_context_tail_route_refs_signal ON omitted_context_tail_route_refs(route_signal)",
    "CREATE INDEX IF NOT EXISTS idx_omitted_context_tail_route_refs_session ON omitted_context_tail_route_refs(session_label, session_id)",
    "CREATE INDEX IF NOT EXISTS idx_omitted_context_tail_route_refs_date ON omitted_context_tail_route_refs(session_date DESC, id DESC)",
]


def search_index_name_from_statement(statement: str) -> str:
    marker = "INDEX IF NOT EXISTS "
    if marker not in statement:
        return ""
    return statement.split(marker, 1)[1].split(None, 1)[0]


def create_search_db_indexes(
    conn: sqlite3.Connection,
    *,
    progress_callback: Callable[[str, dict[str, Any]], None] | None = None,
) -> list[dict[str, Any]]:
    timings: list[dict[str, Any]] = []
    for statement in SEARCH_DB_INDEX_STATEMENTS:
        index_name = search_index_name_from_statement(statement)
        started = time.monotonic()
        if progress_callback is not None:
            progress_callback("search_index_sqlite_index_start", {"index": index_name})
        conn.execute(statement)
        elapsed_ms = int((time.monotonic() - started) * 1000)
        timing = {"index": index_name, "elapsed_ms": elapsed_ms}
        timings.append(timing)
        if progress_callback is not None:
            progress_callback("search_index_sqlite_index_done", timing)
    return timings


def sqlite_sidecar_paths(db_path: Path) -> list[Path]:
    return [Path(str(db_path) + suffix) for suffix in ("-journal", "-wal", "-shm")]


def cleanup_sqlite_sidecars(db_path: Path) -> None:
    for path in sqlite_sidecar_paths(db_path):
        if path.exists():
            path.unlink()


def search_route_term_cache(conn: sqlite3.Connection) -> dict[tuple[str, str], int]:
    cache = getattr(conn, "aoa_route_term_cache", None)
    if isinstance(cache, dict):
        return cache
    cache = {}
    try:
        setattr(conn, "aoa_route_term_cache", cache)
        return cache
    except AttributeError:
        return {}


def clear_search_route_term_cache(conn: sqlite3.Connection) -> None:
    cache = getattr(conn, "aoa_route_term_cache", None)
    if isinstance(cache, dict):
        cache.clear()
    SEARCH_ROUTE_TERM_CACHE.pop(id(conn), None)


def seed_search_freshness_state_from_session_index(conn: sqlite3.Connection, *, updated_at: str) -> None:
    has_session_state = bool(
        conn.execute("SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'session_index_state'").fetchone()
    )
    has_freshness_state = bool(
        conn.execute("SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'search_freshness_state'").fetchone()
    )
    if not has_session_state or not has_freshness_state:
        return
    session_state_columns = {str(row[1]) for row in conn.execute("PRAGMA table_info(session_index_state)").fetchall()}
    projection_mode_expr = (
        "COALESCE(projection_fingerprint_mode, '')"
        if "projection_fingerprint_mode" in session_state_columns
        else "''"
    )
    conn.execute(
        f"""
        INSERT OR IGNORE INTO search_freshness_state (
            session_id, session_label, session_dir, source_fingerprint, source_latest_mtime,
            status, reason, last_checked, last_indexed_at, deferred_live_reason,
            live_transcript_path, live_transcript_mtime, search_schema_version,
            route_signal_classifier_version, document_count, updated_at,
            projection_fingerprint_mode
        )
        SELECT
            session_id, session_label, '', source_fingerprint, source_latest_mtime,
            'current', 'seeded_from_session_index_state', COALESCE(indexed_at, ?), indexed_at, '',
            '', 0, search_schema_version, route_signal_classifier_version, document_count, ?,
            {projection_mode_expr}
        FROM session_index_state
        WHERE COALESCE(session_id, '') <> ''
        """,
        (updated_at, updated_at),
    )


def init_search_db(
    db_path: Path,
    *,
    rebuild: bool = False,
    create_indexes: bool = True,
    budget_deadline: float | None = None,
) -> sqlite3.Connection:
    db_path.parent.mkdir(parents=True, exist_ok=True)
    if rebuild and db_path.exists():
        cleanup_sqlite_sidecars(db_path)
        db_path.unlink()
    conn = sqlite3.connect(str(db_path), factory=SearchSqliteConnection)
    conn.row_factory = sqlite3.Row
    conn.execute("PRAGMA busy_timeout=5000")
    journal_mode = "DELETE" if rebuild else "WAL"
    try:
        conn.execute(f"PRAGMA journal_mode={journal_mode}")
    except sqlite3.Error:
        if rebuild:
            raise
        conn.execute("PRAGMA journal_mode=DELETE")
    conn.execute("PRAGMA synchronous=NORMAL")
    conn.execute("PRAGMA temp_store=FILE")
    conn.execute("PRAGMA cache_size=-64000")
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS meta (
            key TEXT PRIMARY KEY,
            value TEXT NOT NULL
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS documents (
            rowid INTEGER PRIMARY KEY AUTOINCREMENT,
            id TEXT NOT NULL UNIQUE,
            doc_type TEXT NOT NULL,
            session_id TEXT,
            session_label TEXT,
            session_title TEXT,
            session_date TEXT,
            cwd TEXT,
            archive_status TEXT,
            distillation_status TEXT,
            review_status TEXT,
            segment_id TEXT,
            event_id TEXT,
            event_type TEXT,
            family TEXT,
            phase TEXT,
            actor TEXT,
            action TEXT,
            object TEXT,
            outcome TEXT,
            conversation_act TEXT,
            session_act TEXT,
            agent_event TEXT,
            usage_role TEXT,
            task_episode_id TEXT,
            route_layers TEXT,
            route_signals TEXT,
            tags TEXT,
            raw_ref TEXT,
            raw_block_ref TEXT,
            segment_ref TEXT,
            manifest_path TEXT,
            raw_path TEXT,
            segment_index_path TEXT,
            raw_sha256 TEXT,
            segment_index_sha256 TEXT,
            freshness_status TEXT,
            stale_reason TEXT,
            title TEXT,
            body TEXT,
            payload_json TEXT NOT NULL
        )
        """
    )
    existing_route_columns = {str(row[1]) for row in conn.execute("PRAGMA table_info(document_routes)").fetchall()}
    existing_term_columns = {str(row[1]) for row in conn.execute("PRAGMA table_info(route_terms)").fetchall()}
    if existing_route_columns and not {"doc_rowid", "route_id"}.issubset(existing_route_columns):
        conn.execute("DROP TABLE IF EXISTS document_routes")
        conn.execute("DROP TABLE IF EXISTS route_terms")
        clear_search_route_term_cache(conn)
        existing_route_columns = set()
        existing_term_columns = set()
    if existing_term_columns and not {"layer", "key", "route_signal"}.issubset(existing_term_columns):
        conn.execute("DROP TABLE IF EXISTS document_routes")
        conn.execute("DROP TABLE IF EXISTS route_terms")
        clear_search_route_term_cache(conn)
        existing_route_columns = set()
        existing_term_columns = set()
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS route_terms (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            layer TEXT NOT NULL,
            key TEXT NOT NULL,
            route_signal TEXT NOT NULL,
            UNIQUE(layer, key),
            UNIQUE(route_signal)
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS document_routes (
            doc_rowid INTEGER NOT NULL,
            route_id INTEGER NOT NULL,
            PRIMARY KEY(doc_rowid, route_id)
        ) WITHOUT ROWID
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS document_bodies (
            doc_rowid INTEGER PRIMARY KEY,
            body_zlib BLOB NOT NULL,
            body_sha256 TEXT NOT NULL,
            body_chars INTEGER NOT NULL
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS omitted_context_tail_route_refs (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            doc_id TEXT NOT NULL DEFAULT '',
            session_id TEXT NOT NULL DEFAULT '',
            session_label TEXT NOT NULL DEFAULT '',
            session_date TEXT NOT NULL DEFAULT '',
            event_id TEXT NOT NULL DEFAULT '',
            event_type TEXT NOT NULL DEFAULT '',
            raw_ref TEXT NOT NULL DEFAULT '',
            segment_ref TEXT NOT NULL DEFAULT '',
            layer TEXT NOT NULL,
            key TEXT NOT NULL,
            route_signal TEXT NOT NULL
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS session_index_state (
            session_id TEXT PRIMARY KEY,
            session_label TEXT,
            source_fingerprint TEXT NOT NULL,
            source_latest_mtime REAL,
            search_schema_version TEXT,
            route_signal_classifier_version INTEGER,
            indexed_at TEXT,
            document_count INTEGER,
            projection_fingerprint_mode TEXT
        )
        """
    )
    conn.execute(
        """
        CREATE TABLE IF NOT EXISTS search_freshness_state (
            session_id TEXT PRIMARY KEY,
            session_label TEXT,
            session_dir TEXT,
            source_fingerprint TEXT NOT NULL,
            source_latest_mtime REAL,
            status TEXT NOT NULL,
            reason TEXT,
            last_checked TEXT,
            last_indexed_at TEXT,
            deferred_live_reason TEXT,
            live_transcript_path TEXT,
            live_transcript_mtime REAL,
            search_schema_version TEXT,
            route_signal_classifier_version INTEGER,
            document_count INTEGER,
            updated_at TEXT NOT NULL,
            projection_fingerprint_mode TEXT
        )
        """
    )
    existing_session_state_columns = {str(row[1]) for row in conn.execute("PRAGMA table_info(session_index_state)").fetchall()}
    if "projection_fingerprint_mode" not in existing_session_state_columns:
        conn.execute("ALTER TABLE session_index_state ADD COLUMN projection_fingerprint_mode TEXT")
    existing_freshness_columns = {str(row[1]) for row in conn.execute("PRAGMA table_info(search_freshness_state)").fetchall()}
    if "projection_fingerprint_mode" not in existing_freshness_columns:
        conn.execute("ALTER TABLE search_freshness_state ADD COLUMN projection_fingerprint_mode TEXT")
    seed_search_freshness_state_from_session_index(conn, updated_at=utc_now())
    existing_columns = {str(row[1]) for row in conn.execute("PRAGMA table_info(documents)").fetchall()}
    if "session_act" not in existing_columns:
        conn.execute("ALTER TABLE documents ADD COLUMN session_act TEXT")
    if "agent_event" not in existing_columns:
        conn.execute("ALTER TABLE documents ADD COLUMN agent_event TEXT")
    if "usage_role" not in existing_columns:
        conn.execute("ALTER TABLE documents ADD COLUMN usage_role TEXT")
    if "task_episode_id" not in existing_columns:
        conn.execute("ALTER TABLE documents ADD COLUMN task_episode_id TEXT")
    if "route_layers" not in existing_columns:
        conn.execute("ALTER TABLE documents ADD COLUMN route_layers TEXT")
    if "route_signals" not in existing_columns:
        conn.execute("ALTER TABLE documents ADD COLUMN route_signals TEXT")
    conn.execute(
        """
        CREATE VIRTUAL TABLE IF NOT EXISTS documents_fts
        USING fts5(title, body, session_label, session_title, content='documents', content_rowid='rowid')
        """
    )
    if create_indexes:
        if budget_deadline is not None:
            conn.set_progress_handler(lambda: 1 if time.monotonic() >= budget_deadline else 0, 10000)
        try:
            create_search_db_indexes(conn)
        finally:
            if budget_deadline is not None:
                conn.set_progress_handler(None, 0)
    conn.commit()
    return conn


def reset_search_db(conn: sqlite3.Connection) -> None:
    conn.execute("DELETE FROM documents_fts")
    conn.execute("DELETE FROM document_bodies")
    conn.execute("DELETE FROM document_routes")
    conn.execute("DELETE FROM route_terms")
    conn.execute("DELETE FROM omitted_context_tail_route_refs")
    conn.execute("DELETE FROM documents")
    conn.execute("DELETE FROM session_index_state")
    conn.execute("DELETE FROM search_freshness_state")
    conn.execute("DELETE FROM meta")
    clear_search_route_term_cache(conn)


def migrate_search_schema_usage_role_db(
    *,
    db_path: Path,
    now: str,
    target_kind: str,
    shard: str = "",
) -> dict[str, Any]:
    if not db_path.exists():
        return {
            "ok": False,
            "target_kind": target_kind,
            "shard": shard,
            "db_path": str(db_path),
            "diagnostics": ["search_index_missing"],
        }
    conn: sqlite3.Connection | None = None
    diagnostics: list[str] = []
    try:
        conn = init_search_db(db_path, rebuild=False, create_indexes=False)
        before_metadata = search_index_metadata(conn)
        before_schema_version = str(before_metadata.get("schema_version") or "")
        before_event_missing = int_value(
            conn.execute(
                "SELECT COUNT(*) FROM documents WHERE doc_type = 'event' AND COALESCE(usage_role, '') = ''"
            ).fetchone()[0]
        )
        direct_placeholders = ",".join("?" for _ in sorted(ENTITY_USAGE_DIRECT_TYPES))
        result_placeholders = ",".join("?" for _ in sorted(ENTITY_USAGE_RESULT_TYPES))
        outcome_placeholders = ",".join("?" for _ in sorted(ENTITY_USAGE_OUTCOME_TYPES))
        entrypoint_placeholders = ",".join("?" for _ in sorted(ENTITY_USAGE_ENTRYPOINT_TYPES))
        goal_placeholders = ",".join("?" for _ in sorted(GOAL_SESSION_ACTS))
        conn.execute(
            f"""
            UPDATE documents
            SET usage_role = CASE
                WHEN session_act IN ({goal_placeholders}) THEN 'usage'
                WHEN event_type IN ({direct_placeholders}) THEN 'usage'
                WHEN event_type IN ({result_placeholders}) THEN 'result'
                WHEN event_type IN ({outcome_placeholders}) THEN 'outcome'
                WHEN event_type IN ({entrypoint_placeholders}) THEN 'entrypoint'
                WHEN conversation_act LIKE '%request%' OR session_act LIKE '%request%' THEN 'entrypoint'
                ELSE 'context'
            END
            WHERE doc_type = 'event'
              AND COALESCE(usage_role, '') = ''
            """,
            [
                *sorted(GOAL_SESSION_ACTS),
                *sorted(ENTITY_USAGE_DIRECT_TYPES),
                *sorted(ENTITY_USAGE_RESULT_TYPES),
                *sorted(ENTITY_USAGE_OUTCOME_TYPES),
                *sorted(ENTITY_USAGE_ENTRYPOINT_TYPES),
            ],
        )
        conn.execute("UPDATE documents SET usage_role = '' WHERE doc_type <> 'event' AND COALESCE(usage_role, '') <> ''")
        after_event_missing = int_value(
            conn.execute(
                "SELECT COUNT(*) FROM documents WHERE doc_type = 'event' AND COALESCE(usage_role, '') = ''"
            ).fetchone()[0]
        )
        role_counts = {
            str(row["usage_role"] or ""): int_value(row["count"])
            for row in conn.execute(
                "SELECT COALESCE(usage_role, '') AS usage_role, COUNT(*) AS count FROM documents WHERE doc_type = 'event' GROUP BY COALESCE(usage_role, '')"
            ).fetchall()
        }
        conn.executemany(
            "INSERT OR REPLACE INTO meta(key, value) VALUES (?, ?)",
            [
                ("schema_version", str(SEARCH_SCHEMA_VERSION)),
                ("search_usage_role_projection_version", str(SEARCH_USAGE_ROLE_PROJECTION_VERSION)),
                ("search_schema_migrated_at", now),
                ("entity_registry_search_schema_version", str(SEARCH_SCHEMA_VERSION)),
            ],
        )
        conn.execute("UPDATE session_index_state SET search_schema_version = ?", (str(SEARCH_SCHEMA_VERSION),))
        conn.execute(
            "UPDATE search_freshness_state SET search_schema_version = ?, updated_at = ?",
            (str(SEARCH_SCHEMA_VERSION), now),
        )
        index_timings = create_search_db_indexes(conn)
        conn.commit()
        after_metadata = search_index_metadata(conn)
        payload = {
            "ok": after_event_missing == 0,
            "target_kind": target_kind,
            "shard": shard,
            "db_path": str(db_path),
            "search_schema_version_before": before_schema_version,
            "search_schema_version_after": str(after_metadata.get("schema_version") or ""),
            "usage_role_projection_version": SEARCH_USAGE_ROLE_PROJECTION_VERSION,
            "event_missing_usage_role_before": before_event_missing,
            "event_missing_usage_role_after": after_event_missing,
            "backfilled_event_document_count": max(0, before_event_missing - after_event_missing),
            "role_counts": dict(sorted(role_counts.items())),
            "index_count": len(index_timings),
            "index_timings": index_timings,
            "diagnostics": diagnostics if after_event_missing == 0 else [*diagnostics, "usage_role_backfill_incomplete"],
            "truth_status": "generated_search_projection_migration_not_raw_truth",
        }
    except sqlite3.Error as exc:
        if conn is not None:
            conn.rollback()
        payload = {
            "ok": False,
            "target_kind": target_kind,
            "shard": shard,
            "db_path": str(db_path),
            "diagnostics": [sqlite_error_diagnostic(exc)],
        }
    finally:
        if conn is not None:
            conn.close()
    return payload


def migrate_search_schema_usage_role(
    *,
    aoa_root: Path,
    write_report: bool = False,
) -> dict[str, Any]:
    now = utc_now()
    monolith_path = search_db_path(aoa_root)
    targets: list[dict[str, Any]] = [
        {"target_kind": "monolith", "shard": "", "db_path": monolith_path},
    ]
    catalog = read_search_catalog(aoa_root)
    seen_paths = {str(monolith_path)}
    for item in catalog.get("shards", []) if isinstance(catalog.get("shards"), list) else []:
        if not isinstance(item, dict) or not item.get("materialized"):
            continue
        shard_path = Path(str(item.get("shard_db_path") or ""))
        if not shard_path or str(shard_path) in seen_paths:
            continue
        seen_paths.add(str(shard_path))
        targets.append(
            {
                "target_kind": "shard",
                "shard": str(item.get("shard") or ""),
                "db_path": shard_path,
            }
        )
    target_results = [
        migrate_search_schema_usage_role_db(
            db_path=Path(str(target["db_path"])),
            now=now,
            target_kind=str(target.get("target_kind") or ""),
            shard=str(target.get("shard") or ""),
        )
        for target in targets
    ]
    monolith = next((item for item in target_results if item.get("target_kind") == "monolith"), target_results[0] if target_results else {})
    shard_role_counts: Counter[str] = Counter()
    for item in target_results:
        if item.get("target_kind") != "shard":
            continue
        for role, count in (item.get("role_counts") if isinstance(item.get("role_counts"), dict) else {}).items():
            shard_role_counts[str(role)] += int_value(count)
    diagnostics = [
        f"{item.get('target_kind')}:{item.get('shard') or item.get('db_path')}:{diag}"
        for item in target_results
        for diag in (item.get("diagnostics") if isinstance(item.get("diagnostics"), list) else [])
        if diag
    ]
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "search_schema_migration",
        "generated_at": now,
        "ok": bool(target_results) and all(bool(item.get("ok")) for item in target_results),
        "mutates": True,
        "db_path": str(monolith_path),
        "target_count": len(target_results),
        "target_results": target_results,
        "search_schema_version_before": monolith.get("search_schema_version_before", ""),
        "search_schema_version_after": monolith.get("search_schema_version_after", ""),
        "usage_role_projection_version": SEARCH_USAGE_ROLE_PROJECTION_VERSION,
        "event_missing_usage_role_before": sum(int_value(item.get("event_missing_usage_role_before")) for item in target_results),
        "event_missing_usage_role_after": sum(int_value(item.get("event_missing_usage_role_after")) for item in target_results),
        "backfilled_event_document_count": sum(int_value(item.get("backfilled_event_document_count")) for item in target_results),
        "role_counts": monolith.get("role_counts", {}) if isinstance(monolith.get("role_counts"), dict) else {},
        "shard_role_counts": dict(sorted(shard_role_counts.items())),
        "index_count": sum(int_value(item.get("index_count")) for item in target_results),
        "diagnostics": diagnostics,
        "truth_status": "generated_search_projection_migration_not_raw_truth",
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__search-schema-migrate"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, json_markdown_report("Search Schema Migration", payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def search_fts_delete_enabled(conn: sqlite3.Connection) -> bool:
    if not sqlite_table_exists(conn, "documents_fts"):
        return False
    try:
        metadata = search_index_metadata(conn)
    except sqlite3.Error:
        return True
    fts_mode = str(metadata.get("search_fts_storage_mode") or "").strip()
    raw_support = str(metadata.get("search_raw_text_query_support") or "").strip()
    if fts_mode == SEARCH_STRUCTURED_SHARD_FTS_STORAGE_MODE:
        return False
    if raw_support == SEARCH_RAW_TEXT_QUERY_SUPPORT_MONOLITH_FALLBACK:
        return False
    return True


def delete_search_documents_for_session(
    conn: sqlite3.Connection,
    *,
    session_label: str | None = None,
    session_id: str | None = None,
) -> int:
    clauses: list[str] = []
    values: list[str] = []
    if session_label:
        clauses.append("session_label = ?")
        values.append(session_label)
    if session_id:
        clauses.append("session_id = ?")
        values.append(session_id)
    if not clauses:
        return 0
    if sqlite_table_exists(conn, "omitted_context_tail_route_refs"):
        conn.execute(
            f"DELETE FROM omitted_context_tail_route_refs WHERE {' OR '.join(clauses)}",
            values,
        )
    conn.execute("CREATE TEMP TABLE IF NOT EXISTS search_delete_rowids(rowid INTEGER PRIMARY KEY)")
    conn.execute("DELETE FROM search_delete_rowids")
    conn.execute(
        f"INSERT OR IGNORE INTO search_delete_rowids(rowid) SELECT rowid FROM documents WHERE {' OR '.join(clauses)}",
        values,
    )
    count = int_value(conn.execute("SELECT COUNT(*) FROM search_delete_rowids").fetchone()[0])
    if count <= 0:
        return 0
    conn.execute("DELETE FROM document_routes WHERE doc_rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM document_bodies WHERE doc_rowid IN (SELECT rowid FROM search_delete_rowids)")
    if search_fts_delete_enabled(conn):
        conn.execute("DELETE FROM documents_fts WHERE rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM documents WHERE rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM search_delete_rowids")
    return count


def delete_search_documents_by_doc_type(conn: sqlite3.Connection, doc_type: str) -> int:
    doc_type = str(doc_type or "").strip()
    if not doc_type:
        return 0
    if doc_type == "event" and sqlite_table_exists(conn, "omitted_context_tail_route_refs"):
        conn.execute("DELETE FROM omitted_context_tail_route_refs")
    conn.execute("CREATE TEMP TABLE IF NOT EXISTS search_delete_rowids(rowid INTEGER PRIMARY KEY)")
    conn.execute("DELETE FROM search_delete_rowids")
    conn.execute(
        "INSERT OR IGNORE INTO search_delete_rowids(rowid) SELECT rowid FROM documents WHERE doc_type = ?",
        (doc_type,),
    )
    count = int_value(conn.execute("SELECT COUNT(*) FROM search_delete_rowids").fetchone()[0])
    if count <= 0:
        return 0
    conn.execute("DELETE FROM document_routes WHERE doc_rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM document_bodies WHERE doc_rowid IN (SELECT rowid FROM search_delete_rowids)")
    if search_fts_delete_enabled(conn):
        conn.execute("DELETE FROM documents_fts WHERE rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM documents WHERE rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM search_delete_rowids")
    return count


def delete_search_documents_by_rowids(conn: sqlite3.Connection, rowids: Iterable[int]) -> int:
    normalized_rowids = [(int_value(rowid),) for rowid in rowids if int_value(rowid) > 0]
    if not normalized_rowids:
        return 0
    conn.execute("CREATE TEMP TABLE IF NOT EXISTS search_delete_rowids(rowid INTEGER PRIMARY KEY)")
    conn.execute("DELETE FROM search_delete_rowids")
    conn.executemany("INSERT OR IGNORE INTO search_delete_rowids(rowid) VALUES (?)", normalized_rowids)
    count = int_value(conn.execute("SELECT COUNT(*) FROM search_delete_rowids").fetchone()[0])
    if count <= 0:
        return 0
    conn.execute("DELETE FROM document_routes WHERE doc_rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM document_bodies WHERE doc_rowid IN (SELECT rowid FROM search_delete_rowids)")
    if search_fts_delete_enabled(conn):
        conn.execute("DELETE FROM documents_fts WHERE rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM documents WHERE rowid IN (SELECT rowid FROM search_delete_rowids)")
    conn.execute("DELETE FROM search_delete_rowids")
    return count


def refresh_search_entity_registry_documents(
    conn: sqlite3.Connection,
    *,
    aoa_root: Path,
    route_terms_db_path: Path,
    observed_source: str = "auto",
) -> dict[str, Any]:
    phase_timings: list[dict[str, Any]] = []

    def record_phase(phase: str, phase_started: float, **extra: Any) -> None:
        phase_timings.append({"phase": phase, "elapsed_ms": int((time.monotonic() - phase_started) * 1000), **extra})

    build_started = time.monotonic()
    registry_documents = search_documents_for_entity_registry(
        aoa_root,
        write_snapshot=True,
        route_terms_db_path=route_terms_db_path,
        observed_source=observed_source,
    )
    registry_snapshot = read_json(aoa_root / ENTITY_REGISTRY_PATH, {})
    record_phase(
        "build_entity_registry_documents",
        build_started,
        document_count=len(registry_documents),
        observed_route_source=registry_snapshot.get("observed_route_source") if isinstance(registry_snapshot, dict) else None,
    )
    registry_documents_by_id = {
        str(doc.get("id") or ""): doc
        for doc in registry_documents
        if str(doc.get("id") or "").strip()
    }
    conn.execute("BEGIN")
    existing_started = time.monotonic()
    existing_documents = search_document_existing_signatures(conn, doc_type="entity_registry")
    record_phase("load_existing_entity_registry_signatures", existing_started, existing_count=len(existing_documents))
    stale_rowids = [
        int_value(item.get("rowid"))
        for doc_id, item in existing_documents.items()
        if doc_id not in registry_documents_by_id
    ]
    changed_rowids: list[int] = []
    docs_to_insert: list[dict[str, Any]] = []
    inserted_count = 0
    updated_count = 0
    unchanged_count = 0
    for doc_id, doc in registry_documents_by_id.items():
        existing = existing_documents.get(doc_id)
        next_signature = search_document_storage_signature(doc)
        if not existing:
            docs_to_insert.append(doc)
            inserted_count += 1
            continue
        if str(existing.get("signature") or "") == next_signature:
            unchanged_count += 1
            continue
        changed_rowids.append(int_value(existing.get("rowid")))
        docs_to_insert.append(doc)
        updated_count += 1
    delete_started = time.monotonic()
    removed_count = delete_search_documents_by_rowids(conn, [*stale_rowids, *changed_rowids])
    record_phase("delete_stale_or_changed_entity_registry_documents", delete_started, removed_count=removed_count)
    stale_removed_count = len([rowid for rowid in stale_rowids if rowid > 0])
    changed_removed_count = max(0, removed_count - stale_removed_count)
    insert_started = time.monotonic()
    for doc in docs_to_insert:
        insert_search_document(conn, doc)
    record_phase("insert_changed_entity_registry_documents", insert_started, insert_count=len(docs_to_insert))
    snapshot_signature = entity_registry_snapshot_signature(registry_snapshot if isinstance(registry_snapshot, dict) else {})
    record_entity_registry_search_sync_meta(
        conn,
        snapshot_signature=snapshot_signature,
        document_count=len(registry_documents_by_id),
    )
    commit_started = time.monotonic()
    conn.commit()
    record_phase("commit_entity_registry_search_sync", commit_started)
    return {
        "inserted_count": inserted_count,
        "updated_count": updated_count,
        "unchanged_count": unchanged_count,
        "removed_count": stale_removed_count,
        "replaced_count": changed_removed_count,
        "touched_count": inserted_count + updated_count + stale_removed_count,
        "target_count": len(registry_documents_by_id),
        "skipped": False,
        "snapshot_signature": snapshot_signature,
        "observed_source": observed_source,
        "observed_route_source": registry_snapshot.get("observed_route_source") if isinstance(registry_snapshot, dict) else None,
        "phase_timings": phase_timings,
    }


def search_document_count_from_session_state(conn: sqlite3.Connection, *, entity_registry_document_count: int) -> tuple[int, str]:
    if sqlite_table_exists(conn, "session_index_state"):
        row = conn.execute("SELECT COALESCE(SUM(document_count), 0) FROM session_index_state").fetchone()
        session_document_count = int_value(row[0] if row else 0)
        if session_document_count > 0:
            return session_document_count + max(0, int_value(entity_registry_document_count)), "session_index_state_plus_entity_registry"
    row = conn.execute("SELECT COUNT(*) FROM documents").fetchone()
    return int_value(row[0] if row else 0), "documents_count_scan"


def refresh_entity_registry_search_documents_only(
    *,
    aoa_root: Path,
    write_report: bool = False,
    budget_seconds: float | None = None,
    observed_source: str = "auto",
) -> dict[str, Any]:
    now = utc_now()
    started = time.monotonic()
    db_path = search_db_path(aoa_root)
    conn: sqlite3.Connection | None = None
    diagnostics: list[str] = []
    registry_state: dict[str, Any] = {}
    phase_timings: list[dict[str, Any]] = []

    def record_phase(phase: str, phase_started: float, **extra: Any) -> None:
        phase_timings.append({"phase": phase, "elapsed_ms": int((time.monotonic() - phase_started) * 1000), **extra})

    try:
        init_started = time.monotonic()
        conn = init_search_db(db_path, rebuild=False, create_indexes=True)
        record_phase("init_search_db", init_started)
        conn.execute("INSERT OR REPLACE INTO meta(key, value) VALUES (?, ?)", ("schema_version", str(SEARCH_SCHEMA_VERSION)))
        conn.execute("INSERT OR REPLACE INTO meta(key, value) VALUES (?, ?)", ("generated_at", now))
        conn.execute("INSERT OR REPLACE INTO meta(key, value) VALUES (?, ?)", ("aoa_root", str(aoa_root)))
        conn.commit()
        status_started = time.monotonic()
        registry_state = entity_registry_maintenance_status(aoa_root)
        record_phase("entity_registry_maintenance_status", status_started, status=registry_state.get("status"))
        noop_started = time.monotonic()
        registry_refresh = entity_registry_search_sync_current_noop(
            conn,
            aoa_root=aoa_root,
            registry_state=registry_state,
        )
        record_phase("entity_registry_search_sync_current_noop", noop_started, skipped=registry_refresh is not None)
        if registry_refresh is None:
            refresh_started = time.monotonic()
            registry_refresh = refresh_search_entity_registry_documents(
                conn,
                aoa_root=aoa_root,
                route_terms_db_path=db_path,
                observed_source=observed_source,
            )
            record_phase(
                "refresh_search_entity_registry_documents",
                refresh_started,
                observed_route_source=registry_refresh.get("observed_route_source"),
                touched_count=registry_refresh.get("touched_count"),
            )
            phase_timings.extend(registry_refresh.get("phase_timings", []) if isinstance(registry_refresh.get("phase_timings"), list) else [])
            registry_state = entity_registry_maintenance_status(aoa_root)
        count_started = time.monotonic()
        entity_registry_document_count = int_value(
            conn.execute("SELECT COUNT(*) FROM documents WHERE doc_type = 'entity_registry'").fetchone()[0]
        )
        target_entity_registry_document_count = int_value(registry_refresh.get("target_count"))
        inserted_entity_registry_document_count = int_value(registry_refresh.get("inserted_count"))
        updated_entity_registry_document_count = int_value(registry_refresh.get("updated_count"))
        unchanged_entity_registry_document_count = int_value(registry_refresh.get("unchanged_count"))
        removed_entity_registry_document_count = int_value(registry_refresh.get("removed_count"))
        document_count, document_count_source = search_document_count_from_session_state(
            conn,
            entity_registry_document_count=entity_registry_document_count,
        )
        record_phase(
            "count_search_documents",
            count_started,
            document_count=document_count,
            document_count_source=document_count_source,
            entity_registry_document_count=entity_registry_document_count,
        )
    except sqlite3.Error as exc:
        diagnostics.append(f"sqlite_error:{exc}")
        document_count = 0
        entity_registry_document_count = 0
        target_entity_registry_document_count = 0
        inserted_entity_registry_document_count = 0
        updated_entity_registry_document_count = 0
        unchanged_entity_registry_document_count = 0
        removed_entity_registry_document_count = 0
        if conn is not None:
            try:
                conn.rollback()
            except sqlite3.Error:
                pass
    finally:
        if conn is not None:
            try:
                conn.set_progress_handler(None, 0)
            except sqlite3.Error:
                pass
            conn.close()
    if not registry_state:
        registry_state = entity_registry_maintenance_status(aoa_root)
    elapsed_ms = int((time.monotonic() - started) * 1000)
    budget_value = float(budget_seconds) if budget_seconds is not None and budget_seconds > 0 else None
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "entity_registry_search_sync",
        "search_schema_version": SEARCH_SCHEMA_VERSION,
        "generated_at": now,
        "ok": (
            not diagnostics
            and entity_registry_document_count == int_value(registry_state.get("entity_count"))
            and target_entity_registry_document_count == int_value(registry_state.get("entity_count"))
        ),
        "target": "entity-registry",
        "selected_count": 0,
        "processed_count": 0,
        "document_count": document_count,
        "document_count_source": document_count_source if "document_count_source" in locals() else "unavailable",
        "entity_registry_document_count": entity_registry_document_count,
        "target_entity_registry_document_count": target_entity_registry_document_count,
        "inserted_entity_registry_document_count": inserted_entity_registry_document_count,
        "updated_entity_registry_document_count": updated_entity_registry_document_count,
        "unchanged_entity_registry_document_count": unchanged_entity_registry_document_count,
        "removed_entity_registry_document_count": removed_entity_registry_document_count,
        "skipped": bool(registry_refresh.get("skipped")) if "registry_refresh" in locals() and isinstance(registry_refresh, dict) else False,
        "skip_reason": registry_refresh.get("skip_reason") if "registry_refresh" in locals() and isinstance(registry_refresh, dict) else None,
        "entity_count": registry_state.get("entity_count"),
        "entity_registry": registry_state,
        "db_path": str(db_path),
        "observed_source": observed_source,
        "observed_route_source": registry_refresh.get("observed_route_source") if "registry_refresh" in locals() and isinstance(registry_refresh, dict) else None,
        "budget_seconds": budget_seconds,
        "budget_exhausted": bool(budget_value is not None and elapsed_ms > int(budget_value * 1000)),
        "budget_policy": "soft_observed_atomic_sync_not_interrupted",
        "elapsed_ms": elapsed_ms,
        "phase_timings": phase_timings,
        "diagnostics": diagnostics,
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__entity-registry-search-sync"
        report_json = diagnostics_dir / f"{stem}.json"
        write_json(report_json, payload)
        payload["report_json"] = str(report_json)
    return payload


def search_tokenize(query: str) -> list[str]:
    return [token for token in re.findall(r"[^\W_]+", str(query or ""), flags=re.UNICODE) if token]


def fts_query_from_user(query: str) -> str:
    tokens = search_tokenize(query)
    if not tokens:
        return ""
    return " AND ".join(f'"{token.replace("\"", "\"\"")}"' for token in tokens[:16])


def normalized_search_fts_query_timeout_ms(query_timeout_ms: int | None) -> int:
    if query_timeout_ms is None:
        return SEARCH_FTS_QUERY_TIMEOUT_MS
    return max(0, int_value(query_timeout_ms, SEARCH_FTS_QUERY_TIMEOUT_MS))


def install_search_fts_query_deadline(
    conn: sqlite3.Connection,
    *,
    query_timeout_ms: int | None,
) -> tuple[int, float | None]:
    effective_timeout_ms = normalized_search_fts_query_timeout_ms(query_timeout_ms)
    if effective_timeout_ms <= 0:
        return 0, None
    deadline = time.monotonic() + (effective_timeout_ms / 1000.0)
    conn.set_progress_handler(
        lambda: 1 if time.monotonic() >= deadline else 0,
        SEARCH_FTS_QUERY_PROGRESS_OPCODES,
    )
    return effective_timeout_ms, deadline


def clear_search_fts_query_deadline(conn: sqlite3.Connection) -> None:
    try:
        conn.set_progress_handler(None, 0)
    except sqlite3.Error:
        pass


def search_fts_timeout_next_command(
    command: str,
    *,
    query: str,
    limit: int,
    query_timeout_ms: int,
    options: list[tuple[str, Any]] | None = None,
) -> str:
    expanded_timeout_ms = max(query_timeout_ms * 4 if query_timeout_ms > 0 else SEARCH_FTS_QUERY_TIMEOUT_MS * 4, 30000)
    args = [
        "python3",
        "scripts/aoa_session_memory.py",
        command,
        "--query",
        str(query or ""),
        "--limit",
        str(max(1, int_value(limit, 20))),
        "--query-timeout-ms",
        str(expanded_timeout_ms),
    ]
    for flag, value in options or []:
        if value is None or value == "" or value is False:
            continue
        if isinstance(value, (list, tuple)):
            for item in value:
                if item is not None and item != "":
                    args.extend([flag, str(item)])
        elif value is True:
            args.append(flag)
        else:
            args.extend([flag, str(value)])
    return shlex.join(args)


def search_fts_timeout_payload(
    *,
    aoa_root: Path,
    query: str,
    normalized_query: str,
    db_path: Path,
    provider: str,
    projection_mode: str,
    query_timeout_ms: int,
    elapsed_ms: int,
    command: str,
    limit: int,
    options: list[tuple[str, Any]],
    cost_profile: dict[str, Any],
    provider_config: dict[str, Any],
    exc: sqlite3.Error,
) -> dict[str, Any]:
    diagnostic = f"search_fts_query_timeout:{query_timeout_ms}ms"
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "search_results",
        "search_schema_version": SEARCH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": False,
        "query": query,
        "normalized_query": normalized_query,
        "db_path": str(db_path),
        "aoa_root": str(aoa_root),
        "result_count": 0,
        "results": [],
        "search_projection": {
            "mode": projection_mode,
            "db_path": str(db_path),
            "fallback_db_path": str(search_db_path(aoa_root)),
        },
        "cost_profile": {
            **cost_profile,
            "query_timeout_ms": query_timeout_ms,
            "bounded_query_timeout": True,
            "elapsed_ms": elapsed_ms,
        },
        "provider": {
            "selected": provider,
            "authoritative_result_provider": "portable_sqlite",
            "status": SEARCH_FTS_QUERY_TIMEOUT_STATUS,
            "authority_law": provider_config.get("authority_law"),
        },
        "bounded_timeout": {
            "status": SEARCH_FTS_QUERY_TIMEOUT_STATUS,
            "query_timeout_ms": query_timeout_ms,
            "elapsed_ms": elapsed_ms,
            "next_route": (
                "Prefer structured filters, shard-backed routes, or entity/agent-event/goal routes. "
                "Raise --query-timeout-ms only for an explicit offline raw-text scan."
            ),
            "next_expansion_command": search_fts_timeout_next_command(
                command,
                query=query,
                limit=limit,
                query_timeout_ms=query_timeout_ms,
                options=options,
            ),
        },
        "diagnostics": [diagnostic, sqlite_error_diagnostic(exc)],
    }


def search_json_text(value: Any) -> str:
    if value is None:
        return ""
    if isinstance(value, str):
        return value
    return json.dumps(value, ensure_ascii=False, sort_keys=True)


def search_doc_text(parts: list[Any], *, max_chars: int = 4000) -> str:
    text = " ".join(part.strip() for part in (search_json_text(part) for part in parts) if part.strip())
    text = re.sub(r"\s+", " ", text).strip()
    return text[:max_chars]


def search_raw_lexical_policy(
    max_raw_bytes: int | None = None,
    *,
    use_default_budget: bool = True,
) -> dict[str, Any]:
    requested_max_raw_bytes = max_raw_bytes
    source = "default" if use_default_budget else "unbounded_no_default"
    effective_max_raw_bytes: int | None
    if max_raw_bytes is None:
        effective_max_raw_bytes = SEARCH_RAW_LEXICAL_DEFAULT_MAX_BYTES if use_default_budget else None
    else:
        explicit = int_value(max_raw_bytes)
        if explicit < 0:
            effective_max_raw_bytes = None
            source = "explicit_unbounded"
        else:
            effective_max_raw_bytes = explicit
            source = "explicit"
    effective_max_raw_mb = (
        effective_max_raw_bytes / (1024 * 1024)
        if effective_max_raw_bytes is not None
        else None
    )
    return {
        "mode": SEARCH_RAW_LEXICAL_POLICY_MODE,
        "source": source,
        "requested_max_raw_bytes": requested_max_raw_bytes,
        "default_max_raw_bytes": SEARCH_RAW_LEXICAL_DEFAULT_MAX_BYTES,
        "default_max_raw_mb": SEARCH_RAW_LEXICAL_DEFAULT_MAX_MB,
        "effective_max_raw_bytes": effective_max_raw_bytes,
        "effective_max_raw_mb": effective_max_raw_mb,
        "unbounded": effective_max_raw_bytes is None,
        "skip_status": "skipped_raw_too_large",
        "quality_note": "Raw transcript remains authority; bounded lexical skips only remove heavy raw semantic text from generated FTS and keep refs for proof routes.",
    }


def search_raw_lexical_policy_from_metadata(metadata: dict[str, Any]) -> dict[str, Any]:
    if not metadata:
        return {
            "mode": "unknown",
            "source": "metadata_missing",
            "default_max_raw_bytes": SEARCH_RAW_LEXICAL_DEFAULT_MAX_BYTES,
            "default_max_raw_mb": SEARCH_RAW_LEXICAL_DEFAULT_MAX_MB,
            "effective_max_raw_bytes": None,
            "effective_max_raw_mb": None,
            "unbounded": None,
            "diagnostics": ["search_metadata_missing"],
        }
    raw_value = metadata.get("search_raw_lexical_max_bytes")
    source = str(metadata.get("search_raw_lexical_policy_source") or "metadata")
    diagnostics: list[str] = []
    effective_max_raw_bytes: int | None
    raw_text = "" if raw_value is None else str(raw_value)
    if raw_text in {"", "None", "unbounded"}:
        effective_max_raw_bytes = None
    else:
        try:
            effective_max_raw_bytes = int(raw_text)
        except (TypeError, ValueError):
            effective_max_raw_bytes = None
            diagnostics.append("search_raw_lexical_max_bytes_unreadable")
    effective_max_raw_mb = (
        effective_max_raw_bytes / (1024 * 1024)
        if effective_max_raw_bytes is not None
        else None
    )
    return {
        "mode": str(metadata.get("search_raw_lexical_policy_mode") or "unknown"),
        "source": source,
        "default_max_raw_bytes": int_value(metadata.get("search_raw_lexical_default_max_bytes"), SEARCH_RAW_LEXICAL_DEFAULT_MAX_BYTES),
        "default_max_raw_mb": SEARCH_RAW_LEXICAL_DEFAULT_MAX_MB,
        "effective_max_raw_bytes": effective_max_raw_bytes,
        "effective_max_raw_mb": effective_max_raw_mb,
        "unbounded": effective_max_raw_bytes is None,
        "skip_status": str(metadata.get("search_raw_lexical_skip_status") or "skipped_raw_too_large"),
        "diagnostics": diagnostics,
    }


def search_raw_lexical_policy_status(policy: dict[str, Any]) -> str:
    mode = str(policy.get("mode") or "")
    unbounded = policy.get("unbounded")
    if mode == SEARCH_RAW_LEXICAL_POLICY_MODE and unbounded is False:
        return "bounded_policy_recorded"
    if unbounded is True:
        return "unbounded_or_legacy_policy"
    return "policy_missing_or_unknown"


def packed_route_values(values: Iterable[str]) -> str:
    items = sorted({str(value) for value in values if str(value or "").strip()})
    return "|" + "|".join(items) + "|" if items else ""


def route_fields_from_counts(route_counts: dict[str, Any]) -> tuple[str, str]:
    layers: list[str] = []
    signals: list[str] = []
    for layer, keys in route_counts.items() if isinstance(route_counts, dict) else []:
        if not isinstance(keys, dict):
            continue
        layer_text = str(layer)
        layers.append(layer_text)
        for key, _count in sorted(keys.items(), key=lambda item: (-int_value(item[1]), str(item[0]))):
            signals.append(route_signal_token(layer_text, str(key)))
    return packed_route_values(layers), packed_route_values(signals)


def route_fields_from_signals(signals_value: Any) -> tuple[str, str]:
    layers: list[str] = []
    signals: list[str] = []
    for signal in signals_value if isinstance(signals_value, list) else []:
        if not isinstance(signal, dict):
            continue
        layer = str(signal.get("layer") or "")
        key = str(signal.get("key") or "")
        if layer:
            layers.append(layer)
        if layer and key:
            signals.append(route_signal_token(layer, key))
    return packed_route_values(layers), packed_route_values(signals)


def unpacked_route_values(value: Any) -> list[str]:
    seen: set[str] = set()
    items: list[str] = []
    for token in str(value or "").strip("|").split("|"):
        normalized = token.strip()
        if not normalized or normalized in seen:
            continue
        seen.add(normalized)
        items.append(normalized)
    return items


def aggregate_route_posting_limit(doc_type: str, layer: str) -> int | None:
    if doc_type not in SEARCH_AGGREGATE_ROUTE_POSTING_DOC_TYPES:
        return None
    return SEARCH_AGGREGATE_ROUTE_POSTING_LAYER_LIMITS.get(layer, SEARCH_AGGREGATE_ROUTE_POSTING_DEFAULT_LAYER_LIMIT)


def document_route_entries(route_layers: Any, route_signals: Any, *, doc_type: str = "") -> list[dict[str, str]]:
    entries: list[dict[str, str]] = []
    seen: set[tuple[str, str]] = set()
    per_layer_counts: Counter[str] = Counter()
    normalized_doc_type = str(doc_type or "")
    for signal in unpacked_route_values(route_signals):
        if ":" not in signal:
            continue
        layer, key = signal.split(":", 1)
        normalized_layer = route_key_slug(layer, fallback="")
        normalized_key = route_key_slug(key, fallback="")
        if not normalized_layer or not normalized_key:
            continue
        layer_limit = aggregate_route_posting_limit(normalized_doc_type, normalized_layer)
        if layer_limit is not None and per_layer_counts[normalized_layer] >= layer_limit:
            continue
        token = (normalized_layer, normalized_key)
        if token in seen:
            continue
        seen.add(token)
        per_layer_counts[normalized_layer] += 1
        entries.append(
            {
                "layer": normalized_layer,
                "key": normalized_key,
                "route_signal": route_signal_token(normalized_layer, normalized_key),
            }
        )
    if not entries:
        for layer in unpacked_route_values(route_layers):
            normalized_layer = route_key_slug(layer, fallback="")
            if not normalized_layer:
                continue
            token = (normalized_layer, "")
            if token in seen:
                continue
            seen.add(token)
            entries.append({"layer": normalized_layer, "key": "", "route_signal": f"{normalized_layer}:"})
    return entries


def normalize_search_context_tail_omission_policy(value: str | None) -> str:
    text = str(value or "").strip()
    if not text:
        return SEARCH_CONTEXT_TAIL_OMISSION_POLICY_AUTO
    return SEARCH_CONTEXT_TAIL_OMISSION_POLICY_CLI_VALUES.get(text, text)


def search_context_tail_omission_policy_cli_value(policy: str) -> str:
    normalized = normalize_search_context_tail_omission_policy(policy)
    for cli_value, internal_value in SEARCH_CONTEXT_TAIL_OMISSION_POLICY_CLI_VALUES.items():
        if internal_value == normalized:
            return cli_value
    return "keep-all"


def search_context_tail_omission_policy_from_metadata(metadata: dict[str, Any]) -> str:
    policy = normalize_search_context_tail_omission_policy(
        str(metadata.get("search_context_tail_omission_policy") or "")
    )
    if policy in {
        SEARCH_CONTEXT_TAIL_OMISSION_POLICY_KEEP_ALL,
        SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED,
    }:
        return policy
    return ""


def search_context_tail_omission_policy_resolution(
    *,
    aoa_root: Path | None,
    requested_policy: str | None,
    structured_only: bool,
    shard_keys: Iterable[str] | None = None,
) -> dict[str, Any]:
    requested = normalize_search_context_tail_omission_policy(requested_policy)
    normalized_shards = sorted({str(item or "").strip() for item in (shard_keys or []) if str(item or "").strip()})
    if not structured_only:
        resolved = (
            SEARCH_CONTEXT_TAIL_OMISSION_POLICY_KEEP_ALL
            if requested == SEARCH_CONTEXT_TAIL_OMISSION_POLICY_AUTO
            else requested
        )
        return {
            "requested_policy": requested,
            "resolved_policy": resolved,
            "source": "full_text_shards_force_keep_all" if requested == SEARCH_CONTEXT_TAIL_OMISSION_POLICY_AUTO else "explicit",
            "structured_only": False,
            "shards_considered": normalized_shards,
            "shard_policies": [],
            "diagnostics": [],
        }
    if requested != SEARCH_CONTEXT_TAIL_OMISSION_POLICY_AUTO:
        return {
            "requested_policy": requested,
            "resolved_policy": requested,
            "source": "explicit",
            "structured_only": True,
            "shards_considered": normalized_shards,
            "shard_policies": [],
            "diagnostics": [],
        }
    shard_policies: list[dict[str, Any]] = []
    if aoa_root is not None:
        for shard_key in normalized_shards:
            db_path = search_shard_db_path(aoa_root, shard_key)
            policy = search_context_tail_omission_policy_from_metadata(search_db_metadata_at_path(db_path))
            if not policy:
                continue
            shard_policies.append(
                {
                    "shard": shard_key,
                    "db_path": str(db_path),
                    "policy": policy,
                }
            )
    policy_values = {str(item.get("policy") or "") for item in shard_policies}
    diagnostics: list[str] = []
    if SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED in policy_values:
        resolved = SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED
        source = "existing_shard_meta"
        if len(policy_values) > 1:
            source = "mixed_existing_shard_meta_route_ref_backed_preferred"
            diagnostics.append("context_tail_omission_policy_auto_mixed_existing_shard_meta")
    elif SEARCH_CONTEXT_TAIL_OMISSION_POLICY_KEEP_ALL in policy_values:
        resolved = SEARCH_CONTEXT_TAIL_OMISSION_POLICY_KEEP_ALL
        source = "existing_shard_meta"
    else:
        resolved = SEARCH_CONTEXT_TAIL_OMISSION_POLICY_KEEP_ALL
        source = "auto_default_keep_all_no_existing_shard_policy"
    return {
        "requested_policy": requested,
        "resolved_policy": resolved,
        "source": source,
        "structured_only": True,
        "shards_considered": normalized_shards,
        "shard_policies": shard_policies,
        "diagnostics": diagnostics,
        "truth_status": "generated_search_projection_policy_selection_not_archive_truth",
    }


def search_document_is_context_tail_candidate(doc: dict[str, Any]) -> bool:
    return (
        str(doc.get("doc_type") or "") == "event"
        and str(doc.get("usage_role") or "") == SEARCH_OPERATIONAL_EVENT_CONTEXT_ROLE
        and not str(doc.get("agent_event") or "").strip()
        and not str(doc.get("task_episode_id") or "").strip()
        and str(doc.get("event_type") or "") not in SEARCH_OPERATIONAL_EVENT_PROTECTED_CONTEXT_EVENT_TYPES
    )


def search_document_has_route_ref_backing(doc: dict[str, Any]) -> bool:
    return any(
        item.get("key")
        for item in document_route_entries(
            doc.get("route_layers"),
            doc.get("route_signals"),
            doc_type=str(doc.get("doc_type") or ""),
        )
    )


def omitted_context_tail_route_ref_rows_for_doc(doc: dict[str, Any]) -> list[dict[str, str]]:
    rows: list[dict[str, str]] = []
    for entry in document_route_entries(
        doc.get("route_layers"),
        doc.get("route_signals"),
        doc_type=str(doc.get("doc_type") or ""),
    ):
        layer = str(entry.get("layer") or "")
        key = str(entry.get("key") or "")
        if not layer or not key:
            continue
        route_signal = str(entry.get("route_signal") or route_signal_token(layer, key))
        rows.append(
            {
                "doc_id": str(doc.get("id") or ""),
                "session_id": str(doc.get("session_id") or ""),
                "session_label": str(doc.get("session_label") or ""),
                "session_date": str(doc.get("session_date") or ""),
                "event_id": str(doc.get("event_id") or ""),
                "event_type": str(doc.get("event_type") or ""),
                "raw_ref": str(doc.get("raw_ref") or ""),
                "segment_ref": str(doc.get("segment_ref") or ""),
                "layer": layer,
                "key": key,
                "route_signal": route_signal,
            }
        )
    return rows


def insert_omitted_context_tail_route_refs(conn: sqlite3.Connection, rows: Iterable[dict[str, Any]]) -> int:
    normalized_rows = [
        {
            "doc_id": str(row.get("doc_id") or ""),
            "session_id": str(row.get("session_id") or ""),
            "session_label": str(row.get("session_label") or ""),
            "session_date": str(row.get("session_date") or ""),
            "event_id": str(row.get("event_id") or ""),
            "event_type": str(row.get("event_type") or ""),
            "raw_ref": str(row.get("raw_ref") or ""),
            "segment_ref": str(row.get("segment_ref") or ""),
            "layer": str(row.get("layer") or ""),
            "key": str(row.get("key") or ""),
            "route_signal": str(row.get("route_signal") or ""),
        }
        for row in rows
        if str(row.get("layer") or "") and str(row.get("key") or "")
    ]
    if not normalized_rows:
        return 0
    conn.executemany(
        """
        INSERT INTO omitted_context_tail_route_refs(
            doc_id, session_id, session_label, session_date, event_id,
            event_type, raw_ref, segment_ref, layer, key, route_signal
        ) VALUES (
            :doc_id, :session_id, :session_label, :session_date, :event_id,
            :event_type, :raw_ref, :segment_ref, :layer, :key, :route_signal
        )
        """,
        normalized_rows,
    )
    return len(normalized_rows)


def apply_search_context_tail_omission_policy(
    documents: list[dict[str, Any]],
    *,
    policy: str | None,
) -> tuple[list[dict[str, Any]], dict[str, Any], list[dict[str, str]]]:
    normalized_policy = normalize_search_context_tail_omission_policy(policy)
    if normalized_policy == SEARCH_CONTEXT_TAIL_OMISSION_POLICY_AUTO:
        normalized_policy = SEARCH_CONTEXT_TAIL_OMISSION_POLICY_KEEP_ALL
    counts: Counter[str] = Counter()
    kept: list[dict[str, Any]] = []
    omitted_route_ref_rows: list[dict[str, str]] = []
    omitted_examples: list[dict[str, Any]] = []
    for doc in documents:
        counts["input_document_count"] += 1
        if not search_document_is_context_tail_candidate(doc):
            counts["non_candidate_keep_count"] += 1
            kept.append(doc)
            continue
        counts["candidate_context_tail_count"] += 1
        if not search_document_has_route_ref_backing(doc):
            counts["unrouted_keep_candidate_count"] += 1
            kept.append(doc)
            continue
        counts["route_ref_backed_omission_candidate_count"] += 1
        if normalized_policy != SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED:
            counts["route_ref_backed_keep_candidate_count"] += 1
            kept.append(doc)
            continue
        counts["omitted_document_count"] += 1
        doc_route_ref_rows = omitted_context_tail_route_ref_rows_for_doc(doc)
        omitted_route_ref_rows.extend(doc_route_ref_rows)
        counts["omitted_route_ref_row_count"] += len(doc_route_ref_rows)
        if len(omitted_examples) < 5:
            omitted_examples.append(
                {
                    "id": str(doc.get("id") or ""),
                    "event_id": str(doc.get("event_id") or ""),
                    "session_label": str(doc.get("session_label") or ""),
                    "event_type": str(doc.get("event_type") or ""),
                    "raw_ref": str(doc.get("raw_ref") or ""),
                    "segment_ref": str(doc.get("segment_ref") or ""),
                    "route_signals": unpacked_route_values(doc.get("route_signals"))[:8],
                }
            )
    counts["output_document_count"] = len(kept)
    return kept, {
        "schema_version": 1,
        "policy": normalized_policy,
        "policy_cli_value": search_context_tail_omission_policy_cli_value(normalized_policy),
        "applied": normalized_policy == SEARCH_CONTEXT_TAIL_OMISSION_POLICY_ROUTE_REF_BACKED,
        "counts": dict(sorted(counts.items())),
        "input_document_count": int_value(counts.get("input_document_count")),
        "output_document_count": int_value(counts.get("output_document_count")),
        "candidate_context_tail_count": int_value(counts.get("candidate_context_tail_count")),
        "route_ref_backed_omission_candidate_count": int_value(
            counts.get("route_ref_backed_omission_candidate_count")
        ),
        "unrouted_keep_candidate_count": int_value(counts.get("unrouted_keep_candidate_count")),
        "omitted_document_count": int_value(counts.get("omitted_document_count")),
        "omitted_route_ref_row_count": int_value(counts.get("omitted_route_ref_row_count")),
        "omitted_examples": omitted_examples,
        "protected_boundary": (
            "agent_event, task_episode, protected event types, and unrouted context-tail rows are kept"
        ),
        "authority_boundary": (
            "this omits only generated structured-shard rows; raw transcripts, segment indexes, and monolith "
            "raw-text fallback remain authority"
        ),
        "truth_status": "generated_search_projection_policy_not_archive_truth",
    }, omitted_route_ref_rows


def bounded_packed_route_values(value: Any, *, max_chars: int) -> str:
    text = str(value or "")
    if len(text) <= max_chars:
        return text
    tokens = unpacked_route_values(text)
    if not tokens:
        return bounded_storage_text(text, max_chars=max_chars)
    kept: list[str] = []
    for token in tokens:
        candidate = "|" + "|".join([*kept, token]) + "|"
        if len(candidate) > max_chars:
            break
        kept.append(token)
    if not kept:
        return bounded_storage_text(text, max_chars=max_chars)
    return "|" + "|".join(kept) + "|"


def search_document_storage_profile(*, store_raw_text: bool) -> dict[str, Any]:
    if store_raw_text:
        return {
            "name": SEARCH_DOCUMENT_STORAGE_PROFILE_FULL,
            "body_preview_chars": SEARCH_BODY_PREVIEW_CHARS,
            "route_layers_preview_chars": SEARCH_ROUTE_LAYERS_PREVIEW_CHARS,
            "route_signals_preview_chars": SEARCH_ROUTE_SIGNALS_PREVIEW_CHARS,
            "tags_preview_chars": SEARCH_TAGS_PREVIEW_CHARS,
            "tags_storage_policy": SEARCH_TAGS_STORAGE_POLICY_FULL,
            "ref_path_storage_policy": SEARCH_REF_PATH_STORAGE_POLICY_DERIVED,
            "store_raw_path": False,
            "store_segment_index_path": False,
        }
    return {
        "name": SEARCH_DOCUMENT_STORAGE_PROFILE_STRUCTURED_SHARD,
        "body_preview_chars": SEARCH_STRUCTURED_SHARD_BODY_PREVIEW_CHARS,
        "route_layers_preview_chars": SEARCH_STRUCTURED_SHARD_ROUTE_LAYERS_PREVIEW_CHARS,
        "route_signals_preview_chars": SEARCH_STRUCTURED_SHARD_ROUTE_SIGNALS_PREVIEW_CHARS,
        "tags_preview_chars": SEARCH_STRUCTURED_SHARD_TAGS_PREVIEW_CHARS,
        "tags_storage_policy": SEARCH_TAGS_STORAGE_POLICY_STRUCTURED_SHARD,
        "ref_path_storage_policy": SEARCH_REF_PATH_STORAGE_POLICY_DERIVED,
        "store_raw_path": False,
        "store_segment_index_path": False,
    }


def compact_search_tags_for_storage(value: Any, *, max_chars: int, policy: str) -> str:
    text = re.sub(r"\s+", " ", str(value or "")).strip()
    if not text:
        return ""
    if policy in {SEARCH_TAGS_STORAGE_POLICY_DROP_ROUTE_SIGNAL_TOKENS, SEARCH_TAGS_STORAGE_POLICY_STRUCTURED_SHARD}:
        kept = [
            token
            for token in text.split()
            if not token.startswith("route_signal:") and not token.startswith("route_layer:")
        ]
        text = " ".join(kept).strip()
    if max_chars <= 0:
        return text
    return bounded_storage_text(text, max_chars=max_chars)


def route_term_id(conn: sqlite3.Connection, entry: dict[str, str]) -> int:
    layer = str(entry.get("layer") or "")
    key = str(entry.get("key") or "")
    route_signal = str(entry.get("route_signal") or route_signal_token(layer, key))
    cache = search_route_term_cache(conn)
    token = (layer, key)
    cached = cache.get(token)
    if cached is not None:
        return cached
    conn.execute(
        "INSERT OR IGNORE INTO route_terms(layer, key, route_signal) VALUES (?, ?, ?)",
        (layer, key, route_signal),
    )
    row = conn.execute("SELECT id FROM route_terms WHERE layer = ? AND key = ?", (layer, key)).fetchone()
    route_id = int(row[0]) if row else 0
    if route_id:
        cache[token] = route_id
    return route_id


def event_search_text_limit(event_type: str) -> int:
    if event_type in {"USER_INTENT", "ASSISTANT_PLAN", "ASSISTANT_MESSAGE", "DECISION", "ASSUMPTION", "CHECKPOINT", "FINAL_STATE", "PROCESS_LESSON", "OPEN_THREAD"}:
        return 1400
    if event_type in {"COMMAND", "FILE_READ", "FILE_WRITE", "DIFF", "TOOL_CALL"}:
        return 1000
    if event_type in {"COMMAND_OUTPUT", "TOOL_OUTPUT", "ERROR", "VERIFICATION"}:
        return 700
    return 500


def event_type_gets_raw_search_text(event_type: str, outcome: str) -> bool:
    if event_type in {
        "USER_INTENT",
        "ASSISTANT_PLAN",
        "ASSISTANT_MESSAGE",
        "DECISION",
        "ASSUMPTION",
        "CHECKPOINT",
        "FINAL_STATE",
        "PROCESS_LESSON",
        "OPEN_THREAD",
        "COMMAND",
        "FILE_READ",
        "FILE_WRITE",
        "DIFF",
        "TOOL_CALL",
        "ERROR",
        "VERIFICATION",
    }:
        return True
    return event_type in {"COMMAND_OUTPUT", "TOOL_OUTPUT"} and outcome == "failed"


def search_manifest_freshness(manifest: dict[str, Any], raw_path: Path | None) -> dict[str, Any]:
    raw = manifest.get("raw") if isinstance(manifest.get("raw"), dict) else {}
    expected_sha = str(raw.get("sha256") or "")
    if not raw_path or not raw_path.exists():
        return {"status": "unverifiable", "reasons": ["raw_path_missing"]}
    if not expected_sha:
        return {"status": "unverifiable", "reasons": ["raw_sha_missing"]}
    current_sha = sha256_file(raw_path)
    if current_sha != expected_sha:
        return {"status": "stale", "reasons": ["raw_sha_mismatch"], "current_raw_sha256": current_sha}
    return {"status": "fresh", "reasons": []}


def segment_index_freshness(index_path: Path | None, expected_sha: str | None) -> dict[str, Any]:
    if not index_path or not index_path.exists():
        return {"status": "unverifiable", "reasons": ["segment_index_missing"]}
    if not expected_sha:
        return {"status": "unverifiable", "reasons": ["segment_index_sha_missing"]}
    current_sha = sha256_file(index_path)
    if current_sha != expected_sha:
        return {"status": "stale", "reasons": ["segment_index_sha_mismatch"], "current_segment_index_sha256": current_sha}
    return {"status": "fresh", "reasons": []}


def combine_freshness(*items: dict[str, Any]) -> dict[str, Any]:
    reasons: list[str] = []
    status = "fresh"
    combined: dict[str, Any] = {}
    for item in items:
        item_status = str(item.get("status") or "")
        if item_status == "stale":
            status = "stale"
        elif item_status == "unverifiable" and status != "stale":
            status = "unverifiable"
        for reason in item.get("reasons", []) if isinstance(item.get("reasons"), list) else []:
            if reason not in reasons:
                reasons.append(str(reason))
        for key, value in item.items():
            if key not in {"status", "reasons"}:
                combined[key] = value
    return {"status": status, "reasons": reasons, **combined}


