def search_sessions_shard_fanout(
    *,
    aoa_root: Path,
    query: str = "",
    limit: int = 20,
    provider: str = "portable_sqlite",
    include_host_context: bool = False,
    include_semantic_context: bool = False,
    rerank_local: bool = False,
    rerank_candidate_limit: int | None = None,
    allow_host_warnings: bool = False,
    host_timeout: int = 45,
    session: str | None = None,
    doc_type: str | None = None,
    event_type: str | None = None,
    family: str | None = None,
    outcome: str | None = None,
    conversation_act: str | None = None,
    session_act: str | None = None,
    agent_event: str | None = None,
    usage_role: str | None = None,
    task_episode_id: str | None = None,
    route_layer: str | None = None,
    route_signal: str | None = None,
    archive_status: str | None = None,
    freshness_status: str | None = None,
    date_from: str | None = None,
    date_to: str | None = None,
    explain: bool = False,
    semantic_preview: bool = True,
    hydrate_body: bool = True,
    exclude_agent_event_stream_copies: bool = False,
    max_shards: int = 24,
    query_timeout_ms: int | None = SEARCH_FTS_QUERY_TIMEOUT_MS,
) -> dict[str, Any]:
    if provider != "portable_sqlite" or include_host_context or include_semantic_context or rerank_local:
        return search_shard_fanout_unavailable_payload(
            reason="search_shard_fanout_requires_portable_sqlite_without_host_overlays",
            aoa_root=aoa_root,
            query=query,
            limit=limit,
            provider=provider,
            include_host_context=include_host_context,
            include_semantic_context=include_semantic_context,
            rerank_local=rerank_local,
            rerank_candidate_limit=rerank_candidate_limit,
            allow_host_warnings=allow_host_warnings,
            host_timeout=host_timeout,
            session=session,
            doc_type=doc_type,
            event_type=event_type,
            family=family,
            outcome=outcome,
            conversation_act=conversation_act,
            session_act=session_act,
            agent_event=agent_event,
            usage_role=usage_role,
            task_episode_id=task_episode_id,
            route_layer=route_layer,
            route_signal=route_signal,
            archive_status=archive_status,
            freshness_status=freshness_status,
            date_from=date_from,
            date_to=date_to,
            explain=explain,
            semantic_preview=semantic_preview,
            hydrate_body=hydrate_body,
            exclude_agent_event_stream_copies=exclude_agent_event_stream_copies,
            query_timeout_ms=query_timeout_ms,
        )
    catalog = read_search_catalog(aoa_root)
    shards = catalog.get("shards") if isinstance(catalog.get("shards"), list) else []
    session_filter_column, session_filter_value = exact_session_filter_for_search(aoa_root, session)
    session_scope_shard = ""
    if session and session_filter_column and session_filter_value:
        session_scope_record: dict[str, Any] = {}
        try:
            session_scope_record = resolve_session_record(aoa_root, session)
        except ValueError:
            session_scope_record = {}
        session_scope_label = str(session_scope_record.get("session_label") or "")
        session_scope_date = session_record_date(session_scope_record) if session_scope_record else ""
        if not session_scope_label and session_filter_column == "documents.session_label":
            session_scope_label = session_filter_value
        if session_scope_label or session_scope_date:
            session_scope_shard = search_shard_key_for_session(session_scope_label, session_scope_date)
    candidate_shards: list[dict[str, Any]] = []
    uses_fts = bool(fts_query_from_user(query))
    skipped_raw_text_nonmaterialized_shards: list[str] = []
    for item in shards:
        if not isinstance(item, dict):
            continue
        shard_key = str(item.get("shard") or "")
        shard_path = Path(str(item.get("shard_db_path") or ""))
        if not shard_key or not shard_path.exists():
            continue
        shard_materialized = bool(item.get("materialized"))
        if not search_shard_overlaps_date_filter(shard_key, date_from, date_to):
            continue
        if session_scope_shard and shard_key != session_scope_shard:
            continue
        if not shard_materialized and uses_fts:
            skipped_raw_text_nonmaterialized_shards.append(shard_key)
            continue
        candidate_shards.append(item)
    candidate_shards.sort(key=lambda item: str(item.get("shard") or ""), reverse=True)
    effective_max_shards = max(1, int_value(max_shards, 24))
    truncated = len(candidate_shards) > effective_max_shards
    queried_shards = candidate_shards[:effective_max_shards]
    queried_structured_nonmaterialized_shards = [
        str(item.get("shard") or "")
        for item in queried_shards
        if isinstance(item, dict) and not item.get("materialized") and str(item.get("shard") or "")
    ]
    if not queried_shards:
        payload = search_shard_fanout_unavailable_payload(
            reason="search_shard_fanout_no_materialized_shards_fallback_monolith",
            aoa_root=aoa_root,
            query=query,
            limit=limit,
            provider=provider,
            include_host_context=include_host_context,
            include_semantic_context=include_semantic_context,
            rerank_local=rerank_local,
            rerank_candidate_limit=rerank_candidate_limit,
            allow_host_warnings=allow_host_warnings,
            host_timeout=host_timeout,
            session=session,
            doc_type=doc_type,
            event_type=event_type,
            family=family,
            outcome=outcome,
            conversation_act=conversation_act,
            session_act=session_act,
            agent_event=agent_event,
            usage_role=usage_role,
            task_episode_id=task_episode_id,
            route_layer=route_layer,
            route_signal=route_signal,
            archive_status=archive_status,
            freshness_status=freshness_status,
            date_from=date_from,
            date_to=date_to,
            explain=explain,
            semantic_preview=semantic_preview,
            hydrate_body=hydrate_body,
            exclude_agent_event_stream_copies=exclude_agent_event_stream_copies,
            query_timeout_ms=query_timeout_ms,
        )
        if uses_fts or skipped_raw_text_nonmaterialized_shards:
            payload.setdefault("search_projection", {})["raw_text_fallback"] = search_raw_text_fallback_route_packet(
                aoa_root=aoa_root,
                shard_rows=[],
                nonmaterialized_shards=skipped_raw_text_nonmaterialized_shards,
                candidate_shard_count=0,
                queried_shard_count=0,
            )
        return payload
    effective_limit = max(1, int_value(limit, 20))
    if uses_fts:
        unsupported_raw_text_shards: list[str] = []
        for shard_item in queried_shards:
            shard_key = str(shard_item.get("shard") or "")
            shard_path = Path(str(shard_item.get("shard_db_path") or ""))
            raw_text_support = str(shard_item.get("raw_text_query_support") or "").strip()
            if not raw_text_support:
                raw_text_support = search_raw_text_query_support_from_metadata(search_db_metadata_at_path(shard_path))
            if raw_text_support != SEARCH_RAW_TEXT_QUERY_SUPPORT_FULL:
                unsupported_raw_text_shards.append(shard_key)
        if unsupported_raw_text_shards:
            raw_text_fallback = search_raw_text_fallback_route_packet(
                aoa_root=aoa_root,
                shard_rows=queried_shards,
                unsupported_shards=unsupported_raw_text_shards,
                nonmaterialized_shards=skipped_raw_text_nonmaterialized_shards,
                candidate_shard_count=len(candidate_shards),
                queried_shard_count=len(queried_shards),
            )
            payload = search_shard_fanout_unavailable_payload(
                reason="search_shard_fanout_raw_text_uses_monolith_fallback",
                aoa_root=aoa_root,
                query=query,
                limit=limit,
                provider=provider,
                include_host_context=include_host_context,
                include_semantic_context=include_semantic_context,
                rerank_local=rerank_local,
                rerank_candidate_limit=rerank_candidate_limit,
                allow_host_warnings=allow_host_warnings,
                host_timeout=host_timeout,
                session=session,
                doc_type=doc_type,
                event_type=event_type,
                family=family,
                outcome=outcome,
                conversation_act=conversation_act,
                session_act=session_act,
                agent_event=agent_event,
                usage_role=usage_role,
                task_episode_id=task_episode_id,
                route_layer=route_layer,
                route_signal=route_signal,
                archive_status=archive_status,
                freshness_status=freshness_status,
                date_from=date_from,
                date_to=date_to,
                explain=explain,
                semantic_preview=semantic_preview,
                hydrate_body=hydrate_body,
                exclude_agent_event_stream_copies=exclude_agent_event_stream_copies,
                query_timeout_ms=query_timeout_ms,
            )
            payload.setdefault("search_projection", {})["unsupported_raw_text_shards"] = unsupported_raw_text_shards
            payload.setdefault("search_projection", {})["raw_text_query_support"] = SEARCH_RAW_TEXT_QUERY_SUPPORT_MONOLITH_FALLBACK
            payload.setdefault("search_projection", {})["raw_text_fallback"] = raw_text_fallback
            return payload
    structured_route_filter = bool(
        any([doc_type, event_type, family, outcome, conversation_act, session_act, agent_event, usage_role, task_episode_id, route_layer, route_signal])
    )
    lightweight_route = bool(structured_route_filter and not uses_fts)
    effective_hydrate_body = bool(hydrate_body and not lightweight_route)
    effective_semantic_preview = bool(semantic_preview and not lightweight_route)
    shard_payloads: list[dict[str, Any]] = []
    merged: dict[str, dict[str, Any]] = {}
    diagnostics: list[str] = []
    for shard_item in queried_shards:
        shard_key = str(shard_item.get("shard") or "")
        shard_path = Path(str(shard_item.get("shard_db_path") or ""))
        shard_payload = search_sessions(
            aoa_root=aoa_root,
            query=query,
            limit=effective_limit,
            provider=provider,
            include_host_context=False,
            include_semantic_context=False,
            rerank_local=False,
            rerank_candidate_limit=None,
            allow_host_warnings=allow_host_warnings,
            host_timeout=host_timeout,
            session=session,
            doc_type=doc_type,
            event_type=event_type,
            family=family,
            outcome=outcome,
            conversation_act=conversation_act,
            session_act=session_act,
            agent_event=agent_event,
            usage_role=usage_role,
            task_episode_id=task_episode_id,
            route_layer=route_layer,
            route_signal=route_signal,
            archive_status=archive_status,
            freshness_status=freshness_status,
            date_from=date_from,
            date_to=date_to,
            explain=explain,
            semantic_preview=effective_semantic_preview,
            hydrate_body=effective_hydrate_body,
            exclude_agent_event_stream_copies=exclude_agent_event_stream_copies,
            use_shards=False,
            db_path_override=shard_path,
            projection_mode=SEARCH_ACTIVE_PROJECTION_SHARD,
            query_timeout_ms=query_timeout_ms,
        )
        shard_payloads.append(
            {
                "shard": shard_key,
                "db_path": str(shard_path),
                "ok": shard_payload.get("ok"),
                "result_count": shard_payload.get("result_count"),
                "raw_text_query_support": shard_item.get("raw_text_query_support") or "",
                "storage_mode": shard_item.get("storage_mode") or "",
                "diagnostics": shard_payload.get("diagnostics", []),
            }
        )
        diagnostics.extend(f"{shard_key}:{item}" for item in shard_payload.get("diagnostics", []) if item)
        for result in shard_payload.get("results", []) if isinstance(shard_payload.get("results"), list) else []:
            doc_id = str(result.get("doc_id") or "")
            if not doc_id or doc_id in merged:
                continue
            search_catalog = result.get("search_catalog") if isinstance(result.get("search_catalog"), dict) else {}
            result["search_catalog"] = {
                **search_catalog,
                "active_projection": SEARCH_ACTIVE_PROJECTION_SHARD,
                "shard_strategy": SEARCH_SHARD_STRATEGY,
                "shard": shard_key,
                "shard_db_path": str(shard_path),
            }
            merged[doc_id] = result
    results = sorted(merged.values(), key=lambda item: search_result_order_key(item, query=query))[:effective_limit]
    if truncated:
        diagnostics.append(f"search_shard_fanout_truncated:{len(candidate_shards)}:{effective_max_shards}")
    if queried_structured_nonmaterialized_shards and not uses_fts:
        diagnostics.append(f"search_shard_fanout_using_structured_nonmaterialized_shards:{len(queried_structured_nonmaterialized_shards)}")
    provider_payload = search_provider_status_fast(aoa_root=aoa_root, provider_name=provider)
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "search_results",
        "search_schema_version": SEARCH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": True,
        "query": query,
        "normalized_query": fts_query_from_user(query),
        "db_path": str(search_db_path(aoa_root)),
        "index_generated_at": catalog.get("generated_at"),
        "aoa_root": str(aoa_root),
        "search_projection": {
            "mode": SEARCH_ACTIVE_PROJECTION_SHARD_FANOUT,
            "catalog_status": catalog.get("status"),
            "catalog_path": catalog.get("catalog_path"),
            "candidate_shard_count": len(candidate_shards),
            "queried_shard_count": len(queried_shards),
            "max_shards": effective_max_shards,
            "truncated": truncated,
            "fallback_db_path": str(search_db_path(aoa_root)),
            "queried_shards": shard_payloads,
            "structured_nonmaterialized_shards_used": queried_structured_nonmaterialized_shards,
            "session_scope": {
                "requested": session or "",
                "exact_filter_column": session_filter_column or "",
                "exact_filter_value": session_filter_value or "",
                "resolved_shard": session_scope_shard,
            },
            "next_expansion_command": (
                "python3 scripts/aoa_session_memory.py search --use-shards --max-shards "
                f"{len(candidate_shards)} --query {shlex.quote(query)}"
                if truncated
                else ""
            ),
        },
        "cost_profile": {
            "lightweight_route": lightweight_route,
            "structured_route_filter": structured_route_filter,
            "uses_fts": uses_fts,
            "hydrates_body": effective_hydrate_body,
            "semantic_preview": effective_semantic_preview,
            "uses_shards": True,
            "shard_query_limit": effective_limit,
        },
        "provider": {
            "selected": provider,
            "authoritative_result_provider": "portable_sqlite",
            "status": provider_payload,
            "accelerator_provider": None,
            "accelerator_status": None,
            "overlay": None,
            "semantic_overlay": None,
            "local_rerank": None,
            "authority_law": search_provider_config(aoa_root).get("authority_law"),
        },
        "result_count": len(results),
        "results": results,
        "diagnostics": diagnostics,
    }


def search_sessions(
    *,
    aoa_root: Path,
    query: str = "",
    limit: int = 20,
    provider: str = "portable_sqlite",
    include_host_context: bool = False,
    include_semantic_context: bool = False,
    rerank_local: bool = False,
    rerank_candidate_limit: int | None = None,
    allow_host_warnings: bool = False,
    host_timeout: int = 45,
    session: str | None = None,
    doc_type: str | None = None,
    event_type: str | None = None,
    family: str | None = None,
    outcome: str | None = None,
    conversation_act: str | None = None,
    session_act: str | None = None,
    agent_event: str | None = None,
    usage_role: str | None = None,
    task_episode_id: str | None = None,
    route_layer: str | None = None,
    route_signal: str | None = None,
    archive_status: str | None = None,
    freshness_status: str | None = None,
    date_from: str | None = None,
    date_to: str | None = None,
    explain: bool = False,
    semantic_preview: bool = True,
    hydrate_body: bool = True,
    exclude_agent_event_stream_copies: bool = False,
    use_shards: bool = False,
    max_shards: int = 24,
    db_path_override: Path | None = None,
    projection_mode: str | None = None,
    query_timeout_ms: int | None = SEARCH_FTS_QUERY_TIMEOUT_MS,
) -> dict[str, Any]:
    now = utc_now()
    normalized_agent_event = normalize_agent_event_route_class(agent_event) if agent_event else None
    provider_config = search_provider_config(aoa_root)
    configured_providers = provider_config.get("providers") if isinstance(provider_config.get("providers"), dict) else {}
    if provider not in configured_providers:
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "search_results",
            "search_schema_version": SEARCH_SCHEMA_VERSION,
            "generated_at": now,
            "ok": False,
            "query": query,
            "result_count": 0,
            "results": [],
            "provider": {"selected": provider, "status": "unknown_provider"},
            "diagnostics": [f"unknown search provider: {provider}"],
        }
    if use_shards and db_path_override is None:
        return search_sessions_shard_fanout(
            aoa_root=aoa_root,
            query=query,
            limit=limit,
            provider=provider,
            include_host_context=include_host_context,
            include_semantic_context=include_semantic_context,
            rerank_local=rerank_local,
            rerank_candidate_limit=rerank_candidate_limit,
            allow_host_warnings=allow_host_warnings,
            host_timeout=host_timeout,
            session=session,
            doc_type=doc_type,
            event_type=event_type,
            family=family,
            outcome=outcome,
            conversation_act=conversation_act,
            session_act=session_act,
            agent_event=normalized_agent_event,
            usage_role=usage_role,
            task_episode_id=task_episode_id,
            route_layer=route_layer,
            route_signal=route_signal,
            archive_status=archive_status,
            freshness_status=freshness_status,
            date_from=date_from,
            date_to=date_to,
            explain=explain,
            semantic_preview=semantic_preview,
            hydrate_body=hydrate_body,
            exclude_agent_event_stream_copies=exclude_agent_event_stream_copies,
            max_shards=max_shards,
            query_timeout_ms=query_timeout_ms,
        )
    db_path = db_path_override or search_db_path(aoa_root)
    effective_projection_mode = projection_mode or (
        SEARCH_ACTIVE_PROJECTION_SHARD if db_path_override is not None else SEARCH_ACTIVE_PROJECTION_MONOLITH
    )
    if not db_path.exists():
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "search_results",
            "search_schema_version": SEARCH_SCHEMA_VERSION,
            "generated_at": now,
            "ok": False,
            "query": query,
            "db_path": str(db_path),
            "result_count": 0,
            "results": [],
            "provider": {"selected": provider, "status": "portable_sqlite_missing"},
            "diagnostics": ["search index missing; run search-index"],
        }
    filters: list[str] = []
    params: list[Any] = []
    route_filters: list[str] = []
    route_params: list[Any] = []
    if session:
        exact_column, exact_value = exact_session_filter_for_search(aoa_root, session)
        if exact_column and exact_value:
            filters.append(f"{exact_column} = ?")
            params.append(exact_value)
        else:
            filters.append("(documents.session_id = ? OR documents.session_label LIKE ? OR documents.session_title LIKE ?)")
            like = f"%{session}%"
            params.extend([session, like, like])
    requested_freshness_status = str(freshness_status or "").strip()
    for column, value in [
        ("documents.doc_type", doc_type),
        ("documents.event_type", event_type),
        ("documents.family", family),
        ("documents.outcome", outcome),
        ("documents.conversation_act", conversation_act),
        ("documents.session_act", session_act),
        ("documents.agent_event", normalized_agent_event),
        ("documents.usage_role", usage_role),
        ("documents.task_episode_id", task_episode_id),
        ("documents.archive_status", archive_status),
    ]:
        if value:
            filters.append(f"{column} = ?")
            params.append(value)
    if exclude_agent_event_stream_copies:
        filters.append("COALESCE(documents.tags, '') NOT LIKE ?")
        params.append("%agent_event_source:event_msg_stream%")
    if route_layer:
        route_filters.append("route_terms.layer = ?")
        route_params.append(route_key_slug(route_layer, fallback=str(route_layer)))
    if route_signal:
        normalized_signal = str(route_signal)
        if ":" in normalized_signal:
            layer, key = normalized_signal.split(":", 1)
            normalized_signal = route_signal_token(route_key_slug(layer, fallback=layer), route_key_slug(key, fallback=key))
        route_filters.append("route_terms.route_signal = ?")
        route_params.append(normalized_signal)
    if date_from:
        filters.append("documents.session_date >= ?")
        params.append(parse_date_arg(date_from))
    if date_to:
        filters.append("documents.session_date <= ?")
        params.append(parse_date_arg(date_to))
    route_join = ""
    route_where = " AND ".join(route_filters)
    fts_query = fts_query_from_user(query)
    structured_route_filter = any(
        bool(value)
        for value in [
            doc_type,
            event_type,
            family,
            outcome,
            conversation_act,
            session_act,
            normalized_agent_event,
            usage_role,
            task_episode_id,
            route_layer,
            route_signal,
        ]
    )
    lightweight_route = bool(structured_route_filter and not fts_query and not include_host_context and not include_semantic_context and not rerank_local)
    effective_semantic_preview = bool(semantic_preview and not lightweight_route)
    effective_hydrate_body = bool(hydrate_body and not lightweight_route)
    effective_query_timeout_ms = normalized_search_fts_query_timeout_ms(query_timeout_ms) if fts_query else 0
    conn: sqlite3.Connection | None = None
    started_monotonic = time.monotonic()
    try:
        conn = connect_existing_search_db(db_path)
        if fts_query:
            effective_query_timeout_ms, _deadline = install_search_fts_query_deadline(
                conn,
                query_timeout_ms=query_timeout_ms,
            )
        body_overrides: dict[int, str] = {}
        if route_where:
            conn.execute("CREATE TEMP TABLE search_route_filter(doc_rowid INTEGER PRIMARY KEY)")
            conn.execute(
                """
                INSERT OR IGNORE INTO search_route_filter(doc_rowid)
                SELECT document_routes.doc_rowid
                FROM document_routes JOIN route_terms ON route_terms.id = document_routes.route_id
                WHERE """
                + route_where,
                route_params,
            )
            route_join = " JOIN search_route_filter AS route_filter ON route_filter.doc_rowid = documents.rowid"
        effective_limit = max(1, int_value(limit, 20))
        query_limit = max(effective_limit, 200) if requested_freshness_status else effective_limit

        def fetch_search_rows(
            *,
            extra_filters: list[str] | None = None,
            extra_params: list[Any] | None = None,
            limit_value: int,
            offset: int = 0,
        ) -> list[sqlite3.Row]:
            query_filters = [*filters, *(extra_filters or [])]
            query_params_base = [*params, *(extra_params or [])]
            query_where = " AND ".join(query_filters)
            if fts_query:
                rank_select = "0.0 AS rank" if effective_query_timeout_ms else "bm25(documents_fts) AS rank"
                order_clause = (
                    " ORDER BY documents.session_date DESC, documents.rowid DESC LIMIT ? OFFSET ?"
                    if effective_query_timeout_ms
                    else " ORDER BY rank, documents.session_date DESC, documents.rowid DESC LIMIT ? OFFSET ?"
                )
                sql = (
                    "SELECT documents.*, "
                    + rank_select
                    + " "
                    "FROM documents_fts JOIN documents ON documents_fts.rowid = documents.rowid"
                    f"{route_join} "
                    "WHERE documents_fts MATCH ?"
                )
                query_params: list[Any] = [fts_query]
                if query_where:
                    sql += " AND " + query_where
                    query_params.extend(query_params_base)
                sql += order_clause
                query_params.extend([limit_value, offset])
                return conn.execute(sql, query_params).fetchall()
            sql = f"SELECT documents.*, 0.0 AS rank FROM documents{route_join}"
            query_params = [*query_params_base]
            if query_where:
                sql += " WHERE " + query_where
            sql += " ORDER BY documents.session_date DESC, documents.rowid DESC LIMIT ? OFFSET ?"
            query_params.extend([limit_value, offset])
            return conn.execute(sql, query_params).fetchall()

        unfiltered_rows = fetch_search_rows(limit_value=query_limit)
        rows = list(unfiltered_rows)
        metadata = search_index_metadata(conn)
        freshness_filter_diagnostics: list[str] = []
        if requested_freshness_status:
            results: list[dict[str, Any]] = []
            seen_rowids: set[int] = set()
            scanned_candidate_count = 0

            def append_live_freshness_matches(candidate_rows: list[sqlite3.Row]) -> bool:
                nonlocal scanned_candidate_count
                candidate_body_overrides = search_document_bodies_for_rows(conn, candidate_rows) if effective_hydrate_body else {}
                for row in candidate_rows:
                    rowid = int_value(row["rowid"])
                    if rowid in seen_rowids:
                        continue
                    seen_rowids.add(rowid)
                    scanned_candidate_count += 1
                    result = compact_search_result(
                        row,
                        explain=explain,
                        query=query,
                        full_body=candidate_body_overrides.get(rowid),
                        semantic_preview=effective_semantic_preview,
                    )
                    freshness = result.get("freshness") if isinstance(result.get("freshness"), dict) else {}
                    if str(freshness.get("status") or "") == requested_freshness_status:
                        results.append(result)
                        if len(results) >= effective_limit:
                            return True
                return False

            found_enough = append_live_freshness_matches(rows)
            offset = query_limit
            while not found_enough and len(unfiltered_rows) == query_limit:
                next_rows = fetch_search_rows(limit_value=query_limit, offset=offset)
                if not next_rows:
                    break
                offset += len(next_rows)
                found_enough = append_live_freshness_matches(next_rows)
                if len(next_rows) < query_limit:
                    break
            results = results[:effective_limit]
            freshness_filter_diagnostics.append(f"freshness_status_filter_applied_after_live_check:{requested_freshness_status}")
            freshness_filter_diagnostics.append(f"freshness_status_candidate_count:{scanned_candidate_count}")
        else:
            body_overrides = search_document_bodies_for_rows(conn, rows) if effective_hydrate_body else {}
            results = [
                compact_search_result(
                    row,
                    explain=explain,
                    query=query,
                    full_body=body_overrides.get(int_value(row["rowid"])),
                    semantic_preview=effective_semantic_preview,
                )
                for row in rows
            ]
            freshness_filter_diagnostics = []
    except sqlite3.Error as exc:
        status = sqlite_error_status(exc)
        if status == SEARCH_FTS_QUERY_TIMEOUT_STATUS and fts_query:
            return search_fts_timeout_payload(
                aoa_root=aoa_root,
                query=query,
                normalized_query=fts_query,
                db_path=db_path,
                provider=provider,
                projection_mode=effective_projection_mode,
                query_timeout_ms=effective_query_timeout_ms,
                elapsed_ms=int((time.monotonic() - started_monotonic) * 1000),
                command="search",
                limit=limit,
                options=[
                    ("--session", session),
                    ("--doc-type", doc_type),
                    ("--event-type", event_type),
                    ("--family", family),
                    ("--outcome", outcome),
                    ("--conversation-act", conversation_act),
                    ("--session-act", session_act),
                    ("--agent-event", normalized_agent_event),
                    ("--usage-role", usage_role),
                    ("--task-episode-id", task_episode_id),
                    ("--route-layer", route_layer),
                    ("--route-signal", route_signal),
                    ("--archive-status", archive_status),
                    ("--freshness-status", freshness_status),
                    ("--date-from", date_from),
                    ("--date-to", date_to),
                    ("--explain", explain),
                ],
                cost_profile={
                    "lightweight_route": lightweight_route,
                    "structured_route_filter": structured_route_filter,
                    "uses_fts": True,
                    "hydrates_body": effective_hydrate_body,
                    "semantic_preview": effective_semantic_preview,
                    "uses_shards": db_path_override is not None,
                    "rank_mode": "bounded_date_order_no_bm25" if effective_query_timeout_ms else "bm25",
                },
                provider_config=provider_config,
                exc=exc,
            )
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "search_results",
            "search_schema_version": SEARCH_SCHEMA_VERSION,
            "generated_at": now,
            "ok": False,
            "query": query,
            "db_path": str(db_path),
            "result_count": 0,
            "results": [],
            "provider": {"selected": provider, "status": status},
            "diagnostics": [sqlite_error_diagnostic(exc)],
        }
    finally:
        if conn is not None:
            clear_search_fts_query_deadline(conn)
            conn.close()
    accelerator_provider = provider if provider != "portable_sqlite" else "abyss_machine_nervous"
    if provider == "portable_sqlite" and not include_host_context:
        provider_payload = search_provider_status_fast(aoa_root=aoa_root, provider_name=provider)
    else:
        provider_payload = search_provider_status(
            aoa_root=aoa_root,
            provider_name=provider,
            include_host=provider != "portable_sqlite",
            timeout=host_timeout,
        )
    accelerator_status: dict[str, Any] | None = None
    if rerank_local or include_semantic_context:
        accelerator_status = search_provider_status(
            aoa_root=aoa_root,
            provider_name=accelerator_provider,
            include_host=True,
            timeout=host_timeout,
        )
    diagnostics: list[str] = list(freshness_filter_diagnostics)
    provider_overlay: dict[str, Any] | None = None
    semantic_overlay: dict[str, Any] | None = None
    local_rerank: dict[str, Any] | None = None
    if provider != "portable_sqlite":
        selected_status = provider_payload.get("providers", {}).get(provider) if isinstance(provider_payload.get("providers"), dict) else {}
        status = str(selected_status.get("status") if isinstance(selected_status, dict) else "")
        if status == "ready_with_warnings" and not allow_host_warnings:
            diagnostics.append("host provider has warnings; returned portable SQLite .aoa hits without host context overlay")
        elif not selected_status.get("ok"):
            diagnostics.append(f"host provider unavailable: {status}")
        elif include_host_context:
            provider_overlay = host_context_overlay(
                config=provider_config,
                provider_name=provider,
                query=query,
                limit=limit,
                timeout=host_timeout,
            )
    selected_accelerator = (
        accelerator_status.get("providers", {}).get(accelerator_provider)
        if isinstance(accelerator_status, dict) and isinstance(accelerator_status.get("providers"), dict)
        else {}
    )
    accelerator_ok = bool(selected_accelerator.get("ok")) if isinstance(selected_accelerator, dict) else False
    accelerator_status_name = str(selected_accelerator.get("status") or "") if isinstance(selected_accelerator, dict) else ""
    if (rerank_local or include_semantic_context) and not accelerator_ok:
        diagnostics.append(f"local accelerator unavailable: {accelerator_status_name or 'unknown'}")
    elif (rerank_local or include_semantic_context) and accelerator_status_name == "ready_with_warnings" and not allow_host_warnings:
        diagnostics.append("local accelerator has warnings; use --allow-host-warnings to include semantic/rerank overlays")
    else:
        if include_semantic_context:
            semantic_overlay = host_semantic_overlay(
                config=provider_config,
                provider_name=accelerator_provider,
                query=query,
                limit=limit,
                timeout=host_timeout,
            )
            if not semantic_overlay.get("ok"):
                diagnostics.append(f"semantic overlay unavailable: {semantic_overlay.get('status')}")
        if rerank_local:
            rerank_payload = local_rerank_search_results(
                config=provider_config,
                provider_name=accelerator_provider,
                query=query,
                results=results,
                timeout=host_timeout,
                candidate_limit=rerank_candidate_limit,
            )
            if rerank_payload.get("ok"):
                results = rerank_payload.pop("results", results)
                local_rerank = rerank_payload
            else:
                diagnostics.append(f"local rerank unavailable: {rerank_payload.get('status')}")
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "search_results",
        "search_schema_version": SEARCH_SCHEMA_VERSION,
        "generated_at": now,
        "ok": True,
        "query": query,
        "normalized_query": fts_query,
        "db_path": str(db_path),
        "index_generated_at": metadata.get("generated_at"),
        "aoa_root": str(aoa_root),
        "search_projection": {
            "mode": effective_projection_mode,
            "db_path": str(db_path),
            "fallback_db_path": str(search_db_path(aoa_root)),
        },
        "cost_profile": {
            "lightweight_route": lightweight_route,
            "structured_route_filter": structured_route_filter,
            "uses_fts": bool(fts_query),
            "hydrates_body": effective_hydrate_body,
            "semantic_preview": effective_semantic_preview,
            "query_timeout_ms": effective_query_timeout_ms,
            "bounded_query_timeout": bool(fts_query and effective_query_timeout_ms),
            "rank_mode": "bounded_date_order_no_bm25" if fts_query and effective_query_timeout_ms else ("bm25" if fts_query else "none"),
        },
        "provider": {
            "selected": provider,
            "authoritative_result_provider": "portable_sqlite",
            "status": provider_payload,
            "accelerator_provider": accelerator_provider if rerank_local or include_semantic_context else None,
            "accelerator_status": accelerator_status,
            "overlay": provider_overlay,
            "semantic_overlay": semantic_overlay,
            "local_rerank": local_rerank,
            "authority_law": provider_config.get("authority_law"),
        },
        "result_count": len(results),
        "results": results,
        "diagnostics": diagnostics,
    }


