def path_total_size(path: Path) -> int:
    if not path.exists() and not path.is_symlink():
        return 0
    try:
        if path.is_file() or path.is_symlink():
            return path.stat().st_size
    except OSError:
        return 0
    total = 0
    for root, dirs, files in os.walk(path):
        dirs[:] = [name for name in dirs if name not in {".git", ".pytest_cache", "__pycache__"}]
        root_path = Path(root)
        for name in files:
            try:
                total += (root_path / name).stat().st_size
            except OSError:
                continue
    return total


def storage_size_entry(path: Path, *, label: str | None = None) -> dict[str, Any]:
    size = path_total_size(path)
    return {
        "label": label or path.name,
        "path": str(path),
        "exists": path.exists() or path.is_symlink(),
        "size_bytes": size,
        "size_human": human_size(size),
    }


def sqlite_storage_stats(
    db_path: Path,
    *,
    deep: bool = False,
    row_counts: bool = False,
    table_limit: int = 40,
) -> dict[str, Any]:
    payload: dict[str, Any] = storage_size_entry(db_path, label=db_path.name)
    payload.update({"kind": "sqlite", "ok": False, "diagnostics": []})
    wal_path = Path(str(db_path) + "-wal")
    shm_path = Path(str(db_path) + "-shm")
    wal_bytes = path_total_size(wal_path)
    shm_bytes = path_total_size(shm_path)
    payload["wal"] = {
        "path": str(wal_path),
        "exists": wal_path.exists(),
        "size_bytes": wal_bytes,
        "size_human": human_size(wal_bytes),
    }
    payload["shm"] = {
        "path": str(shm_path),
        "exists": shm_path.exists(),
        "size_bytes": shm_bytes,
        "size_human": human_size(shm_bytes),
    }
    payload["total_with_wal_bytes"] = int_value(payload.get("size_bytes")) + wal_bytes + shm_bytes
    payload["total_with_wal_human"] = human_size(payload["total_with_wal_bytes"])
    if not db_path.exists():
        payload["diagnostics"] = ["sqlite_db_missing"]
        return payload
    try:
        conn = sqlite3.connect(str(db_path))
        conn.row_factory = sqlite3.Row
        metadata: dict[str, str] = {}
        for meta_table in ("metadata", "meta"):
            try:
                rows = conn.execute(f"SELECT key, value FROM {meta_table} ORDER BY key").fetchall()
            except sqlite3.Error:
                continue
            for row in rows:
                metadata[str(row["key"])] = str(row["value"])
        if metadata:
            payload["metadata"] = metadata
            payload["raw_lexical_policy"] = search_raw_lexical_policy_from_metadata(metadata)
        page_size = int(conn.execute("PRAGMA page_size").fetchone()[0])
        page_count = int(conn.execute("PRAGMA page_count").fetchone()[0])
        freelist_count = int(conn.execute("PRAGMA freelist_count").fetchone()[0])
        payload.update(
            {
                "ok": True,
                "page_size": page_size,
                "page_count": page_count,
                "freelist_count": freelist_count,
                "allocated_bytes": page_size * page_count,
                "freelist_bytes": page_size * freelist_count,
                "freelist_human": human_size(page_size * freelist_count),
            }
        )
        if row_counts:
            payload["row_count_status"] = "requested"
            row_count_payload: dict[str, int] = {}
            tables = [
                str(row["name"])
                for row in conn.execute("SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%' ORDER BY name").fetchall()
            ]
            for table in tables:
                try:
                    row = conn.execute(f"SELECT COUNT(*) FROM {table}").fetchone()
                    row_count_payload[table] = int(row[0] or 0) if row else 0
                except sqlite3.Error:
                    continue
            payload["row_counts"] = row_count_payload
        else:
            payload["row_count_status"] = "not_requested"
        if deep:
            payload["deep_dbstat_status"] = "requested"
            try:
                rows = conn.execute(
                    """
                    SELECT name, SUM(pgsize) AS bytes, COUNT(*) AS pages
                    FROM dbstat
                    GROUP BY name
                    ORDER BY bytes DESC
                    LIMIT ?
                    """,
                    (max(1, int_value(table_limit, 40)),),
                ).fetchall()
                payload["table_sizes"] = [
                    {
                        "name": str(row["name"]),
                        "size_bytes": int(row["bytes"] or 0),
                        "size_human": human_size(int(row["bytes"] or 0)),
                        "pages": int(row["pages"] or 0),
                    }
                    for row in rows
                ]
                payload["deep_dbstat_status"] = "completed"
            except sqlite3.Error as exc:
                payload.setdefault("diagnostics", []).append(f"dbstat_unavailable:{exc}")
                payload["deep_dbstat_status"] = "unavailable"
        else:
            payload["deep_dbstat_status"] = "not_requested"
        conn.close()
    except sqlite3.Error as exc:
        payload["diagnostics"] = [f"sqlite_error:{exc}"]
    return payload


def sqlite_wal_checkpoint(
    db_path: Path,
    *,
    timeout: float = 120.0,
) -> dict[str, Any]:
    wal_path = Path(str(db_path) + "-wal")
    shm_path = Path(str(db_path) + "-shm")
    before = {
        "db_bytes": path_total_size(db_path),
        "wal_bytes": path_total_size(wal_path),
        "shm_bytes": path_total_size(shm_path),
    }
    diagnostics: list[str] = []
    result_rows: list[list[int]] = []
    if not db_path.exists():
        return {
            "path": str(db_path),
            "ok": False,
            "status": "missing",
            "mutates": False,
            "before": before,
            "after": before,
            "reclaimed_bytes": 0,
            "reclaimed_human": "0 B",
            "diagnostics": ["sqlite_db_missing"],
        }
    try:
        conn = sqlite3.connect(str(db_path), timeout=timeout)
        try:
            result_rows = [[int_value(value) for value in row] for row in conn.execute("PRAGMA wal_checkpoint(TRUNCATE)").fetchall()]
            conn.commit()
        finally:
            conn.close()
    except sqlite3.Error as exc:
        diagnostics.append(sqlite_error_diagnostic(exc))
    after = {
        "db_bytes": path_total_size(db_path),
        "wal_bytes": path_total_size(wal_path),
        "shm_bytes": path_total_size(shm_path),
    }
    busy = bool(result_rows and result_rows[0] and int_value(result_rows[0][0]) != 0)
    reclaimed = max(0, before["db_bytes"] + before["wal_bytes"] + before["shm_bytes"] - after["db_bytes"] - after["wal_bytes"] - after["shm_bytes"])
    status = "checkpointed"
    if diagnostics:
        status = "sqlite_error"
    elif busy:
        status = "busy_deferred"
        diagnostics.append("sqlite_wal_checkpoint_busy")
    return {
        "path": str(db_path),
        "ok": not diagnostics or busy,
        "status": status,
        "mutates": True,
        "result": result_rows,
        "before": before,
        "after": after,
        "reclaimed_bytes": reclaimed,
        "reclaimed_human": human_size(reclaimed),
        "diagnostics": diagnostics,
    }


def storage_maintenance(
    *,
    aoa_root: Path,
    write_report: bool = False,
) -> dict[str, Any]:
    now = utc_now()
    targets = {
        "graph_store": graph_paths(aoa_root)["store"],
        "search_store": search_db_path(aoa_root),
    }
    checkpoints = {
        name: sqlite_wal_checkpoint(path)
        for name, path in targets.items()
    }
    diagnostics = sorted(
        {
            f"{name}:{diag}"
            for name, item in checkpoints.items()
            for diag in (item.get("diagnostics", []) if isinstance(item.get("diagnostics"), list) else [])
            if diag
        }
    )
    reclaimed = sum(int_value(item.get("reclaimed_bytes")) for item in checkpoints.values())
    busy = any(str(item.get("status") or "") == "busy_deferred" for item in checkpoints.values())
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_storage_maintenance",
        "generated_at": now,
        "ok": not any(str(item.get("status") or "") == "sqlite_error" for item in checkpoints.values()),
        "mutates": True,
        "status": "deferred_busy" if busy else "checkpointed",
        "aoa_root": str(aoa_root),
        "actions": {
            "sqlite_wal_checkpoint_truncate": checkpoints,
        },
        "reclaimed_bytes": reclaimed,
        "reclaimed_human": human_size(reclaimed),
        "diagnostics": diagnostics,
        "stop_line": "Only SQLite WAL files are checkpointed here. Do not delete raw evidence or VACUUM live graph/search stores from this route.",
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__storage-maintenance"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, storage_maintenance_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def session_storage_breakdown(aoa_root: Path) -> dict[str, Any]:
    sessions_root = aoa_root / SESSION_ROOT
    buckets = {
        "raw_session_jsonl": 0,
        "raw_blocks": 0,
        "raw_ledgers": 0,
        "segment_markdown": 0,
        "segment_indexes": 0,
        "session_companions": 0,
        "hooks_incidents_distillation": 0,
    }
    raw_block_plain_bytes = 0
    raw_block_compressed_bytes = 0
    raw_block_other_bytes = 0
    if not sessions_root.exists():
        return {"root": str(sessions_root), "exists": False, "buckets": buckets, "total_bytes": 0, "total_human": "0 B"}
    for session_dir in sessions_root.iterdir():
        if not session_dir.is_dir():
            continue
        buckets["raw_session_jsonl"] += path_total_size(session_dir / "raw" / "session.raw.jsonl")
        blocks_dir = session_dir / "raw" / "blocks"
        buckets["raw_blocks"] += path_total_size(blocks_dir)
        if blocks_dir.exists():
            for path in blocks_dir.iterdir():
                if not path.is_file():
                    continue
                size = path.stat().st_size
                if path.name.endswith(".raw.jsonl"):
                    raw_block_plain_bytes += size
                elif path.name.endswith(".raw.jsonl.gz"):
                    raw_block_compressed_bytes += size
                else:
                    raw_block_other_bytes += size
        buckets["raw_ledgers"] += path_total_size(session_dir / "raw" / "blocks.index.json")
        buckets["raw_ledgers"] += path_total_size(session_dir / "raw" / "compaction-events.jsonl")
        for path in (session_dir / "segments").glob("*.md"):
            buckets["segment_markdown"] += path_total_size(path)
        for path in (session_dir / "segments").glob("*.index.json"):
            buckets["segment_indexes"] += path_total_size(path)
        for name in ("SESSION.md", "session.index.json", "session.manifest.json", "AGENTS.md"):
            buckets["session_companions"] += path_total_size(session_dir / name)
        for name in ("hooks", "incidents", "distillation", "naming"):
            buckets["hooks_incidents_distillation"] += path_total_size(session_dir / name)
    total = sum(buckets.values())
    return {
        "root": str(sessions_root),
        "exists": True,
        "buckets": {
            key: {"size_bytes": value, "size_human": human_size(value)}
            for key, value in sorted(buckets.items())
        },
        "total_bytes": total,
        "total_human": human_size(total),
        "raw_block_storage": {
            "plain_bytes": raw_block_plain_bytes,
            "plain_human": human_size(raw_block_plain_bytes),
            "compressed_bytes": raw_block_compressed_bytes,
            "compressed_human": human_size(raw_block_compressed_bytes),
            "other_bytes": raw_block_other_bytes,
            "other_human": human_size(raw_block_other_bytes),
        },
        "raw_block_duplication_candidate_bytes": min(buckets["raw_session_jsonl"], raw_block_plain_bytes),
        "raw_block_duplication_candidate_human": human_size(min(buckets["raw_session_jsonl"], raw_block_plain_bytes)),
    }


def graph_aggregate_payload_compaction_sample(
    db_path: Path,
    *,
    sample_limit: int = 400,
) -> dict[str, Any]:
    payload: dict[str, Any] = {
        "status": "missing",
        "mutates": False,
        "sample_limit": max(1, int_value(sample_limit, 400)),
        "tables": {},
        "sample_count": 0,
        "invalid_payload_count": 0,
        "original_payload_bytes": 0,
        "compacted_payload_bytes": 0,
        "delta_bytes": 0,
        "delta_ratio": 0.0,
        "diagnostics": [],
    }
    if not db_path.exists():
        payload["diagnostics"].append("sqlite_db_missing")
        return payload
    try:
        conn = sqlite3.connect(str(db_path))
        conn.row_factory = sqlite3.Row
    except sqlite3.Error as exc:
        payload["status"] = "sqlite_error"
        payload["diagnostics"].append(sqlite_error_diagnostic(exc))
        return payload
    try:
        table_specs = (("nodes", "node"), ("edges", "edge"))
        per_table_limit = max(1, payload["sample_limit"] // len(table_specs))
        for table, kind in table_specs:
            table_payload = {
                "status": "empty",
                "sample_limit": per_table_limit,
                "rowid_max": 0,
                "sample_count": 0,
                "already_compact_count": 0,
                "invalid_payload_count": 0,
                "original_payload_bytes": 0,
                "compacted_payload_bytes": 0,
                "delta_bytes": 0,
                "delta_ratio": 0.0,
                "anchors": [],
                "diagnostics": [],
            }
            try:
                row = conn.execute(f"SELECT MAX(rowid) FROM {table}").fetchone()
                rowid_max = int_value(row[0]) if row else 0
            except sqlite3.Error as exc:
                table_payload["status"] = "sqlite_error"
                table_payload["diagnostics"].append(sqlite_error_diagnostic(exc))
                payload["diagnostics"].append(f"{table}:{sqlite_error_diagnostic(exc)}")
                payload["tables"][table] = table_payload
                continue
            table_payload["rowid_max"] = rowid_max
            if rowid_max <= 0:
                payload["tables"][table] = table_payload
                continue
            anchors = sorted({0, rowid_max // 4, rowid_max // 2, (rowid_max * 3) // 4, max(0, rowid_max - per_table_limit)})
            table_payload["anchors"] = anchors
            per_anchor_limit = max(1, per_table_limit // len(anchors))
            seen_rowids: set[int] = set()
            for anchor in anchors:
                remaining = per_table_limit - table_payload["sample_count"]
                if remaining <= 0:
                    break
                try:
                    rows = conn.execute(
                        f"SELECT rowid, payload_json FROM {table} WHERE rowid > ? ORDER BY rowid LIMIT ?",
                        (anchor, min(per_anchor_limit, remaining)),
                    ).fetchall()
                except sqlite3.Error as exc:
                    table_payload["status"] = "sqlite_error"
                    table_payload["diagnostics"].append(sqlite_error_diagnostic(exc))
                    payload["diagnostics"].append(f"{table}:{sqlite_error_diagnostic(exc)}")
                    break
                for row in rows:
                    rowid = int_value(row["rowid"])
                    if rowid in seen_rowids:
                        continue
                    seen_rowids.add(rowid)
                    payload_json = str(row["payload_json"] or "")
                    original_bytes = len(payload_json.encode("utf-8"))
                    table_payload["sample_count"] += 1
                    table_payload["original_payload_bytes"] += original_bytes
                    try:
                        row_payload = json.loads(payload_json)
                    except json.JSONDecodeError:
                        table_payload["invalid_payload_count"] += 1
                        continue
                    if not isinstance(row_payload, dict):
                        table_payload["invalid_payload_count"] += 1
                        continue
                    compacted_json = graph_json(graph_compact_aggregate_payload(row_payload, kind=kind))
                    compacted_bytes = len(compacted_json.encode("utf-8"))
                    table_payload["compacted_payload_bytes"] += compacted_bytes
                    table_payload["delta_bytes"] += max(0, original_bytes - compacted_bytes)
                    if compacted_json == payload_json:
                        table_payload["already_compact_count"] += 1
            original = int_value(table_payload["original_payload_bytes"])
            if original > 0:
                table_payload["delta_ratio"] = round(int_value(table_payload["delta_bytes"]) / original, 8)
            if table_payload["status"] != "sqlite_error":
                table_payload["status"] = "completed" if table_payload["sample_count"] else "empty"
            payload["tables"][table] = table_payload
            payload["sample_count"] += int_value(table_payload["sample_count"])
            payload["invalid_payload_count"] += int_value(table_payload["invalid_payload_count"])
            payload["original_payload_bytes"] += original
            payload["compacted_payload_bytes"] += int_value(table_payload["compacted_payload_bytes"])
            payload["delta_bytes"] += int_value(table_payload["delta_bytes"])
        if payload["original_payload_bytes"] > 0:
            payload["delta_ratio"] = round(payload["delta_bytes"] / payload["original_payload_bytes"], 8)
        if payload["sample_count"] <= 0:
            payload["status"] = "empty"
        elif payload["diagnostics"]:
            payload["status"] = "completed_with_diagnostics"
        else:
            payload["status"] = "completed"
    finally:
        conn.close()
    return payload


def graph_aggregate_payload_compaction_recommendation(
    *,
    table_sizes: dict[str, int],
    sample: dict[str, Any],
) -> dict[str, Any]:
    aggregate_table_bytes = int_value(table_sizes.get("nodes")) + int_value(table_sizes.get("edges"))
    if not table_sizes:
        return {
            "status": "implemented_for_new_rebuilds_and_touched_sources",
            "estimated_reclaimable_bytes": 0,
            "estimated_reclaimable_human": "requires --deep-dbstat",
            "estimate_status": "requires_deep_dbstat",
            "aggregate_table_size_bytes": 0,
            "aggregate_table_size_human": "requires --deep-dbstat",
            "next_route": "run storage-audit --deep-dbstat before deciding whether aggregate compaction or graph cardinality is the real weight driver",
        }
    sample_status = str(sample.get("status") or "not_requested")
    original_payload_bytes = int_value(sample.get("original_payload_bytes"))
    delta_bytes = int_value(sample.get("delta_bytes"))
    if sample_status in {"completed", "completed_with_diagnostics"} and original_payload_bytes > 0:
        delta_ratio = max(0.0, min(1.0, float(delta_bytes) / float(original_payload_bytes)))
        estimated = int(aggregate_table_bytes * delta_ratio)
        if estimated <= 0:
            return {
                "status": "already_compact_sampled_cardinality_dominates",
                "estimated_reclaimable_bytes": 0,
                "estimated_reclaimable_human": "0 B",
                "estimate_status": "sampled_no_payload_delta",
                "aggregate_table_size_bytes": aggregate_table_bytes,
                "aggregate_table_size_human": human_size(aggregate_table_bytes),
                "sample_delta_ratio": round(delta_ratio, 8),
                "next_route": "analyze graph cardinality, sharding, and query projections; do not rebuild solely for aggregate payload compaction",
            }
        return {
            "status": "sampled_payload_delta_available",
            "estimated_reclaimable_bytes": estimated,
            "estimated_reclaimable_human": human_size(estimated),
            "estimate_status": "sampled_payload_delta_ratio",
            "aggregate_table_size_bytes": aggregate_table_bytes,
            "aggregate_table_size_human": human_size(aggregate_table_bytes),
            "sample_delta_ratio": round(delta_ratio, 8),
            "next_route": "run a controlled graph-build all --write --store-only --in-place only if the sampled reclaim justifies the rebuild cost",
        }
    return {
        "status": "aggregate_payload_sample_unavailable",
        "estimated_reclaimable_bytes": 0,
        "estimated_reclaimable_human": "0 B",
        "estimate_status": f"sample_{sample_status}",
        "aggregate_table_size_bytes": aggregate_table_bytes,
        "aggregate_table_size_human": human_size(aggregate_table_bytes),
        "next_route": "fix the aggregate payload sample before using table size as a reclaim estimate; table bytes alone are cardinality evidence, not reclaimable bytes",
    }


def graph_raw_ref_materialization_recommendation(aoa_root: Path) -> dict[str, Any]:
    projection = graph_cardinality_projection_read(aoa_root, limit=80)
    counts = projection.get("counts") if isinstance(projection.get("counts"), dict) else {}
    node_counts = counts.get("node") if isinstance(counts.get("node"), dict) else {}
    edge_counts = counts.get("edge") if isinstance(counts.get("edge"), dict) else {}
    raw_ref_node_count = int_value(node_counts.get("raw_ref"))
    has_raw_ref_edge_count = int_value(edge_counts.get("has_raw_ref"))
    affected_rows = raw_ref_node_count + has_raw_ref_edge_count
    if GRAPH_MATERIALIZE_RAW_REF_NODES:
        status = "enabled"
        next_route = "evaluate whether raw_ref graph nodes are still required before disabling materialization"
    elif affected_rows:
        status = "disabled_for_new_builds_existing_store_mixed"
        next_route = "run graph-raw-ref-prune --apply --write-report to prune generated rows; physical graph.sqlite3 shrink still requires controlled VACUUM or rebuild with reserved disk"
    else:
        status = "disabled_for_new_builds_no_materialized_raw_ref_nodes"
        next_route = "no raw_ref graph-node compaction is needed; keep raw refs in event evidence packets"
    return {
        "status": status,
        "policy": GRAPH_RAW_REF_MATERIALIZATION_POLICY,
        "materialize_raw_ref_nodes": GRAPH_MATERIALIZE_RAW_REF_NODES,
        "raw_ref_node_count": raw_ref_node_count,
        "has_raw_ref_edge_count": has_raw_ref_edge_count,
        "affected_row_count": affected_rows,
        "estimate_status": "cardinality_only_rebuild_or_vacuum_required",
        "estimated_reclaimable_bytes": 0,
        "estimated_reclaimable_human": "requires controlled rebuild/prune",
        "quality_tradeoff": "none_expected; raw refs remain in event evidence refs and raw/segment/session authority stays unchanged",
        "speed_tradeoff": "smaller future graph stores; graph packets hydrate raw refs from event evidence instead of traversing raw_ref nodes",
        "projection_status": projection.get("status"),
        "next_route": next_route,
    }


def graph_event_sequence_projection_recommendation(
    *,
    aoa_root: Path,
    graph_store: dict[str, Any],
    table_sizes: dict[str, int],
) -> dict[str, Any]:
    projection = graph_cardinality_projection_read(aoa_root, limit=80)
    counts = projection.get("counts") if isinstance(projection.get("counts"), dict) else {}
    edge_counts = counts.get("edge") if isinstance(counts.get("edge"), dict) else {}
    omitted_types = sorted(GRAPH_EVENT_RELATIONSHIP_EDGE_OMIT_TYPES)
    sequence_edge_count = sum(int_value(edge_counts.get(edge_type)) for edge_type in omitted_types)
    total_edge_count = sum(int_value(value) for value in edge_counts.values())
    row_counts = graph_store.get("row_counts") if isinstance(graph_store.get("row_counts"), dict) else {}
    stored_edge_rows = int_value(row_counts.get("edges"), total_edge_count)
    stored_edge_contrib_rows = int_value(row_counts.get("edge_contribs"))
    edge_storage_bytes = sum(
        int_value(table_sizes.get(name))
        for name in (
            "edges",
            "edge_contribs",
            "sqlite_autoindex_edges_1",
            "sqlite_autoindex_edge_contribs_1",
            "idx_edges_source",
            "idx_edges_target",
            "idx_edge_contribs_edge",
        )
    )
    cardinality_denominator = max(total_edge_count, stored_edge_rows, 1)
    estimated_bytes = int(edge_storage_bytes * (sequence_edge_count / cardinality_denominator)) if sequence_edge_count > 0 and edge_storage_bytes > 0 else 0
    if str(projection.get("status") or "") != "current":
        status = "requires_cardinality_projection"
        next_route = "run graph-cardinality --refresh before estimating sequence-edge pressure"
    elif sequence_edge_count > 0:
        status = "policy_applied_after_rebuild_existing_store_mixed"
        next_route = "run graph-event-sequence-prune --apply --write-report, then maintenance-status and graph-cardinality --refresh; physical shrink still requires rebuild or VACUUM"
    else:
        status = "policy_already_applied_no_sequence_edges"
        next_route = "no sequence-edge graph cardinality action is needed"
    return {
        "status": status,
        "policy": GRAPH_EVENT_RELATIONSHIP_EDGE_POLICY,
        "omitted_edge_types": omitted_types,
        "sequence_edge_count": sequence_edge_count,
        "total_edge_count": total_edge_count,
        "stored_edge_rows": stored_edge_rows,
        "stored_edge_contrib_rows": stored_edge_contrib_rows,
        "edge_storage_bytes": edge_storage_bytes,
        "edge_storage_human": human_size(edge_storage_bytes),
        "estimated_reclaimable_bytes": estimated_bytes,
        "estimated_reclaimable_human": human_size(estimated_bytes) if estimated_bytes else "requires controlled rebuild/prune",
        "estimate_status": "cardinality_ratio_estimate" if estimated_bytes else "cardinality_only_rebuild_or_vacuum_required",
        "quality_tradeoff": "none_expected; linear event order remains in segment indexes and raw/session evidence, while graph keeps causal/correlation edges",
        "speed_tradeoff": "smaller graph neighborhoods and faster graph-store scans after generated rows are rebuilt or pruned",
        "projection_status": projection.get("status"),
        "next_route": next_route,
    }


def search_sqlite_physical_compaction_recommendation(plan: dict[str, Any]) -> dict[str, Any]:
    reclaimable = int_value(plan.get("conservative_reclaimable_bytes"))
    db_bytes = int_value(plan.get("db_bytes"))
    reclaim_ratio = round(reclaimable / db_bytes, 6) if db_bytes > 0 else 0.0
    status = str(plan.get("status") or "unknown")
    if plan.get("ok") and reclaimable <= 128 * 1024 * 1024:
        status = "low_reclaim_not_primary"
        next_route = "keep search-sqlite-compact as a safe route after large generated-store rewrites; current reclaim is too small to treat physical compaction as the search weight fix"
    elif plan.get("ok") and reclaim_ratio < 0.05:
        status = "low_reclaim_not_primary"
        next_route = "prefer search-index bounded raw lexical policy, shard policy, and route benchmarks before physical SQLite compaction; current freelist reclaim is small"
    elif plan.get("apply_ready"):
        next_route = "run search-sqlite-compact --write-report for a read-only plan; use --apply --method vacuum-into --target-path with optional --promote-copy and --delete-backup-after-verify only when disk headroom is sufficient"
    else:
        next_route = "fix search SQLite compaction preflight diagnostics before using physical compaction as a pressure route"
    return {
        "status": status,
        "quality_tradeoff": "none_expected_for_vacuum_into_copy; raw/session evidence is untouched and live replacement requires --promote-copy integrity checks",
        "speed_tradeoff": "manual-bulk SQLite copy/rewrite; not an interactive query path",
        "estimated_reclaimable_bytes": reclaimable,
        "estimated_reclaimable_human": plan.get("conservative_reclaimable_human"),
        "reclaim_ratio": reclaim_ratio,
        "required_free_human": plan.get("required_free_human"),
        "free_human": plan.get("free_human"),
        "min_free_after_human": plan.get("min_free_after_human"),
        "apply_ready": plan.get("apply_ready"),
        "next_route": next_route,
    }


def search_raw_text_fallback_dependency_recommendation(packet: dict[str, Any]) -> dict[str, Any]:
    status = str(packet.get("status") or "unknown")
    if status == "shard_full_text_ready":
        recommendation_status = "scoped_full_text_ready"
        next_route = "raw-text shard fan-out is available for materialized shard scope; keep monolith as generated fallback until broader route benchmarks justify removal"
    elif status == "monolith_required_for_raw_text_query":
        recommendation_status = "controlled_monolith_dependency"
        next_route = str(packet.get("next_route") or "use scoped full-text shard materialization for repeated literal raw-text work")
    elif status == "no_shards":
        recommendation_status = "requires_shard_materialization"
        next_route = "run search-shards all --write-report before evaluating raw-text shard fallback dependency"
    else:
        recommendation_status = "mixed_projection_review"
        next_route = str(packet.get("next_route") or "refresh search catalog and inspect shard raw-text support")
    return {
        "status": recommendation_status,
        "raw_text_fallback_status": status,
        "quality_tradeoff": packet.get("quality_tradeoff"),
        "speed_tradeoff": "structured routes stay fast and slim; literal raw-text queries use monolith fallback unless scoped full-text shards are materialized",
        "weight_tradeoff": packet.get("weight_tradeoff"),
        "estimated_reclaimable_bytes": 0,
        "estimated_reclaimable_human": "0 B",
        "estimate_status": "route_dependency_not_reclaim_estimate",
        "unsupported_shard_count": packet.get("unsupported_shard_count"),
        "structured_only_shard_count": packet.get("structured_only_shard_count"),
        "full_text_shard_count": packet.get("full_text_shard_count"),
        "scoped_full_text_next_commands": packet.get("scoped_full_text_next_commands"),
        "global_full_text_next_command": packet.get("global_full_text_next_command"),
        "next_route": next_route,
    }


def storage_audit(
    *,
    aoa_root: Path,
    deep_dbstat: bool = False,
    row_counts: bool = False,
    write_report: bool = False,
) -> dict[str, Any]:
    now = utc_now()
    graph_paths_payload = graph_paths(aoa_root)
    search_path = search_db_path(aoa_root)
    top_level = [
        storage_size_entry(aoa_root / name, label=name)
        for name in ("sessions", "graph", "search", "maps", "diagnostics")
    ]
    top_total = storage_size_entry(aoa_root, label=".aoa")
    graph_store = sqlite_storage_stats(graph_paths_payload["store"], deep=deep_dbstat, row_counts=row_counts)
    search_store = sqlite_storage_stats(search_path, deep=deep_dbstat, row_counts=row_counts)
    if deep_dbstat:
        graph_store["aggregate_payload_compaction_sample"] = graph_aggregate_payload_compaction_sample(graph_paths_payload["store"])
    sessions = session_storage_breakdown(aoa_root)
    raw_block_reclaim_bytes = int_value(sessions.get("raw_block_duplication_candidate_bytes"))
    search_raw_lexical_policy = (
        search_store.get("raw_lexical_policy")
        if isinstance(search_store.get("raw_lexical_policy"), dict)
        else {}
    )
    search_policy_status = search_raw_lexical_policy_status(search_raw_lexical_policy)
    table_sizes = {
        item.get("name"): int_value(item.get("size_bytes"))
        for item in graph_store.get("table_sizes", []) if isinstance(item, dict)
    }
    graph_compaction = graph_aggregate_payload_compaction_recommendation(
        table_sizes=table_sizes,
        sample=graph_store.get("aggregate_payload_compaction_sample") if isinstance(graph_store.get("aggregate_payload_compaction_sample"), dict) else {},
    )
    raw_ref_materialization = graph_raw_ref_materialization_recommendation(aoa_root)
    event_sequence_projection = graph_event_sequence_projection_recommendation(
        aoa_root=aoa_root,
        graph_store=graph_store,
        table_sizes=table_sizes,
    )
    graph_sqlite_plan = sqlite_vacuum_headroom_plan(
        db_path=graph_paths_payload["store"],
        method="vacuum-into",
        target_path=aoa_root / DIAGNOSTICS_ROOT / "graph.sqlite3.vacuum-copy",
        min_free_after_gb=GRAPH_SQLITE_COMPACT_DEFAULT_MIN_FREE_AFTER_GB,
    )
    search_sqlite_plan = sqlite_vacuum_headroom_plan(
        db_path=search_path,
        method="vacuum-into",
        target_path=aoa_root / DIAGNOSTICS_ROOT / "aoa-search.sqlite3.vacuum-copy",
        min_free_after_gb=SEARCH_SQLITE_COMPACT_DEFAULT_MIN_FREE_AFTER_GB,
    )
    search_shard_projection = session_memory_search_shard_projection_summary(aoa_root)
    search_raw_text_fallback = (
        search_shard_projection.get("raw_text_fallback_dependency")
        if isinstance(search_shard_projection.get("raw_text_fallback_dependency"), dict)
        else search_raw_text_fallback_route_packet(aoa_root=aoa_root)
    )
    sqlite_wal_reclaimable = int_value(graph_store.get("wal", {}).get("size_bytes") if isinstance(graph_store.get("wal"), dict) else 0) + int_value(
        search_store.get("wal", {}).get("size_bytes") if isinstance(search_store.get("wal"), dict) else 0
    )
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_storage_audit",
        "generated_at": now,
        "ok": True,
        "mutates": False,
        "aoa_root": str(aoa_root),
        "deep_dbstat": deep_dbstat,
        "row_counts": row_counts,
        "total": top_total,
        "top_level": top_level,
        "sessions": sessions,
        "graph_store": graph_store,
        "search_store": search_store,
        "recommendations": [
            {
                "id": "sqlite_wal_checkpoint",
                "status": "safe_live_route",
                "quality_tradeoff": "none_expected",
                "speed_tradeoff": "brief SQLite checkpoint lock; defers safely when readers or writers are active",
                "estimated_reclaimable_bytes": sqlite_wal_reclaimable,
                "estimated_reclaimable_human": human_size(sqlite_wal_reclaimable),
                "next_route": "run storage-maintenance --write-report to checkpoint graph/search WAL files",
            },
            {
                "id": "graph_compact_aggregate_payload",
                "status": graph_compaction["status"],
                "quality_tradeoff": "none_expected",
                "speed_tradeoff": "bounded graph packets hydrate refs on demand from contribution rows",
                "estimated_reclaimable_bytes": graph_compaction["estimated_reclaimable_bytes"],
                "estimated_reclaimable_human": graph_compaction["estimated_reclaimable_human"],
                "estimate_status": graph_compaction["estimate_status"],
                "aggregate_table_size_bytes": graph_compaction["aggregate_table_size_bytes"],
                "aggregate_table_size_human": graph_compaction["aggregate_table_size_human"],
                "sample_delta_ratio": graph_compaction.get("sample_delta_ratio"),
                "next_route": graph_compaction["next_route"],
            },
            {
                "id": "graph_event_sequence_edge_projection",
                "status": event_sequence_projection["status"],
                "quality_tradeoff": event_sequence_projection["quality_tradeoff"],
                "speed_tradeoff": event_sequence_projection["speed_tradeoff"],
                "policy": event_sequence_projection["policy"],
                "omitted_edge_types": event_sequence_projection["omitted_edge_types"],
                "sequence_edge_count": event_sequence_projection["sequence_edge_count"],
                "total_edge_count": event_sequence_projection["total_edge_count"],
                "stored_edge_rows": event_sequence_projection["stored_edge_rows"],
                "stored_edge_contrib_rows": event_sequence_projection["stored_edge_contrib_rows"],
                "edge_storage_bytes": event_sequence_projection["edge_storage_bytes"],
                "edge_storage_human": event_sequence_projection["edge_storage_human"],
                "estimated_reclaimable_bytes": event_sequence_projection["estimated_reclaimable_bytes"],
                "estimated_reclaimable_human": event_sequence_projection["estimated_reclaimable_human"],
                "estimate_status": event_sequence_projection["estimate_status"],
                "projection_status": event_sequence_projection["projection_status"],
                "next_route": event_sequence_projection["next_route"],
            },
            {
                "id": "graph_raw_ref_materialization_policy",
                "status": raw_ref_materialization["status"],
                "quality_tradeoff": raw_ref_materialization["quality_tradeoff"],
                "speed_tradeoff": raw_ref_materialization["speed_tradeoff"],
                "policy": raw_ref_materialization["policy"],
                "materialize_raw_ref_nodes": raw_ref_materialization["materialize_raw_ref_nodes"],
                "raw_ref_node_count": raw_ref_materialization["raw_ref_node_count"],
                "has_raw_ref_edge_count": raw_ref_materialization["has_raw_ref_edge_count"],
                "affected_row_count": raw_ref_materialization["affected_row_count"],
                "estimated_reclaimable_bytes": raw_ref_materialization["estimated_reclaimable_bytes"],
                "estimated_reclaimable_human": raw_ref_materialization["estimated_reclaimable_human"],
                "estimate_status": raw_ref_materialization["estimate_status"],
                "next_route": raw_ref_materialization["next_route"],
            },
            {
                "id": "graph_sqlite_physical_compaction",
                "status": graph_sqlite_plan["status"],
                "quality_tradeoff": "none_expected_for_vacuum_into_copy; raw/session evidence is untouched and live replacement requires --promote-copy integrity checks",
                "speed_tradeoff": "manual-bulk SQLite copy/rewrite; not an interactive query path",
                "estimated_reclaimable_bytes": graph_sqlite_plan["conservative_reclaimable_bytes"],
                "estimated_reclaimable_human": graph_sqlite_plan["conservative_reclaimable_human"],
                "required_free_human": graph_sqlite_plan["required_free_human"],
                "free_human": graph_sqlite_plan["free_human"],
                "min_free_after_human": graph_sqlite_plan["min_free_after_human"],
                "apply_ready": graph_sqlite_plan["apply_ready"],
                "next_route": "run graph-sqlite-compact --write-report for a read-only plan; use --apply --method vacuum-into --target-path with optional --promote-copy and --delete-backup-after-verify only when disk headroom is sufficient",
            },
            {"id": "search_sqlite_physical_compaction", **search_sqlite_physical_compaction_recommendation(search_sqlite_plan)},
            {
                "id": "search_raw_text_fallback_dependency",
                **search_raw_text_fallback_dependency_recommendation(search_raw_text_fallback),
            },
            {
                "id": "raw_block_offset_or_compressed_store",
                "status": "current_no_plain_duplicates" if raw_block_reclaim_bytes == 0 else "planned_safe_route",
                "quality_tradeoff": "none_if_raw refs and readers support offset/compressed blocks before cleanup",
                "estimated_reclaimable_bytes": raw_block_reclaim_bytes,
                "estimated_reclaimable_human": sessions.get("raw_block_duplication_candidate_human", "0 B"),
                "next_route": (
                    "none for plaintext raw-block duplicates; keep raw-block-ref-audit in storage verification and monitor compressed sidecar weight"
                    if raw_block_reclaim_bytes == 0
                    else "run raw-block-ref-audit all --limit 20 --sample-limit 80 --write-report, then raw-block-storage-compact all --skip-no-plain --limit 20 --estimate-compression --write-report before any apply"
                ),
            },
            {
                "id": "search_hot_store_v3",
                "status": search_policy_status,
                "quality_tradeoff": "none_expected; FTS keeps searchable text, compressed bodies hydrate snippets, full route postings stay normalized while hot rows keep bounded route previews and compact payload deltas",
                "raw_lexical_policy": search_raw_lexical_policy,
                "estimated_reclaimable_bytes": 0,
                "estimated_reclaimable_human": "0 B",
                "estimate_status": "requires_bounded_rebuild_benchmark" if search_policy_status != "bounded_policy_recorded" else "bounded_policy_recorded_residual_not_estimated",
                "next_route": "run search-index all with the bounded default raw lexical policy and compare storage-audit plus route-performance-baseline before considering deeper FTS sharding",
            },
        ],
        "stop_line": "Do not delete raw evidence. Prefer compact generated stores, offset refs, and rebuildable caches.",
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__storage-audit"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, storage_audit_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def storage_audit_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Session Memory Storage Audit",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- aoa_root: `{payload.get('aoa_root')}`",
        f"- total: `{(payload.get('total') or {}).get('size_human') if isinstance(payload.get('total'), dict) else ''}`",
        f"- deep_dbstat: `{payload.get('deep_dbstat')}`",
        f"- row_counts: `{payload.get('row_counts')}`",
        "",
        "## Top Level",
        "",
        "| layer | size | path |",
        "| --- | ---: | --- |",
    ]
    for item in payload.get("top_level", []) if isinstance(payload.get("top_level"), list) else []:
        if isinstance(item, dict):
            lines.append(f"| `{item.get('label')}` | `{item.get('size_human')}` | `{item.get('path')}` |")
    sessions = payload.get("sessions") if isinstance(payload.get("sessions"), dict) else {}
    if sessions:
        lines.extend(["", "## Sessions", "", "| bucket | size |", "| --- | ---: |"])
        for key, item in (sessions.get("buckets") or {}).items() if isinstance(sessions.get("buckets"), dict) else []:
            if isinstance(item, dict):
                lines.append(f"| `{key}` | `{item.get('size_human')}` |")
        raw_block_storage = sessions.get("raw_block_storage") if isinstance(sessions.get("raw_block_storage"), dict) else {}
        if raw_block_storage:
            lines.extend(
                [
                    "",
                    "### Raw Block Storage",
                    "",
                    f"- plaintext_duplicate: `{raw_block_storage.get('plain_human')}`",
                    f"- compressed_sidecars: `{raw_block_storage.get('compressed_human')}`",
                    f"- other: `{raw_block_storage.get('other_human')}`",
                    f"- remaining_duplication_candidate: `{sessions.get('raw_block_duplication_candidate_human')}`",
                ]
            )
    for key in ("graph_store", "search_store"):
        store = payload.get(key) if isinstance(payload.get(key), dict) else {}
        if not store:
            continue
        wal = store.get("wal") if isinstance(store.get("wal"), dict) else {}
        lines.extend(
            [
                "",
                f"## {key}",
                "",
                f"- size: `{store.get('size_human')}`",
                f"- freelist: `{store.get('freelist_human')}`",
                f"- wal: `{wal.get('size_human')}`",
                f"- total_with_wal: `{store.get('total_with_wal_human')}`",
                f"- deep_dbstat_status: `{store.get('deep_dbstat_status')}`",
                f"- row_count_status: `{store.get('row_count_status')}`",
            ]
        )
        metadata = store.get("metadata") if isinstance(store.get("metadata"), dict) else {}
        if metadata:
            lines.extend(["", "| metadata | value |", "| --- | --- |"])
            for meta_key, meta_value in sorted(metadata.items()):
                lines.append(f"| `{meta_key}` | `{meta_value}` |")
        table_sizes = store.get("table_sizes") if isinstance(store.get("table_sizes"), list) else []
        if table_sizes:
            lines.extend(["", "| table | size |", "| --- | ---: |"])
            for item in table_sizes:
                if isinstance(item, dict):
                    lines.append(f"| `{item.get('name')}` | `{item.get('size_human')}` |")
        aggregate_sample = store.get("aggregate_payload_compaction_sample") if isinstance(store.get("aggregate_payload_compaction_sample"), dict) else {}
        if aggregate_sample:
            lines.extend(
                [
                    "",
                    "### Aggregate Payload Compaction Sample",
                    "",
                    f"- status: `{aggregate_sample.get('status')}`",
                    f"- sample_count: `{aggregate_sample.get('sample_count')}`",
                    f"- delta: `{human_size(int_value(aggregate_sample.get('delta_bytes')))}`",
                    f"- delta_ratio: `{aggregate_sample.get('delta_ratio')}`",
                ]
            )
    lines.extend(["", "## Recommendations", "", "| id | status | estimated reclaimable | next route |", "| --- | --- | ---: | --- |"])
    for item in payload.get("recommendations", []) if isinstance(payload.get("recommendations"), list) else []:
        if isinstance(item, dict):
            lines.append(f"| `{item.get('id')}` | `{item.get('status')}` | `{item.get('estimated_reclaimable_human')}` | {item.get('next_route')} |")
    lines.append("")
    return "\n".join(lines)


def storage_maintenance_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Session Memory Storage Maintenance",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- status: `{payload.get('status')}`",
        f"- mutates: `{payload.get('mutates')}`",
        f"- reclaimed: `{payload.get('reclaimed_human')}`",
        f"- stop_line: `{payload.get('stop_line')}`",
        "",
        "## WAL Checkpoints",
        "",
        "| target | status | reclaimed | diagnostics |",
        "| --- | --- | ---: | --- |",
    ]
    actions = payload.get("actions") if isinstance(payload.get("actions"), dict) else {}
    checkpoints = actions.get("sqlite_wal_checkpoint_truncate") if isinstance(actions.get("sqlite_wal_checkpoint_truncate"), dict) else {}
    for name, item in checkpoints.items():
        if not isinstance(item, dict):
            continue
        diagnostics = ", ".join(str(value) for value in item.get("diagnostics", []) if value) if isinstance(item.get("diagnostics"), list) else ""
        lines.append(f"| `{name}` | `{item.get('status')}` | `{item.get('reclaimed_human')}` | {diagnostics or 'none'} |")
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        lines.extend(f"- `{item}`" for item in diagnostics)
    lines.append("")
    return "\n".join(lines)


def load_session_graph(aoa_root: Path, *, allow_ephemeral: bool = True) -> dict[str, Any]:
    paths = graph_paths(aoa_root)
    index = read_json(paths["index"], {})
    if paths["nodes"].exists() and paths["edges"].exists() and isinstance(index, dict) and index:
        nodes, node_diagnostics = read_jsonl_records(paths["nodes"])
        edges, edge_diagnostics = read_jsonl_records(paths["edges"])
        payload = dict(index)
        payload.update(
            {
                "ok": bool(nodes) and not node_diagnostics and not edge_diagnostics,
                "source": "sidecar",
                "nodes": nodes,
                "edges": edges,
                "diagnostics": list(index.get("diagnostics", [])) + node_diagnostics + edge_diagnostics,
            }
        )
        return payload
    if allow_ephemeral:
        payload = build_session_graph(aoa_root=aoa_root, write=False, include_rows=True)
        payload["source"] = "ephemeral_from_session_indexes"
        payload.setdefault("diagnostics", []).append("graph sidecar missing; built read-only ephemeral graph")
        return payload
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_index",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "ok": False,
        "source": "missing",
        "nodes": [],
        "edges": [],
        "diagnostics": ["graph sidecar missing; run graph-build --write outside read-only MCP"],
    }


def search_index_generated_at(aoa_root: Path) -> str:
    db_path = search_db_path(aoa_root)
    if not db_path.exists():
        return ""
    try:
        conn = sqlite3.connect(str(db_path))
        row = conn.execute("SELECT value FROM meta WHERE key = ?", ("generated_at",)).fetchone()
        conn.close()
    except sqlite3.Error:
        return ""
    return str(row[0] or "") if row else ""


def graph_freshness(aoa_root: Path, graph: dict[str, Any]) -> dict[str, Any]:
    search_generated_at = search_index_generated_at(aoa_root)
    graph_generated_at = str(graph.get("generated_at") or "")
    source = str(graph.get("source") or "")
    if source.startswith("ephemeral"):
        status = "ephemeral_current"
    elif source.startswith("bounded"):
        status = "bounded_current"
    elif source.startswith("sqlite_graph_store"):
        status = "graph_store_current"
    elif graph_generated_at:
        status = "fresh"
    else:
        status = "unverifiable"
    payload = {
        "status": status,
        "graph_source": source,
        "graph_generated_at": graph_generated_at,
        "search_index_generated_at": search_generated_at,
        "law": "freshness is a routing check; raw/segment refs remain stronger than graph packets",
    }
    if source.startswith("sqlite_graph_store"):
        try:
            hot_state = graph_store_hot_state(aoa_root)
            hot_status = graph_maintenance_status_from_state(
                hot_state,
                workspace_root=aoa_root.parent,
                aoa_root=aoa_root,
            )
            hot_diagnostics = (
                [str(item) for item in hot_state.get("diagnostics", []) if item]
                if isinstance(hot_state.get("diagnostics"), list)
                else []
            )
            payload.update(
                {
                    "hot_gate_status": hot_state.get("status"),
                    "needs_maintenance": bool(hot_state.get("needs_maintenance")),
                    "needs_full_rebuild": bool(hot_state.get("needs_full_rebuild")),
                    "actionable_graph_source_count": hot_status.get("actionable_count"),
                    "queued_graph_source_count": hot_status.get("queued_count"),
                    "deferred_live_source_count": hot_status.get("deferred_live_source_count"),
                    "ledger_store_missing_count": hot_status.get("ledger_store_missing_count"),
                    "latest_maintenance_remaining_count": hot_status.get("latest_maintenance_remaining_count"),
                    "latest_queue_maintenance_remaining_count": (
                        hot_status.get("latest_queue_maintenance", {}).get("remaining_count")
                        if isinstance(hot_status.get("latest_queue_maintenance"), dict)
                        else None
                    ),
                    "latest_queue_maintenance_selected_count": (
                        hot_status.get("latest_queue_maintenance", {}).get("selected_count")
                        if isinstance(hot_status.get("latest_queue_maintenance"), dict)
                        else None
                    ),
                    "latest_queue_maintenance_elapsed_ms": (
                        hot_status.get("latest_queue_maintenance", {}).get("elapsed_ms")
                        if isinstance(hot_status.get("latest_queue_maintenance"), dict)
                        else None
                    ),
                    "hot_gate_diagnostics": hot_diagnostics,
                    "maintenance_recommendation": hot_status.get("maintenance_recommendation", {}),
                }
            )
            if hot_state.get("needs_maintenance") or hot_state.get("needs_full_rebuild") or hot_diagnostics:
                payload["status"] = "graph_store_stale"
                payload["warning"] = "graph store has stale or incomplete hot-gate state; use graph packet as partial topology and verify through raw/segment refs"
        except Exception as exc:
            payload.update(
                {
                    "status": "graph_store_freshness_unverified",
                    "hot_gate_status": "unavailable",
                    "hot_gate_diagnostics": [f"graph_hot_gate_check_failed:{type(exc).__name__}"],
                }
            )
    return payload


def graph_store_query_state(aoa_root: Path) -> dict[str, Any]:
    paths = graph_paths(aoa_root)
    if not paths["store"].exists():
        return {
            "status": "missing",
            "db_path": str(paths["store"]),
            "metadata": {},
            "diagnostics": ["graph_store_missing"],
        }
    try:
        conn = sqlite3.connect(str(paths["store"]))
        conn.row_factory = sqlite3.Row
        metadata = {str(row["key"]): str(row["value"]) for row in conn.execute("SELECT key, value FROM metadata").fetchall()}
        has_nodes = conn.execute("SELECT 1 FROM nodes LIMIT 1").fetchone() is not None
        has_edges = conn.execute("SELECT 1 FROM edges LIMIT 1").fetchone() is not None
        conn.close()
    except sqlite3.Error as exc:
        return {
            "status": "sqlite_error",
            "db_path": str(paths["store"]),
            "metadata": {},
            "diagnostics": [f"graph_store_sqlite_error:{exc}"],
        }
    reasons: list[str] = []
    if int_value(metadata.get("graph_store_schema_version")) != GRAPH_STORE_SCHEMA_VERSION:
        reasons.append("graph_store_schema_mismatch")
    if int_value(metadata.get("graph_schema_version")) != GRAPH_SCHEMA_VERSION:
        reasons.append("graph_schema_mismatch")
    if not has_nodes:
        reasons.append("graph_store_nodes_empty")
    if not has_edges:
        reasons.append("graph_store_edges_empty")
    return {
        "status": "current" if not reasons else "stale",
        "db_path": str(paths["store"]),
        "db_mtime": path_mtime(paths["store"]),
        "metadata": metadata,
        "reasons": reasons,
        "diagnostics": [],
        "query_scope": "lightweight_store_availability_not_full_dirty_audit",
    }


def graph_cardinality_projection_read(aoa_root: Path, *, limit: int = 40) -> dict[str, Any]:
    paths = graph_paths(aoa_root)
    bounded_limit = max(1, min(int_value(limit, 40), 200))
    if not paths["store"].exists():
        return {
            "status": "missing",
            "mutates": False,
            "db_path": str(paths["store"]),
            "counts": {"node": {}, "edge": {}},
            "top": {"node": [], "edge": []},
            "diagnostics": ["graph_store_missing"],
        }
    try:
        conn = sqlite3.connect(f"{paths['store'].resolve().as_uri()}?mode=ro", uri=True)
        conn.row_factory = sqlite3.Row
        try:
            table_exists = conn.execute(
                "SELECT 1 FROM sqlite_master WHERE type = 'table' AND name = 'graph_type_counts' LIMIT 1"
            ).fetchone() is not None
            if not table_exists:
                return {
                    "status": "projection_missing",
                    "mutates": False,
                    "db_path": str(paths["store"]),
                    "counts": {"node": {}, "edge": {}},
                    "top": {"node": [], "edge": []},
                    "diagnostics": ["graph_type_counts_projection_missing"],
                }
            metadata = {str(row["key"]): str(row["value"]) for row in conn.execute("SELECT key, value FROM metadata").fetchall()}
            counts: dict[str, dict[str, int]] = {}
            top: dict[str, list[dict[str, Any]]] = {}
            for kind in ("node", "edge"):
                rows = conn.execute(
                    "SELECT type, count FROM graph_type_counts WHERE kind = ? ORDER BY type",
                    (kind,),
                ).fetchall()
                counts[kind] = {str(row["type"] or "unknown"): int_value(row["count"]) for row in rows}
                top[kind] = [
                    {"type": str(row["type"] or "unknown"), "count": int_value(row["count"])}
                    for row in conn.execute(
                        "SELECT type, count FROM graph_type_counts WHERE kind = ? ORDER BY count DESC, type LIMIT ?",
                        (kind, bounded_limit),
                    ).fetchall()
                ]
            row = conn.execute("SELECT COUNT(*) FROM graph_type_counts").fetchone()
            row_count = int_value(row[0]) if row else 0
        finally:
            conn.close()
    except sqlite3.Error as exc:
        return {
            "status": "sqlite_error",
            "mutates": False,
            "db_path": str(paths["store"]),
            "counts": {"node": {}, "edge": {}},
            "top": {"node": [], "edge": []},
            "diagnostics": [sqlite_error_diagnostic(exc)],
        }
    status = "current" if str(metadata.get("graph_type_counts_status") or "") == "current" and row_count > 0 else "projection_missing"
    return {
        "status": status,
        "mutates": False,
        "db_path": str(paths["store"]),
        "row_count": row_count,
        "generated_at": metadata.get("graph_type_counts_generated_at", ""),
        "updated_at": metadata.get("graph_type_counts_updated_at", ""),
        "graph_updated_at": metadata.get("graph_type_counts_graph_updated_at", ""),
        "metadata": metadata,
        "counts": counts,
        "top": top,
        "diagnostics": [] if status == "current" else ["graph_type_counts_projection_missing"],
    }


def graph_cardinality(
    *,
    aoa_root: Path,
    refresh: bool = False,
    limit: int = 40,
) -> dict[str, Any]:
    started_at = time.monotonic()
    graph_state = graph_store_query_state(aoa_root)
    projection: dict[str, Any]
    mutates = bool(refresh)
    refresh_result: dict[str, Any] = {}
    if refresh:
        if graph_state.get("status") == "missing":
            projection = {
                "status": "missing",
                "mutates": False,
                "db_path": str(graph_paths(aoa_root)["store"]),
                "counts": {"node": {}, "edge": {}},
                "top": {"node": [], "edge": []},
                "diagnostics": ["graph_store_missing"],
            }
        else:
            store = GraphSqliteStore(aoa_root)
            try:
                projection = store.refresh_type_counts(limit=limit)
                refresh_result = {
                    "state_counts": store.state_counts(),
                    "metadata": {
                        key: store.metadata().get(key)
                        for key in (
                            "graph_type_counts_status",
                            "graph_type_counts_generated_at",
                            "graph_type_counts_updated_at",
                            "graph_type_counts_graph_updated_at",
                        )
                    },
                }
            finally:
                store.close()
    else:
        projection = graph_cardinality_projection_read(aoa_root, limit=limit)
    node_total = sum(int_value(value) for value in (projection.get("counts", {}).get("node", {}) if isinstance(projection.get("counts"), dict) else {}).values())
    edge_total = sum(int_value(value) for value in (projection.get("counts", {}).get("edge", {}) if isinstance(projection.get("counts"), dict) else {}).values())
    diagnostics = projection.get("diagnostics") if isinstance(projection.get("diagnostics"), list) else []
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_cardinality",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "graph_event_route_signal_edge_policy": GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
        "generated_at": utc_now(),
        "ok": str(projection.get("status") or "") == "current",
        "mutates": mutates,
        "refresh": refresh,
        "aoa_root": str(aoa_root),
        "graph_state": graph_state,
        "projection": projection,
        "node_count": node_total,
        "edge_count": edge_total,
        "top_node_types": (projection.get("top", {}) or {}).get("node", []) if isinstance(projection.get("top"), dict) else [],
        "top_edge_types": (projection.get("top", {}) or {}).get("edge", []) if isinstance(projection.get("top"), dict) else [],
        "refresh_result": refresh_result,
        "elapsed_ms": int((time.monotonic() - started_at) * 1000),
        "diagnostics": diagnostics,
        "next_route": (
            "use projection counts for graph size/cardinality questions"
            if str(projection.get("status") or "") == "current"
            else "run graph-cardinality --refresh through the heavy resource lane to materialize graph type counts"
        ),
    }
    if not payload["ok"]:
        payload["exact_next_command"] = (
            f"python3 scripts/aoa_session_memory.py graph-cardinality "
            f"--workspace-root {aoa_root.parent} --aoa-root {aoa_root} --refresh"
        )
    return payload


def graph_high_fanout_edge_policy_row(
    *,
    aoa_root: Path,
    edge_type: str,
    count: int,
    edge_total: int,
) -> dict[str, Any]:
    share = round(count / edge_total, 6) if edge_total > 0 else 0.0
    base = {
        "edge_type": edge_type,
        "count": count,
        "share": share,
        "high_fanout": count >= OPS_GRAPH_HIGH_FANOUT_EDGE_WARNING_COUNT,
        "can_prune_now": False,
        "replacement_required_before_prune": True,
        "authority_boundary": "graph edges are generated topology; raw/segment refs and owner source surfaces remain stronger",
    }
    if edge_type == "mentions_route_signal":
        return {
            **base,
            "class": "event_route_signal_fanout",
            "current_policy": GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
            "mitigation_status": "bounded_event_route_edges_with_segment_summary_replacement",
            "replacement_layers": ["segment_has_route_signal", "session_has_route_signal"],
            "compact_query_route": "graph-cooccurrence",
            "next_route": "Use graph-cooccurrence for dense operational anchors; rebuild stale graph sources only if this policy is missing from generated sources.",
            "example_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-cooccurrence <anchor> --aoa-root {aoa_root} --kind <kind> --limit 30",
        }
    if edge_type == "event_mentions_registered_entity":
        return {
            **base,
            "class": "event_registered_entity_fanout",
            "current_policy": GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
            "mitigation_status": "bounded_event_entity_edges_preserve_usage_refs",
            "replacement_layers": ["session_has_registered_entity", "usage-chain"],
            "compact_query_route": "usage-chain",
            "next_route": "Keep event-level refs for entity usage; reduce only after a usage/rollup replacement preserves consequence and raw/segment refs.",
            "example_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} usage-chain <anchor> --aoa-root {aoa_root} --kind <kind>",
        }
    if edge_type in {"segment_has_route_signal", "session_has_route_signal", "session_has_registered_entity"}:
        return {
            **base,
            "class": "aggregate_summary_layer",
            "current_policy": "aggregate_summary_replacement_layer",
            "mitigation_status": "keep_as_compact_replacement_for_event_fanout",
            "replacement_layers": [],
            "compact_query_route": "search-operational-route-rollup-query",
            "next_route": "Keep this aggregate layer as compact navigation unless a stronger rollup replaces it with raw/segment refs.",
            "example_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} search-operational-route-rollup-query <query> --aoa-root {aoa_root} --layer <layer>",
        }
    if edge_type in {"has_event", "answered_by", "responds_to", "goal_lifecycle_has_event", "has_task_episode"}:
        return {
            **base,
            "class": "structural_event_chain",
            "current_policy": GRAPH_EVENT_RELATIONSHIP_EDGE_POLICY,
            "mitigation_status": "keep_bounded_query_routes_before_prune",
            "replacement_layers": ["agent-responses", "goal-lifecycles", "graph-timeline"],
            "compact_query_route": "graph-timeline",
            "next_route": "Use typed answer/goal/timeline routes before considering structural edge pruning.",
            "example_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-timeline <anchor> --aoa-root {aoa_root} --kind <kind> --limit 40",
        }
    return {
        **base,
        "class": "other_high_fanout_edge",
        "current_policy": "observe_before_mutation",
        "mitigation_status": "needs_targeted_policy_before_prune",
        "replacement_layers": [],
        "compact_query_route": "graph-cardinality",
        "next_route": "Measure the edge class and design a replacement route before any pruning.",
        "example_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-cardinality --aoa-root {aoa_root} --limit 20",
    }


def graph_high_fanout_replacement_plan_for_edge(
    *,
    aoa_root: Path,
    edge_policy: dict[str, Any],
) -> dict[str, Any]:
    edge_type = str(edge_policy.get("edge_type") or "")
    edge_class = str(edge_policy.get("class") or "")
    compact_route = str(edge_policy.get("compact_query_route") or "")
    replacement_layers = [
        str(layer)
        for layer in edge_policy.get("replacement_layers", [])
        if layer
    ] if isinstance(edge_policy.get("replacement_layers"), list) else []
    common = list(GRAPH_HIGH_FANOUT_REPLACEMENT_COMMON_PROOF_GATES)
    if edge_type == "event_mentions_registered_entity":
        missing_gates = common + [
            "usage_chain_preserves_consequence_links",
            "entity_usage_rollup_samples_match_event_refs",
        ]
        return {
            "edge_type": edge_type,
            "status": "replacement_projection_required",
            "candidate_for_cardinality_reduction": True,
            "target_projection": "entity_usage_rollup_by_anchor_session_segment",
            "existing_compact_routes": ["usage-chain", "entity-usage-audit", "entity-registry"],
            "replacement_layers": replacement_layers,
            "missing_proof_gates": missing_gates,
            "proof_commands": [
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-entity-usage-replacement-proof <anchor> --aoa-root {aoa_root} --kind <kind>",
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} usage-chain <anchor> --aoa-root {aoa_root} --kind <kind>",
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} entity-usage-audit <anchor> --aoa-root {aoa_root} --kind <kind>",
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} live-scenario-corpus check --aoa-root {aoa_root} --case-limit 1",
            ],
            "promotion_rule": "promote only after usage/consequence packets preserve raw/segment refs and route freshness on reviewed live cases",
            "can_prune_now": False,
        }
    if edge_type == "mentions_route_signal":
        missing_gates = common + [
            "route_signal_rollup_refs_match_edge_samples",
            "cooccurrence_packet_preserves_dense_anchor_neighbors",
        ]
        return {
            "edge_type": edge_type,
            "status": "compact_layers_exist_replacement_projection_unproven",
            "candidate_for_cardinality_reduction": True,
            "target_projection": "route_signal_cooccurrence_rollup_by_segment_session",
            "existing_compact_routes": ["graph-cooccurrence", "search-operational-route-rollup-query"],
            "replacement_layers": replacement_layers,
            "missing_proof_gates": missing_gates,
            "proof_commands": [
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-cooccurrence <anchor> --aoa-root {aoa_root} --kind <kind> --limit 30",
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} search-operational-route-rollup-query <query> --aoa-root {aoa_root} --layer <layer> --limit 12 --ref-limit 3",
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} live-scenario-corpus check --aoa-root {aoa_root} --case-limit 1",
            ],
            "promotion_rule": "promote only after cooccurrence and rollup packets preserve bounded neighbors, refs, freshness, and exact next expansion",
            "can_prune_now": False,
        }
    if edge_class == "structural_event_chain":
        missing_gates = common + [
            "answer_goal_task_episode_coverage",
            "timeline_packet_preserves_work_chain_order",
        ]
        return {
            "edge_type": edge_type,
            "status": "typed_event_routes_exist_structural_replacement_unproven",
            "candidate_for_cardinality_reduction": edge_type == "has_event",
            "target_projection": "task_answer_goal_timeline_rollup",
            "existing_compact_routes": ["agent-responses", "goal-lifecycles", "graph-timeline"],
            "replacement_layers": replacement_layers,
            "missing_proof_gates": missing_gates,
            "proof_commands": [
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} agent-responses --aoa-root {aoa_root} --limit 12",
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} goal-lifecycles --aoa-root {aoa_root} --limit 12",
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-timeline <anchor> --aoa-root {aoa_root} --kind <kind> --limit 40",
            ],
            "promotion_rule": "promote only after answer/goal/task packets prove the same work-chain navigation without unbounded structural expansion",
            "can_prune_now": False,
        }
    if edge_class == "aggregate_summary_layer":
        return {
            "edge_type": edge_type,
            "status": "keep_as_replacement_layer",
            "candidate_for_cardinality_reduction": False,
            "target_projection": "existing_aggregate_summary_layer",
            "existing_compact_routes": [compact_route] if compact_route else [],
            "replacement_layers": replacement_layers,
            "missing_proof_gates": [],
            "proof_commands": [
                f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} search-operational-route-rollup-query <query> --aoa-root {aoa_root} --layer <layer> --limit 12 --ref-limit 3",
            ],
            "promotion_rule": "keep as compact navigation unless a stronger route-rollup with refs replaces it",
            "can_prune_now": False,
        }
    missing_gates = common + ["targeted_edge_policy_written"]
    return {
        "edge_type": edge_type,
        "status": "targeted_policy_required",
        "candidate_for_cardinality_reduction": bool(edge_policy.get("high_fanout")),
        "target_projection": "unknown_until_edge_policy_is_written",
        "existing_compact_routes": [compact_route] if compact_route else [],
        "replacement_layers": replacement_layers,
        "missing_proof_gates": missing_gates,
        "proof_commands": [
            f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-cardinality --aoa-root {aoa_root} --limit 20",
        ],
        "promotion_rule": "measure and write a targeted compact route before any pruning",
        "can_prune_now": False,
    }


def graph_high_fanout_replacement_readiness(
    *,
    aoa_root: Path,
    edge_policies: list[dict[str, Any]],
    projection_status: str,
    status: str,
) -> dict[str, Any]:
    candidate_plans = [
        row.get("replacement_plan")
        for row in edge_policies
        if isinstance(row.get("replacement_plan"), dict)
        and row["replacement_plan"].get("candidate_for_cardinality_reduction")
    ]
    missing_gate_ids = sorted(
        {
            str(gate)
            for plan in candidate_plans
            for gate in plan.get("missing_proof_gates", [])
            if gate
        }
    )
    candidate_edge_types = [
        str(plan.get("edge_type") or "")
        for plan in candidate_plans
        if plan.get("edge_type")
    ]
    target_projections = sorted(
        {
            str(plan.get("target_projection") or "")
            for plan in candidate_plans
            if plan.get("target_projection")
        }
    )
    proof_commands = []
    seen_commands: set[str] = set()
    for plan in candidate_plans:
        for command in plan.get("proof_commands", []):
            command_text = str(command)
            if command_text and command_text not in seen_commands:
                proof_commands.append(command_text)
                seen_commands.add(command_text)
    if projection_status != "current":
        readiness_status = "blocked_cardinality_projection_not_current"
    elif not candidate_plans:
        readiness_status = "not_needed"
    elif missing_gate_ids:
        readiness_status = "not_ready_for_prune"
    else:
        readiness_status = "ready_for_reviewed_apply_route"
    apply_ready = False
    if status == "normal" and not candidate_plans:
        gate_status = "not_needed"
        reason = "no high-fanout cardinality replacement is needed"
    elif projection_status != "current":
        gate_status = "blocked_cardinality_projection_not_current"
        reason = "graph cardinality projection must be current before replacement readiness can be trusted"
    else:
        gate_status = "blocked_replacement_projection_not_proven"
        reason = "replacement projections must prove refs, freshness, fallback, live scenario quality, and before/after cardinality before any graph-row pruning"
    required_before_apply = sorted(
        set(missing_gate_ids)
        | {
            "explicit_apply_route_with_before_after_report",
            "operator_reviewed_mutation_boundary",
        }
    ) if candidate_plans else []
    return {
        "status": readiness_status,
        "apply_ready": apply_ready,
        "candidate_count": len(candidate_plans),
        "candidate_edge_types": candidate_edge_types,
        "target_projections": target_projections,
        "proof_gap_count": len(missing_gate_ids),
        "missing_proof_gates": missing_gate_ids,
        "proof_commands": proof_commands[:12],
        "next_route": (
            "prove replacement projections on live scenarios before any graph prune or physical compaction route"
            if candidate_plans
            else "no replacement projection route is needed for the current high-fanout packet"
        ),
        "prune_gate": {
            "status": gate_status,
            "apply_ready": apply_ready,
            "can_prune_now": False,
            "reason": reason,
            "required_before_apply": required_before_apply,
            "mutation_boundary": "read_only_policy_packet_no_graph_rows_are_deleted_or_rebuilt",
        },
        "authority_boundary": "replacement readiness is generated route guidance; raw/segment refs and owner source surfaces remain stronger",
    }


def graph_high_fanout_policy_from_projection(
    *,
    aoa_root: Path,
    projection: dict[str, Any],
    limit: int = 12,
) -> dict[str, Any]:
    selected_limit = max(1, min(int_value(limit, 12), 80))
    counts = projection.get("counts") if isinstance(projection.get("counts"), dict) else {}
    node_counts = counts.get("node") if isinstance(counts.get("node"), dict) else {}
    edge_counts = counts.get("edge") if isinstance(counts.get("edge"), dict) else {}
    node_total = sum(int_value(value) for value in node_counts.values())
    edge_total = sum(int_value(value) for value in edge_counts.values())
    edge_rows = sorted(
        ((str(edge_type), int_value(count)) for edge_type, count in edge_counts.items()),
        key=lambda item: (-item[1], item[0]),
    )
    node_rows = sorted(
        ((str(node_type), int_value(count)) for node_type, count in node_counts.items()),
        key=lambda item: (-item[1], item[0]),
    )
    edge_policies = [
        graph_high_fanout_edge_policy_row(
            aoa_root=aoa_root,
            edge_type=edge_type,
            count=count,
            edge_total=edge_total,
        )
        for edge_type, count in edge_rows[:selected_limit]
    ]
    for row in edge_policies:
        row["replacement_plan"] = graph_high_fanout_replacement_plan_for_edge(
            aoa_root=aoa_root,
            edge_policy=row,
        )
    dominant_edges = [
        row
        for row in edge_policies
        if row.get("high_fanout") or str(row.get("class") or "") in {"event_route_signal_fanout", "event_registered_entity_fanout"}
    ]
    high_fanout_nodes = [
        {
            "node_type": node_type,
            "count": count,
            "share": round(count / node_total, 6) if node_total > 0 else 0.0,
            "high_fanout": count >= OPS_GRAPH_HIGH_FANOUT_NODE_WARNING_COUNT,
            "policy": "prefer typed route packets over unbounded node expansion",
        }
        for node_type, count in node_rows[:selected_limit]
        if count >= OPS_GRAPH_HIGH_FANOUT_NODE_WARNING_COUNT or node_type == "event"
    ]
    projection_status = str(projection.get("status") or "unknown")
    if projection_status != "current":
        status = "cardinality_projection_missing_or_stale"
    elif edge_total >= OPS_GRAPH_EDGE_CARDINALITY_WARNING_COUNT:
        status = "large_cardinality_dominates"
    elif dominant_edges or high_fanout_nodes:
        status = "localized_high_fanout"
    else:
        status = "normal"
    next_actions = [
        {
            "id": "use_compact_graph_routes_for_dense_anchors",
            "reason": "dense anchors should use bounded cooccurrence/timeline/usage packets before raw graph expansion",
            "mutates": False,
            "example_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-cooccurrence <anchor> --aoa-root {aoa_root} --kind <kind> --limit 30",
        },
        {
            "id": "refresh_graph_cardinality_if_stale",
            "reason": "type-count projection must be current before graph storage/cardinality decisions",
            "mutates": False,
            "command": [
                *session_memory_cli_command(aoa_root),
                "graph-cardinality",
                "--aoa-root",
                str(aoa_root),
                "--limit",
                str(selected_limit),
            ],
        },
    ]
    if status == "large_cardinality_dominates":
        next_actions.append(
            {
                "id": "design_high_fanout_replacement_before_prune",
                "reason": "physical compaction or row deletion must wait for a replacement route with refs/freshness/fallback proof",
                "mutates": False,
                "replacement_layers": sorted({layer for row in edge_policies for layer in row.get("replacement_layers", []) if layer}),
            }
        )
    replacement_readiness = graph_high_fanout_replacement_readiness(
        aoa_root=aoa_root,
        edge_policies=edge_policies,
        projection_status=projection_status,
        status=status,
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_high_fanout_policy",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": projection_status == "current",
        "mutates": False,
        "status": status,
        "projection_status": projection_status,
        "node_count": node_total,
        "edge_count": edge_total,
        "edge_warning_count": OPS_GRAPH_EDGE_CARDINALITY_WARNING_COUNT,
        "high_fanout_edge_warning_count": OPS_GRAPH_HIGH_FANOUT_EDGE_WARNING_COUNT,
        "high_fanout_node_warning_count": OPS_GRAPH_HIGH_FANOUT_NODE_WARNING_COUNT,
        "edge_policies": edge_policies,
        "high_fanout_nodes": high_fanout_nodes,
        "dominant_edge_count": len(dominant_edges),
        "dominant_edge_types": [str(row.get("edge_type") or "") for row in dominant_edges],
        "graph_event_route_signal_edge_policy": GRAPH_EVENT_ROUTE_SIGNAL_EDGE_POLICY,
        "graph_event_relationship_edge_policy": GRAPH_EVENT_RELATIONSHIP_EDGE_POLICY,
        "graph_route_signal_materialization_limits": graph_route_signal_materialization_limits(),
        "replacement_readiness": replacement_readiness,
        "prune_gate": replacement_readiness.get("prune_gate"),
        "next_actions": next_actions,
        "exact_read_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-high-fanout-policy --workspace-root {aoa_root.parent} --aoa-root {aoa_root} --limit {selected_limit}",
        "exact_cardinality_command": f"python3 {aoa_root / 'scripts' / 'aoa_session_memory.py'} graph-cardinality --workspace-root {aoa_root.parent} --aoa-root {aoa_root} --limit {selected_limit}",
        "next_route": (
            "use compact graph routes and design replacement projections before mutating high-fanout edge rows"
            if status != "normal"
            else "continue using compact graph packets; no high-fanout policy action is needed"
        ),
        "mutation_boundary": "read_only_policy_packet_no_graph_rows_are_deleted_or_rebuilt",
        "authority_boundary": "graph policy is generated routing guidance; raw/segment refs and owner source surfaces remain stronger",
        "diagnostics": projection.get("diagnostics", []) if isinstance(projection.get("diagnostics"), list) else [],
    }


def graph_high_fanout_policy(*, aoa_root: Path, limit: int = 12) -> dict[str, Any]:
    projection = graph_cardinality_projection_read(aoa_root, limit=max(12, int_value(limit, 12)))
    return graph_high_fanout_policy_from_projection(aoa_root=aoa_root, projection=projection, limit=limit)


def graph_usage_event_node_id(event: dict[str, Any]) -> str:
    doc_id = str(event.get("doc_id") or "")
    if doc_id.startswith("event:"):
        return doc_id
    session_id = str(event.get("session_id") or "")
    segment_id = str(event.get("segment_id") or "")
    event_id = str(event.get("event_id") or "")
    if session_id and segment_id and event_id:
        return f"event:{session_id}:{segment_id}:{event_id}"
    return ""


def graph_ref_has_raw_or_segment(refs: dict[str, Any]) -> bool:
    return any(str(refs.get(key) or "").strip() for key in ("raw", "raw_block", "segment", "segment_index"))


def graph_usage_event_has_raw_or_segment_ref(event: dict[str, Any]) -> bool:
    refs = event.get("refs") if isinstance(event.get("refs"), dict) else {}
    return graph_ref_has_raw_or_segment(refs)


def graph_registry_nodes_for_route_nodes(
    conn: sqlite3.Connection,
    route_node_ids: list[str],
    *,
    limit: int,
) -> list[str]:
    registry_nodes: list[str] = []
    seen: set[str] = set()
    for node_id in route_node_ids:
        node_id = str(node_id or "")
        if not node_id:
            continue
        if node_id.startswith("entity_registry:") and node_id not in seen:
            registry_nodes.append(node_id)
            seen.add(node_id)
        remaining = max(1, limit - len(registry_nodes))
        rows = conn.execute(
            """
            SELECT source_node
            FROM edges
            WHERE target_node = ?
              AND edge_type = 'registry_entity_has_route_signal'
            LIMIT ?
            """,
            (node_id, remaining),
        ).fetchall()
        for row in rows:
            registry_node = str(row["source_node"] or "")
            if registry_node and registry_node not in seen:
                registry_nodes.append(registry_node)
                seen.add(registry_node)
            if len(registry_nodes) >= limit:
                return registry_nodes
    return registry_nodes


def graph_entity_usage_replacement_graph_sample(
    conn: sqlite3.Connection,
    *,
    registry_node_ids: list[str],
    sample_limit: int,
) -> dict[str, Any]:
    event_edge_count = 0
    aggregate_edge_count = 0
    sample_edge_ids: list[str] = []
    sample_session_edge_ids: list[str] = []
    per_registry: list[dict[str, Any]] = []
    for registry_node in registry_node_ids:
        registry_node = str(registry_node or "")
        if not registry_node:
            continue
        event_count = int_value(
            conn.execute(
                """
                SELECT COUNT(*)
                FROM edges
                WHERE target_node = ?
                  AND edge_type = ?
                """,
                (registry_node, GRAPH_ENTITY_USAGE_REPLACEMENT_EDGE_TYPE),
            ).fetchone()[0]
        )
        session_count = int_value(
            conn.execute(
                """
                SELECT COUNT(*)
                FROM edges
                WHERE target_node = ?
                  AND edge_type = ?
                """,
                (registry_node, GRAPH_ENTITY_USAGE_REPLACEMENT_AGGREGATE_EDGE_TYPE),
            ).fetchone()[0]
        )
        event_edge_count += event_count
        aggregate_edge_count += session_count
        if len(sample_edge_ids) < sample_limit:
            rows = conn.execute(
                """
                SELECT id
                FROM edges
                WHERE target_node = ?
                  AND edge_type = ?
                LIMIT ?
                """,
                (registry_node, GRAPH_ENTITY_USAGE_REPLACEMENT_EDGE_TYPE, max(1, sample_limit - len(sample_edge_ids))),
            ).fetchall()
            sample_edge_ids.extend(str(row["id"] or "") for row in rows if row["id"])
        if len(sample_session_edge_ids) < sample_limit:
            rows = conn.execute(
                """
                SELECT id
                FROM edges
                WHERE target_node = ?
                  AND edge_type = ?
                LIMIT ?
                """,
                (registry_node, GRAPH_ENTITY_USAGE_REPLACEMENT_AGGREGATE_EDGE_TYPE, max(1, sample_limit - len(sample_session_edge_ids))),
            ).fetchall()
            sample_session_edge_ids.extend(str(row["id"] or "") for row in rows if row["id"])
        per_registry.append(
            {
                "registry_node": registry_node,
                "event_edge_count": event_count,
                "session_aggregate_edge_count": session_count,
            }
        )
    event_samples = graph_store_fetch_payloads(conn, "edges", sample_edge_ids[:sample_limit])
    aggregate_samples = graph_store_fetch_payloads(conn, "edges", sample_session_edge_ids[:sample_limit])
    reduction_ratio = round(1 - (aggregate_edge_count / event_edge_count), 6) if event_edge_count > 0 else 0.0
    return {
        "event_edge_count": event_edge_count,
        "session_aggregate_edge_count": aggregate_edge_count,
        "sample_event_edge_count": len(event_samples),
        "sample_session_aggregate_edge_count": len(aggregate_samples),
        "sample_event_edges": event_samples,
        "sample_session_aggregate_edges": aggregate_samples,
        "per_registry": per_registry,
        "anchor_sample_reduction_ratio": reduction_ratio,
        "cardinality_improves_for_anchor": event_edge_count > aggregate_edge_count > 0,
    }


def graph_entity_usage_replacement_matching_edges(
    conn: sqlite3.Connection,
    *,
    usage_events: list[dict[str, Any]],
    registry_node_ids: list[str],
    sample_limit: int,
) -> dict[str, Any]:
    checked: list[dict[str, Any]] = []
    matched_edge_ids: list[str] = []
    missing: list[dict[str, Any]] = []
    for event in usage_events[:sample_limit]:
        event_node_id = graph_usage_event_node_id(event)
        matched_registry_node = ""
        matched_edge_id = ""
        if event_node_id:
            for registry_node in registry_node_ids:
                edge_id = graph_edge_id(event_node_id, registry_node, GRAPH_ENTITY_USAGE_REPLACEMENT_EDGE_TYPE)
                row = conn.execute("SELECT id FROM edges WHERE id = ?", (edge_id,)).fetchone()
                if row:
                    matched_registry_node = registry_node
                    matched_edge_id = str(row["id"] or edge_id)
                    break
        item = {
            "event_node_id": event_node_id,
            "session_id": event.get("session_id"),
            "segment_id": event.get("segment_id"),
            "event_id": event.get("event_id"),
            "usage_role": event.get("role"),
            "raw_or_segment_ref_present": graph_usage_event_has_raw_or_segment_ref(event),
            "matched": bool(matched_edge_id),
            "matched_registry_node": matched_registry_node,
            "matched_edge_id": matched_edge_id,
        }
        checked.append(item)
        if matched_edge_id:
            matched_edge_ids.append(matched_edge_id)
        else:
            missing.append(item)
    matched_edges = graph_store_fetch_payloads(conn, "edges", matched_edge_ids[:sample_limit])
    matched_edges_with_refs = 0
    for edge in matched_edges:
        refs = edge.get("evidence_refs") if isinstance(edge.get("evidence_refs"), list) else []
        if refs:
            matched_edges_with_refs += 1
    return {
        "checked_count": len(checked),
        "matched_count": len(matched_edge_ids),
        "missing_count": len(missing),
        "usage_events_checked": checked,
        "missing_usage_events": missing[:sample_limit],
        "matched_edges": matched_edges,
        "matched_edges_with_evidence_refs": matched_edges_with_refs,
    }


def graph_replacement_gate(id_: str, status: str, *, reason: str, details: dict[str, Any] | None = None) -> dict[str, Any]:
    return {
        "id": id_,
        "status": status,
        "passed": status == "passed",
        "reason": reason,
        "details": details or {},
    }


def graph_entity_usage_replacement_proof(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    limit: int = 6,
    per_route_limit: int = 12,
    consequence_window: int = 6,
    sample_limit: int = 8,
    provider: str = "portable_sqlite",
    write_report: bool = False,
) -> dict[str, Any]:
    started_at = time.monotonic()
    normalized_kind = normalize_trace_route_kind(kind)
    if normalized_kind not in TRACE_ROUTE_KINDS:
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "session_memory_graph_entity_usage_replacement_proof",
            "generated_at": utc_now(),
            "ok": False,
            "mutates": False,
            "anchor": anchor,
            **trace_kind_payload_fields(kind, normalized_kind),
            "diagnostics": [f"unknown trace kind: {kind}"],
        }
    selected_limit = max(1, min(int_value(limit, 6), 20))
    selected_sample_limit = max(1, min(int_value(sample_limit, 8), 40))
    selected_per_route_limit = max(selected_limit, min(int_value(per_route_limit, 12), 80))
    usage_packet = entity_usage_chain(
        aoa_root=aoa_root,
        anchor=anchor,
        kind=normalized_kind,
        limit=selected_limit,
        per_route_limit=selected_per_route_limit,
        consequence_window=consequence_window,
        document_limit=max(12, selected_limit * 4),
        provider=provider,
        write_report=False,
    )
    chains = usage_packet.get("usage_chain", {}).get("chains", []) if isinstance(usage_packet.get("usage_chain"), dict) else []
    usage_events = [
        item.get("usage_event")
        for item in chains
        if isinstance(item, dict) and isinstance(item.get("usage_event"), dict)
    ]
    usage_quality = usage_packet.get("quality") if isinstance(usage_packet.get("quality"), dict) else {}
    raw_or_segment_usage_count = sum(1 for event in usage_events if graph_usage_event_has_raw_or_segment_ref(event))
    chain_with_link_count = sum(1 for item in chains if isinstance(item, dict) and "result_or_consequence_count" in item)
    chain_with_result_count = sum(1 for item in chains if isinstance(item, dict) and bool(item.get("has_result_or_consequence")))
    graph_state = graph_store_query_state(aoa_root)
    diagnostics: list[str] = []
    graph_resolution: dict[str, Any] = {}
    graph_sample: dict[str, Any] = {}
    edge_matches: dict[str, Any] = {}
    registry_node_ids: list[str] = []
    if graph_state.get("status") != "current":
        diagnostics.append("graph_store_not_current")
    else:
        try:
            conn = sqlite3.connect(str(graph_paths(aoa_root)["store"]))
            conn.row_factory = sqlite3.Row
            graph_resolution = graph_store_resolve_anchor(conn, anchor, kind=normalized_kind, limit=max(10, selected_sample_limit))
            route_node_ids = [str(node_id) for node_id in graph_resolution.get("start_node_ids", []) if node_id]
            registry_node_ids = graph_registry_nodes_for_route_nodes(conn, route_node_ids, limit=max(4, selected_sample_limit))
            graph_sample = graph_entity_usage_replacement_graph_sample(
                conn,
                registry_node_ids=registry_node_ids,
                sample_limit=selected_sample_limit,
            )
            edge_matches = graph_entity_usage_replacement_matching_edges(
                conn,
                usage_events=usage_events,
                registry_node_ids=registry_node_ids,
                sample_limit=selected_sample_limit,
            )
            conn.close()
        except sqlite3.Error as exc:
            diagnostics.append(f"graph_sqlite_error:{str(exc)[:180]}")
    usage_count = len(usage_events)
    checked_count = int_value(edge_matches.get("checked_count"))
    matched_count = int_value(edge_matches.get("matched_count"))
    gates = [
        graph_replacement_gate(
            "raw_or_segment_refs_preserved",
            "passed" if usage_count and raw_or_segment_usage_count == usage_count else "failed",
            reason="usage-chain usage events expose raw, raw-block, segment, or segment-index refs",
            details={"usage_event_count": usage_count, "raw_or_segment_ref_count": raw_or_segment_usage_count},
        ),
        graph_replacement_gate(
            "freshness_current_or_stale_flag_visible",
            "passed"
            if usage_count
            and all(isinstance(event.get("freshness"), dict) and event.get("freshness", {}).get("status") for event in usage_events)
            else "failed",
            reason="usage-chain keeps freshness status visible on checked usage events",
        ),
        graph_replacement_gate(
            "fallback_route_named",
            "passed" if usage_packet.get("next_expansion_command") or usage_packet.get("next_expansion") else "failed",
            reason="usage-chain packet names a bounded next expansion route",
        ),
        graph_replacement_gate(
            "bounded_packet_default",
            "passed"
            if usage_quality.get("skipped_graph_rag_packet") is True
            and usage_quality.get("skipped_graph_neighborhood") is True
            and usage_quality.get("skipped_raw_preview_neighborhood") is True
            else "failed",
            reason="replacement route avoids GraphRAG, graph-neighborhood, and raw-preview expansion by default",
        ),
        graph_replacement_gate(
            "entity_usage_rollup_samples_match_event_refs",
            "passed" if checked_count and matched_count == checked_count else "failed",
            reason="usage-chain event refs match generated event_mentions_registered_entity graph edges for this anchor sample",
            details={"checked_count": checked_count, "matched_count": matched_count, "missing_count": edge_matches.get("missing_count")},
        ),
        graph_replacement_gate(
            "sample_before_after_cardinality_comparison",
            "passed" if graph_sample.get("cardinality_improves_for_anchor") else "failed",
            reason="anchor sample compares event-level graph edges against session_has_registered_entity aggregate edges",
            details={
                "event_edge_count": graph_sample.get("event_edge_count"),
                "session_aggregate_edge_count": graph_sample.get("session_aggregate_edge_count"),
                "anchor_sample_reduction_ratio": graph_sample.get("anchor_sample_reduction_ratio"),
            },
        ),
        graph_replacement_gate(
            "usage_chain_preserves_consequence_links",
            "passed" if usage_count and chain_with_link_count == usage_count else "failed",
            reason="usage-chain keeps per-usage result_or_consequence link fields even when no consequence was observed",
            details={"chain_count": len(chains), "chain_with_link_count": chain_with_link_count, "chain_with_result_count": chain_with_result_count},
        ),
        graph_replacement_gate(
            "global_before_after_cardinality_comparison",
            "not_proven",
            reason="this proof is bounded to one anchor; global graph-row pruning still needs an explicit apply route and before/after report",
        ),
    ]
    failed_core_gates = [
        gate["id"]
        for gate in gates
        if gate.get("status") == "failed"
        and gate.get("id") != "global_before_after_cardinality_comparison"
    ]
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_entity_usage_replacement_proof",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(usage_packet.get("ok")) and not failed_core_gates and bool(registry_node_ids),
        "mutates": False,
        "truth_status": "generated_graph_replacement_sample_proof_not_prune_permission",
        "anchor": anchor,
        **trace_kind_payload_fields(kind, normalized_kind),
        "target_edge_type": GRAPH_ENTITY_USAGE_REPLACEMENT_EDGE_TYPE,
        "target_projection": GRAPH_ENTITY_USAGE_REPLACEMENT_TARGET_PROJECTION,
        "replacement_scope": "anchor_sample",
        "normalized_entity": usage_packet.get("normalized_entity") if isinstance(usage_packet.get("normalized_entity"), dict) else {},
        "usage_chain": {
            "ok": usage_packet.get("ok"),
            "usage_event_count": usage_count,
            "chain_count": len(chains),
            "chain_with_result_or_consequence_count": chain_with_result_count,
            "raw_or_segment_ref_count": raw_or_segment_usage_count,
            "first_ref": usage_packet.get("first_ref"),
            "quality": usage_quality,
            "next_expansion_command": usage_packet.get("next_expansion_command"),
        },
        "graph_resolution": {
            "status": graph_state.get("status"),
            "route_candidates": graph_resolution.get("route_candidates", []) if isinstance(graph_resolution, dict) else [],
            "start_node_ids": graph_resolution.get("start_node_ids", []) if isinstance(graph_resolution, dict) else [],
            "registry_node_ids": registry_node_ids,
            "registry_node_count": len(registry_node_ids),
            "resolver_strategy": graph_resolution.get("resolver_strategy") if isinstance(graph_resolution, dict) else "",
        },
        "graph_sample": graph_sample,
        "edge_match": edge_matches,
        "proof_gates": gates,
        "proof_gate_summary": {
            "failed_core_gate_count": len(failed_core_gates),
            "failed_core_gates": failed_core_gates,
            "passed_gate_count": sum(1 for gate in gates if gate.get("status") == "passed"),
            "not_proven_gate_count": sum(1 for gate in gates if gate.get("status") == "not_proven"),
        },
        "prune_gate": {
            "status": "blocked_anchor_sample_only",
            "apply_ready": False,
            "can_prune_now": False,
            "reason": "anchor-sample replacement proof does not prove archive-wide cardinality, freshness, fallback, and before/after storage behavior",
            "required_before_apply": [
                "multi_anchor_live_scenario_corpus",
                "materialized_replacement_projection",
                "global_before_after_cardinality_comparison",
                "operator_reviewed_mutation_boundary",
            ],
            "mutation_boundary": "read_only_proof_packet_no_graph_rows_are_deleted_or_rebuilt",
        },
        "next_route": "run this proof across more dense anchors, then materialize the entity-usage rollup only after corpus and cardinality comparison stay green",
        "exact_read_command": entity_usage_chain_command(
            "graph-entity-usage-replacement-proof",
            anchor=anchor,
            kind=normalized_kind,
            aoa_root=aoa_root,
            limit=selected_limit,
            per_route_limit=selected_per_route_limit,
            extra=["--sample-limit", str(selected_sample_limit)],
        ),
        "authority_boundary": "replacement proof is generated route evidence; raw/segment refs and owner source surfaces remain stronger",
        "elapsed_ms": int((time.monotonic() - started_at) * 1000),
        "diagnostics": diagnostics,
    }
    if write_report:
        stem = f"{compact_stamp()}__graph-entity-usage-replacement-proof"
        report_json, report_md = reserve_diagnostic_report_paths(aoa_root / DIAGNOSTICS_ROOT, stem)
        write_json(report_json, payload)
        write_markdown(report_md, json_markdown_report("Graph Entity Usage Replacement Proof", payload))
        payload["report_json"] = str(report_json)
        payload["report_md"] = str(report_md)
    return payload


def normalize_graph_replacement_probes(
    probes: list[dict[str, Any]] | None,
    *,
    limit: int,
    per_route_limit: int,
    consequence_window: int,
    sample_limit: int,
) -> list[dict[str, Any]]:
    source = probes if probes else list(GRAPH_ENTITY_USAGE_REPLACEMENT_DEFAULT_PROBES)
    normalized: list[dict[str, Any]] = []
    seen: set[tuple[str, str]] = set()
    for index, probe in enumerate(source):
        if not isinstance(probe, dict):
            continue
        anchor = str(probe.get("anchor") or probe.get("query") or "").strip()
        if not anchor:
            continue
        raw_kind = str(probe.get("kind") or "auto")
        normalized_kind = normalize_trace_route_kind(raw_kind)
        if normalized_kind not in TRACE_ROUTE_KINDS:
            normalized_kind = "auto"
        key = (anchor, normalized_kind)
        if key in seen:
            continue
        seen.add(key)
        normalized.append(
            {
                "name": str(probe.get("name") or route_key_slug(anchor, fallback=f"probe_{index}", max_chars=80)),
                "anchor": anchor,
                "kind": normalized_kind,
                "limit": max(1, min(int_value(probe.get("limit"), limit), 20)),
                "per_route_limit": max(1, min(int_value(probe.get("per_route_limit"), per_route_limit), 80)),
                "consequence_window": max(0, min(int_value(probe.get("consequence_window"), consequence_window), 40)),
                "sample_limit": max(1, min(int_value(probe.get("sample_limit"), sample_limit), 40)),
            }
        )
    return normalized


def graph_replacement_probe_summary(
    *,
    probe: dict[str, Any],
    proof: dict[str, Any],
    elapsed_ms: int,
) -> dict[str, Any]:
    usage_chain = proof.get("usage_chain") if isinstance(proof.get("usage_chain"), dict) else {}
    graph_sample = proof.get("graph_sample") if isinstance(proof.get("graph_sample"), dict) else {}
    edge_match = proof.get("edge_match") if isinstance(proof.get("edge_match"), dict) else {}
    proof_summary = proof.get("proof_gate_summary") if isinstance(proof.get("proof_gate_summary"), dict) else {}
    prune_gate = proof.get("prune_gate") if isinstance(proof.get("prune_gate"), dict) else {}
    diagnostics = [str(item) for item in proof.get("diagnostics", []) if item] if isinstance(proof.get("diagnostics"), list) else []
    failed_core_gate_count = int_value(proof_summary.get("failed_core_gate_count"))
    missing_edge_count = int_value(edge_match.get("missing_count"))
    usage_event_count = int_value(usage_chain.get("usage_event_count"))
    checked_count = int_value(edge_match.get("checked_count"))
    target_projection = str(proof.get("target_projection") or "")
    quality_flags: list[str] = []
    if not proof.get("ok"):
        quality_flags.append("graph_replacement_probe_not_ok")
    if usage_event_count <= 0:
        quality_flags.append("graph_replacement_probe_no_usage_events")
    if checked_count <= 0:
        quality_flags.append("graph_replacement_probe_no_checked_event_edges")
    if missing_edge_count > 0:
        quality_flags.append("graph_replacement_probe_missing_event_edges")
    if failed_core_gate_count > 0:
        quality_flags.append("graph_replacement_probe_failed_core_gates")
    if prune_gate.get("apply_ready") is not False:
        quality_flags.append("graph_replacement_probe_prune_gate_not_closed")
    if target_projection != GRAPH_ENTITY_USAGE_REPLACEMENT_TARGET_PROJECTION:
        quality_flags.append("graph_replacement_probe_target_projection_mismatch")
    if diagnostics:
        quality_flags.append("graph_replacement_probe_diagnostics_present")
    status = "failed" if quality_flags else "passed"
    return {
        "name": probe.get("name"),
        "anchor": probe.get("anchor"),
        "kind": proof.get("kind") or probe.get("kind"),
        "status": status,
        "ok": not quality_flags,
        "elapsed_ms": elapsed_ms,
        "target_projection": target_projection,
        "replacement_scope": proof.get("replacement_scope"),
        "usage_event_count": usage_event_count,
        "raw_or_segment_ref_count": int_value(usage_chain.get("raw_or_segment_ref_count")),
        "graph_event_edge_checked_count": checked_count,
        "graph_event_edge_match_count": int_value(edge_match.get("matched_count")),
        "graph_event_edge_missing_count": missing_edge_count,
        "event_edge_count": int_value(graph_sample.get("event_edge_count")),
        "session_aggregate_edge_count": int_value(graph_sample.get("session_aggregate_edge_count")),
        "anchor_sample_reduction_ratio": graph_sample.get("anchor_sample_reduction_ratio"),
        "proof_failed_core_gate_count": failed_core_gate_count,
        "proof_not_proven_gate_count": int_value(proof_summary.get("not_proven_gate_count")),
        "replacement_prune_apply_ready": prune_gate.get("apply_ready"),
        "replacement_prune_gate_status": prune_gate.get("status"),
        "first_ref": usage_chain.get("first_ref") if isinstance(usage_chain.get("first_ref"), dict) else {},
        "quality_flags": quality_flags,
    }


def graph_high_fanout_replacement_scenario_audit(
    *,
    aoa_root: Path,
    probes: list[dict[str, Any]] | None = None,
    limit: int = 1,
    per_route_limit: int = 4,
    consequence_window: int = 4,
    sample_limit: int = 1,
    provider: str = "portable_sqlite",
) -> dict[str, Any]:
    started = time.monotonic()
    selected_limit = max(1, min(int_value(limit, 1), 20))
    selected_per_route_limit = max(selected_limit, min(int_value(per_route_limit, 4), 80))
    selected_sample_limit = max(1, min(int_value(sample_limit, 1), 40))
    selected_consequence_window = max(0, min(int_value(consequence_window, 4), 40))
    normalized_probes = normalize_graph_replacement_probes(
        probes,
        limit=selected_limit,
        per_route_limit=selected_per_route_limit,
        consequence_window=selected_consequence_window,
        sample_limit=selected_sample_limit,
    )
    samples: list[dict[str, Any]] = []
    for probe in normalized_probes:
        probe_started = time.monotonic()
        try:
            proof = graph_entity_usage_replacement_proof(
                aoa_root=aoa_root,
                anchor=str(probe["anchor"]),
                kind=str(probe["kind"]),
                limit=int_value(probe.get("limit"), selected_limit),
                per_route_limit=int_value(probe.get("per_route_limit"), selected_per_route_limit),
                consequence_window=int_value(probe.get("consequence_window"), selected_consequence_window),
                sample_limit=int_value(probe.get("sample_limit"), selected_sample_limit),
                provider=provider,
                write_report=False,
            )
            elapsed_ms = int((time.monotonic() - probe_started) * 1000)
            samples.append(graph_replacement_probe_summary(probe=probe, proof=proof, elapsed_ms=elapsed_ms))
        except Exception as exc:  # pragma: no cover - defensive route packet
            samples.append(
                {
                    "name": probe.get("name"),
                    "anchor": probe.get("anchor"),
                    "kind": probe.get("kind"),
                    "status": "failed",
                    "ok": False,
                    "elapsed_ms": int((time.monotonic() - probe_started) * 1000),
                    "error": str(exc)[:500],
                    "quality_flags": ["graph_replacement_probe_exception"],
                }
            )
    status_counts = Counter(str(sample.get("status") or "unknown") for sample in samples)
    kind_counts = Counter(str(sample.get("kind") or "unknown") for sample in samples if sample.get("kind"))
    anchor_counts = Counter(str(sample.get("anchor") or "") for sample in samples if sample.get("anchor"))
    quality = {
        "sample_count": len(samples),
        "passed_count": status_counts.get("passed", 0),
        "warn_count": status_counts.get("warn", 0),
        "failed_count": status_counts.get("failed", 0),
        "kind_counts": dict(sorted(kind_counts.items())),
        "anchor_count": len(anchor_counts),
        "anchor_counts": dict(sorted(anchor_counts.items())),
        "usage_event_count": sum(int_value(sample.get("usage_event_count")) for sample in samples),
        "raw_or_segment_ref_count": sum(int_value(sample.get("raw_or_segment_ref_count")) for sample in samples),
        "graph_event_edge_checked_count": sum(int_value(sample.get("graph_event_edge_checked_count")) for sample in samples),
        "graph_event_edge_match_count": sum(int_value(sample.get("graph_event_edge_match_count")) for sample in samples),
        "graph_event_edge_missing_count": sum(int_value(sample.get("graph_event_edge_missing_count")) for sample in samples),
        "event_edge_count": sum(int_value(sample.get("event_edge_count")) for sample in samples),
        "session_aggregate_edge_count": sum(int_value(sample.get("session_aggregate_edge_count")) for sample in samples),
        "proof_failed_core_gate_count": sum(int_value(sample.get("proof_failed_core_gate_count")) for sample in samples),
        "proof_not_proven_gate_count": sum(int_value(sample.get("proof_not_proven_gate_count")) for sample in samples),
        "replacement_prune_open_count": sum(1 for sample in samples if sample.get("replacement_prune_apply_ready") is not False),
        "target_projection_match_count": sum(
            1
            for sample in samples
            if sample.get("target_projection") == GRAPH_ENTITY_USAGE_REPLACEMENT_TARGET_PROJECTION
        ),
        "max_sample_elapsed_ms": max((int_value(sample.get("elapsed_ms")) for sample in samples), default=0),
        "elapsed_ms": int((time.monotonic() - started) * 1000),
    }
    first_ref = next(
        (
            sample.get("first_ref")
            for sample in samples
            if isinstance(sample.get("first_ref"), dict) and sample.get("first_ref")
        ),
        {},
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_high_fanout_replacement_scenario_audit",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(samples) and quality["failed_count"] == 0,
        "mutates": False,
        "truth_status": "multi_anchor_graph_replacement_live_scenario_not_prune_permission",
        "target_projection": GRAPH_ENTITY_USAGE_REPLACEMENT_TARGET_PROJECTION
        if samples and quality["target_projection_match_count"] == len(samples)
        else "",
        "replacement_scope": "multi_anchor_sample" if len(samples) > 1 else "anchor_sample",
        "samples": samples,
        "quality": quality,
        "first_ref": first_ref,
        "prune_gate": {
            "status": "blocked_multi_anchor_sample_only",
            "apply_ready": False,
            "can_prune_now": False,
            "reason": "multi-anchor replacement proof is still read-only route evidence and not an archive-wide prune permission",
            "required_before_apply": [
                "materialized_replacement_projection",
                "global_before_after_cardinality_comparison",
                "freshness_current_after_rebuild",
                "operator_reviewed_mutation_boundary",
            ],
            "mutation_boundary": "read_only_scenario_packet_no_graph_rows_are_deleted_or_rebuilt",
        },
        "next_route": "materialize the entity-usage rollup only after this corpus stays green and a separate before/after storage comparison proves equal-or-better recall",
        "authority_boundary": "scenario audit is generated route evidence; raw/segment refs and owner source surfaces remain stronger",
    }


def graph_node_by_id(graph: dict[str, Any]) -> dict[str, dict[str, Any]]:
    return {str(node.get("id")): node for node in graph.get("nodes", []) if isinstance(node, dict) and node.get("id")}


def graph_edge_by_id(graph: dict[str, Any]) -> dict[str, dict[str, Any]]:
    return {str(edge.get("id")): edge for edge in graph.get("edges", []) if isinstance(edge, dict) and edge.get("id")}


def graph_anchor_alias_keys(anchor: str) -> list[str]:
    aliases = trace_anchor_aliases(anchor)
    keys = [route_key_slug(alias, fallback="", max_chars=120) for alias in aliases]
    return [key for key in dict.fromkeys(keys) if key]


def graph_node_anchor_score(node: dict[str, Any], alias_keys: list[str]) -> int:
    values = [
        node.get("id"),
        node.get("label"),
        node.get("title"),
        node.get("route_key"),
        node.get("route_signal"),
        node.get("session_label"),
        node.get("event_type"),
        node.get("raw_ref"),
        node.get("work_root"),
    ]
    value_keys = [route_key_slug(value, fallback="", max_chars=180) for value in values if value]
    score = 0
    for alias in alias_keys:
        for value in value_keys:
            if not value:
                continue
            if alias == value:
                score = max(score, 100)
            elif len(alias) >= 3 and alias in value:
                score = max(score, 50)
            elif len(value) >= 3 and value in alias:
                score = max(score, 25)
    return score


def graph_store_fetch_payloads(conn: sqlite3.Connection, table: str, ids: list[str]) -> list[dict[str, Any]]:
    if not ids:
        return []
    rows: list[dict[str, Any]] = []
    for item_id in ids:
        row = conn.execute(f"SELECT payload_json, count FROM {table} WHERE id = ?", (item_id,)).fetchone()
        if not row:
            continue
        payload = json.loads(str(row["payload_json"]))
        if isinstance(payload, dict):
            payload["count"] = int_value(row["count"], int_value(payload.get("count"), 1))
            rows.append(payload)
    return graph_hydrate_store_payload_evidence(conn, table, rows)


def graph_store_resolve_anchor(
    conn: sqlite3.Connection,
    anchor: str,
    *,
    kind: str = "auto",
    limit: int = 40,
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    candidates = trace_route_candidates(anchor, kind=route_kind)
    diagnostics = trace_identity_diagnostics(anchor, kind=route_kind)
    lookup_candidates = trace_route_lookup_candidates(candidates, suppress_generic=bool(diagnostics))
    ordered_lookup_candidates = sorted(
        lookup_candidates,
        key=lambda candidate: (
            0
            if str(candidate.get("layer") or "") == route_kind
            else 1
            if str(candidate.get("layer") or "") != "entity"
            else 2,
            str(candidate.get("layer") or ""),
            str(candidate.get("key") or ""),
        ),
    )
    start_node_ids: list[str] = []
    exact_route_node_ids: list[str] = []
    for candidate in ordered_lookup_candidates:
        layer = str(candidate.get("layer") or "")
        key = str(candidate.get("key") or "")
        if key:
            route_node = graph_route_node_id(layer, key)
            row = conn.execute("SELECT id FROM nodes WHERE id = ?", (route_node,)).fetchone()
            if row and route_node not in start_node_ids:
                start_node_ids.append(route_node)
                exact_route_node_ids.append(route_node)
    alias_keys = graph_anchor_alias_keys(anchor)
    if exact_route_node_ids and ":" not in str(anchor or ""):
        return {
            "anchor": anchor,
            **trace_kind_payload_fields(kind, route_kind),
            "aliases": trace_anchor_aliases(anchor),
            "alias_keys": alias_keys,
            "route_candidates": lookup_candidates,
            "start_node_ids": start_node_ids[:limit],
            "resolver_strategy": "exact_route_node",
            "diagnostics": diagnostics,
        }
    if diagnostics and not lookup_candidates:
        return {
            "anchor": anchor,
            **trace_kind_payload_fields(kind, route_kind),
            "aliases": trace_anchor_aliases(anchor),
            "alias_keys": alias_keys,
            "route_candidates": [],
            "start_node_ids": [],
            "resolver_strategy": "identity_diagnostic_no_route",
            "diagnostics": diagnostics,
        }
    scored: list[tuple[int, str]] = []
    like_terms = [f"%{key}%" for key in alias_keys[:8] if key]
    for term in like_terms:
        for row in conn.execute("SELECT id, payload_json, count FROM nodes WHERE id LIKE ? OR payload_json LIKE ? LIMIT 200", (term, term)).fetchall():
            node_id = str(row["id"])
            if node_id in start_node_ids:
                continue
            payload = json.loads(str(row["payload_json"]))
            if isinstance(payload, dict):
                payload["count"] = int_value(row["count"], int_value(payload.get("count"), 1))
                score = graph_node_anchor_score(payload, alias_keys)
                if score:
                    scored.append((score, node_id))
    for _, node_id in sorted(scored, key=lambda item: (-item[0], item[1])):
        if node_id not in start_node_ids:
            start_node_ids.append(node_id)
        if len(start_node_ids) >= limit:
            break
    return {
        "anchor": anchor,
        **trace_kind_payload_fields(kind, route_kind),
        "aliases": trace_anchor_aliases(anchor),
        "alias_keys": alias_keys,
        "route_candidates": lookup_candidates,
        "start_node_ids": start_node_ids[:limit],
        "diagnostics": diagnostics,
    }


def graph_store_neighbor_edge_priority(edge_type: str) -> int:
    return {
        "registry_entity_has_route_signal": 0,
        "mentions_route_signal": 1,
        "segment_has_route_signal": 2,
        "event_mentions_registered_entity": 3,
        "session_has_registered_entity": 4,
        "has_event": 5,
        "answered_by": 5,
        "responds_to": 5,
    }.get(str(edge_type or ""), 6)


def graph_store_neighbor_edge_rows(
    conn: sqlite3.Connection,
    *,
    node_id: str,
    edge_budget: int,
) -> tuple[list[sqlite3.Row], dict[str, Any]]:
    compact_unordered = edge_budget <= 64
    query_limit = max(32, min(200, edge_budget * 8))
    rows: list[sqlite3.Row] = []
    seen: set[str] = set()
    directions: list[dict[str, Any]] = []
    for column in ("source_node", "target_node"):
        if compact_unordered:
            sql = f"""
                SELECT id, source_node, target_node, edge_type, count
                FROM edges
                WHERE {column} = ?
                LIMIT ?
                """
        else:
            sql = f"""
                SELECT id, source_node, target_node, edge_type, count
                FROM edges
                WHERE {column} = ?
                ORDER BY
                  CASE edge_type
                    WHEN 'registry_entity_has_route_signal' THEN 0
                    WHEN 'mentions_route_signal' THEN 1
                    WHEN 'segment_has_route_signal' THEN 2
                    WHEN 'event_mentions_registered_entity' THEN 3
                    WHEN 'session_has_registered_entity' THEN 4
                    WHEN 'has_event' THEN 5
                    WHEN 'answered_by' THEN 5
                    WHEN 'responds_to' THEN 5
                    ELSE 6
                  END,
                  count DESC,
                  id ASC
                LIMIT ?
                """
        fetched = conn.execute(sql, (node_id, query_limit)).fetchall()
        directions.append({"column": column, "fetched_count": len(fetched), "query_limit": query_limit})
        for row in fetched:
            edge_id = str(row["id"])
            if edge_id in seen:
                continue
            seen.add(edge_id)
            rows.append(row)
    rows.sort(key=lambda row: (graph_store_neighbor_edge_priority(str(row["edge_type"])), -int_value(row["count"]), str(row["id"])))
    return rows[: max(query_limit, edge_budget)], {
        "strategy": "split_unordered_compact" if compact_unordered else "split_ordered",
        "query_limit": query_limit,
        "directions": directions,
    }


def graph_from_store_neighborhood(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    depth: int = 1,
    limit: int = 40,
    edge_limit: int | None = None,
) -> dict[str, Any] | None:
    state = graph_store_query_state(aoa_root)
    if state.get("status") != "current":
        return None
    paths = graph_paths(aoa_root)
    try:
        conn = sqlite3.connect(str(paths["store"]))
        conn.row_factory = sqlite3.Row
        resolved = graph_store_resolve_anchor(conn, anchor, kind=kind, limit=max(10, limit))
        if not resolved.get("start_node_ids"):
            conn.close()
            if resolved.get("resolver_strategy") == "identity_diagnostic_no_route":
                return {
                    "schema_version": SCHEMA_VERSION,
                    "artifact_type": "session_memory_bounded_graph",
                    "graph_schema_version": GRAPH_SCHEMA_VERSION,
                    "generated_at": (state.get("metadata") or {}).get("updated_at") or (state.get("metadata") or {}).get("generated_at") or utc_now(),
                    "ok": False,
                    "truth_status": "bounded_graph_from_sqlite_store_not_reviewed_truth",
                    "source": "sqlite_graph_store",
                    "aoa_root": str(aoa_root),
                    "node_count": 0,
                    "edge_count": 0,
                    "nodes": [],
                    "edges": [],
                    "resolved": resolved,
                    "store_state": state,
                    "diagnostics": state.get("diagnostics", []) if isinstance(state.get("diagnostics"), list) else [],
                }
            return None
        depth = max(0, min(int_value(depth, 1), 3))
        limit = max(1, min(int_value(limit, 40), 200))
        default_edge_limit = max(24, min(limit * 4, 160))
        max_edges = max(1, min(int_value(edge_limit, default_edge_limit), 2000))
        selected_nodes: list[str] = []
        selected_edges: list[str] = []
        seen_nodes: set[str] = set()
        seen_edges: set[str] = set()
        omitted_node_count = 0
        omitted_edge_count = 0
        edge_query_strategies: Counter[str] = Counter()
        queue_nodes: deque[tuple[str, int]] = deque((node_id, 0) for node_id in resolved["start_node_ids"])
        while queue_nodes and len(selected_nodes) < limit:
            node_id, distance = queue_nodes.popleft()
            if node_id in seen_nodes:
                continue
            seen_nodes.add(node_id)
            selected_nodes.append(node_id)
            if distance >= depth:
                continue
            edge_rows, edge_query = graph_store_neighbor_edge_rows(conn, node_id=node_id, edge_budget=max_edges)
            edge_query_strategies[str(edge_query.get("strategy") or "unknown")] += 1
            for row in edge_rows:
                edge_id = str(row["id"])
                if edge_id not in seen_edges and len(selected_edges) < max_edges:
                    seen_edges.add(edge_id)
                    selected_edges.append(edge_id)
                elif edge_id not in seen_edges:
                    seen_edges.add(edge_id)
                    omitted_edge_count += 1
                neighbor = str(row["target_node"] if row["source_node"] == node_id else row["source_node"])
                if neighbor not in seen_nodes and len(selected_nodes) + len(queue_nodes) < limit:
                    queue_nodes.append((neighbor, distance + 1))
                elif neighbor not in seen_nodes:
                    omitted_node_count += 1
        nodes = graph_store_fetch_payloads(conn, "nodes", selected_nodes)
        edges = graph_store_fetch_payloads(conn, "edges", selected_edges)
        conn.close()
    except sqlite3.Error:
        return None
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_bounded_graph",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": (state.get("metadata") or {}).get("updated_at") or (state.get("metadata") or {}).get("generated_at") or utc_now(),
        "ok": bool(nodes),
        "truth_status": "bounded_graph_from_sqlite_store_not_reviewed_truth",
        "source": "sqlite_graph_store",
        "aoa_root": str(aoa_root),
        "node_count": len(nodes),
        "edge_count": len(edges),
        "node_limit": limit,
        "edge_limit": max_edges,
        "truncated": bool(queue_nodes or omitted_node_count or omitted_edge_count),
        "omitted_node_count": omitted_node_count + len(queue_nodes),
        "omitted_edge_count": omitted_edge_count,
        "nodes": nodes,
        "edges": edges,
        "resolved": resolved,
        "edge_query_strategies": dict(edge_query_strategies),
        "store_state": state,
        "diagnostics": state.get("diagnostics", []) if isinstance(state.get("diagnostics"), list) else [],
    }


def graph_from_store_timeline_events(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    limit: int = 40,
) -> dict[str, Any] | None:
    state = graph_store_query_state(aoa_root)
    if state.get("status") != "current":
        return None
    paths = graph_paths(aoa_root)
    edge_types = ("mentions_route_signal", "event_mentions_registered_entity", "goal_lifecycle_has_event")
    placeholders = ",".join("?" for _item in edge_types)
    event_limit = max(1, min(int_value(limit, 40), 200))
    edge_fetch_limit = max(event_limit, min(event_limit * 8, 400))
    try:
        conn = sqlite3.connect(str(paths["store"]))
        conn.row_factory = sqlite3.Row
        resolved = graph_store_resolve_anchor(conn, anchor, kind=kind, limit=max(10, event_limit))
        start_node_ids = [str(node_id) for node_id in resolved.get("start_node_ids", []) if node_id]
        event_ids: list[str] = []
        edge_ids: list[str] = []
        seen_events: set[str] = set()
        seen_edges: set[str] = set()
        for node_id in start_node_ids:
            if len(event_ids) >= edge_fetch_limit:
                break
            for column, opposite_column in (("target_node", "source_node"), ("source_node", "target_node")):
                remaining = max(1, edge_fetch_limit - len(event_ids))
                rows = conn.execute(
                    f"""
                    SELECT id, source_node, target_node, edge_type
                    FROM edges
                    WHERE {column} = ?
                      AND edge_type IN ({placeholders})
                    LIMIT ?
                    """,
                    (node_id, *edge_types, remaining),
                ).fetchall()
                for row in rows:
                    edge_id = str(row["id"])
                    candidate = str(row[opposite_column])
                    if not candidate.startswith("event:"):
                        continue
                    if edge_id and edge_id not in seen_edges:
                        seen_edges.add(edge_id)
                        edge_ids.append(edge_id)
                    if candidate not in seen_events:
                        seen_events.add(candidate)
                        event_ids.append(candidate)
                    if len(event_ids) >= edge_fetch_limit:
                        break
                if len(event_ids) >= edge_fetch_limit:
                    break
        nodes = graph_store_fetch_payloads(conn, "nodes", event_ids)
        edges = graph_store_fetch_payloads(conn, "edges", edge_ids)
        conn.close()
    except sqlite3.Error:
        return None
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_bounded_graph",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": (state.get("metadata") or {}).get("updated_at") or (state.get("metadata") or {}).get("generated_at") or utc_now(),
        "ok": bool(nodes),
        "truth_status": "bounded_graph_timeline_from_sqlite_store_not_reviewed_truth",
        "source": "sqlite_graph_store_direct_timeline",
        "aoa_root": str(aoa_root),
        "node_count": len(nodes),
        "edge_count": len(edges),
        "nodes": nodes,
        "edges": edges,
        "resolved": resolved,
        "store_state": state,
        "diagnostics": state.get("diagnostics", []) if isinstance(state.get("diagnostics"), list) else [],
    }


def resolve_graph_anchor(
    graph: dict[str, Any],
    anchor: str,
    *,
    kind: str = "auto",
    limit: int = 40,
) -> dict[str, Any]:
    node_map = graph_node_by_id(graph)
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    candidates = trace_route_candidates(anchor, kind=route_kind)
    diagnostics = trace_identity_diagnostics(anchor, kind=route_kind)
    lookup_candidates = trace_route_lookup_candidates(candidates, suppress_generic=bool(diagnostics))
    ordered_lookup_candidates = sorted(
        lookup_candidates,
        key=lambda candidate: (
            0
            if str(candidate.get("layer") or "") == route_kind
            else 1
            if str(candidate.get("layer") or "") != "entity"
            else 2,
            str(candidate.get("layer") or ""),
            str(candidate.get("key") or ""),
        ),
    )
    start_node_ids: list[str] = []
    exact_route_node_ids: list[str] = []
    scored: list[tuple[int, str]] = []

    for candidate in ordered_lookup_candidates:
        layer = str(candidate.get("layer") or "")
        key = str(candidate.get("key") or "")
        if key:
            route_node = graph_route_node_id(layer, key)
            if route_node in node_map and route_node not in start_node_ids:
                start_node_ids.append(route_node)
                exact_route_node_ids.append(route_node)
        elif layer:
            node_type = graph_route_node_type(layer)
            for node_id, node in node_map.items():
                if node.get("type") == node_type and node.get("route_layer") == layer and node_id not in start_node_ids:
                    start_node_ids.append(node_id)
                    if len(start_node_ids) >= limit:
                        break
    alias_keys = graph_anchor_alias_keys(anchor)
    if exact_route_node_ids and ":" not in str(anchor or ""):
        return {
            "anchor": anchor,
            **trace_kind_payload_fields(kind, route_kind),
            "aliases": trace_anchor_aliases(anchor),
            "alias_keys": alias_keys,
            "route_candidates": lookup_candidates,
            "start_node_ids": exact_route_node_ids[:limit],
            "resolver_strategy": "exact_route_node",
            "diagnostics": diagnostics,
        }
    if diagnostics and not lookup_candidates:
        return {
            "anchor": anchor,
            **trace_kind_payload_fields(kind, route_kind),
            "aliases": trace_anchor_aliases(anchor),
            "alias_keys": alias_keys,
            "route_candidates": [],
            "start_node_ids": [],
            "resolver_strategy": "identity_diagnostic_no_route",
            "diagnostics": diagnostics,
        }

    for node_id, node in node_map.items():
        if node_id in start_node_ids:
            continue
        score = graph_node_anchor_score(node, alias_keys)
        if score:
            scored.append((score, node_id))
    for _, node_id in sorted(scored, key=lambda item: (-item[0], item[1])):
        if node_id not in start_node_ids:
            start_node_ids.append(node_id)
        if len(start_node_ids) >= limit:
            break
    return {
        "anchor": anchor,
        **trace_kind_payload_fields(kind, route_kind),
        "aliases": trace_anchor_aliases(anchor),
        "alias_keys": alias_keys,
        "route_candidates": lookup_candidates,
        "start_node_ids": start_node_ids[:limit],
        "diagnostics": diagnostics,
    }


def graph_adjacency(edges: list[dict[str, Any]]) -> dict[str, list[tuple[str, str]]]:
    adjacency: dict[str, list[tuple[str, str]]] = defaultdict(list)
    for edge in edges:
        if not isinstance(edge, dict):
            continue
        source = str(edge.get("source") or "")
        target = str(edge.get("target") or "")
        edge_id = str(edge.get("id") or "")
        if not source or not target:
            continue
        adjacency[source].append((target, edge_id))
        adjacency[target].append((source, edge_id))
    return adjacency


def graph_expand_node_ids(
    start_node_ids: list[str],
    *,
    edges: list[dict[str, Any]],
    depth: int,
    max_nodes: int,
    max_edges: int | None = None,
) -> tuple[list[str], list[str], dict[str, int | bool]]:
    adjacency = graph_adjacency(edges)
    selected_nodes: list[str] = []
    selected_edges: list[str] = []
    seen_nodes: set[str] = set()
    seen_edges: set[str] = set()
    edge_budget = max(1, min(int_value(max_edges, max(24, min(max_nodes * 4, 160))), 2000))
    omitted_node_count = 0
    omitted_edge_count = 0
    queue: deque[tuple[str, int]] = deque((node_id, 0) for node_id in start_node_ids)
    while queue and len(selected_nodes) < max_nodes:
        node_id, distance = queue.popleft()
        if node_id in seen_nodes:
            continue
        seen_nodes.add(node_id)
        selected_nodes.append(node_id)
        if distance >= depth:
            continue
        for neighbor, edge_id in adjacency.get(node_id, []):
            if edge_id and edge_id not in seen_edges and len(selected_edges) < edge_budget:
                seen_edges.add(edge_id)
                selected_edges.append(edge_id)
            elif edge_id and edge_id not in seen_edges:
                seen_edges.add(edge_id)
                omitted_edge_count += 1
            if neighbor not in seen_nodes and len(selected_nodes) + len(queue) < max_nodes:
                queue.append((neighbor, distance + 1))
            elif neighbor not in seen_nodes:
                omitted_node_count += 1
    return selected_nodes, selected_edges, {
        "edge_limit": edge_budget,
        "truncated": bool(queue or omitted_node_count or omitted_edge_count),
        "omitted_node_count": omitted_node_count + len(queue),
        "omitted_edge_count": omitted_edge_count,
    }


def graph_collect_evidence(
    nodes: list[dict[str, Any]],
    edges: list[dict[str, Any]],
    *,
    limit: int = 50,
) -> list[Any]:
    evidence: list[Any] = []
    for item in [*nodes, *edges]:
        if not isinstance(item, dict):
            continue
        if isinstance(item.get("evidence_refs"), list):
            evidence.extend(item["evidence_refs"])
        refs = item.get("refs")
        if isinstance(refs, dict) and refs:
            evidence.append({"node_id": item.get("id"), "refs": refs})
    return graph_unique_records(evidence, limit=limit)


def graph_compact_node_for_packet(node: dict[str, Any], *, evidence_limit: int = 3) -> dict[str, Any]:
    compact = dict(node)
    if isinstance(compact.get("evidence_refs"), list):
        if not isinstance(compact.get("refs"), dict) or not compact.get("refs"):
            for ref in compact["evidence_refs"]:
                refs = ref.get("refs") if isinstance(ref, dict) and isinstance(ref.get("refs"), dict) else {}
                if refs:
                    compact["refs"] = refs
                    break
        compact["evidence_refs"] = compact["evidence_refs"][:evidence_limit]
        if len(node.get("evidence_refs", [])) > evidence_limit:
            compact["evidence_ref_count"] = len(node.get("evidence_refs", []))
    if isinstance(compact.get("route_signals"), list):
        compact["route_signals"] = compact["route_signals"][:20]
    return compact


def graph_compact_edge_for_packet(edge: dict[str, Any], *, evidence_limit: int = 2) -> dict[str, Any]:
    compact = dict(edge)
    if isinstance(compact.get("evidence_refs"), list):
        compact["evidence_refs"] = compact["evidence_refs"][:evidence_limit]
        if len(edge.get("evidence_refs", [])) > evidence_limit:
            compact["evidence_ref_count"] = len(edge.get("evidence_refs", []))
    return compact


def graph_route_signals_from_values(value: Any) -> list[dict[str, str]]:
    if isinstance(value, str):
        tokens = value.strip("|").split("|")
    elif isinstance(value, (list, tuple)):
        tokens = [str(item) for item in value if item]
    else:
        tokens = []
    signals: list[dict[str, str]] = []
    for token in tokens:
        if ":" not in token:
            continue
        layer, key = token.split(":", 1)
        layer_slug = route_key_slug(layer, fallback="")
        key_slug = route_key_slug(key, fallback="")
        if layer_slug and key_slug:
            signals.append({"layer": layer_slug, "key": key_slug, "route_signal": route_signal_token(layer_slug, key_slug)})
    return graph_unique_records(signals, limit=80)


def graph_event_node_from_usage_event(event: dict[str, Any]) -> dict[str, Any]:
    refs = event.get("refs") if isinstance(event.get("refs"), dict) else {}
    session_id = str(event.get("session_id") or "")
    segment_id = str(event.get("segment_id") or "")
    event_id = str(event.get("event_id") or "")
    doc_id = str(event.get("doc_id") or "")
    node_id = doc_id if doc_id.startswith("event:") else f"event:{session_id}:{segment_id}:{event_id or route_key_slug(doc_id, fallback='event')}"
    evidence_ref = {
        "session_id": session_id,
        "segment_id": segment_id,
        "event_id": event_id,
        "doc_id": doc_id,
        "refs": refs,
    }
    return {
        "id": node_id,
        "type": "event",
        "label": event.get("title") or doc_id or event_id,
        "title": event.get("title"),
        "session_id": session_id,
        "session_label": event.get("session_label"),
        "session_date": event.get("session_date"),
        "segment_id": segment_id,
        "event_id": event_id,
        "event_type": event.get("event_type"),
        "family": event.get("family"),
        "phase": event.get("phase"),
        "actor": event.get("actor"),
        "action": event.get("action"),
        "outcome": event.get("outcome"),
        "conversation_act": event.get("conversation_act"),
        "session_act": event.get("session_act"),
        "role": event.get("role"),
        "source": event.get("source"),
        "relation": event.get("relation"),
        "distance": event.get("distance"),
        "timestamp": event.get("timestamp") or event.get("session_date"),
        "line": line_from_raw_ref(refs.get("raw")),
        "matched_routes": event.get("matched_routes", []) if isinstance(event.get("matched_routes"), list) else [],
        "route_signals": graph_route_signals_from_values(event.get("route_signals")),
        "refs": refs,
        "freshness": event.get("freshness"),
        "evidence_refs": [evidence_ref],
    }


def graph_route_signals_from_pipe(value: Any) -> list[dict[str, str]]:
    return graph_route_signals_from_values(value)


def graph_from_search_results(
    *,
    aoa_root: Path,
    hits: list[dict[str, Any]],
    source: str,
    route_candidates: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    nodes: dict[str, dict[str, Any]] = {}
    edges: dict[str, dict[str, Any]] = {}
    now = utc_now()
    for hit in hits:
        if not isinstance(hit, dict):
            continue
        doc_id = str(hit.get("doc_id") or "")
        session_id = str(hit.get("session_id") or "")
        session_label = str(hit.get("session_label") or session_id)
        segment_id = str(hit.get("segment_id") or "")
        event_id = str(hit.get("event_id") or "")
        parts = doc_id.split(":")
        if not session_id and len(parts) >= 2:
            session_id = parts[1]
        if not segment_id and len(parts) >= 3:
            segment_id = parts[2]
        if not event_id and len(parts) >= 4:
            event_id = parts[3]
        refs = hit.get("refs") if isinstance(hit.get("refs"), dict) else {}
        session_node_id = f"session:{session_id or session_label or 'unknown'}"
        graph_add_node(
            nodes,
            {
                "id": session_node_id,
                "type": "session",
                "label": session_label,
                "session_id": session_id,
                "session_label": session_label,
                "refs": {"session": refs.get("session")} if refs.get("session") else {},
                "evidence_refs": [{"session_id": session_id, "refs": refs}],
            },
        )
        parent_node_id = session_node_id
        if segment_id:
            segment_node_id = f"segment:{session_id}:{segment_id}"
            graph_add_node(
                nodes,
                {
                    "id": segment_node_id,
                    "type": "segment",
                    "label": f"{session_label} segment {segment_id}",
                    "session_id": session_id,
                    "session_label": session_label,
                    "segment_id": segment_id,
                    "refs": {key: refs.get(key) for key in ("session", "session_index", "segment", "segment_index") if refs.get(key)},
                    "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "refs": refs}],
                },
            )
            graph_add_edge(
                edges,
                {
                    "source": session_node_id,
                    "target": segment_node_id,
                    "type": "has_segment",
                    "session_id": session_id,
                    "segment_id": segment_id,
                    "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "refs": refs}],
                },
            )
            parent_node_id = segment_node_id
        event_node_id = doc_id if doc_id.startswith("event:") else f"event:{session_id}:{segment_id}:{event_id or route_key_slug(doc_id, fallback='event')}"
        graph_add_node(
            nodes,
            {
                "id": event_node_id,
                "type": "event" if str(hit.get("doc_type") or "") == "event" else str(hit.get("doc_type") or "search_hit"),
                "label": hit.get("title") or doc_id,
                "title": hit.get("title"),
                "session_id": session_id,
                "session_label": session_label,
                "segment_id": segment_id,
                "event_id": event_id,
                "event_type": hit.get("event_type"),
                "family": hit.get("family"),
                "phase": hit.get("phase"),
                "actor": hit.get("actor"),
                "action": hit.get("action"),
                "outcome": hit.get("outcome"),
                "conversation_act": hit.get("conversation_act"),
                "session_act": hit.get("session_act"),
                "route_signals": graph_route_signals_from_pipe(hit.get("route_signals")),
                "refs": refs,
                "freshness": hit.get("freshness"),
                "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "event_id": event_id, "refs": refs}],
            },
        )
        graph_add_edge(
            edges,
            {
                "source": parent_node_id,
                "target": event_node_id,
                "type": "has_event",
                "session_id": session_id,
                "segment_id": segment_id,
                "event_id": event_id,
                "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "event_id": event_id, "refs": refs}],
            },
        )
        if refs.get("raw") and GRAPH_MATERIALIZE_RAW_REF_NODES:
            raw_node_id = graph_raw_ref_node_id(session_id, str(refs.get("raw")))
            graph_add_node(
                nodes,
                {
                    "id": raw_node_id,
                    "type": "raw_ref",
                    "label": refs.get("raw"),
                    "session_id": session_id,
                    "session_label": session_label,
                    "raw_ref": refs.get("raw"),
                    "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "event_id": event_id, "refs": refs}],
                },
            )
            graph_add_edge(
                edges,
                {
                    "source": event_node_id,
                    "target": raw_node_id,
                    "type": "has_raw_ref",
                    "session_id": session_id,
                    "segment_id": segment_id,
                    "event_id": event_id,
                    "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "event_id": event_id, "refs": refs}],
                },
            )
        signals = graph_route_signals_from_pipe(hit.get("route_signals"))
        if not signals and route_candidates:
            for candidate in route_candidates:
                if isinstance(candidate, dict) and candidate.get("layer") and candidate.get("key"):
                    signals.append(
                        {
                            "layer": route_key_slug(candidate.get("layer"), fallback=""),
                            "key": route_key_slug(candidate.get("key"), fallback=""),
                            "route_signal": str(candidate.get("route_signal") or ""),
                        }
                    )
        for signal in graph_unique_records(signals, limit=80):
            if not isinstance(signal, dict) or not signal.get("layer") or not signal.get("key"):
                continue
            route_node_id = graph_route_node_id(str(signal["layer"]), str(signal["key"]))
            graph_add_node(
                nodes,
                {
                    "id": route_node_id,
                    "type": graph_route_node_type(str(signal["layer"]), str(signal["key"])),
                    "label": signal.get("route_signal") or route_signal_token(str(signal["layer"]), str(signal["key"])),
                    "route_layer": signal["layer"],
                    "route_key": signal["key"],
                    "route_signal": signal.get("route_signal") or route_signal_token(str(signal["layer"]), str(signal["key"])),
                    "axis": ROUTE_SIGNAL_LAYER_TO_AXIS.get(str(signal["layer"]), ""),
                    "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "event_id": event_id, "refs": refs}],
                },
            )
            graph_add_edge(
                edges,
                {
                    "source": event_node_id,
                    "target": route_node_id,
                    "type": "mentions_route_signal",
                    "session_id": session_id,
                    "segment_id": segment_id,
                    "event_id": event_id,
                    "route_signal": signal.get("route_signal") or route_signal_token(str(signal["layer"]), str(signal["key"])),
                    "evidence_refs": [{"session_id": session_id, "segment_id": segment_id, "event_id": event_id, "refs": refs}],
                },
            )
    node_rows = sorted(nodes.values(), key=lambda item: str(item.get("id") or ""))
    edge_rows = sorted(edges.values(), key=lambda item: str(item.get("id") or ""))
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_bounded_graph",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": now,
        "ok": bool(node_rows),
        "truth_status": "bounded_graph_from_search_hits_not_reviewed_truth",
        "source": source,
        "aoa_root": str(aoa_root),
        "node_count": len(node_rows),
        "edge_count": len(edge_rows),
        "nodes": node_rows,
        "edges": edge_rows,
        "diagnostics": [],
    }


def graph_packet_cli_kind(kind: str, route_kind: str) -> str:
    requested = str(kind or "").strip()
    if requested in TRACE_ROUTE_KIND_CHOICES:
        return requested
    if route_kind in TRACE_ROUTE_KIND_CHOICES:
        return route_kind
    return "auto"


def graph_packet_expanded_limit(value: Any, *, default: int, maximum: int) -> int:
    current = int_value(value, default)
    current = max(1, current)
    return min(maximum, max(current + max(8, current // 2), current * 2))


def graph_packet_command_line(
    *,
    aoa_root: Path,
    command_name: str,
    anchors: list[str],
    kind: str,
    route_kind: str,
    limit: int | None = None,
    depth: int | None = None,
    edge_limit: int | None = None,
    max_depth: int | None = None,
) -> str:
    command = ["python3", "scripts/aoa_session_memory.py", command_name, *[str(anchor) for anchor in anchors], "--aoa-root", str(aoa_root)]
    command.extend(["--kind", graph_packet_cli_kind(kind, route_kind)])
    if depth is not None:
        command.extend(["--depth", str(max(0, min(int_value(depth, 1), 3)))])
    if limit is not None:
        command.extend(["--limit", str(max(1, int_value(limit, 40)))])
    if edge_limit is not None:
        command.extend(["--edge-limit", str(max(1, int_value(edge_limit, 24)))])
    if max_depth is not None:
        command.extend(["--max-depth", str(max(1, min(int_value(max_depth, 4), 8)))])
    return " ".join(shlex.quote(part) for part in command)


def graph_neighborhood(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    depth: int = 1,
    limit: int = 40,
    edge_limit: int | None = None,
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    store_graph = graph_from_store_neighborhood(
        aoa_root=aoa_root,
        anchor=anchor,
        kind=route_kind,
        depth=depth,
        limit=limit,
        edge_limit=edge_limit,
    )
    if store_graph is not None and (store_graph.get("ok") or (isinstance(store_graph.get("resolved"), dict) and store_graph["resolved"].get("resolver_strategy") == "identity_diagnostic_no_route")):
        nodes = store_graph.get("nodes", []) if isinstance(store_graph.get("nodes"), list) else []
        edges = store_graph.get("edges", []) if isinstance(store_graph.get("edges"), list) else []
        evidence_ref_limit = max(12, min(int_value(store_graph.get("edge_limit"), 24) * 2, 50))
        evidence_refs = graph_collect_evidence(nodes, edges, limit=evidence_ref_limit)
        resolved = store_graph.get("resolved") if isinstance(store_graph.get("resolved"), dict) else {}
        current_command = graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-neighborhood",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            depth=max(0, min(int_value(depth, 1), 3)),
            limit=int_value(store_graph.get("node_limit"), limit),
            edge_limit=int_value(store_graph.get("edge_limit")) if store_graph.get("edge_limit") is not None else None,
        )
        expansion_command = graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-neighborhood",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            depth=min(max(0, min(int_value(depth, 1), 3)) + 1, 3),
            limit=graph_packet_expanded_limit(store_graph.get("node_limit"), default=limit, maximum=200),
            edge_limit=graph_packet_expanded_limit(store_graph.get("edge_limit"), default=edge_limit or 24, maximum=400),
        )
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "session_memory_graph_neighborhood",
            "graph_schema_version": GRAPH_SCHEMA_VERSION,
            "generated_at": utc_now(),
            "ok": bool(nodes),
            "mutates": False,
            "truth_status": "graph_route_packet_not_reviewed_truth",
            "anchor": anchor,
            **trace_kind_payload_fields(kind, route_kind),
            "depth": max(0, min(int_value(depth, 1), 3)),
            "resolved": resolved,
            "graph": {
                "source": store_graph.get("source"),
                "generated_at": store_graph.get("generated_at"),
                "node_count": store_graph.get("node_count"),
                "edge_count": store_graph.get("edge_count"),
            },
            "node_count": len(nodes),
            "edge_count": len(edges),
            "node_limit": store_graph.get("node_limit"),
            "edge_limit": store_graph.get("edge_limit"),
            "truncated": bool(store_graph.get("truncated")),
            "omitted_node_count": store_graph.get("omitted_node_count"),
            "omitted_edge_count": store_graph.get("omitted_edge_count"),
            "edge_query_strategies": store_graph.get("edge_query_strategies") if isinstance(store_graph.get("edge_query_strategies"), dict) else {},
            "evidence_ref_limit": evidence_ref_limit,
            "nodes": [graph_compact_node_for_packet(node) for node in nodes],
            "edges": [graph_compact_edge_for_packet(edge) for edge in edges],
            "evidence_refs": evidence_refs,
            "freshness": graph_freshness(aoa_root, store_graph),
            "diagnostics": [
                *(store_graph.get("diagnostics", []) if isinstance(store_graph.get("diagnostics"), list) else []),
                *(resolved.get("diagnostics", []) if isinstance(resolved.get("diagnostics"), list) else []),
            ],
            "next_route": "verify important claims through raw_ref, segment_ref, and session_ref before promotion",
            "next_command": current_command,
            "next_expansion_command": expansion_command,
            "next_expansion_reason": "Increase bounded graph depth/limits when the packet is truncated or more neighboring relations are needed.",
        }
    trace = trace_route(
        aoa_root=aoa_root,
        anchor=anchor,
        kind=route_kind,
        limit=max(1, min(int_value(limit, 40), 200)),
        per_route_limit=max(5, min(int_value(limit, 40), 50)),
        doc_type="event",
        explain=True,
    )
    hits = trace.get("results", []) if isinstance(trace.get("results"), list) else []
    trace_diagnostics = trace.get("diagnostics", []) if isinstance(trace.get("diagnostics"), list) else []
    trace_identity_blocked = any(str(item).startswith("unknown_mcp_service_identity:") for item in trace_diagnostics)
    if not hits and not trace_identity_blocked:
        fallback = search_sessions(aoa_root=aoa_root, query=anchor, limit=max(1, min(int_value(limit, 40), 100)), doc_type="event", explain=True)
        hits = fallback.get("results", []) if isinstance(fallback.get("results"), list) else []
    graph = graph_from_search_results(
        aoa_root=aoa_root,
        hits=hits,
        source="bounded_trace_search",
        route_candidates=trace.get("route_candidates", []) if isinstance(trace.get("route_candidates"), list) else [],
    )
    node_map = graph_node_by_id(graph)
    edge_map = graph_edge_by_id(graph)
    resolved = resolve_graph_anchor(graph, anchor, kind=route_kind, limit=max(10, limit))
    if not resolved.get("start_node_ids") and resolved.get("resolver_strategy") != "identity_diagnostic_no_route":
        resolved["start_node_ids"] = [str(node.get("id")) for node in graph.get("nodes", [])[: max(1, min(limit, 20))] if isinstance(node, dict)]
    depth = max(0, min(int_value(depth, 1), 3))
    limit = max(1, min(int_value(limit, 40), 200))
    selected_node_ids, selected_edge_ids, expansion_quality = graph_expand_node_ids(
        resolved["start_node_ids"],
        edges=graph.get("edges", []) if isinstance(graph.get("edges"), list) else [],
        depth=depth,
        max_nodes=limit,
        max_edges=edge_limit,
    )
    nodes = [node_map[node_id] for node_id in selected_node_ids if node_id in node_map]
    edges = [edge_map[edge_id] for edge_id in selected_edge_ids if edge_id in edge_map]
    evidence_ref_limit = max(12, min(int_value(expansion_quality.get("edge_limit"), 24) * 2, 50))
    evidence_refs = graph_collect_evidence(nodes, edges, limit=evidence_ref_limit)
    current_command = graph_packet_command_line(
        aoa_root=aoa_root,
        command_name="graph-neighborhood",
        anchors=[anchor],
        kind=kind,
        route_kind=route_kind,
        depth=depth,
        limit=limit,
        edge_limit=expansion_quality.get("edge_limit"),
    )
    expansion_command = graph_packet_command_line(
        aoa_root=aoa_root,
        command_name="graph-neighborhood",
        anchors=[anchor],
        kind=kind,
        route_kind=route_kind,
        depth=min(depth + 1, 3),
        limit=graph_packet_expanded_limit(limit, default=limit, maximum=200),
        edge_limit=graph_packet_expanded_limit(expansion_quality.get("edge_limit"), default=edge_limit or 24, maximum=400),
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_neighborhood",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(nodes),
        "mutates": False,
        "truth_status": "graph_route_packet_not_reviewed_truth",
        "anchor": anchor,
        **trace_kind_payload_fields(kind, route_kind),
        "depth": depth,
        "resolved": resolved,
        "graph": {
            "source": graph.get("source"),
            "generated_at": graph.get("generated_at"),
            "node_count": graph.get("node_count"),
            "edge_count": graph.get("edge_count"),
        },
        "node_count": len(nodes),
        "edge_count": len(edges),
        "node_limit": limit,
        "edge_limit": expansion_quality.get("edge_limit"),
        "truncated": bool(expansion_quality.get("truncated")),
        "omitted_node_count": expansion_quality.get("omitted_node_count"),
        "omitted_edge_count": expansion_quality.get("omitted_edge_count"),
        "evidence_ref_limit": evidence_ref_limit,
        "nodes": [graph_compact_node_for_packet(node) for node in nodes],
        "edges": [graph_compact_edge_for_packet(edge) for edge in edges],
        "evidence_refs": evidence_refs,
        "freshness": {
            **graph_freshness(aoa_root, graph),
            "trace_result_count": trace.get("result_count"),
            "trace_ok": trace.get("ok"),
        },
        "diagnostics": [
            *(graph.get("diagnostics", []) if isinstance(graph.get("diagnostics"), list) else []),
            *(trace.get("diagnostics", []) if isinstance(trace.get("diagnostics"), list) else []),
            *(resolved.get("diagnostics", []) if isinstance(resolved.get("diagnostics"), list) else []),
        ],
        "next_route": "verify important claims through raw_ref, segment_ref, and session_ref before promotion",
        "next_command": current_command,
        "next_expansion_command": expansion_command,
        "next_expansion_reason": "Increase bounded graph depth/limits when the packet is truncated or more neighboring relations are needed.",
    }


def graph_timeline(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    limit: int = 40,
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    event_limit = max(1, min(int_value(limit, 40), 200))
    neighborhood_limit = max(event_limit * 4, min(60, event_limit + 12))
    direct_packet = graph_from_store_timeline_events(aoa_root=aoa_root, anchor=anchor, kind=route_kind, limit=event_limit)
    if direct_packet is not None and (
        direct_packet.get("ok")
        or (isinstance(direct_packet.get("resolved"), dict) and direct_packet["resolved"].get("start_node_ids"))
    ):
        direct_nodes = direct_packet.get("nodes", []) if isinstance(direct_packet.get("nodes"), list) else []
        direct_edges = direct_packet.get("edges", []) if isinstance(direct_packet.get("edges"), list) else []
        packet = {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "session_memory_graph_neighborhood",
            "graph_schema_version": GRAPH_SCHEMA_VERSION,
            "generated_at": utc_now(),
            "ok": bool(direct_nodes),
            "mutates": False,
            "truth_status": "graph_route_packet_not_reviewed_truth",
            "anchor": anchor,
            **trace_kind_payload_fields(kind, route_kind),
            "depth": 1,
            "resolved": direct_packet.get("resolved") if isinstance(direct_packet.get("resolved"), dict) else {},
            "graph": {
                "source": direct_packet.get("source"),
                "generated_at": direct_packet.get("generated_at"),
                "node_count": direct_packet.get("node_count"),
                "edge_count": direct_packet.get("edge_count"),
            },
            "node_count": len(direct_nodes),
            "edge_count": len(direct_edges),
            "nodes": [graph_compact_node_for_packet(node) for node in direct_nodes],
            "edges": [graph_compact_edge_for_packet(edge) for edge in direct_edges],
            "evidence_refs": graph_collect_evidence(direct_nodes, direct_edges),
            "freshness": graph_freshness(aoa_root, direct_packet),
            "diagnostics": direct_packet.get("diagnostics", []) if isinstance(direct_packet.get("diagnostics"), list) else [],
            "next_route": "verify important claims through raw_ref, segment_ref, and session_ref before promotion",
        }
    else:
        packet = graph_neighborhood(aoa_root=aoa_root, anchor=anchor, kind=route_kind, depth=2, limit=neighborhood_limit)
    events = [node for node in packet.get("nodes", []) if isinstance(node, dict) and node.get("type") == "event"]
    resolved = packet.get("resolved") if isinstance(packet.get("resolved"), dict) else {}
    if resolved.get("resolver_strategy") == "exact_route_node":
        start_node_ids = {str(node_id) for node_id in resolved.get("start_node_ids", []) if node_id}
        direct_event_ids: set[str] = set()
        for edge in packet.get("edges", []) if isinstance(packet.get("edges"), list) else []:
            if not isinstance(edge, dict):
                continue
            source = str(edge.get("source") or "")
            target = str(edge.get("target") or "")
            if source in start_node_ids and target.startswith("event:"):
                direct_event_ids.add(target)
            if target in start_node_ids and source.startswith("event:"):
                direct_event_ids.add(source)
        if direct_event_ids:
            events = [event for event in events if str(event.get("id") or "") in direct_event_ids]
    events.sort(key=lambda node: (str(node.get("timestamp") or ""), str(node.get("session_label") or ""), int_value(node.get("line")), str(node.get("event_id") or "")))
    selected = events[:event_limit]
    evidence_refs = graph_collect_evidence(selected, [], limit=80)
    packet_graph = packet.get("graph") if isinstance(packet.get("graph"), dict) else {}
    packet_graph_source = str(packet_graph.get("source") or "")
    timeline_source = "sqlite_graph_store_direct_timeline" if packet_graph_source == "sqlite_graph_store_direct_timeline" else "graph_neighborhood"
    provider_summary: dict[str, Any] = {}
    quality: dict[str, Any] = {}
    freshness = packet.get("freshness")
    diagnostics = packet.get("diagnostics", []) if isinstance(packet.get("diagnostics"), list) else []
    if not selected and resolved.get("start_node_ids"):
        audit_limit = event_limit
        usage_audit = entity_usage_audit(
            aoa_root=aoa_root,
            anchor=anchor,
            kind=route_kind,
            limit=audit_limit,
            per_route_limit=max(audit_limit, min(audit_limit * 2, 100)),
            consequence_window=2,
            document_limit=40,
        )
        fallback_nodes: list[dict[str, Any]] = []
        seen_node_ids: set[str] = set()
        for bucket in (
            "usage_events",
            "result_events",
            "outcome_events",
            "entrypoint_events",
            "context_events",
            "consequence_events",
        ):
            for event in usage_audit.get(bucket, []) if isinstance(usage_audit.get(bucket), list) else []:
                if not isinstance(event, dict):
                    continue
                node = graph_event_node_from_usage_event(event)
                node_id = str(node.get("id") or "")
                if not node_id or node_id in seen_node_ids:
                    continue
                seen_node_ids.add(node_id)
                fallback_nodes.append(node)
        fallback_nodes.sort(key=lambda node: (str(node.get("timestamp") or ""), str(node.get("session_label") or ""), int_value(node.get("line")), str(node.get("event_id") or "")))
        selected = fallback_nodes[:audit_limit]
        evidence_refs = graph_collect_evidence(selected, [], limit=80)
        if selected:
            timeline_source = "entity_usage_audit_fallback"
            provider = usage_audit.get("provider") if isinstance(usage_audit.get("provider"), dict) else {}
            provider_summary = compact_search_provider_status_for_route(provider, provider_name="portable_sqlite") if provider else {}
            provider_payload = provider_summary.get("providers", {}).get("portable_sqlite") if isinstance(provider_summary.get("providers"), dict) else {}
            provider_freshness = provider_payload.get("freshness") if isinstance(provider_payload, dict) else {}
            freshness = {
                "status": "usage_route_current",
                "timeline_source": timeline_source,
                "graph_status": (packet.get("freshness") or {}).get("status") if isinstance(packet.get("freshness"), dict) else None,
                "graph_source": (packet.get("freshness") or {}).get("graph_source") if isinstance(packet.get("freshness"), dict) else None,
                "graph_event_node_status": "missing_in_graph_neighborhood",
                "search_provider_status": provider_payload.get("status") if isinstance(provider_payload, dict) else None,
                "search_provider_freshness_status": provider_freshness.get("status") if isinstance(provider_freshness, dict) else None,
                "law": "timeline fallback routes through usage events; raw/segment refs remain stronger than graph packets",
            }
            usage_quality = usage_audit.get("quality") if isinstance(usage_audit.get("quality"), dict) else {}
            quality = {
                "fallback_source": "entity_usage_audit",
                "usage_event_count": usage_audit.get("usage_event_count"),
                "consequence_event_count": usage_audit.get("consequence_event_count"),
                "direct_usage_present": usage_quality.get("direct_usage_present"),
                "consequence_present": usage_quality.get("consequence_present"),
                "fresh_event_count": usage_quality.get("fresh_event_count"),
                "stale_event_count": usage_quality.get("stale_event_count"),
                "unverifiable_event_count": usage_quality.get("unverifiable_event_count"),
                "usage_role_fast_path_applied": usage_quality.get("usage_role_fast_path_applied"),
                "search_has_route_index": usage_quality.get("search_has_route_index"),
                "search_has_route_terms": usage_quality.get("search_has_route_terms"),
            }
            diagnostics = [
                *diagnostics,
                *(usage_audit.get("diagnostics", []) if isinstance(usage_audit.get("diagnostics"), list) else []),
                "graph_timeline_event_nodes_missing_used_entity_usage_fallback",
            ]
        else:
            diagnostics = [
                *diagnostics,
                *(usage_audit.get("diagnostics", []) if isinstance(usage_audit.get("diagnostics"), list) else []),
                "graph_timeline_event_nodes_missing_usage_fallback_empty",
            ]
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_timeline",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(selected),
        "mutates": False,
        "truth_status": "graph_timeline_packet_not_reviewed_truth",
        "anchor": anchor,
        **trace_kind_payload_fields(kind, route_kind),
        "timeline_source": timeline_source,
        "event_count": len(selected),
        "events": [graph_compact_node_for_packet(event) for event in selected],
        "resolved": resolved,
        "evidence_refs": evidence_refs,
        "freshness": freshness,
        "diagnostics": diagnostics,
        "next_route": "verify important claims through raw_ref, segment_ref, and session_ref before promotion",
        "next_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-timeline",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            limit=event_limit,
        ),
        "next_expansion_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-timeline",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            limit=graph_packet_expanded_limit(event_limit, default=event_limit, maximum=200),
        ),
        "next_expansion_reason": "Increase the bounded timeline limit when more event ordering evidence is needed.",
    }
    if provider_summary:
        payload["provider"] = provider_summary
    if quality:
        payload["quality"] = quality
    return payload


def graph_shortest_path(
    *,
    aoa_root: Path,
    source_anchor: str,
    target_anchor: str,
    kind: str = "auto",
    max_depth: int = 4,
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    source_packet = graph_neighborhood(aoa_root=aoa_root, anchor=source_anchor, kind=route_kind, depth=2, limit=80)
    target_packet = graph_neighborhood(aoa_root=aoa_root, anchor=target_anchor, kind=route_kind, depth=2, limit=80)
    graph = {
        "source": "bounded_shortest_path_union",
        "generated_at": utc_now(),
        "nodes": graph_unique_records(
            [
                *(source_packet.get("nodes", []) if isinstance(source_packet.get("nodes"), list) else []),
                *(target_packet.get("nodes", []) if isinstance(target_packet.get("nodes"), list) else []),
            ],
            limit=200,
        ),
        "edges": graph_unique_records(
            [
                *(source_packet.get("edges", []) if isinstance(source_packet.get("edges"), list) else []),
                *(target_packet.get("edges", []) if isinstance(target_packet.get("edges"), list) else []),
            ],
            limit=300,
        ),
        "diagnostics": [
            *(source_packet.get("diagnostics", []) if isinstance(source_packet.get("diagnostics"), list) else []),
            *(target_packet.get("diagnostics", []) if isinstance(target_packet.get("diagnostics"), list) else []),
        ],
    }
    node_map = graph_node_by_id(graph)
    edge_map = graph_edge_by_id(graph)
    source = resolve_graph_anchor(graph, source_anchor, kind=route_kind, limit=30)
    target = resolve_graph_anchor(graph, target_anchor, kind=route_kind, limit=30)
    target_ids = set(target.get("start_node_ids", []))
    adjacency = graph_adjacency(graph.get("edges", []) if isinstance(graph.get("edges"), list) else [])
    max_depth = max(1, min(int_value(max_depth, 4), 8))
    queue: deque[tuple[str, list[str], list[str]]] = deque((node_id, [node_id], []) for node_id in source.get("start_node_ids", []))
    seen: set[str] = set()
    found_nodes: list[str] = []
    found_edges: list[str] = []
    while queue:
        node_id, path_nodes, path_edges = queue.popleft()
        if node_id in seen:
            continue
        seen.add(node_id)
        if node_id in target_ids:
            found_nodes = path_nodes
            found_edges = path_edges
            break
        if len(path_edges) >= max_depth:
            continue
        for neighbor, edge_id in adjacency.get(node_id, []):
            if neighbor in path_nodes:
                continue
            queue.append((neighbor, [*path_nodes, neighbor], [*path_edges, edge_id]))
    nodes = [node_map[node_id] for node_id in found_nodes if node_id in node_map]
    edges = [edge_map[edge_id] for edge_id in found_edges if edge_id in edge_map]
    evidence_refs = graph_collect_evidence(nodes, edges)
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_shortest_path",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(found_nodes),
        "mutates": False,
        "truth_status": "graph_path_packet_not_reviewed_truth",
        "source_anchor": source_anchor,
        "target_anchor": target_anchor,
        "source_resolved": source,
        "target_resolved": target,
        "max_depth": max_depth,
        "path_length": len(edges) if edges else 0,
        "nodes": [graph_compact_node_for_packet(node) for node in nodes],
        "edges": [graph_compact_edge_for_packet(edge) for edge in edges],
        "evidence_refs": evidence_refs,
        "freshness": graph_freshness(aoa_root, graph),
        "diagnostics": graph.get("diagnostics", []),
        "next_route": "verify path claims through raw_ref, segment_ref, and session_ref before promotion",
        "next_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-shortest-path",
            anchors=[source_anchor, target_anchor],
            kind=kind,
            route_kind=route_kind,
            max_depth=max_depth,
        ),
        "next_expansion_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-shortest-path",
            anchors=[source_anchor, target_anchor],
            kind=kind,
            route_kind=route_kind,
            max_depth=min(max_depth + 1, 8),
        ),
        "next_expansion_reason": "Increase bounded max depth when no bridge is found or a longer relation chain is acceptable.",
    }


def graph_shortest_path_from_packets(
    *,
    aoa_root: Path,
    source_anchor: str,
    target_anchor: str,
    source_packet: dict[str, Any],
    target_packet: dict[str, Any],
    kind: str = "auto",
    source_kind: str = "auto",
    target_kind: str = "auto",
    max_depth: int = 4,
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    source_route_kind = normalize_trace_route_kind(source_kind)
    if source_route_kind not in TRACE_ROUTE_KINDS:
        source_route_kind = route_kind
    target_route_kind = normalize_trace_route_kind(target_kind)
    if target_route_kind not in TRACE_ROUTE_KINDS:
        target_route_kind = route_kind
    graph = {
        "source": "bounded_shortest_path_side_neighborhoods",
        "generated_at": utc_now(),
        "nodes": graph_unique_records(
            [
                *(source_packet.get("nodes", []) if isinstance(source_packet.get("nodes"), list) else []),
                *(target_packet.get("nodes", []) if isinstance(target_packet.get("nodes"), list) else []),
            ],
            limit=120,
        ),
        "edges": graph_unique_records(
            [
                *(source_packet.get("edges", []) if isinstance(source_packet.get("edges"), list) else []),
                *(target_packet.get("edges", []) if isinstance(target_packet.get("edges"), list) else []),
            ],
            limit=180,
        ),
        "diagnostics": [
            *(source_packet.get("diagnostics", []) if isinstance(source_packet.get("diagnostics"), list) else []),
            *(target_packet.get("diagnostics", []) if isinstance(target_packet.get("diagnostics"), list) else []),
        ],
    }
    node_map = graph_node_by_id(graph)
    edge_map = graph_edge_by_id(graph)
    source = resolve_graph_anchor(graph, source_anchor, kind=source_route_kind, limit=30)
    target = resolve_graph_anchor(graph, target_anchor, kind=target_route_kind, limit=30)
    target_ids = set(target.get("start_node_ids", []))
    adjacency = graph_adjacency(graph.get("edges", []) if isinstance(graph.get("edges"), list) else [])
    max_depth = max(1, min(int_value(max_depth, 4), 8))
    queue: deque[tuple[str, list[str], list[str]]] = deque((node_id, [node_id], []) for node_id in source.get("start_node_ids", []))
    seen: set[str] = set()
    found_nodes: list[str] = []
    found_edges: list[str] = []
    while queue:
        node_id, path_nodes, path_edges = queue.popleft()
        if node_id in seen:
            continue
        seen.add(node_id)
        if node_id in target_ids:
            found_nodes = path_nodes
            found_edges = path_edges
            break
        if len(path_edges) >= max_depth:
            continue
        for neighbor, edge_id in adjacency.get(node_id, []):
            if neighbor in path_nodes:
                continue
            queue.append((neighbor, [*path_nodes, neighbor], [*path_edges, edge_id]))
    nodes = [node_map[node_id] for node_id in found_nodes if node_id in node_map]
    edges = [edge_map[edge_id] for edge_id in found_edges if edge_id in edge_map]
    evidence_refs = graph_collect_evidence(nodes, edges)
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_shortest_path",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(found_nodes),
        "mutates": False,
        "truth_status": "graph_path_packet_not_reviewed_truth",
        "source_anchor": source_anchor,
        "target_anchor": target_anchor,
        "source_resolved": source,
        "target_resolved": target,
        "max_depth": max_depth,
        "path_length": len(edges) if edges else 0,
        "nodes": [graph_compact_node_for_packet(node) for node in nodes],
        "edges": [graph_compact_edge_for_packet(edge) for edge in edges],
        "evidence_refs": evidence_refs,
        "freshness": graph_freshness(aoa_root, graph),
        "diagnostics": graph.get("diagnostics", []),
        "next_route": "verify path claims through raw_ref, segment_ref, and session_ref before promotion",
        "next_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-shortest-path",
            anchors=[source_anchor, target_anchor],
            kind=kind,
            route_kind=route_kind,
            max_depth=max_depth,
        ),
        "next_expansion_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-shortest-path",
            anchors=[source_anchor, target_anchor],
            kind=kind,
            route_kind=route_kind,
            max_depth=min(max_depth + 1, 8),
        ),
        "next_expansion_reason": "Increase bounded max depth when no bridge is found or a longer relation chain is acceptable.",
    }


def graph_bridge_command_line(
    *,
    aoa_root: Path,
    source_anchor: str,
    target_anchor: str,
    kind: str,
    route_kind: str,
    source_kind: str,
    source_route_kind: str,
    target_kind: str,
    target_route_kind: str,
    limit: int,
    max_depth: int,
) -> str:
    command = [
        "python3",
        "scripts/aoa_session_memory.py",
        "graph-bridge",
        source_anchor,
        target_anchor,
        "--aoa-root",
        str(aoa_root),
        "--kind",
        graph_packet_cli_kind(kind, route_kind),
        "--limit",
        str(max(1, int_value(limit, 8))),
        "--max-depth",
        str(max(1, min(int_value(max_depth, 4), 8))),
    ]
    if str(source_kind or ""):
        command.extend(["--source-kind", graph_packet_cli_kind(source_kind, source_route_kind)])
    if str(target_kind or ""):
        command.extend(["--target-kind", graph_packet_cli_kind(target_kind, target_route_kind)])
    return " ".join(shlex.quote(part) for part in command)


def graph_bridge_entity_summary(
    *,
    anchor: str,
    requested_kind: str,
    route_kind: str,
    resolved: dict[str, Any],
    timeline: dict[str, Any],
) -> dict[str, Any]:
    route_key = route_key_slug(anchor, fallback="entity", max_chars=80)
    route_signal = f"{route_kind}:{route_key}" if route_kind != "auto" and route_key else ""
    return {
        "anchor": anchor,
        "route_key": route_key,
        "kind": route_kind,
        "requested_kind": str(requested_kind or "auto"),
        "route_signal": route_signal,
        "resolver_strategy": resolved.get("resolver_strategy"),
        "resolved_start_node_count": len(resolved.get("start_node_ids", []) if isinstance(resolved.get("start_node_ids"), list) else []),
        "timeline_event_count": int_value(timeline.get("event_count"), len(timeline.get("events") or [])),
        "timeline_ok": bool(timeline.get("ok")),
    }


def graph_bridge_compact_node(node: dict[str, Any]) -> dict[str, Any]:
    compact: dict[str, Any] = {}
    for key in (
        "id",
        "type",
        "label",
        "title",
        "event_type",
        "session_act",
        "conversation_act",
        "session_id",
        "session_label",
        "segment_id",
        "event_id",
        "timestamp",
        "line",
        "route_signal_count",
    ):
        if node.get(key) not in (None, "", [], {}):
            compact[key] = node.get(key)
    if isinstance(node.get("refs"), dict) and node["refs"]:
        compact["refs"] = node["refs"]
    elif isinstance(node.get("evidence_refs"), list):
        for ref in node["evidence_refs"]:
            refs = ref.get("refs") if isinstance(ref, dict) and isinstance(ref.get("refs"), dict) else {}
            if refs:
                compact["refs"] = refs
                break
    if isinstance(node.get("evidence_refs"), list) and node["evidence_refs"]:
        compact["evidence_ref_count"] = len(node["evidence_refs"])
    return compact


def graph_bridge_compact_edge(edge: dict[str, Any]) -> dict[str, Any]:
    compact: dict[str, Any] = {}
    for key in ("id", "type", "source", "target", "count"):
        if edge.get(key) not in (None, "", [], {}):
            compact[key] = edge.get(key)
    if isinstance(edge.get("evidence_refs"), list) and edge["evidence_refs"]:
        compact["evidence_ref_count"] = len(edge["evidence_refs"])
    return compact


def graph_bridge_evidence_refs(refs: list[Any], *, limit: int) -> list[Any]:
    selected: list[Any] = []
    seen: set[str] = set()
    for ref in refs:
        values = graph_ref_values(ref)
        if any(values.get(key) for key in ("session", "segment", "raw")):
            token = "|".join(str(values.get(key) or "") for key in ("session", "segment", "raw"))
        else:
            token = "|".join(str(values.get(key) or "") for key in ("session_id", "segment_id", "event_id"))
        if not token.strip("|"):
            token = graph_evidence_ref_token(ref)
        if token in seen:
            continue
        seen.add(token)
        selected.append(ref)
        if len(selected) >= limit:
            break
    return selected


def graph_bridge_compact_freshness(packet: dict[str, Any]) -> dict[str, Any]:
    freshness = packet.get("freshness") if isinstance(packet.get("freshness"), dict) else {}
    compact = {
        key: freshness.get(key)
        for key in (
            "status",
            "graph_source",
            "graph_generated_at",
            "search_index_generated_at",
            "hot_gate_status",
            "needs_maintenance",
            "needs_full_rebuild",
            "actionable_graph_source_count",
            "deferred_live_source_count",
            "ledger_store_missing_count",
            "latest_maintenance_remaining_count",
        )
        if freshness.get(key) not in (None, "", [], {})
    }
    recommendation = freshness.get("maintenance_recommendation") if isinstance(freshness.get("maintenance_recommendation"), dict) else {}
    if recommendation and recommendation.get("route") not in (None, "", "none"):
        compact["maintenance_recommendation"] = {
            key: recommendation.get(key)
            for key in ("route", "reason", "command", "actionable_count", "blocked_count")
            if recommendation.get(key) not in (None, "", [], {})
        }
    return compact


def graph_bridge_compact_timeline_from_neighborhood(
    *,
    aoa_root: Path,
    anchor: str,
    requested_kind: str,
    route_kind: str,
    neighborhood: dict[str, Any],
    limit: int,
) -> dict[str, Any]:
    selected_limit = max(1, min(int_value(limit, 8), 30))
    nodes = neighborhood.get("nodes") if isinstance(neighborhood.get("nodes"), list) else []
    events = [node for node in nodes if isinstance(node, dict) and node.get("type") == "event"]
    events.sort(key=lambda node: (str(node.get("timestamp") or ""), str(node.get("session_label") or ""), int_value(node.get("line")), str(node.get("event_id") or "")))
    selected_events = events[:selected_limit]
    evidence_refs = graph_bridge_evidence_refs(
        [
            *(neighborhood.get("evidence_refs", []) if isinstance(neighborhood.get("evidence_refs"), list) else []),
            *graph_collect_evidence(selected_events, [], limit=selected_limit * 4),
        ],
        limit=max(selected_limit * 4, selected_limit),
    )
    freshness = dict(neighborhood.get("freshness") if isinstance(neighborhood.get("freshness"), dict) else {})
    freshness["timeline_source"] = "side_neighborhood_compact_sample"
    freshness["timeline_deferred"] = True
    freshness["law"] = "graph-bridge first packet uses bounded side-neighborhood refs; run graph-timeline only when deeper ordering is needed."
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_timeline",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(selected_events or evidence_refs),
        "mutates": False,
        "truth_status": "graph_timeline_packet_not_reviewed_truth",
        "anchor": anchor,
        **trace_kind_payload_fields(requested_kind, route_kind),
        "timeline_source": "side_neighborhood_compact_sample",
        "event_count": len(selected_events),
        "events": selected_events,
        "resolved": neighborhood.get("resolved") if isinstance(neighborhood.get("resolved"), dict) else {},
        "evidence_refs": evidence_refs,
        "freshness": freshness,
        "diagnostics": neighborhood.get("diagnostics", []) if isinstance(neighborhood.get("diagnostics"), list) else [],
        "next_route": "Run graph-timeline only when event ordering needs more examples; verify important claims through raw/segment refs.",
        "next_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-timeline",
            anchors=[anchor],
            kind=requested_kind,
            route_kind=route_kind,
            limit=selected_limit,
        ),
        "next_expansion_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-timeline",
            anchors=[anchor],
            kind=requested_kind,
            route_kind=route_kind,
            limit=graph_packet_expanded_limit(selected_limit, default=selected_limit, maximum=200),
        ),
    }


def graph_bridge(
    *,
    aoa_root: Path,
    source_anchor: str,
    target_anchor: str,
    kind: str = "auto",
    source_kind: str = "",
    target_kind: str = "",
    max_depth: int = 4,
    limit: int = 8,
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    normalized_source_kind = normalize_trace_route_kind(source_kind or route_kind)
    source_route_kind = normalized_source_kind if normalized_source_kind in TRACE_ROUTE_KINDS else route_kind
    normalized_target_kind = normalize_trace_route_kind(target_kind or route_kind)
    target_route_kind = normalized_target_kind if normalized_target_kind in TRACE_ROUTE_KINDS else route_kind
    selected_limit = max(1, min(int_value(limit, 8), 30))
    selected_max_depth = max(1, min(int_value(max_depth, 4), 8))
    started = time.monotonic()
    phase_timings: list[dict[str, Any]] = []

    def timed_phase(name: str, func: Callable[[], dict[str, Any]]) -> dict[str, Any]:
        phase_started = time.monotonic()
        result = func()
        phase_timings.append({"phase": name, "elapsed_ms": int((time.monotonic() - phase_started) * 1000)})
        return result

    bridge_side_depth = selected_max_depth
    bridge_node_limit = max(selected_limit, 4)
    bridge_edge_limit = max(selected_limit * 2, 8)
    source_neighborhood = timed_phase(
        "source_neighborhood",
        lambda: graph_neighborhood(
            aoa_root=aoa_root,
            anchor=source_anchor,
            kind=source_route_kind,
            depth=bridge_side_depth,
            limit=bridge_node_limit,
            edge_limit=bridge_edge_limit,
        ),
    )
    target_neighborhood = timed_phase(
        "target_neighborhood",
        lambda: graph_neighborhood(
            aoa_root=aoa_root,
            anchor=target_anchor,
            kind=target_route_kind,
            depth=bridge_side_depth,
            limit=bridge_node_limit,
            edge_limit=bridge_edge_limit,
        ),
    )
    path = timed_phase(
        "shortest_path",
        lambda: graph_shortest_path_from_packets(
            aoa_root=aoa_root,
            source_anchor=source_anchor,
            target_anchor=target_anchor,
            source_packet=source_neighborhood,
            target_packet=target_neighborhood,
            kind=route_kind,
            source_kind=source_route_kind,
            target_kind=target_route_kind,
            max_depth=selected_max_depth,
        ),
    )
    source_timeline = timed_phase(
        "source_compact_timeline",
        lambda: graph_bridge_compact_timeline_from_neighborhood(
            aoa_root=aoa_root,
            anchor=source_anchor,
            requested_kind=source_kind or route_kind,
            route_kind=source_route_kind,
            neighborhood=source_neighborhood,
            limit=selected_limit,
        ),
    )
    target_timeline = timed_phase(
        "target_compact_timeline",
        lambda: graph_bridge_compact_timeline_from_neighborhood(
            aoa_root=aoa_root,
            anchor=target_anchor,
            requested_kind=target_kind or route_kind,
            route_kind=target_route_kind,
            neighborhood=target_neighborhood,
            limit=selected_limit,
        ),
    )

    path_nodes = path.get("nodes") if isinstance(path.get("nodes"), list) else []
    path_edges = path.get("edges") if isinstance(path.get("edges"), list) else []
    source_events = source_timeline.get("events") if isinstance(source_timeline.get("events"), list) else []
    target_events = target_timeline.get("events") if isinstance(target_timeline.get("events"), list) else []
    evidence_refs = graph_bridge_evidence_refs(
        [
            *(path.get("evidence_refs", []) if isinstance(path.get("evidence_refs"), list) else []),
            *(source_timeline.get("evidence_refs", []) if isinstance(source_timeline.get("evidence_refs"), list) else []),
            *(target_timeline.get("evidence_refs", []) if isinstance(target_timeline.get("evidence_refs"), list) else []),
        ],
        limit=80,
    )
    ref_counts = graph_ref_quality_counts(evidence_refs)
    path_found = bool(path.get("ok") and path_nodes)
    noise_flags: list[str] = []
    if not path_found:
        noise_flags.append("no_bounded_graph_path_found")
    if not evidence_refs:
        noise_flags.append("no_evidence_refs_returned")
    if not (ref_counts.get("raw_ref_count") or ref_counts.get("segment_ref_count")):
        noise_flags.append("no_raw_or_segment_refs")
    for label, packet in (("path", path), ("source_timeline", source_timeline), ("target_timeline", target_timeline)):
        freshness = packet.get("freshness") if isinstance(packet.get("freshness"), dict) else {}
        if freshness.get("needs_maintenance") or freshness.get("status") in {"stale", "graph_store_stale"}:
            noise_flags.append(f"{label}_freshness_requires_attention")
    for label, packet in (("source_neighborhood", source_neighborhood), ("target_neighborhood", target_neighborhood)):
        freshness = packet.get("freshness") if isinstance(packet.get("freshness"), dict) else {}
        if freshness.get("needs_maintenance") or freshness.get("status") in {"stale", "graph_store_stale"}:
            noise_flags.append(f"{label}_freshness_requires_attention")

    current_command = graph_bridge_command_line(
        aoa_root=aoa_root,
        source_anchor=source_anchor,
        target_anchor=target_anchor,
        kind=kind,
        route_kind=route_kind,
        source_kind=source_kind,
        source_route_kind=source_route_kind,
        target_kind=target_kind,
        target_route_kind=target_route_kind,
        limit=selected_limit,
        max_depth=selected_max_depth,
    )
    expansion_command = graph_bridge_command_line(
        aoa_root=aoa_root,
        source_anchor=source_anchor,
        target_anchor=target_anchor,
        kind=kind,
        route_kind=route_kind,
        source_kind=source_kind,
        source_route_kind=source_route_kind,
        target_kind=target_kind,
        target_route_kind=target_route_kind,
        limit=graph_packet_expanded_limit(selected_limit, default=selected_limit, maximum=30),
        max_depth=min(selected_max_depth + 1, 8),
    )
    source_resolved = path.get("source_resolved") if isinstance(path.get("source_resolved"), dict) else {}
    target_resolved = path.get("target_resolved") if isinstance(path.get("target_resolved"), dict) else {}
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_bridge",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(path_found or evidence_refs or source_events or target_events),
        "mutates": False,
        "truth_status": "graph_bridge_packet_not_reviewed_truth",
        "source_anchor": source_anchor,
        "target_anchor": target_anchor,
        **trace_kind_payload_fields(kind, route_kind),
        "source_kind": source_route_kind,
        "target_kind": target_route_kind,
        "normalized_entities": {
            "source": graph_bridge_entity_summary(
                anchor=source_anchor,
                requested_kind=source_kind or route_kind,
                route_kind=source_route_kind,
                resolved=source_resolved,
                timeline=source_timeline,
            ),
            "target": graph_bridge_entity_summary(
                anchor=target_anchor,
                requested_kind=target_kind or route_kind,
                route_kind=target_route_kind,
                resolved=target_resolved,
                timeline=target_timeline,
            ),
        },
        "bridge": {
            "path_found": path_found,
            "path_length": int_value(path.get("path_length"), len(path_edges)),
            "max_depth": selected_max_depth,
            "nodes": [graph_bridge_compact_node(node) for node in path_nodes[:selected_limit] if isinstance(node, dict)],
            "edges": [graph_bridge_compact_edge(edge) for edge in path_edges[: max(selected_limit * 2, selected_limit)] if isinstance(edge, dict)],
            "evidence_refs": (path.get("evidence_refs", []) if isinstance(path.get("evidence_refs"), list) else [])[:selected_limit],
            "next_expansion_command": path.get("next_expansion_command"),
        },
        "usage_chain": {
            "source_event_count": int_value(source_timeline.get("event_count"), len(source_events)),
            "target_event_count": int_value(target_timeline.get("event_count"), len(target_events)),
            "source_events": [graph_bridge_compact_node(event) for event in source_events[:selected_limit] if isinstance(event, dict)],
            "target_events": [graph_bridge_compact_node(event) for event in target_events[:selected_limit] if isinstance(event, dict)],
        },
        "evidence_refs": evidence_refs[: max(selected_limit * 3, selected_limit)],
        "evidence_ref_count": len(evidence_refs),
        "freshness": {
            "path": graph_bridge_compact_freshness(path),
            "source_timeline": graph_bridge_compact_freshness(source_timeline),
            "target_timeline": graph_bridge_compact_freshness(target_timeline),
            "source_neighborhood": graph_bridge_compact_freshness(source_neighborhood),
            "target_neighborhood": graph_bridge_compact_freshness(target_neighborhood),
        },
        "quality": {
            "one_short_route": True,
            "path_found": path_found,
            "path_length": int_value(path.get("path_length"), len(path_edges)),
            "path_node_count": len(path_nodes),
            "path_edge_count": len(path_edges),
            "compact_side_neighborhood": True,
            "side_neighborhood_depth": bridge_side_depth,
            "side_neighborhood_node_limit": bridge_node_limit,
            "side_neighborhood_edge_limit": bridge_edge_limit,
            "side_timeline_policy": "side_neighborhood_compact_sample",
            "side_timelines_deferred": True,
            "source_event_count": int_value(source_timeline.get("event_count"), len(source_events)),
            "target_event_count": int_value(target_timeline.get("event_count"), len(target_events)),
            "source_neighborhood_node_count": int_value(source_neighborhood.get("node_count"), len(source_neighborhood.get("nodes") or [])),
            "target_neighborhood_node_count": int_value(target_neighborhood.get("node_count"), len(target_neighborhood.get("nodes") or [])),
            "evidence_ref_count": len(evidence_refs),
            "raw_or_segment_ref_present": bool(ref_counts.get("raw_ref_count") or ref_counts.get("segment_ref_count")),
            "ref_counts": ref_counts,
            "noise_flag_count": len(noise_flags),
        },
        "noise_flags": noise_flags,
        "diagnostics": [
            *(path.get("diagnostics", []) if isinstance(path.get("diagnostics"), list) else []),
            *(source_timeline.get("diagnostics", []) if isinstance(source_timeline.get("diagnostics"), list) else []),
            *(target_timeline.get("diagnostics", []) if isinstance(target_timeline.get("diagnostics"), list) else []),
            *(source_neighborhood.get("diagnostics", []) if isinstance(source_neighborhood.get("diagnostics"), list) else []),
            *(target_neighborhood.get("diagnostics", []) if isinstance(target_neighborhood.get("diagnostics"), list) else []),
        ],
        "elapsed_ms": int((time.monotonic() - started) * 1000),
        "timings": phase_timings,
        "next_route": "Use graph-bridge as a compact relation route; verify important claims through raw_ref, segment_ref, and owner source surfaces.",
        "next_command": current_command,
        "next_expansion_command": expansion_command,
        "next_expansion": [
            {
                "id": "shortest_path",
                "command": path.get("next_expansion_command"),
                "use_when": "the bounded bridge path is missing or a longer relation chain is acceptable",
            },
            {
                "id": "source_timeline",
                "command": source_timeline.get("next_expansion_command"),
                "use_when": "source-side usage/event ordering needs more examples",
            },
            {
                "id": "target_timeline",
                "command": target_timeline.get("next_expansion_command"),
                "use_when": "target-side usage/event ordering needs more examples",
            },
        ],
        "authority_boundary": "graph bridge routes relation evidence only; raw/segment refs and owner source surfaces remain stronger.",
    }
    return payload


def graph_cooccurrence_from_packet(
    *,
    aoa_root: Path,
    packet: dict[str, Any],
    anchor: str,
    kind: str = "auto",
    limit: int = 30,
    source: str = "bounded_cooccurrence_neighborhood",
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    graph = {
        "source": source,
        "generated_at": utc_now(),
        "nodes": packet.get("nodes", []) if isinstance(packet.get("nodes"), list) else [],
        "edges": packet.get("edges", []) if isinstance(packet.get("edges"), list) else [],
        "diagnostics": packet.get("diagnostics", []) if isinstance(packet.get("diagnostics"), list) else [],
    }
    node_map = graph_node_by_id(graph)
    resolved = packet.get("resolved") if isinstance(packet.get("resolved"), dict) else {}
    if not resolved.get("start_node_ids"):
        resolved = resolve_graph_anchor(graph, anchor, kind=route_kind, limit=60)
    if not resolved.get("start_node_ids"):
        resolved = packet.get("resolved", resolved) if isinstance(packet.get("resolved"), dict) else resolved
    start_ids = set(resolved.get("start_node_ids", []))
    event_to_routes: dict[str, set[str]] = defaultdict(set)
    route_to_events: dict[str, set[str]] = defaultdict(set)
    for edge in graph.get("edges", []) if isinstance(graph.get("edges"), list) else []:
        if not isinstance(edge, dict) or edge.get("type") != "mentions_route_signal":
            continue
        source = str(edge.get("source") or "")
        target = str(edge.get("target") or "")
        event_to_routes[source].add(target)
        route_to_events[target].add(source)
    anchor_events: set[str] = set()
    for node_id in start_ids:
        node = node_map.get(node_id, {})
        if node.get("type") == "event":
            anchor_events.add(node_id)
        if node_id in route_to_events:
            anchor_events.update(route_to_events[node_id])
    counts: Counter[str] = Counter()
    samples: dict[str, list[dict[str, Any]]] = defaultdict(list)
    for event_id in anchor_events:
        event_node = node_map.get(event_id, {})
        for route_id in event_to_routes.get(event_id, set()):
            if route_id in start_ids:
                continue
            counts[route_id] += 1
            if len(samples[route_id]) < 5:
                samples[route_id].append(
                    {
                        "event_node_id": event_id,
                        "event_title": event_node.get("title") or event_node.get("label"),
                        "session_id": event_node.get("session_id"),
                        "segment_id": event_node.get("segment_id"),
                        "event_id": event_node.get("event_id"),
                        "refs": event_node.get("refs"),
                    }
                )
    selected = []
    for route_id, count in counts.most_common(max(1, min(int_value(limit, 30), 100))):
        route_node = node_map.get(route_id, {})
        selected.append({"node": graph_compact_node_for_packet(route_node), "count": count, "samples": samples.get(route_id, [])})
    evidence_nodes = [node_map[event_id] for event_id in anchor_events if event_id in node_map]
    selected_limit = max(1, min(int_value(limit, 30), 100))
    diagnostics = list(graph.get("diagnostics", []))
    if anchor_events and not selected:
        diagnostics.append("graph_cooccurrence_no_route_neighbors_in_bounded_packet")
    if packet.get("truncated") and not selected:
        diagnostics.append("graph_cooccurrence_bounded_packet_truncated_before_cooccurrence_routes")
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_cooccurrence",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(selected),
        "mutates": False,
        "truth_status": "cooccurrence_packet_not_reviewed_truth",
        "source": source,
        "anchor": anchor,
        **trace_kind_payload_fields(kind, route_kind),
        "resolved": resolved,
        "anchor_event_count": len(anchor_events),
        "cooccurrence_count": len(selected),
        "cooccurrences": selected,
        "evidence_refs": graph_collect_evidence(evidence_nodes, [], limit=80),
        "freshness": packet.get("freshness") if isinstance(packet.get("freshness"), dict) else graph_freshness(aoa_root, graph),
        "diagnostics": diagnostics,
        "next_route": (
            "verify cooccurrence claims through raw_ref, segment_ref, and session_ref before promotion"
            if selected
            else "use graph-neighborhood for nearby evidence refs or increase the bounded cooccurrence route only when route cooccurrences are required"
        ),
        "next_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-cooccurrence",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            limit=selected_limit,
        ),
        "next_expansion_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-cooccurrence",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            limit=graph_packet_expanded_limit(selected_limit, default=selected_limit, maximum=100),
        ),
        "next_expansion_reason": "Increase the bounded cooccurrence limit when more neighboring route signals are needed.",
    }


def graph_cooccurrence_from_store(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    limit: int = 30,
) -> dict[str, Any] | None:
    state = graph_store_query_state(aoa_root)
    if state.get("status") != "current":
        return None
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    selected_limit = max(1, min(int_value(limit, 30), 100))
    anchor_event_limit = max(40, min(selected_limit * 10, 300))
    route_edge_limit = max(120, min(anchor_event_limit * 12, 2400))
    paths = graph_paths(aoa_root)
    diagnostics: list[str] = []
    try:
        conn = sqlite3.connect(str(paths["store"]))
        conn.row_factory = sqlite3.Row
        resolved = graph_store_resolve_anchor(conn, anchor, kind=route_kind, limit=max(10, selected_limit))
        start_ids = [str(node_id) for node_id in resolved.get("start_node_ids", []) if node_id]
        if not start_ids:
            conn.close()
            return None
        anchor_events: list[str] = []
        seen_anchor_events: set[str] = set()
        for node_id in start_ids:
            if node_id.startswith("event:") and node_id not in seen_anchor_events:
                seen_anchor_events.add(node_id)
                anchor_events.append(node_id)
            if len(anchor_events) >= anchor_event_limit:
                break
            for column, opposite_column, index_name in (
                ("target_node", "source_node", "idx_edges_target"),
                ("source_node", "target_node", "idx_edges_source"),
            ):
                if len(anchor_events) >= anchor_event_limit:
                    break
                remaining = anchor_event_limit - len(anchor_events)
                rows = conn.execute(
                    f"""
                    SELECT source_node, target_node
                    FROM edges INDEXED BY {index_name}
                    WHERE {column} = ?
                      AND edge_type = 'mentions_route_signal'
                    LIMIT ?
                    """,
                    (node_id, remaining),
                ).fetchall()
                for row in rows:
                    event_id = str(row[opposite_column] or "")
                    if not event_id.startswith("event:") or event_id in seen_anchor_events:
                        continue
                    seen_anchor_events.add(event_id)
                    anchor_events.append(event_id)
                    if len(anchor_events) >= anchor_event_limit:
                        break
        route_counts: Counter[str] = Counter()
        samples: dict[str, list[dict[str, Any]]] = defaultdict(list)
        selected_edge_ids: list[str] = []
        seen_edge_ids: set[str] = set()
        start_id_set = set(start_ids)
        for offset in range(0, len(anchor_events), 80):
            if len(selected_edge_ids) >= route_edge_limit:
                break
            chunk = anchor_events[offset : offset + 80]
            if not chunk:
                continue
            placeholders = ",".join("?" for _item in chunk)
            remaining_edges = max(1, route_edge_limit - len(selected_edge_ids))
            rows = conn.execute(
                f"""
                SELECT id, source_node, target_node, count
                FROM edges INDEXED BY idx_edges_source
                WHERE source_node IN ({placeholders})
                  AND edge_type = 'mentions_route_signal'
                LIMIT ?
                """,
                (*chunk, remaining_edges),
            ).fetchall()
            for row in rows:
                edge_id = str(row["id"])
                route_id = str(row["target_node"] or "")
                event_id = str(row["source_node"] or "")
                if route_id in start_id_set:
                    continue
                route_counts[route_id] += max(1, int_value(row["count"], 1))
                if edge_id not in seen_edge_ids and len(selected_edge_ids) < route_edge_limit:
                    seen_edge_ids.add(edge_id)
                    selected_edge_ids.append(edge_id)
                if len(samples[route_id]) < 5:
                    samples[route_id].append({"event_node_id": event_id})
        route_ids = [route_id for route_id, _count in route_counts.most_common(selected_limit)]
        event_nodes = graph_store_fetch_payloads(conn, "nodes", anchor_events)
        route_nodes = graph_store_fetch_payloads(conn, "nodes", route_ids)
        edge_payloads = graph_store_fetch_payloads(conn, "edges", selected_edge_ids[: min(route_edge_limit, selected_limit * 20)])
        conn.close()
    except sqlite3.Error:
        return None
    event_node_map = {str(node.get("id")): node for node in event_nodes if isinstance(node, dict)}
    route_node_map = {str(node.get("id")): node for node in route_nodes if isinstance(node, dict)}
    selected: list[dict[str, Any]] = []
    for route_id, count in route_counts.most_common(selected_limit):
        sample_rows: list[dict[str, Any]] = []
        for sample in samples.get(route_id, []):
            event_node = event_node_map.get(str(sample.get("event_node_id") or ""), {})
            sample_rows.append(
                {
                    "event_node_id": sample.get("event_node_id"),
                    "event_title": event_node.get("title") or event_node.get("label"),
                    "session_id": event_node.get("session_id"),
                    "segment_id": event_node.get("segment_id"),
                    "event_id": event_node.get("event_id"),
                    "refs": event_node.get("refs"),
                }
            )
        selected.append(
            {
                "node": graph_compact_node_for_packet(route_node_map.get(route_id, {"id": route_id})),
                "count": count,
                "samples": sample_rows,
            }
        )
    anchor_event_sample_truncated = len(anchor_events) >= anchor_event_limit
    route_edge_sample_truncated = len(selected_edge_ids) >= route_edge_limit
    if anchor_events and not selected:
        diagnostics.append("graph_cooccurrence_no_route_neighbors_in_store_sample")
    if anchor_event_sample_truncated:
        diagnostics.append("graph_cooccurrence_anchor_event_sample_truncated")
    if route_edge_sample_truncated:
        diagnostics.append("graph_cooccurrence_route_edge_sample_truncated")
    freshness_graph = {
        "source": "sqlite_graph_store_direct_cooccurrence",
        "generated_at": (state.get("metadata") or {}).get("updated_at") or (state.get("metadata") or {}).get("generated_at") or utc_now(),
    }
    evidence_refs = graph_collect_evidence(event_nodes, edge_payloads, limit=80)
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_cooccurrence",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(selected),
        "mutates": False,
        "truth_status": "cooccurrence_packet_not_reviewed_truth",
        "source": "sqlite_graph_store_direct_cooccurrence",
        "anchor": anchor,
        **trace_kind_payload_fields(kind, route_kind),
        "resolved": resolved,
        "anchor_event_count": len(anchor_events),
        "anchor_event_sample_limit": anchor_event_limit,
        "anchor_event_sample_truncated": anchor_event_sample_truncated,
        "route_edge_sample_limit": route_edge_limit,
        "route_edge_sample_truncated": route_edge_sample_truncated,
        "cooccurrence_count": len(selected),
        "cooccurrences": selected,
        "evidence_refs": evidence_refs,
        "freshness": graph_freshness(aoa_root, freshness_graph),
        "quality": {
            "one_short_route": True,
            "bounded_store_query": True,
            "anchor_event_count": len(anchor_events),
            "cooccurrence_count": len(selected),
            "evidence_ref_count": len(evidence_refs),
            "anchor_event_sample_truncated": anchor_event_sample_truncated,
            "route_edge_sample_truncated": route_edge_sample_truncated,
        },
        "diagnostics": diagnostics,
        "next_route": (
            "verify cooccurrence claims through raw_ref, segment_ref, and session_ref before promotion"
            if selected
            else "use graph-neighborhood for nearby evidence refs or increase the bounded cooccurrence route only when route cooccurrences are required"
        ),
        "next_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-cooccurrence",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            limit=selected_limit,
        ),
        "next_expansion_command": graph_packet_command_line(
            aoa_root=aoa_root,
            command_name="graph-cooccurrence",
            anchors=[anchor],
            kind=kind,
            route_kind=route_kind,
            limit=graph_packet_expanded_limit(selected_limit, default=selected_limit, maximum=100),
        ),
        "next_expansion_reason": "Increase the bounded cooccurrence limit when more neighboring route signals are needed.",
        "authority_boundary": "graph cooccurrence routes relation evidence only; raw/segment refs and owner source surfaces remain stronger.",
    }


def graph_cooccurrence(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    limit: int = 30,
) -> dict[str, Any]:
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    store_packet = graph_cooccurrence_from_store(aoa_root=aoa_root, anchor=anchor, kind=kind, limit=limit)
    if store_packet is not None:
        return store_packet
    packet = graph_neighborhood(aoa_root=aoa_root, anchor=anchor, kind=route_kind, depth=1, limit=max(limit * 6, 60))
    return graph_cooccurrence_from_packet(
        aoa_root=aoa_root,
        packet=packet,
        anchor=anchor,
        kind=kind,
        limit=limit,
        source="bounded_cooccurrence_neighborhood",
    )


def refs_from_search_hits(hits: list[dict[str, Any]], *, limit: int = 60) -> list[dict[str, Any]]:
    refs: list[dict[str, Any]] = []
    for hit in hits:
        if not isinstance(hit, dict):
            continue
        hit_refs = hit.get("refs") if isinstance(hit.get("refs"), dict) else {}
        refs.append(
            {
                "doc_id": hit.get("doc_id"),
                "session_id": hit.get("session_id"),
                "segment_id": hit.get("segment_id"),
                "event_id": hit.get("event_id"),
                "refs": hit_refs,
                "freshness": hit.get("freshness"),
            }
        )
    return graph_unique_records(refs, limit=limit)


def graph_rag_packet(
    *,
    aoa_root: Path,
    query: str,
    anchor: str = "",
    kind: str = "auto",
    mode: str = "hybrid",
    limit: int = 8,
    include_semantic_context: bool = False,
    rerank_local: bool = False,
) -> dict[str, Any]:
    text = str(query or anchor or "").strip()
    if not text:
        normalized_kind = normalize_trace_route_kind(kind)
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "session_memory_graphrag_packet",
            "graph_schema_version": GRAPH_SCHEMA_VERSION,
            "generated_at": utc_now(),
            "ok": False,
            "query": query,
            **trace_kind_payload_fields(kind, normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"),
            "diagnostics": ["query or anchor is required"],
        }
    limit = max(1, min(int_value(limit, 8), 50))
    anchor_text = str(anchor or text)
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    lexical = search_sessions(
        aoa_root=aoa_root,
        query=text,
        limit=limit,
        include_semantic_context=include_semantic_context,
        rerank_local=rerank_local,
        explain=True,
    )
    neighborhood = graph_neighborhood(aoa_root=aoa_root, anchor=anchor_text, kind=route_kind, depth=2, limit=max(limit * 8, 40))
    cooccurrence = graph_cooccurrence_from_packet(
        aoa_root=aoa_root,
        packet=neighborhood,
        anchor=anchor_text,
        kind=route_kind,
        limit=min(limit * 4, 40),
        source="shared_graphrag_neighborhood",
    )
    search_hits = lexical.get("results", []) if isinstance(lexical.get("results"), list) else []
    lexical_refs = refs_from_search_hits(search_hits, limit=limit * 4)
    graph_refs = neighborhood.get("evidence_refs", []) if isinstance(neighborhood.get("evidence_refs"), list) else []
    cooccurring_routes = [
        item
        for item in cooccurrence.get("cooccurrences", [])[: max(1, min(limit, 20))]
        if isinstance(item, dict)
    ]
    evidence_refs = graph_unique_records([*lexical_refs, *graph_refs], limit=max(30, limit * 8))
    packet = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graphrag_packet",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(search_hits or graph_refs),
        "mutates": False,
        "truth_status": "rag_graphrag_evidence_packet_not_reviewed_truth",
        "query": text,
        "anchor": anchor_text,
        **trace_kind_payload_fields(kind, route_kind),
        "mode": mode,
        "retrieval_modes": {
            "lexical": "portable_sqlite_fts",
            "vector": "optional_semantic_overlay" if include_semantic_context else "not_requested",
            "rerank": "optional_local_rerank" if rerank_local else "not_requested",
            "graph": "route_signal_sidecar_or_ephemeral_graph",
            "graphrag": "lexical_entrypoints_plus_graph_expansion_plus_cooccurrence_packet",
        },
        "lexical": {
            "ok": lexical.get("ok"),
            "result_count": lexical.get("result_count"),
            "provider": lexical.get("provider"),
            "results": search_hits[:limit],
        },
        "graph": {
            "ok": neighborhood.get("ok"),
            "source": neighborhood.get("graph", {}).get("source") if isinstance(neighborhood.get("graph"), dict) else None,
            "node_count": neighborhood.get("node_count"),
            "edge_count": neighborhood.get("edge_count"),
            "resolved": neighborhood.get("resolved"),
            "nodes": neighborhood.get("nodes", [])[: max(limit * 3, 12)],
            "edges": neighborhood.get("edges", [])[: max(limit * 3, 12)],
        },
        "communities": {
            "method": "route_signal_cooccurrence",
            "source": cooccurrence.get("source"),
            "items": cooccurring_routes,
        },
        "evidence_refs": evidence_refs,
        "freshness": {
            "search": {
                "index_generated_at": lexical.get("index_generated_at"),
                "provider_status": lexical.get("provider", {}).get("status") if isinstance(lexical.get("provider"), dict) else None,
            },
            "graph": neighborhood.get("freshness"),
        },
        "diagnostics": [
            *(lexical.get("diagnostics", []) if isinstance(lexical.get("diagnostics"), list) else []),
            *(neighborhood.get("diagnostics", []) if isinstance(neighborhood.get("diagnostics"), list) else []),
        ],
        "stop_line": "GraphRAG may rank routes and gather refs, but it does not promote claims without raw/segment/session evidence review.",
    }
    packet["answer_rules"] = graph_answer_rules(
        evidence_refs=evidence_refs,
        freshness=packet.get("freshness") if isinstance(packet.get("freshness"), dict) else {},
        min_evidence_ref_count=1,
        review_status="unreviewed",
    )
    if not packet["answer_rules"].get("graph_rag_synthesis_allowed"):
        packet["diagnostics"].append(f"answer_rule_gate:{packet['answer_rules'].get('status')}")
    return packet


def graph_explain_packet(
    *,
    aoa_root: Path,
    intent: str,
    anchor: str = "",
    query: str = "",
    kind: str = "auto",
    limit: int = 8,
) -> dict[str, Any]:
    intent_text = str(intent or query or anchor or "").strip()
    normalized_kind = normalize_trace_route_kind(kind)
    route_kind = normalized_kind if normalized_kind in TRACE_ROUTE_KINDS else "auto"
    packet = graph_rag_packet(
        aoa_root=aoa_root,
        query=query or intent_text,
        anchor=anchor or intent_text,
        kind=route_kind,
        mode="explain",
        limit=limit,
    )
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_graph_explain_packet",
        "graph_schema_version": GRAPH_SCHEMA_VERSION,
        "generated_at": utc_now(),
        "ok": bool(packet.get("ok")),
        "mutates": False,
        "truth_status": "graph_explain_packet_not_reviewed_truth",
        "intent": intent_text,
        "anchor": anchor or intent_text,
        "query": query or intent_text,
        **trace_kind_payload_fields(kind, route_kind),
        "explanation": {
            "entrypoints": "portable lexical search plus route-candidate graph expansion",
            "graph_expansion": (
                "bounded trace/search hits are converted into event, route-signal, session, and segment nodes; "
                "raw refs stay in event evidence refs"
            ),
            "community_signal": "cooccurrence is route-signal co-presence around evidence events",
            "freshness": "search provider and graph packet freshness are routing checks, not authority",
            "authority": "raw/segment/session refs remain stronger than packet summaries",
        },
        "packet": packet,
        "evidence_refs": packet.get("evidence_refs", []),
        "answer_rules": packet.get("answer_rules"),
        "stop_line": "Use this explanation to choose evidence to read, not as reviewed truth.",
    }


