def maintenance_next_action_lane(action: dict[str, Any]) -> str:
    action_id = route_key_slug(str(action.get("id") or ""), fallback="")
    route_kind = route_key_slug(str(action.get("route_kind") or ""), fallback="")
    command = " ".join(str(item) for item in action.get("command", []) if item) if isinstance(action.get("command"), list) else ""
    command_key = route_key_slug(command, fallback="")
    if action_id.startswith("repair_graph") or "graph" in route_kind or "graph_maintenance" in command_key:
        return "graph"
    if action_id in {"run_live_catchup", "wait_live_catchup"} or "catchup" in route_kind:
        return "live_tail"
    if action_id.startswith("entity_registry") or "entity_registry" in route_kind or "entity_registry" in command_key:
        return "entity_registry"
    if action_id.startswith("refresh_search_shard") or "search_shard" in route_kind:
        return "search_shard"
    if "rollup" in action_id or "rollup" in route_kind or "route_rollup" in command_key:
        return "route_rollup"
    if "shrink" in action_id or "shrink" in route_kind or "shrink" in command_key:
        return "search_projection"
    if action_id == "use_graph_search":
        return "use_graph_search"
    if "search" in action_id or "search" in route_kind or "search" in command_key or "index_maintenance" in command_key:
        return "search"
    if action_id == "install_or_bootstrap_runtime":
        return "install"
    return "other"


def live_scenario_maintenance_status_audit(
    *,
    workspace_root: Path,
    aoa_root: Path,
) -> dict[str, Any]:
    started = time.monotonic()
    packet = session_memory_maintenance_status(
        workspace_root=workspace_root,
        aoa_root=aoa_root,
        include_timers=False,
    )
    next_actions = [item for item in packet.get("next_actions", []) if isinstance(item, dict)] if isinstance(packet.get("next_actions"), list) else []
    next_action_ids = [str(item.get("id") or "") for item in next_actions if item.get("id")]
    lane_counts = Counter(maintenance_next_action_lane(item) for item in next_actions)
    graph = packet.get("graph") if isinstance(packet.get("graph"), dict) else {}
    search = packet.get("search") if isinstance(packet.get("search"), dict) else {}
    entity_registry = packet.get("entity_registry") if isinstance(packet.get("entity_registry"), dict) else {}
    operations = packet.get("operations") if isinstance(packet.get("operations"), dict) else {}
    graph_pressure = operations.get("graph_pressure") if isinstance(operations.get("graph_pressure"), dict) else {}
    high_fanout_policy = (
        graph_pressure.get("high_fanout_policy")
        if isinstance(graph_pressure.get("high_fanout_policy"), dict)
        else {}
    )
    graph_replacement_readiness = (
        high_fanout_policy.get("replacement_readiness")
        if isinstance(high_fanout_policy.get("replacement_readiness"), dict)
        else {}
    )
    graph_prune_gate = (
        high_fanout_policy.get("prune_gate")
        if isinstance(high_fanout_policy.get("prune_gate"), dict)
        else {}
    )
    agent_route = packet.get("agent_route") if isinstance(packet.get("agent_route"), dict) else {}
    exact_next_command = str(packet.get("exact_next_command") or "")
    graph_queue_action_present = any(
        (
            maintenance_next_action_lane(item) == "graph"
            and (
                "queue" in route_key_slug(str(item.get("id") or ""), fallback="")
                or " --use-queue " in f" {shlex.join(item.get('command', [])) if isinstance(item.get('command'), list) else ''} "
            )
        )
        or (
            item.get("catchup_command_kind") == "graph_queue_maintenance"
            and (
                maintenance_next_action_lane(item) == "live_tail"
                or " --use-queue "
                in f" {shlex.join(item.get('catchup_command_after_quiet_window', [])) if isinstance(item.get('catchup_command_after_quiet_window'), list) else ''} "
            )
        )
        for item in next_actions
    )
    diagnostics: list[str] = []
    if packet.get("mutates") is not False:
        diagnostics.append("maintenance_status_packet_mutates")
    if not isinstance(packet.get("agent_route"), dict) or not agent_route:
        diagnostics.append("maintenance_status_missing_agent_route")
    if not next_actions:
        diagnostics.append("maintenance_status_missing_next_actions")
    if not exact_next_command and next_actions:
        diagnostics.append("maintenance_status_missing_exact_next_command")
    if not isinstance(packet.get("search"), dict):
        diagnostics.append("maintenance_status_missing_search_lane")
    if not isinstance(packet.get("graph"), dict):
        diagnostics.append("maintenance_status_missing_graph_lane")
    if not isinstance(packet.get("entity_registry"), dict):
        diagnostics.append("maintenance_status_missing_entity_registry_lane")
    if int_value(graph.get("queued_count")) > 0 and not graph_queue_action_present:
        diagnostics.append("maintenance_status_graph_queue_without_queue_next_action")
    if (
        str(graph_pressure.get("status") or "") == "large_cardinality_dominates"
        and not high_fanout_policy
    ):
        diagnostics.append("maintenance_status_graph_pressure_missing_high_fanout_policy")
    elapsed_ms = int((time.monotonic() - started) * 1000)
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_maintenance_status_scenario_audit",
        "generated_at": utc_now(),
        "ok": not diagnostics,
        "mutates": False,
        "truth_status": "maintenance_status_live_route_contract_not_memory_truth",
        "status_packet_ok": packet.get("ok"),
        "recommendation": packet.get("recommendation"),
        "agent_route_action": agent_route.get("action"),
        "maintenance_required": agent_route.get("maintenance_required"),
        "can_use_graph_search": agent_route.get("can_use_graph_search"),
        "exact_next_command_present": bool(exact_next_command),
        "next_action_count": len(next_actions),
        "next_action_ids": next_action_ids,
        "next_action_lane_counts": dict(sorted(lane_counts.items())),
        "graph_next_action_count": lane_counts.get("graph", 0),
        "search_next_action_count": lane_counts.get("search", 0) + lane_counts.get("search_shard", 0) + lane_counts.get("route_rollup", 0) + lane_counts.get("search_projection", 0),
        "entity_registry_next_action_count": lane_counts.get("entity_registry", 0),
        "live_tail_next_action_count": lane_counts.get("live_tail", 0),
        "route_lane_count": len([lane for lane, count in lane_counts.items() if count > 0]),
        "graph_queue_action_present": graph_queue_action_present,
        "search_status": search.get("status"),
        "graph_status": graph.get("status"),
        "entity_registry_status": entity_registry.get("status"),
        "search_actionable_dirty_session_count": search.get("actionable_dirty_session_count"),
        "search_deferred_live_session_count": search.get("deferred_live_session_count"),
        "graph_actionable_count": graph.get("actionable_count"),
        "graph_queued_count": graph.get("queued_count"),
        "graph_deferred_live_source_count": graph.get("deferred_live_source_count"),
        "graph_pressure_status": graph_pressure.get("status"),
        "graph_high_fanout_policy_status": high_fanout_policy.get("status"),
        "graph_high_fanout_dominant_edge_count": high_fanout_policy.get("dominant_edge_count"),
        "graph_high_fanout_mutation_boundary": high_fanout_policy.get("mutation_boundary"),
        "graph_high_fanout_replacement_status": graph_replacement_readiness.get("status"),
        "graph_high_fanout_replacement_candidate_count": graph_replacement_readiness.get("candidate_count"),
        "graph_high_fanout_replacement_proof_gap_count": graph_replacement_readiness.get("proof_gap_count"),
        "graph_high_fanout_prune_apply_ready": graph_prune_gate.get("apply_ready"),
        "graph_high_fanout_prune_gate_status": graph_prune_gate.get("status"),
        "entity_count": entity_registry.get("entity_count"),
        "elapsed_ms": elapsed_ms,
        "diagnostics": diagnostics,
        "first_ref": {},
        "next_route": "Run the first maintenance-status next action only if it is an explicit operator/maintenance route; MCP consumers should keep this packet read-only.",
        "authority_boundary": "maintenance-status is generated route guidance; raw/session evidence and owner layers remain authoritative.",
    }


def live_scenario_profile_expectation_failures(scenario: dict[str, Any], expectation: dict[str, Any]) -> list[str]:
    failures: list[str] = []
    profile = str(expectation.get("profile") or scenario.get("profile") or "")
    status = str(scenario.get("status") or "")
    allowed_statuses = [
        str(item)
        for item in expectation.get("allowed_statuses", [])
        if item
    ] if isinstance(expectation.get("allowed_statuses"), list) else []
    if allowed_statuses and status not in allowed_statuses:
        failures.append(f"{profile}:status:{status} not in {allowed_statuses}")
    min_sample_count = int_value(expectation.get("min_sample_count"))
    if min_sample_count and int_value(scenario.get("sample_count")) < min_sample_count:
        failures.append(f"{profile}:sample_count:{scenario.get('sample_count')}<{min_sample_count}")
    for expectation_key, scenario_key in (
        ("min_result_count", "result_count"),
        ("min_total_receipt_count", "total_receipt_count"),
        ("min_returned_receipt_count", "returned_receipt_count"),
        ("min_node_count", "node_count"),
        ("min_edge_count", "edge_count"),
        ("min_anchor_event_count", "anchor_event_count"),
        ("min_cooccurrence_count", "cooccurrence_count"),
        ("min_work_chain_linked_count", "work_chain_linked_count"),
        ("min_work_chain_episode_count", "work_chain_episode_count"),
        ("min_work_chain_goal_event_ref_count", "work_chain_goal_event_ref_count"),
        ("min_work_chain_answer_ref_count", "work_chain_answer_ref_count"),
        ("min_work_chain_closeout_ref_count", "work_chain_closeout_ref_count"),
    ):
        minimum = int_value(expectation.get(expectation_key))
        if minimum and int_value(scenario.get(scenario_key)) < minimum:
            failures.append(f"{profile}:{scenario_key}:{scenario.get(scenario_key)}<{minimum}")
    work_chain_next_route_counts = (
        scenario.get("work_chain_next_route_counts")
        if isinstance(scenario.get("work_chain_next_route_counts"), dict)
        else {}
    )
    for route_name in expectation.get("required_work_chain_next_routes", []) if isinstance(expectation.get("required_work_chain_next_routes"), list) else []:
        if int_value(work_chain_next_route_counts.get(str(route_name))) <= 0:
            failures.append(f"{profile}:missing_work_chain_next_route:{route_name}")
    for expectation_key, scenario_key in (
        ("require_work_chain_no_search", "work_chain_uses_search"),
        ("require_work_chain_no_graph", "work_chain_uses_graph"),
        ("require_work_chain_no_raw_open", "work_chain_opens_raw"),
        ("require_work_chain_no_body_hydration", "work_chain_hydrates_body"),
    ):
        if expectation.get(expectation_key) is True and scenario.get(scenario_key) is not False:
            failures.append(f"{profile}:{scenario_key}:{scenario.get(scenario_key)}")
    max_elapsed_ms = expectation.get("max_elapsed_ms")
    if max_elapsed_ms is not None and int_value(scenario.get("elapsed_ms")) > int_value(max_elapsed_ms):
        failures.append(f"{profile}:elapsed_ms:{scenario.get('elapsed_ms')}>{int_value(max_elapsed_ms)}")
    max_failed_count = expectation.get("max_failed_count")
    if max_failed_count is not None and int_value(scenario.get("failed_count")) > int_value(max_failed_count):
        failures.append(f"{profile}:failed_count:{scenario.get('failed_count')}>{int_value(max_failed_count)}")
    max_warn_count = expectation.get("max_warn_count")
    if max_warn_count is not None and int_value(scenario.get("warn_count")) > int_value(max_warn_count):
        failures.append(f"{profile}:warn_count:{scenario.get('warn_count')}>{int_value(max_warn_count)}")
    counts = scenario.get("evidence_ref_counts") if isinstance(scenario.get("evidence_ref_counts"), dict) else {}
    ref_expectations = {
        "min_raw_ref_count": "raw_ref",
        "min_segment_ref_count": "segment_ref",
        "min_session_ref_count": "session_ref",
        "min_receipt_ref_count": "receipt_ref",
    }
    for expectation_key, count_key in ref_expectations.items():
        minimum = int_value(expectation.get(expectation_key))
        if minimum and int_value(counts.get(count_key)) < minimum:
            failures.append(f"{profile}:{count_key}:{counts.get(count_key)}<{minimum}")
    min_source_ref_count = int_value(expectation.get("min_source_ref_count"))
    if min_source_ref_count and int_value(scenario.get("source_ref_count")) < min_source_ref_count:
        failures.append(f"{profile}:source_ref_count:{scenario.get('source_ref_count')}<{min_source_ref_count}")
    min_evidence_ref_count = int_value(expectation.get("min_evidence_ref_count"))
    if min_evidence_ref_count and int_value(scenario.get("evidence_ref_count")) < min_evidence_ref_count:
        failures.append(f"{profile}:evidence_ref_count:{scenario.get('evidence_ref_count')}<{min_evidence_ref_count}")
    for expectation_key, scenario_key in (
        ("min_active_lookup_count", "active_lookup_count"),
        ("min_observed_lookup_count", "observed_lookup_count"),
        ("min_unknown_lookup_count", "unknown_lookup_count"),
        ("min_stale_lookup_count", "stale_lookup_count"),
        ("min_removed_lookup_count", "removed_lookup_count"),
        ("min_retired_lookup_count", "retired_lookup_count"),
        ("min_registered_lookup_count", "registered_lookup_count"),
        ("min_unregistered_lookup_count", "unregistered_lookup_count"),
        ("min_transition_probe_count", "transition_probe_count"),
    ):
        minimum = int_value(expectation.get(expectation_key))
        if minimum and int_value(scenario.get(scenario_key)) < minimum:
            failures.append(f"{profile}:{scenario_key}:{scenario.get(scenario_key)}<{minimum}")
    for expectation_key, scenario_key in (
        ("min_direct_usage_sample_count", "direct_usage_sample_count"),
        ("min_non_usage_evidence_sample_count", "non_usage_evidence_sample_count"),
        ("min_raw_or_segment_ref_sample_count", "raw_or_segment_ref_sample_count"),
    ):
        minimum = int_value(expectation.get(expectation_key))
        if minimum and int_value(scenario.get(scenario_key)) < minimum:
            failures.append(f"{profile}:{scenario_key}:{scenario.get(scenario_key)}<{minimum}")
    count_expectations = (
        ("kind_counts", "required_kinds", "min_kind_count", "kind"),
        ("layer_counts", "required_layers", "min_layer_count", "layer"),
        ("evidence_mode_counts", "required_evidence_modes", "min_evidence_mode_count", "evidence_mode"),
    )
    for counts_key, required_key, minimum_key, label in count_expectations:
        observed_counts = scenario.get(counts_key) if isinstance(scenario.get(counts_key), dict) else {}
        observed_nonzero = {str(key) for key, value in observed_counts.items() if int_value(value) > 0}
        minimum = int_value(expectation.get(minimum_key))
        if minimum and len(observed_nonzero) < minimum:
            failures.append(f"{profile}:{label}_count:{len(observed_nonzero)}<{minimum}")
        for required in expectation.get(required_key, []) if isinstance(expectation.get(required_key), list) else []:
            required_value = str(required)
            if required_value not in observed_nonzero:
                failures.append(f"{profile}:missing_{label}:{required_value}")
    primary_route_counts = scenario.get("primary_route_counts") if isinstance(scenario.get("primary_route_counts"), dict) else {}
    for route_id in expectation.get("required_primary_routes", []) if isinstance(expectation.get("required_primary_routes"), list) else []:
        if int_value(primary_route_counts.get(str(route_id))) <= 0:
            failures.append(f"{profile}:missing_primary_route:{route_id}")
    for route_id in expectation.get("forbidden_primary_routes", []) if isinstance(expectation.get("forbidden_primary_routes"), list) else []:
        if int_value(primary_route_counts.get(str(route_id))) > 0:
            failures.append(f"{profile}:forbidden_primary_route:{route_id}")
    shape_counts = scenario.get("shape_counts") if isinstance(scenario.get("shape_counts"), dict) else {}
    for shape in expectation.get("required_shape_counts", []) if isinstance(expectation.get("required_shape_counts"), list) else []:
        if int_value(shape_counts.get(str(shape))) <= 0:
            failures.append(f"{profile}:missing_shape:{shape}")
    for counts_key, required_key, label in (
        ("route_anchor_counts", "required_route_anchors", "route_anchor"),
        ("route_anchor_kind_counts", "required_route_anchor_kinds", "route_anchor_kind"),
        ("route_anchor_source_counts", "required_route_anchor_sources", "route_anchor_source"),
        ("match_relation_counts", "required_match_relations", "match_relation"),
    ):
        observed_counts = scenario.get(counts_key) if isinstance(scenario.get(counts_key), dict) else {}
        for required in expectation.get(required_key, []) if isinstance(expectation.get(required_key), list) else []:
            required_value = str(required)
            if int_value(observed_counts.get(required_value)) <= 0:
                failures.append(f"{profile}:missing_{label}:{required_value}")
    for expectation_key, scenario_key in (
        ("min_next_action_count", "next_action_count"),
        ("min_graph_next_action_count", "graph_next_action_count"),
        ("min_search_next_action_count", "search_next_action_count"),
        ("min_entity_registry_next_action_count", "entity_registry_next_action_count"),
        ("min_live_tail_next_action_count", "live_tail_next_action_count"),
        ("min_route_lane_count", "route_lane_count"),
        ("min_graph_queued_count", "graph_queued_count"),
        ("min_graph_high_fanout_dominant_edge_count", "graph_high_fanout_dominant_edge_count"),
        ("min_graph_high_fanout_replacement_candidate_count", "graph_high_fanout_replacement_candidate_count"),
        ("min_graph_high_fanout_replacement_proof_gap_count", "graph_high_fanout_replacement_proof_gap_count"),
        ("min_graph_replacement_usage_event_count", "usage_event_count"),
        ("min_graph_replacement_edge_checked_count", "graph_event_edge_checked_count"),
        ("min_graph_replacement_edge_match_count", "graph_event_edge_match_count"),
        ("min_graph_replacement_event_edge_count", "event_edge_count"),
        ("min_graph_replacement_session_aggregate_edge_count", "session_aggregate_edge_count"),
        ("min_graph_replacement_anchor_count", "anchor_count"),
        ("min_graph_replacement_target_projection_match_count", "target_projection_match_count"),
    ):
        minimum = int_value(expectation.get(expectation_key))
        if minimum and int_value(scenario.get(scenario_key)) < minimum:
            failures.append(f"{profile}:{scenario_key}:{scenario.get(scenario_key)}<{minimum}")
    max_graph_replacement_sample_elapsed_ms = expectation.get("max_graph_replacement_sample_elapsed_ms")
    if (
        max_graph_replacement_sample_elapsed_ms is not None
        and int_value(scenario.get("max_sample_elapsed_ms")) > int_value(max_graph_replacement_sample_elapsed_ms)
    ):
        failures.append(
            f"{profile}:max_sample_elapsed_ms:{scenario.get('max_sample_elapsed_ms')}>{int_value(max_graph_replacement_sample_elapsed_ms)}"
        )
    graph_replacement_anchor_counts = scenario.get("anchor_counts") if isinstance(scenario.get("anchor_counts"), dict) else {}
    for anchor in expectation.get("required_graph_replacement_anchors", []) if isinstance(expectation.get("required_graph_replacement_anchors"), list) else []:
        if int_value(graph_replacement_anchor_counts.get(str(anchor))) <= 0:
            failures.append(f"{profile}:missing_graph_replacement_anchor:{anchor}")
    graph_replacement_kind_counts = scenario.get("kind_counts") if isinstance(scenario.get("kind_counts"), dict) else {}
    for kind in expectation.get("required_graph_replacement_kinds", []) if isinstance(expectation.get("required_graph_replacement_kinds"), list) else []:
        if int_value(graph_replacement_kind_counts.get(str(kind))) <= 0:
            failures.append(f"{profile}:missing_graph_replacement_kind:{kind}")
    if expectation.get("require_exact_next_command") is True and scenario.get("exact_next_command_present") is not True:
        failures.append(f"{profile}:exact_next_command_present:{scenario.get('exact_next_command_present')}")
    if expectation.get("require_maintenance_packet_no_mutation") is True and scenario.get("mutates") is not False:
        failures.append(f"{profile}:mutates:{scenario.get('mutates')}")
    if expectation.get("require_bounded_store_query") is True and scenario.get("bounded_store_query") is not True:
        failures.append(f"{profile}:bounded_store_query:{scenario.get('bounded_store_query')}")
    if (
        expectation.get("require_graph_queue_action_when_queued") is True
        and int_value(scenario.get("graph_queued_count")) > 0
        and scenario.get("graph_queue_action_present") is not True
    ):
        failures.append(f"{profile}:graph_queue_action_missing_for_queued_count:{scenario.get('graph_queued_count')}")
    if (
        expectation.get("require_graph_high_fanout_policy_when_pressure") is True
        and scenario.get("graph_pressure_status") == "large_cardinality_dominates"
        and not scenario.get("graph_high_fanout_policy_status")
    ):
        failures.append(f"{profile}:graph_high_fanout_policy_missing_for_pressure")
    if (
        expectation.get("require_graph_high_fanout_no_mutation_boundary") is True
        and scenario.get("graph_high_fanout_policy_status")
        and scenario.get("graph_high_fanout_mutation_boundary") != "read_only_policy_packet_no_graph_rows_are_deleted_or_rebuilt"
    ):
        failures.append(f"{profile}:graph_high_fanout_mutation_boundary:{scenario.get('graph_high_fanout_mutation_boundary')}")
    if (
        expectation.get("require_graph_high_fanout_replacement_status") is True
        and scenario.get("graph_pressure_status") == "large_cardinality_dominates"
        and not scenario.get("graph_high_fanout_replacement_status")
    ):
        failures.append(f"{profile}:graph_high_fanout_replacement_status_missing_for_pressure")
    if (
        expectation.get("require_graph_high_fanout_prune_gate_closed") is True
        and scenario.get("graph_high_fanout_policy_status")
        and scenario.get("graph_high_fanout_prune_apply_ready") is not False
    ):
        failures.append(f"{profile}:graph_high_fanout_prune_apply_ready:{scenario.get('graph_high_fanout_prune_apply_ready')}")
    if (
        expectation.get("require_graph_replacement_target_projection") is True
        and scenario.get("target_projection") != GRAPH_ENTITY_USAGE_REPLACEMENT_TARGET_PROJECTION
    ):
        failures.append(f"{profile}:target_projection:{scenario.get('target_projection')}")
    if (
        expectation.get("require_graph_replacement_proof_ok") is True
        and scenario.get("replacement_proof_ok") is not True
    ):
        failures.append(f"{profile}:replacement_proof_ok:{scenario.get('replacement_proof_ok')}")
    if (
        expectation.get("require_graph_replacement_prune_gate_closed") is True
        and scenario.get("replacement_prune_apply_ready") is not False
    ):
        failures.append(f"{profile}:replacement_prune_apply_ready:{scenario.get('replacement_prune_apply_ready')}")
    if (
        expectation.get("require_graph_replacement_no_missing_event_edges") is True
        and int_value(scenario.get("graph_event_edge_missing_count")) > 0
    ):
        failures.append(f"{profile}:graph_event_edge_missing_count:{scenario.get('graph_event_edge_missing_count')}")
    if (
        expectation.get("require_graph_replacement_no_failed_core_gates") is True
        and int_value(scenario.get("proof_failed_core_gate_count")) > 0
    ):
        failures.append(f"{profile}:proof_failed_core_gate_count:{scenario.get('proof_failed_core_gate_count')}")
    next_action_ids = {str(item) for item in scenario.get("next_action_ids", []) if item} if isinstance(scenario.get("next_action_ids"), list) else set()
    for action_id in expectation.get("required_next_action_ids", []) if isinstance(expectation.get("required_next_action_ids"), list) else []:
        if str(action_id) not in next_action_ids:
            failures.append(f"{profile}:missing_next_action_id:{action_id}")
    next_action_lane_counts = scenario.get("next_action_lane_counts") if isinstance(scenario.get("next_action_lane_counts"), dict) else {}
    for lane in expectation.get("required_next_action_lanes", []) if isinstance(expectation.get("required_next_action_lanes"), list) else []:
        if int_value(next_action_lane_counts.get(str(lane))) <= 0:
            failures.append(f"{profile}:missing_next_action_lane:{lane}")
    return failures


def live_scenario_expectation_failures(audit: dict[str, Any], expect: dict[str, Any]) -> list[str]:
    failures: list[str] = []
    quality = audit.get("quality") if isinstance(audit.get("quality"), dict) else {}
    if not audit.get("ok") and "max_failed_count" not in expect:
        failures.append("audit_not_ok")
    max_failed_count = expect.get("max_failed_count")
    if max_failed_count is not None and int_value(quality.get("failed_count")) > int_value(max_failed_count):
        failures.append(f"failed_count:{quality.get('failed_count')}>{int_value(max_failed_count)}")
    max_warn_count = expect.get("max_warn_count")
    if max_warn_count is not None and int_value(quality.get("warn_count")) > int_value(max_warn_count):
        failures.append(f"warn_count:{quality.get('warn_count')}>{int_value(max_warn_count)}")
    max_actionable_gap_count = expect.get("max_actionable_gap_count")
    if max_actionable_gap_count is not None and int_value(quality.get("actionable_gap_count")) > int_value(max_actionable_gap_count):
        failures.append(f"actionable_gap_count:{quality.get('actionable_gap_count')}>{int_value(max_actionable_gap_count)}")
    max_first_useful_packet_ms = expect.get("max_first_useful_packet_ms")
    if max_first_useful_packet_ms is not None and int_value(quality.get("first_useful_packet_ms")) > int_value(max_first_useful_packet_ms):
        failures.append(f"first_useful_packet_ms:{quality.get('first_useful_packet_ms')}>{int_value(max_first_useful_packet_ms)}")
    max_elapsed_ms = expect.get("max_elapsed_ms")
    if max_elapsed_ms is not None and int_value(quality.get("elapsed_ms")) > int_value(max_elapsed_ms):
        failures.append(f"elapsed_ms:{quality.get('elapsed_ms')}>{int_value(max_elapsed_ms)}")
    min_ref_scenarios = int_value(expect.get("min_raw_or_segment_ref_scenario_count"))
    if min_ref_scenarios and int_value(quality.get("raw_or_segment_ref_scenario_count")) < min_ref_scenarios:
        failures.append(
            f"raw_or_segment_ref_scenario_count:{quality.get('raw_or_segment_ref_scenario_count')}<{min_ref_scenarios}"
        )
    scenarios_by_profile = {
        str(item.get("profile") or ""): item
        for item in audit.get("scenarios", [])
        if isinstance(item, dict)
    } if isinstance(audit.get("scenarios"), list) else {}
    for profile_expectation in expect.get("profile_expectations", []) if isinstance(expect.get("profile_expectations"), list) else []:
        if not isinstance(profile_expectation, dict):
            continue
        profile = str(profile_expectation.get("profile") or "")
        scenario = scenarios_by_profile.get(profile)
        if not scenario:
            failures.append(f"missing_profile:{profile}")
            continue
        failures.extend(live_scenario_profile_expectation_failures(scenario, profile_expectation))
    return failures


def live_scenario_corpus_case_check(
    aoa_root: Path,
    case: dict[str, Any],
) -> dict[str, Any]:
    live_check = str(case.get("live_check") or "run")
    if live_check in {"skip", "fixture_required"}:
        return {
            "id": case.get("id"),
            "ok": True,
            "skipped": True,
            "skip_reason": live_check,
            "failures": [],
            "actionable_gaps": [],
            "observed": {},
        }
    profiles = [
        route_key_slug(str(item), fallback="", max_chars=80)
        for item in case.get("profiles", [])
        if item
    ] if isinstance(case.get("profiles"), list) else []
    expect = case.get("expect") if isinstance(case.get("expect"), dict) else {}
    if not profiles:
        profiles = [
            str(item.get("profile") or "")
            for item in expect.get("profile_expectations", [])
            if isinstance(item, dict) and item.get("profile")
        ]
    audit = live_scenario_audit(
        aoa_root=aoa_root,
        seed=str(case.get("seed") or case.get("id") or "live-scenario-corpus"),
        profiles=profiles or None,
        sample_size=max(1, min(int_value(case.get("sample_size"), 4), 12)),
        recent_days=max(1, min(int_value(case.get("recent_days"), 7), 90)),
        limit=max(1, min(int_value(case.get("limit"), 3), 10)),
        literal_probes=case.get("literal_probes") if isinstance(case.get("literal_probes"), list) else None,
        entity_usage_probes=case.get("entity_usage_probes") if isinstance(case.get("entity_usage_probes"), list) else None,
        graph_replacement_probes=case.get("graph_replacement_probes") if isinstance(case.get("graph_replacement_probes"), list) else None,
        route_rollup_query=str(case.get("route_rollup_query") or "aoa-session-memory-mcp"),
        route_rollup_layer=str(case.get("route_rollup_layer") or "mcp"),
        write_report=False,
    )
    failures = live_scenario_expectation_failures(audit, expect)
    return {
        "id": case.get("id"),
        "ok": not failures,
        "skipped": False,
        "profiles": audit.get("profiles"),
        "failures": failures,
        "actionable_gaps": audit.get("actionable_gaps", []) if isinstance(audit.get("actionable_gaps"), list) else [],
        "observed": live_scenario_compact_observed(audit),
    }


def live_scenario_corpus_check(
    *,
    aoa_root: Path,
    corpus_path: Path | None = None,
    case_limit: int = 0,
    write_report: bool = False,
) -> dict[str, Any]:
    now = utc_now()
    target = corpus_path or live_scenario_corpus_default_path(aoa_root)
    corpus, diagnostics = load_live_scenario_corpus(target)
    all_cases = [case for case in corpus.get("cases", []) if isinstance(case, dict)] if isinstance(corpus.get("cases"), list) else []
    selected_limit = max(0, int_value(case_limit, 0))
    cases = all_cases[:selected_limit] if selected_limit else all_cases
    try:
        live_session_count = len(chronological_session_records(aoa_root))
    except Exception as exc:  # pragma: no cover - defensive route packet
        live_session_count = 0
        diagnostics.append(f"session_record_read_error:{exc}")
    if cases and live_session_count <= 0:
        results = [
            {
                "id": case.get("id"),
                "ok": True,
                "skipped": True,
                "skip_reason": "empty_archive_no_live_scenarios",
                "profiles": case.get("profiles") if isinstance(case.get("profiles"), list) else [],
                "failures": [],
                "actionable_gaps": [],
                "observed": {},
            }
            for case in cases
        ]
    else:
        results = [live_scenario_corpus_case_check(aoa_root, case) for case in cases]
    failures = [result for result in results if not result.get("ok")]
    actionable_gaps = [
        {**gap, "case_id": result.get("id")}
        for result in results
        for gap in result.get("actionable_gaps", [])
        if isinstance(gap, dict)
    ]
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_live_scenario_regression_check",
        "generated_at": now,
        "ok": not diagnostics and bool(results) and not failures,
        "mutates": False,
        "truth_status": "reviewed_live_scenario_route_controls_not_memory_truth",
        "corpus_path": str(target),
        "case_count": len(results),
        "available_case_count": len(all_cases),
        "live_session_count": live_session_count,
        "passed_count": sum(1 for result in results if result.get("ok")),
        "skipped_count": sum(1 for result in results if result.get("skipped")),
        "failed_count": len(failures),
        "actionable_gap_count": len(actionable_gaps),
        "actionable_gaps": actionable_gaps[:40],
        "results": results,
        "diagnostics": diagnostics,
        "next_route": "Open result failures first; warnings in actionable_gaps are quality debts even when the reviewed case allows them.",
        "authority_boundary": "Live scenario corpus checks route behavior over the current archive; raw/segment refs remain stronger than the corpus packet.",
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__live-scenario-corpus-check"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, live_scenario_corpus_check_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def live_scenario_corpus_check_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Live Scenario Corpus Check",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- corpus_path: `{payload.get('corpus_path')}`",
        f"- passed: `{payload.get('passed_count')}/{payload.get('case_count')}`",
        f"- skipped: `{payload.get('skipped_count')}`",
        f"- actionable_gaps: `{payload.get('actionable_gap_count')}`",
        "",
        "| id | ok | skipped | profiles | failures |",
        "| --- | --- | --- | --- | --- |",
    ]
    for result in payload.get("results", []) if isinstance(payload.get("results"), list) else []:
        if isinstance(result, dict):
            lines.append(
                "| `{}` | `{}` | `{}` | `{}` | {} |".format(
                    result.get("id"),
                    result.get("ok"),
                    result.get("skipped"),
                    ", ".join(str(item) for item in result.get("profiles", []) if item) if isinstance(result.get("profiles"), list) else "",
                    markdown_cell(", ".join(str(item) for item in result.get("failures", []) if item)),
                )
            )
    gaps = payload.get("actionable_gaps") if isinstance(payload.get("actionable_gaps"), list) else []
    if gaps:
        lines.extend(["", "## Actionable Gaps", ""])
        for gap in gaps:
            if isinstance(gap, dict):
                lines.append(f"- `{gap.get('case_id')}` `{gap.get('profile')}` `{gap.get('status')}`: {', '.join(str(item) for item in gap.get('reasons', []) if item)}")
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        for item in diagnostics:
            lines.append(f"- `{item}`")
    return "\n".join(lines) + "\n"


def performance_step_summary(payload: dict[str, Any]) -> dict[str, Any]:
    keys = (
        "ok",
        "artifact_type",
        "match_count",
        "result_count",
        "event_count",
        "usage_event_count",
        "consequence_event_count",
        "document_count",
        "entity_count",
        "entity_registry_document_count",
        "target_entity_registry_document_count",
        "inserted_entity_registry_document_count",
        "updated_entity_registry_document_count",
        "unchanged_entity_registry_document_count",
        "removed_entity_registry_document_count",
        "skipped",
        "skip_reason",
        "selected_count",
        "processed_count",
        "remaining_count",
        "budget_seconds",
        "budget_exhausted",
        "partial",
        "kind",
        "requested_kind",
        "node_count",
        "edge_count",
        "diagnostics",
    )
    summary = {key: payload.get(key) for key in keys if key in payload}
    if payload.get("artifact_type") == "session_memory_graphrag_packet":
        lexical = payload.get("lexical") if isinstance(payload.get("lexical"), dict) else {}
        graph = payload.get("graph") if isinstance(payload.get("graph"), dict) else {}
        summary["lexical_result_count"] = lexical.get("result_count")
        summary["graph_node_count"] = graph.get("node_count")
        summary["graph_edge_count"] = graph.get("edge_count")
        summary["evidence_ref_count"] = len(payload.get("evidence_refs", []) if isinstance(payload.get("evidence_refs"), list) else [])
    if payload.get("artifact_type") == "agent_event_route_results":
        quality = payload.get("quality") if isinstance(payload.get("quality"), dict) else {}
        projection = payload.get("search_projection") if isinstance(payload.get("search_projection"), dict) else {}
        cost_profile = payload.get("cost_profile") if isinstance(payload.get("cost_profile"), dict) else {}
        summary["agent_events"] = payload.get("agent_events", []) if isinstance(payload.get("agent_events"), list) else []
        summary["search_projection_mode"] = projection.get("mode")
        summary["queried_shard_count"] = projection.get("queried_shard_count")
        summary["uses_shards"] = cost_profile.get("uses_shards")
        summary["uses_fts"] = cost_profile.get("uses_fts")
        summary["hydrates_body"] = cost_profile.get("hydrates_body")
        summary["raw_ref_present_count"] = quality.get("raw_ref_present_count")
        summary["segment_ref_present_count"] = quality.get("segment_ref_present_count")
        summary["freshness_counts"] = quality.get("freshness_counts")
    if payload.get("artifact_type") == "session_memory_entity_usage_neighborhood":
        quality = payload.get("quality") if isinstance(payload.get("quality"), dict) else {}
        summary["usage_neighborhood_present"] = quality.get("usage_neighborhood_present")
        summary["raw_preview_available"] = quality.get("raw_preview_available")
    if payload.get("artifact_type") == "entity_registry_lookup":
        route = payload.get("agent_route_packet") if isinstance(payload.get("agent_route_packet"), dict) else {}
        summary["registered"] = route.get("registered")
        summary["status"] = route.get("status")
    return summary


def performance_baseline_step(
    step_id: str,
    *,
    description: str,
    mutates: bool,
    run: Callable[[], dict[str, Any]],
) -> dict[str, Any]:
    started = time.monotonic()
    try:
        payload = run()
    except Exception as exc:  # pragma: no cover - defensive CLI boundary.
        return {
            "id": step_id,
            "description": description,
            "ok": False,
            "mutates": mutates,
            "elapsed_ms": int((time.monotonic() - started) * 1000),
            "summary": {},
            "diagnostics": [f"{exc.__class__.__name__}:{exc}"],
        }
    diagnostics = payload.get("diagnostics", []) if isinstance(payload.get("diagnostics"), list) else []
    return {
        "id": step_id,
        "description": description,
        "ok": bool(payload.get("ok")),
        "mutates": mutates,
        "elapsed_ms": int((time.monotonic() - started) * 1000),
        "artifact_type": payload.get("artifact_type"),
        "summary": performance_step_summary(payload),
        "diagnostics": diagnostics,
    }


def skipped_performance_step(step_id: str, *, description: str, reason: str, mutates: bool) -> dict[str, Any]:
    return {
        "id": step_id,
        "description": description,
        "ok": True,
        "status": "skipped",
        "mutates": False,
        "would_mutate": mutates,
        "elapsed_ms": 0,
        "summary": {},
        "diagnostics": [reason],
    }


PERFORMANCE_BASELINE_WARNING_DIAGNOSTIC_PREFIXES = (
    "answer_rule_gate:",
    "search_shard_fanout_using_structured_nonmaterialized_shards:",
)


def performance_baseline_diagnostic_is_warning(item: str) -> bool:
    return any(str(item).startswith(prefix) for prefix in PERFORMANCE_BASELINE_WARNING_DIAGNOSTIC_PREFIXES)


def performance_storage_summary(aoa_root: Path) -> dict[str, Any]:
    search_path = search_db_path(aoa_root)
    graph_path = graph_paths(aoa_root)["store"]
    search_entry = maintenance_light_sqlite_size(search_path)
    graph_entry = maintenance_light_sqlite_size(graph_path)
    summary: dict[str, Any] = {
        "search": {
            **search_entry,
            "db_path": str(search_path),
            "diagnostics": search_entry.get("diagnostics", []) if isinstance(search_entry.get("diagnostics"), list) else [],
        },
        "graph": {
            **graph_entry,
            "db_path": str(graph_path),
            "diagnostics": graph_entry.get("diagnostics", []) if isinstance(graph_entry.get("diagnostics"), list) else [],
        },
    }
    if search_path.exists():
        try:
            conn = sqlite3.connect(str(search_path))
            total = int_value(conn.execute("SELECT COUNT(*) FROM documents").fetchone()[0])
            doc_type_counts = [
                {"doc_type": str(row[0] or ""), "count": int_value(row[1])}
                for row in conn.execute(
                    "SELECT doc_type, COUNT(*) FROM documents GROUP BY doc_type ORDER BY COUNT(*) DESC LIMIT 20"
                ).fetchall()
            ]
            route_term_count = int_value(conn.execute("SELECT COUNT(*) FROM route_terms").fetchone()[0])
            conn.close()
            summary["search"].update(
                {
                    "document_count": total,
                    "doc_type_counts": doc_type_counts,
                    "route_term_count": route_term_count,
                    "event_document_count": next((item["count"] for item in doc_type_counts if item.get("doc_type") == "event"), 0),
                    "entity_registry_document_count": next((item["count"] for item in doc_type_counts if item.get("doc_type") == "entity_registry"), 0),
                }
            )
        except sqlite3.Error as exc:
            summary["search"]["diagnostics"] = [f"sqlite_error:{exc}"]
    graph_state = graph_store_query_state(aoa_root)
    summary["graph"].update(
        {
            "status": graph_state.get("status"),
            "metadata": graph_state.get("metadata") if isinstance(graph_state.get("metadata"), dict) else {},
            "diagnostics": graph_state.get("diagnostics", []) if isinstance(graph_state.get("diagnostics"), list) else [],
        }
    )
    search_shards = session_memory_search_shard_projection_summary(aoa_root)
    summary["search_shards"] = {
        key: search_shards.get(key)
        for key in (
            "status",
            "catalog_status",
            "shard_strategy",
            "active_projection",
            "fallback_status",
            "session_count",
            "shard_count",
            "materialized_shard_count",
            "current_shard_count",
            "stale_shard_count",
            "missing_shard_count",
            "noncurrent_shard_count",
            "document_count",
            "shard_db_total_bytes",
            "shard_db_total_human",
            "monolith_db_total_bytes",
            "monolith_db_total_human",
            "combined_search_projection_total_bytes",
            "combined_search_projection_total_human",
            "raw_text_query_route",
            "truth_status",
        )
        if key in search_shards
    }
    summary["search_shards"]["largest_shards"] = [
        {
            key: item.get(key)
            for key in (
                "shard",
                "status",
                "session_count",
                "document_count",
                "size_human",
                "total_with_wal_human",
                "raw_text_query_support",
                "storage_profile",
            )
            if key in item
        }
        for item in (search_shards.get("largest_shards") or [])[:4]
        if isinstance(item, dict)
    ]
    return summary


def performance_baseline_diagnosis(steps: list[dict[str, Any]], storage: dict[str, Any] | None = None) -> dict[str, Any]:
    completed = [step for step in steps if step.get("status") != "skipped"]
    slowest = max(completed, key=lambda step: int_value(step.get("elapsed_ms")), default={})
    by_id = {str(step.get("id") or ""): step for step in completed}
    likely_components: list[dict[str, Any]] = []

    def elapsed(step_id: str) -> int:
        return int_value((by_id.get(step_id) or {}).get("elapsed_ms"))

    registry_ms = elapsed("narrow_entity_registry_refresh")
    search_ms = elapsed("narrow_search_index_refresh")
    if search_ms and registry_ms and search_ms > max(1000, registry_ms * 2):
        search_summary = by_id.get("narrow_search_index_refresh", {}).get("summary")
        likely_components.append(
            {
                "component": "session_search_index_refresh",
                "reason": "narrow search-index refresh is materially slower than registry-only refresh",
                "elapsed_ms": search_ms,
                "comparison_elapsed_ms": registry_ms,
                "selected_count": (search_summary or {}).get("selected_count") if isinstance(search_summary, dict) else None,
                "processed_count": (search_summary or {}).get("processed_count") if isinstance(search_summary, dict) else None,
            }
        )
    for step_id, component in (
        ("registry_lookup", "entity_registry_lookup"),
        ("agent_event_route", "agent_event_route_search"),
        ("usage_audit", "entity_usage_audit"),
        ("usage_neighborhood", "entity_usage_neighborhood"),
        ("graphrag_packet", "graph_rag_packet"),
    ):
        step_ms = elapsed(step_id)
        if step_ms > 2000:
            likely_components.append(
                {
                    "component": component,
                    "reason": "read route exceeds interactive 2s target",
                    "elapsed_ms": step_ms,
                }
            )
    storage = storage if isinstance(storage, dict) else {}
    search_storage = storage.get("search") if isinstance(storage.get("search"), dict) else {}
    graph_storage = storage.get("graph") if isinstance(storage.get("graph"), dict) else {}
    event_document_count = int_value(search_storage.get("event_document_count"))
    search_size_bytes = int_value(search_storage.get("size_bytes"))
    graph_size_bytes = int_value(graph_storage.get("size_bytes"))
    if event_document_count > 250_000:
        likely_components.append(
            {
                "component": "search_event_document_volume",
                "reason": "portable search has a large event-document hot set; prefer compact/hot event projections before broad rebuilds",
                "event_document_count": event_document_count,
                "size_bytes": search_size_bytes,
            }
        )
    if graph_size_bytes > 10 * 1024 * 1024 * 1024:
        likely_components.append(
            {
                "component": "graph_store_weight",
                "reason": "graph store is heavy enough that read packets should stay bounded or use hot materialized neighborhoods",
                "size_bytes": graph_size_bytes,
            }
        )
    refresh_step = by_id.get("narrow_entity_registry_refresh", {})
    refresh_summary = refresh_step.get("summary") if isinstance(refresh_step.get("summary"), dict) else {}
    search_step = by_id.get("narrow_search_index_refresh", {})
    search_summary = search_step.get("summary") if isinstance(search_step.get("summary"), dict) else {}
    return {
        "slowest_step": slowest.get("id"),
        "slowest_elapsed_ms": slowest.get("elapsed_ms"),
        "likely_heavy_components": likely_components,
        "refresh_path": {
            "entity_registry_refresh_reindexes_session_docs": False if refresh_step else None,
            "entity_registry_selected_count": refresh_summary.get("selected_count"),
            "entity_registry_processed_count": refresh_summary.get("processed_count"),
            "search_index_refresh_reindexes_session_docs": bool(int_value(search_summary.get("processed_count"))),
            "search_index_selected_count": search_summary.get("selected_count"),
            "search_index_processed_count": search_summary.get("processed_count"),
        },
        "interpretation": "Use registry-only refresh for entity source drift; reserve search-index refresh for session/search document drift.",
    }


def performance_baseline_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Performance Baseline",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- anchor: `{payload.get('anchor')}`",
        f"- route_family: `{payload.get('route_family')}`",
        f"- kind: `{payload.get('kind')}`",
        f"- apply_refresh: `{payload.get('apply_refresh')}`",
        f"- search_target: `{payload.get('search_target')}`",
        f"- total_elapsed_ms: `{payload.get('elapsed_ms')}`",
        "",
        "| step | ok | mutates | elapsed_ms | summary |",
        "| --- | --- | --- | --- | --- |",
    ]
    for step in payload.get("steps", []) if isinstance(payload.get("steps"), list) else []:
        if not isinstance(step, dict):
            continue
        summary = json.dumps(step.get("summary", {}), ensure_ascii=False, sort_keys=True)
        lines.append(
            f"| `{step.get('id')}` | `{step.get('ok')}` | `{step.get('mutates')}` | "
            f"`{step.get('elapsed_ms')}` | `{short_text(summary, max_chars=220)}` |"
        )
    diagnosis = payload.get("diagnosis") if isinstance(payload.get("diagnosis"), dict) else {}
    lines.extend(
        [
            "",
            "## Diagnosis",
            "",
            f"- slowest_step: `{diagnosis.get('slowest_step')}`",
            f"- slowest_elapsed_ms: `{diagnosis.get('slowest_elapsed_ms')}`",
        ]
    )
    for item in diagnosis.get("likely_heavy_components", []) if isinstance(diagnosis.get("likely_heavy_components"), list) else []:
        if isinstance(item, dict):
            lines.append(f"- `{item.get('component')}`: `{item.get('reason')}` elapsed_ms=`{item.get('elapsed_ms')}`")
    storage = payload.get("storage") if isinstance(payload.get("storage"), dict) else {}
    search_storage = storage.get("search") if isinstance(storage.get("search"), dict) else {}
    graph_storage = storage.get("graph") if isinstance(storage.get("graph"), dict) else {}
    search_shards = storage.get("search_shards") if isinstance(storage.get("search_shards"), dict) else {}
    lines.extend(
        [
            "",
            "## Storage",
            "",
            f"- search_size_bytes: `{search_storage.get('size_bytes')}`",
            f"- search_total_with_wal: `{search_storage.get('total_with_wal_human')}`",
            f"- search_wal: `{(search_storage.get('wal') or {}).get('size_human') if isinstance(search_storage.get('wal'), dict) else ''}`",
            f"- search_document_count: `{search_storage.get('document_count')}`",
            f"- search_event_document_count: `{search_storage.get('event_document_count')}`",
            f"- search_route_term_count: `{search_storage.get('route_term_count')}`",
            f"- graph_size_bytes: `{graph_storage.get('size_bytes')}`",
            f"- graph_total_with_wal: `{graph_storage.get('total_with_wal_human')}`",
            f"- graph_wal: `{(graph_storage.get('wal') or {}).get('size_human') if isinstance(graph_storage.get('wal'), dict) else ''}`",
            f"- graph_status: `{graph_storage.get('status')}`",
            f"- search_shards: `{search_shards.get('status')}` materialized=`{search_shards.get('materialized_shard_count')}/{search_shards.get('shard_count')}` shard_total=`{search_shards.get('shard_db_total_human')}` combined=`{search_shards.get('combined_search_projection_total_human')}`",
        ]
    )
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        lines.extend(f"- `{item}`" for item in diagnostics)
    warnings = payload.get("warnings") if isinstance(payload.get("warnings"), list) else []
    if warnings:
        lines.extend(["", "## Warnings", ""])
        lines.extend(f"- `{item}`" for item in warnings)
    return "\n".join(lines) + "\n"


def performance_baseline(
    *,
    aoa_root: Path,
    anchor: str,
    kind: str = "auto",
    limit: int = 6,
    per_route_limit: int = 10,
    search_target: str = "latest",
    max_raw_bytes: int | None = None,
    apply_refresh: bool = False,
    refresh_budget_seconds: float | None = 120.0,
    write_report: bool = False,
) -> dict[str, Any]:
    now = utc_now()
    started = time.monotonic()
    limit = max(1, min(int_value(limit, 6), 30))
    per_route_limit = max(1, min(int_value(per_route_limit, 10), 50))
    anchor_text = str(anchor or "").strip() or "aoa-session-memory-mcp"
    kind_text = str(kind or "auto").strip().lower() or "auto"
    trace_kind = normalize_trace_route_kind(kind_text)
    route_family = "agent_event" if trace_kind == "agent_event" else "operational_entity"
    steps: list[dict[str, Any]] = [
        performance_baseline_step(
            "registry_lookup",
            description="Resolve the anchor through generated entity registry.",
            mutates=False,
            run=lambda: entity_registry_lookup(aoa_root=aoa_root, anchor=anchor_text, kind=kind_text),
        ),
    ]
    if route_family == "agent_event":
        agent_event_classes = normalize_agent_event_route_classes([anchor_text], default=AGENT_RESPONSE_ROUTE_CLASSES)
        steps.extend(
            [
                performance_baseline_step(
                    "agent_event_route",
                    description="Measure the compact structured agent-event route.",
                    mutates=False,
                    run=lambda: agent_event_route_search(
                        aoa_root=aoa_root,
                        agent_events=agent_event_classes,
                        limit=limit,
                        explain=True,
                        use_shards=True,
                    ),
                ),
                skipped_performance_step(
                    "usage_audit",
                    description="Trace usage events, consequences, and document refs.",
                    reason="skipped_agent_event_route_family_uses_agent_event_route",
                    mutates=False,
                ),
                skipped_performance_step(
                    "usage_neighborhood",
                    description="Open local before/after windows around usage events.",
                    reason="skipped_agent_event_route_family_uses_agent_event_route",
                    mutates=False,
                ),
                skipped_performance_step(
                    "graphrag_packet",
                    description="Build lexical plus graph expansion evidence packet.",
                    reason="skipped_compact_agent_event_baseline_requires_explicit_graphrag_route",
                    mutates=False,
                ),
            ]
        )
    else:
        steps.extend(
            [
                performance_baseline_step(
                    "usage_audit",
                    description="Trace usage events, consequences, and document refs.",
                    mutates=False,
                    run=lambda: entity_usage_audit(
                        aoa_root=aoa_root,
                        anchor=anchor_text,
                        kind=trace_kind,
                        limit=limit,
                        per_route_limit=per_route_limit,
                        consequence_window=4,
                        document_limit=max(20, limit * 6),
                    ),
                ),
                performance_baseline_step(
                    "usage_neighborhood",
                    description="Open local before/after windows around usage events.",
                    mutates=False,
                    run=lambda: entity_usage_neighborhood(
                        aoa_root=aoa_root,
                        anchor=anchor_text,
                        kind=trace_kind,
                        limit=min(limit, 6),
                        per_route_limit=per_route_limit,
                        before=2,
                        after=4,
                        raw_preview_chars=400,
                        document_limit=max(24, limit * 8),
                    ),
                ),
                performance_baseline_step(
                    "graphrag_packet",
                    description="Build lexical plus graph expansion evidence packet.",
                    mutates=False,
                    run=lambda: graph_rag_packet(
                        aoa_root=aoa_root,
                        query=anchor_text,
                        anchor=anchor_text,
                        kind=trace_kind,
                        limit=min(limit, 8),
                    ),
                ),
            ]
        )
    if apply_refresh:
        steps.append(
            performance_baseline_step(
                "narrow_entity_registry_refresh",
                description="Refresh entity registry snapshot and entity_registry search docs only.",
                mutates=True,
                run=lambda: refresh_entity_registry_search_documents_only(
                    aoa_root=aoa_root,
                    write_report=False,
                    budget_seconds=refresh_budget_seconds,
                ),
            )
        )
        steps.append(
            performance_baseline_step(
                "narrow_search_index_refresh",
                description="Refresh one selected session through incremental search-index path.",
                mutates=True,
                run=lambda: search_index_sessions(
                    aoa_root=aoa_root,
                    target=search_target,
                    max_raw_bytes=max_raw_bytes,
                    rebuild=False,
                    write_report=False,
                    budget_seconds=refresh_budget_seconds,
                ),
            )
        )
    else:
        steps.append(
            skipped_performance_step(
                "narrow_entity_registry_refresh",
                description="Refresh entity registry snapshot and entity_registry search docs only.",
                reason="skipped_requires_apply_refresh",
                mutates=True,
            )
        )
        steps.append(
            skipped_performance_step(
                "narrow_search_index_refresh",
                description="Refresh one selected session through incremental search-index path.",
                reason="skipped_requires_apply_refresh",
                mutates=True,
            )
        )
    observed_diagnostics = sorted(
        {
            str(item)
            for step in steps
            for item in (step.get("diagnostics", []) if isinstance(step.get("diagnostics"), list) else [])
            if item and not str(item).startswith("skipped_")
        }
    )
    warnings = [item for item in observed_diagnostics if performance_baseline_diagnostic_is_warning(item)]
    diagnostics = [item for item in observed_diagnostics if not performance_baseline_diagnostic_is_warning(item)]
    storage = performance_storage_summary(aoa_root)
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_performance_baseline",
        "generated_at": now,
        "ok": all(bool(step.get("ok")) for step in steps) and not diagnostics,
        "mutates": bool(apply_refresh),
        "truth_status": "performance_measurement_not_correctness_proof",
        "anchor": anchor_text,
        "route_family": route_family,
        **trace_kind_payload_fields(kind_text, trace_kind),
        "limit": limit,
        "per_route_limit": per_route_limit,
        "search_target": search_target,
        "max_raw_bytes": max_raw_bytes,
        "apply_refresh": apply_refresh,
        "refresh_budget_seconds": refresh_budget_seconds,
        "elapsed_ms": int((time.monotonic() - started) * 1000),
        "steps": steps,
        "storage": storage,
        "diagnosis": performance_baseline_diagnosis(steps, storage=storage),
        "diagnostics": diagnostics,
        "warnings": warnings,
        "next_route": "Use this baseline to choose the next optimization; repeat after changes and compare step elapsed_ms.",
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__performance-baseline__{route_key_slug(anchor_text, fallback='anchor', max_chars=80)}"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, performance_baseline_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


