def command_search_index(args: argparse.Namespace) -> int:
    explicit_workspace = Path(args.workspace_root) if args.workspace_root else None
    root = aoa_root_for(explicit_workspace, Path(args.aoa_root) if args.aoa_root else None)
    since = since_date_from_args(args.since, args.since_days if args.since_days is not None else None)
    max_raw_bytes = (
        -1
        if getattr(args, "unbounded_raw_text", False)
        else int(args.max_raw_mb * 1024 * 1024) if args.max_raw_mb is not None else None
    )
    def run_search_index() -> dict[str, Any]:
        try:
            rebuild = search_index_default_rebuild(
                target=args.session,
                since=since,
                until=args.until,
                limit=args.limit,
                force_rebuild=args.rebuild,
                no_rebuild=args.no_rebuild,
            )
        except ValueError as exc:
            return {
                "schema_version": SCHEMA_VERSION,
                "artifact_type": "search_index",
                "search_schema_version": SEARCH_SCHEMA_VERSION,
                "generated_at": utc_now(),
                "ok": False,
                "target": args.session,
                "selected_count": 0,
                "document_count": 0,
                "max_raw_bytes": max_raw_bytes,
                "raw_lexical_policy": search_raw_lexical_policy(
                    max_raw_bytes,
                    use_default_budget=not getattr(args, "unbounded_raw_text", False),
                ),
                "db_path": str(search_db_path(root)),
                "diagnostics": [str(exc)],
                "sessions": [],
            }
        return search_index_sessions(
            aoa_root=root,
            target=args.session,
            since=since,
            until=args.until,
            limit=args.limit,
            max_raw_bytes=max_raw_bytes,
            use_default_raw_lexical_budget=not getattr(args, "unbounded_raw_text", False),
            rebuild=rebuild,
            write_report=args.write_report,
            budget_seconds=args.budget_seconds,
            progress_every=args.progress_every,
        )

    payload = run_with_maintenance_lock(
        root,
        run_search_index,
        owner_job="search-index",
        mode="manual-bulk",
        target=args.session,
        reason="operator_requested",
        touched_surfaces=maintenance_surfaces(repair_indexes=False, repair_graph=False, search=True, entity_registry=True),
        budget_seconds=args.budget_seconds,
    )
    print(json.dumps(payload, indent=2, ensure_ascii=False))
    return 0 if payload.get("ok") else 1


