def atlas_policy_axes(aoa_root: Path) -> list[str]:
    policy = read_json(aoa_root / ATLAS_POLICY_PATH, {})
    axes = policy.get("axes") if isinstance(policy, dict) else None
    names: list[str] = []
    if isinstance(axes, list):
        names = [str(axis.get("name")) for axis in axes if isinstance(axis, dict) and axis.get("name")]
    if not names:
        names = DEFAULT_ATLAS_AXES
    return sorted(dict.fromkeys(names))


def clear_generated_atlas(aoa_root: Path, axes: list[str]) -> None:
    maps_root = aoa_root / ATLAS_ROOT
    for name in ("INDEX.md", "index.json"):
        path = maps_root / name
        if path.exists():
            path.unlink()
    for axis in axes:
        axis_dir = maps_root / axis
        for name in ("INDEX.md", "index.json"):
            path = axis_dir / name
            if path.exists():
                path.unlink()
        entries_dir = axis_dir / "entries"
        if not entries_dir.exists():
            continue
        for path in entries_dir.iterdir():
            if path.name == ".gitkeep":
                continue
            if path.is_file() and path.suffix in {".json", ".md"}:
                path.unlink()


def route_signal_evidence_from_segment(
    segment_index: dict[str, Any],
    *,
    layer: str | None = None,
    key: str | None = None,
    session_act: str | None = None,
    conversation_act: str | None = None,
) -> dict[str, str] | None:
    event_ids: list[str] = []
    if layer and key:
        by_layer = segment_index.get("by_route_layer") if isinstance(segment_index.get("by_route_layer"), dict) else {}
        by_key = by_layer.get(layer) if isinstance(by_layer.get(layer), dict) else {}
        event_ids = [str(item) for item in by_key.get(key, [])] if isinstance(by_key.get(key), list) else []
    elif session_act:
        by_session_act = segment_index.get("by_session_act") if isinstance(segment_index.get("by_session_act"), dict) else {}
        event_ids = [str(item) for item in by_session_act.get(session_act, [])] if isinstance(by_session_act.get(session_act), list) else []
    elif conversation_act:
        by_conversation_act = segment_index.get("by_conversation_act") if isinstance(segment_index.get("by_conversation_act"), dict) else {}
        event_ids = [str(item) for item in by_conversation_act.get(conversation_act, [])] if isinstance(by_conversation_act.get(conversation_act), list) else []
    if not event_ids:
        return None
    events = segment_index.get("events") if isinstance(segment_index.get("events"), list) else []
    wanted = event_ids[0]
    for event in events:
        if isinstance(event, dict) and str(event.get("event_id") or "") == wanted:
            return {
                "raw_ref": str(event.get("raw_ref") or ""),
                "segment_ref": str(event.get("md_anchor") or segment_index.get("markdown") or ""),
                "generated_index_ref": str(segment_index.get("_index_path") or ""),
            }
    return None


def event_evidence_from_segment_index(segment_index: dict[str, Any], event_id: str) -> dict[str, str] | None:
    for event in segment_index.get("events", []) if isinstance(segment_index.get("events"), list) else []:
        if isinstance(event, dict) and str(event.get("event_id") or "") == event_id:
            return {
                "raw_ref": str(event.get("raw_ref") or ""),
                "segment_ref": str(event.get("md_anchor") or segment_index.get("markdown") or ""),
                "generated_index_ref": str(segment_index.get("_index_path") or ""),
            }
    return None


def first_id(value: Any) -> str:
    if isinstance(value, list) and value:
        return str(value[0])
    return ""


def session_axis_evidence_cache(session_dir: Path, manifest: dict[str, Any]) -> dict[str, dict[str, dict[str, str]]]:
    cache: dict[str, dict[str, dict[str, str]]] = {
        "route": {},
        "session_act": {},
        "conversation_act": {},
    }
    for segment in manifest.get("segments", []) if isinstance(manifest.get("segments"), list) else []:
        if not isinstance(segment, dict):
            continue
        index_path = Path(str(segment.get("index") or ""))
        if not index_path.exists():
            continue
        segment_index = read_json(index_path, {})
        if not isinstance(segment_index, dict):
            continue
        segment_index["_index_path"] = str(index_path)
        events_by_id = {
            str(event.get("event_id")): event
            for event in segment_index.get("events", [])
            if isinstance(event, dict) and event.get("event_id")
        } if isinstance(segment_index.get("events"), list) else {}

        def evidence_for_event_id(event_id: Any) -> dict[str, str] | None:
            event = events_by_id.get(str(event_id or ""))
            if not isinstance(event, dict):
                return None
            return {
                "raw_ref": str(event.get("raw_ref") or ""),
                "segment_ref": str(event.get("md_anchor") or segment_index.get("markdown") or ""),
                "generated_index_ref": str(segment_index.get("_index_path") or ""),
            }

        by_route_layer = segment_index.get("by_route_layer") if isinstance(segment_index.get("by_route_layer"), dict) else {}
        for layer, key_map in by_route_layer.items():
            if not isinstance(key_map, dict):
                continue
            for key, ids in key_map.items():
                token = route_signal_token(str(layer), str(key))
                if token in cache["route"]:
                    continue
                evidence = evidence_for_event_id(first_id(ids))
                if evidence:
                    cache["route"][token] = {
                        "session_ref": str(session_dir / SESSION_INDEX_MARKDOWN),
                        **evidence,
                    }
        by_session_act = segment_index.get("by_session_act") if isinstance(segment_index.get("by_session_act"), dict) else {}
        for act, ids in by_session_act.items():
            if str(act) in cache["session_act"]:
                continue
            evidence = evidence_for_event_id(first_id(ids))
            if evidence:
                cache["session_act"][str(act)] = {
                    "session_ref": str(session_dir / SESSION_INDEX_MARKDOWN),
                    **evidence,
                }
        by_conversation_act = segment_index.get("by_conversation_act") if isinstance(segment_index.get("by_conversation_act"), dict) else {}
        for act, ids in by_conversation_act.items():
            if str(act) in cache["conversation_act"]:
                continue
            evidence = evidence_for_event_id(first_id(ids))
            if evidence:
                cache["conversation_act"][str(act)] = {
                    "session_ref": str(session_dir / SESSION_INDEX_MARKDOWN),
                    **evidence,
                }
    return cache


def session_axis_evidence(
    session_dir: Path,
    manifest: dict[str, Any],
    *,
    layer: str | None = None,
    key: str | None = None,
    session_act: str | None = None,
    conversation_act: str | None = None,
) -> dict[str, str]:
    fallback = session_axis_fallback_evidence(session_dir, manifest)
    for segment in manifest.get("segments", []) if isinstance(manifest.get("segments"), list) else []:
        if not isinstance(segment, dict):
            continue
        index_path = Path(str(segment.get("index") or ""))
        if not index_path.exists():
            continue
        segment_index = read_json(index_path, {})
        if not isinstance(segment_index, dict):
            continue
        segment_index["_index_path"] = str(index_path)
        evidence = route_signal_evidence_from_segment(
            segment_index,
            layer=layer,
            key=key,
            session_act=session_act,
            conversation_act=conversation_act,
        )
        if evidence:
            return {**fallback, **evidence}
    return fallback


def session_axis_fallback_evidence(session_dir: Path, manifest: dict[str, Any]) -> dict[str, str]:
    fallback = {
        "session_ref": str(session_dir / SESSION_INDEX_MARKDOWN),
        "segment_ref": "",
        "raw_ref": "",
        "generated_index_ref": str(session_dir / SESSION_INDEX_JSON),
    }
    work_context = manifest.get("work_context") if isinstance(manifest.get("work_context"), dict) else {}
    for item in work_context.get("evidence", []) if isinstance(work_context.get("evidence"), list) else []:
        if isinstance(item, dict) and item.get("ref"):
            fallback["raw_ref"] = str(item["ref"])
            break
    return fallback


def atlas_entry_markdown(entry: dict[str, Any]) -> str:
    evidence = entry.get("evidence") if isinstance(entry.get("evidence"), dict) else {}
    lines = [
        "---",
        "aoa_artifact_type: atlas_route_entry",
        f"schema_version: {entry.get('schema_version')}",
        f"axis: {entry.get('axis')}",
        f"route_key: {entry.get('route_key')}",
        f"truth_status: {entry.get('truth_status')}",
        "---",
        "",
        f"# {entry.get('axis')} / {entry.get('route_key')}",
        "",
        f"- session: `{entry.get('session')}`",
        f"- session_id: `{entry.get('session_id', '')}`",
        f"- session_date: `{entry.get('session_date', '')}`",
        f"- work_context: `{entry.get('work_context', '')}`",
        f"- work_family: `{entry.get('work_family', '')}`",
        f"- confidence: `{entry.get('confidence')}`",
        f"- status: `{entry.get('status')}`",
        f"- signal_count: `{entry.get('signal_count', '')}`",
        "",
        "## Next Route",
        "",
        entry.get("next_route", ""),
        "",
        "## Evidence",
        "",
        f"- session_ref: `{evidence.get('session_ref', '')}`",
        f"- segment_ref: `{evidence.get('segment_ref', '')}`",
        f"- raw_ref: `{evidence.get('raw_ref', '')}`",
        f"- generated_index_ref: `{evidence.get('generated_index_ref', '')}`",
        "",
        "## Summary",
        "",
        entry.get("summary", ""),
        "",
    ]
    return "\n".join(lines)


def atlas_entry_filename(route_key: str, session_label: str, suffix: str) -> str:
    route = route_key_slug(route_key, fallback="route", max_chars=80)
    label = readable_slug(session_label, fallback="session", max_chars=96)
    return f"{route}__{label}{suffix}"


def add_atlas_candidate(
    entries: list[dict[str, Any]],
    *,
    axis: str,
    route_key: str,
    signal_count: int,
    session_dir: Path,
    manifest: dict[str, Any],
    record: dict[str, Any],
    layer: str | None = None,
    key: str | None = None,
    session_act: str | None = None,
    conversation_act: str | None = None,
    evidence_cache: dict[str, dict[str, dict[str, str]]] | None = None,
    allow_segment_scan: bool = False,
    confidence: str = "medium",
) -> None:
    if not route_key:
        return
    display = manifest.get("display") if isinstance(manifest.get("display"), dict) else {}
    work_context = manifest.get("work_context") if isinstance(manifest.get("work_context"), dict) else {}
    label = str(display.get("label") or record.get("session_label") or session_dir.name)
    session_date = str(display.get("date") or record.get("date") or record.get("session_date") or "")
    if not session_date:
        match = re.match(r"(20\d{2}-[01]\d-[0-3]\d)", label)
        session_date = match.group(1) if match else ""
    normalized_key = route_key_slug(route_key, fallback="route")
    evidence: dict[str, str] | None = None
    if evidence_cache:
        if layer and key:
            evidence = evidence_cache.get("route", {}).get(route_signal_token(layer, key))
        elif session_act:
            evidence = evidence_cache.get("session_act", {}).get(session_act)
        elif conversation_act:
            evidence = evidence_cache.get("conversation_act", {}).get(conversation_act)
    if evidence is None:
        if allow_segment_scan:
            evidence = session_axis_evidence(
                session_dir,
                manifest,
                layer=layer,
                key=key,
                session_act=session_act,
                conversation_act=conversation_act,
            )
        else:
            evidence = session_axis_fallback_evidence(session_dir, manifest)
    entries.append(
        {
            "schema_version": ATLAS_SCHEMA_VERSION,
            "artifact_identity": atlas_route_entry_artifact_identity(),
            "axis": axis,
            "route_key": normalized_key,
            "status": "generated",
            "truth_status": "route_signal_not_reviewed_truth",
            "session": label,
            "session_id": str(manifest.get("session_id") or record.get("session_id") or ""),
            "session_date": session_date,
            "work_context": str(work_context.get("work_name") or ""),
            "work_family": str(work_context.get("work_family") or ""),
            "authority_surface": "",
            "summary": f"{label}: {axis} -> {normalized_key} ({signal_count} signal(s)).",
            "confidence": confidence,
            "next_route": f"Read {session_dir / SESSION_INDEX_JSON}, then follow the evidence refs before treating this route as truth.",
            "evidence": evidence,
            "related_axes": [
                related
                for related in ["by-work-context", "by-session-act", "by-verification-state", "by-route-next-action"]
                if related != axis
            ],
            "signal_count": signal_count,
            "route_layer": layer or "",
            "generated_at": utc_now(),
        }
    )


def atlas_entries_for_session(aoa_root: Path, record: dict[str, Any], axes: set[str]) -> list[dict[str, Any]]:
    session_dir = session_dir_from_record(record)
    manifest = read_json(session_dir / "session.manifest.json", {})
    session_index = read_json(session_dir / SESSION_INDEX_JSON, {})
    if not isinstance(manifest, dict) or not isinstance(session_index, dict):
        return []
    entries: list[dict[str, Any]] = []
    evidence_cache: dict[str, dict[str, dict[str, str]]] | None = None
    route_index_current = route_signal_index_is_current(session_index)
    route_counts = session_index.get("route_signal_counts") if route_index_current and isinstance(session_index.get("route_signal_counts"), dict) else {}
    needs_event_evidence = (
        "by-session-act" in axes
        or "by-conversation-act" in axes
        or any(ROUTE_SIGNAL_LAYER_TO_AXIS.get(str(layer)) in axes for layer in route_counts)
    )
    if needs_event_evidence:
        evidence_cache = session_axis_evidence_cache(session_dir, manifest)
    work_context = manifest.get("work_context") if isinstance(manifest.get("work_context"), dict) else {}
    work_name = str(work_context.get("work_name") or "")
    work_family = str(work_context.get("work_family") or "")
    if "by-work-context" in axes and work_name:
        add_atlas_candidate(entries, axis="by-work-context", route_key=work_name, signal_count=1, session_dir=session_dir, manifest=manifest, record=record, evidence_cache=evidence_cache, confidence=str(work_context.get("confidence") or "medium"))
    if "by-repo-family" in axes and work_family:
        add_atlas_candidate(entries, axis="by-repo-family", route_key=work_family, signal_count=1, session_dir=session_dir, manifest=manifest, record=record, evidence_cache=evidence_cache, confidence=str(work_context.get("confidence") or "medium"))
    display = manifest.get("display") if isinstance(manifest.get("display"), dict) else {}
    if "by-time" in axes:
        date_key = str(display.get("date") or record.get("date") or record.get("session_date") or "")
        if date_key:
            add_atlas_candidate(entries, axis="by-time", route_key=date_key, signal_count=1, session_dir=session_dir, manifest=manifest, record=record, evidence_cache=evidence_cache, confidence="high")
    for act, count in (session_index.get("session_act_counts") or {}).items() if isinstance(session_index.get("session_act_counts"), dict) else []:
        if "by-session-act" in axes:
            add_atlas_candidate(entries, axis="by-session-act", route_key=str(act), signal_count=int_value(count, 1), session_dir=session_dir, manifest=manifest, record=record, session_act=str(act), evidence_cache=evidence_cache, confidence="high")
    for act, count in (session_index.get("conversation_act_counts") or {}).items() if isinstance(session_index.get("conversation_act_counts"), dict) else []:
        if "by-conversation-act" in axes:
            add_atlas_candidate(entries, axis="by-conversation-act", route_key=str(act), signal_count=int_value(count, 1), session_dir=session_dir, manifest=manifest, record=record, conversation_act=str(act), evidence_cache=evidence_cache, confidence="high")
    for layer, key_counts in route_counts.items():
        axis = ROUTE_SIGNAL_LAYER_TO_AXIS.get(str(layer))
        if not axis or axis not in axes or not isinstance(key_counts, dict):
            continue
        ranked_keys = sorted(key_counts.items(), key=lambda item: (int_value(item[1]), str(item[0])), reverse=True)
        for key, count in ranked_keys[:MAX_ATLAS_ROUTE_KEYS_PER_LAYER]:
            add_atlas_candidate(
                entries,
                axis=axis,
                route_key=str(key),
                signal_count=int_value(count, 1),
                session_dir=session_dir,
                manifest=manifest,
                record=record,
                layer=str(layer),
                key=str(key),
                evidence_cache=evidence_cache,
                confidence="medium",
            )
    if "by-review-state" in axes:
        review_key = str(manifest.get("review_status") or manifest.get("distillation_status") or "raw_archived")
        add_atlas_candidate(entries, axis="by-review-state", route_key=review_key, signal_count=1, session_dir=session_dir, manifest=manifest, record=record, evidence_cache=evidence_cache, confidence="medium")
    if "by-index-health" in axes:
        archive_status = str(manifest.get("archive_status") or "unknown")
        index_key = archive_status if route_index_current else "route_signal_classifier_stale"
        add_atlas_candidate(entries, axis="by-index-health", route_key=index_key, signal_count=1, session_dir=session_dir, manifest=manifest, record=record, evidence_cache=evidence_cache, confidence="medium")
    if "by-route-next-action" in axes:
        archive_status = str(manifest.get("archive_status") or "")
        next_key = "restore_ready" if archive_status == "indexed" and route_index_current else "repair_or_reindex"
        add_atlas_candidate(entries, axis="by-route-next-action", route_key=next_key, signal_count=1, session_dir=session_dir, manifest=manifest, record=record, evidence_cache=evidence_cache, confidence="medium")
    return entries


def write_atlas_axis_index(axis_dir: Path, axis: str, entries: list[dict[str, Any]]) -> dict[str, Any]:
    payload = {
        "schema_version": ATLAS_SCHEMA_VERSION,
        "artifact_type": "atlas_axis_index",
        "axis": axis,
        "generated_at": utc_now(),
        "entry_count": len(entries),
        "entries": entries,
    }
    write_json(axis_dir / "index.json", payload)
    lines = [
        f"# {axis}",
        "",
        "Generated atlas axis index. Entries are route signals, not reviewed truth.",
        "",
        "| route_key | session | confidence | evidence |",
        "| --- | --- | --- | --- |",
    ]
    for entry in entries:
        evidence = entry.get("evidence") if isinstance(entry.get("evidence"), dict) else {}
        lines.append(
            f"| `{entry.get('route_key')}` | `{entry.get('session')}` | `{entry.get('confidence')}` | `{evidence.get('raw_ref') or evidence.get('segment_ref') or evidence.get('session_ref')}` |"
        )
    write_markdown(axis_dir / "INDEX.md", "\n".join(lines) + "\n")
    return payload


def atlas_compact_entry(
    *,
    axis: str,
    entry: dict[str, Any],
    json_path: Path | str,
    markdown_path: Path | str | None = None,
) -> dict[str, Any]:
    json_text = str(json_path)
    markdown_text = str(markdown_path or Path(json_text).with_suffix(".md"))
    evidence = entry.get("evidence") if isinstance(entry.get("evidence"), dict) else {}
    return {
        "axis": axis,
        "route_key": entry.get("route_key"),
        "session": entry.get("session"),
        "session_id": entry.get("session_id"),
        "session_date": entry.get("session_date"),
        "confidence": entry.get("confidence"),
        "json": json_text,
        "markdown": markdown_text,
        "evidence": evidence,
    }


def delete_atlas_entries_for_session(aoa_root: Path, axes: list[str], *, session_label: str, session_id: str) -> int:
    removed = 0
    for axis in axes:
        entries_dir = aoa_root / ATLAS_ROOT / axis / "entries"
        if not entries_dir.is_dir():
            continue
        for json_path in sorted(entries_dir.glob("*.json")):
            entry = read_json(json_path, {})
            if not isinstance(entry, dict):
                continue
            if str(entry.get("session") or "") != session_label and str(entry.get("session_id") or "") != session_id:
                continue
            md_path = json_path.with_suffix(".md")
            try:
                json_path.unlink()
                removed += 1
            except OSError:
                pass
            if md_path.exists():
                try:
                    md_path.unlink()
                    removed += 1
                except OSError:
                    pass
    return removed


def read_atlas_axis_index_entries(axis_dir: Path, axis: str) -> list[dict[str, Any]]:
    payload = read_json(axis_dir / "index.json", {})
    entries = payload.get("entries") if isinstance(payload, dict) else None
    if not isinstance(entries, list):
        return []
    compact_entries: list[dict[str, Any]] = []
    for item in entries:
        if not isinstance(item, dict):
            continue
        json_path = str(item.get("json") or "")
        if not json_path:
            continue
        compact_entries.append(
            atlas_compact_entry(
                axis=axis,
                entry=item,
                json_path=json_path,
                markdown_path=str(item.get("markdown") or ""),
            )
        )
    return sorted(compact_entries, key=lambda item: (str(item.get("route_key")), str(item.get("session"))))


def read_atlas_entries_from_axis(axis_dir: Path, axis: str) -> list[dict[str, Any]]:
    entries_dir = axis_dir / "entries"
    entries: list[dict[str, Any]] = []
    if not entries_dir.is_dir():
        return entries
    for json_path in sorted(entries_dir.glob("*.json")):
        payload = read_json(json_path, {})
        if not isinstance(payload, dict):
            continue
        entries.append(atlas_compact_entry(axis=axis, entry=payload, json_path=json_path))
    return sorted(entries, key=lambda item: (str(item.get("route_key")), str(item.get("session"))))


def atlas_entry_matches_session(entry: dict[str, Any], *, session_labels: set[str], session_ids: set[str]) -> bool:
    return str(entry.get("session") or "") in session_labels or str(entry.get("session_id") or "") in session_ids


def remove_atlas_compact_entry_artifacts(entry: dict[str, Any]) -> int:
    removed = 0
    for key in ("json", "markdown"):
        value = str(entry.get(key) or "")
        if not value:
            continue
        path = Path(value)
        if not path.exists():
            continue
        try:
            path.unlink()
            removed += 1
        except OSError:
            pass
    return removed


def update_atlas_projection_state(
    aoa_root: Path,
    *,
    records: list[dict[str, Any]],
    generated_at: str,
    clean: bool,
) -> dict[str, Any]:
    state = {} if clean else read_atlas_projection_state(aoa_root)
    sessions = state.get("sessions") if isinstance(state.get("sessions"), dict) else {}
    for projection in projection_fingerprints_for_records(records):
        session_id = str(projection.get("session_id") or "")
        if not session_id:
            continue
        sessions[session_id] = {
            "session_id": session_id,
            "session_label": projection.get("session_label"),
            "session_dir": projection.get("session_dir"),
            "source_fingerprint": projection.get("fingerprint"),
            "source_latest_mtime": projection.get("latest_source_mtime"),
            "source_path_count": projection.get("source_path_count"),
            "atlas_schema_version": ATLAS_SCHEMA_VERSION,
            "route_signal_classifier_version": ROUTE_SIGNAL_CLASSIFIER_VERSION,
            "indexed_at": generated_at,
        }
    payload = {
        "schema_version": INDEX_PROJECTION_STATE_SCHEMA_VERSION,
        "artifact_type": "atlas_projection_state",
        "generated_at": generated_at,
        "atlas_schema_version": ATLAS_SCHEMA_VERSION,
        "route_signal_classifier_version": ROUTE_SIGNAL_CLASSIFIER_VERSION,
        "session_count": len(sessions),
        "sessions": dict(sorted(sessions.items())),
    }
    write_json(atlas_projection_state_path(aoa_root), payload)
    return payload


def build_agent_atlas(
    *,
    aoa_root: Path,
    target: str = "all",
    since: str | None = None,
    until: str | None = None,
    limit: int | None = None,
    clean: bool = True,
    write_report: bool = False,
    selected_records: list[dict[str, Any]] | None = None,
    budget_seconds: float | None = None,
    progress_every: int = 0,
) -> dict[str, Any]:
    now = utc_now()
    started = time.monotonic()
    deadline = started + budget_seconds if budget_seconds is not None and budget_seconds > 0 else None
    axes = atlas_policy_axes(aoa_root)
    axis_set = set(axes)
    try:
        records = selected_records if selected_records is not None else ([resolve_session_record(aoa_root, target)] if target != "all" else chronological_session_records(aoa_root, since=since, until=until, limit=limit))
    except ValueError as exc:
        return {
            "schema_version": ATLAS_SCHEMA_VERSION,
            "artifact_type": "agent_atlas",
            "generated_at": now,
            "ok": False,
            "target": target,
            "selected_count": 0,
            "entry_count": 0,
            "diagnostics": [str(exc)],
        }
    maps_root = aoa_root / ATLAS_ROOT
    maps_root.mkdir(parents=True, exist_ok=True)
    if clean:
        clear_generated_atlas(aoa_root, axes)
    previous_axis_entries: dict[str, list[dict[str, Any]]] = {}
    selected_session_labels: set[str] = set()
    selected_session_ids: set[str] = set()
    if not clean:
        for axis in axes:
            axis_dir = maps_root / axis
            indexed_entries = read_atlas_axis_index_entries(axis_dir, axis)
            previous_axis_entries[axis] = indexed_entries if indexed_entries else read_atlas_entries_from_axis(axis_dir, axis)
    by_axis: dict[str, list[dict[str, Any]]] = {axis: [] for axis in axes}
    diagnostics: list[str] = []
    processed_records: list[dict[str, Any]] = []
    remaining_records: list[dict[str, Any]] = []
    budget_exhausted = False
    removed_entry_artifact_count = 0
    for index, record in enumerate(records):
        if deadline is not None and time.monotonic() >= deadline:
            budget_exhausted = True
            remaining_records = records[index:]
            diagnostics.append("agent_atlas_budget_exhausted")
            break
        try:
            entries = atlas_entries_for_session(aoa_root, record, axis_set)
        except Exception as exc:
            diagnostics.append(f"{record.get('session_label') or record.get('session_id')}:atlas_entry_error:{exc}")
            continue
        processed_records.append(record)
        for entry in entries:
            by_axis.setdefault(str(entry["axis"]), []).append(entry)
        if progress_every and len(processed_records) % progress_every == 0:
            print(
                json.dumps(
                    {
                        "event": "agent_atlas_progress",
                        "processed": len(processed_records),
                        "selected": len(records),
                        "remaining": max(0, len(records) - index - 1),
                    },
                    ensure_ascii=False,
                ),
                file=sys.stderr,
            )
    if not clean:
        for record in processed_records:
            session_dir = session_dir_from_record(record)
            manifest = read_json(session_dir / "session.manifest.json", {})
            display = manifest.get("display") if isinstance(manifest, dict) and isinstance(manifest.get("display"), dict) else {}
            selected_session_labels.add(str(display.get("label") or record.get("session_label") or session_dir.name))
            selected_session_ids.add(str(record.get("session_id") or (manifest.get("session_id") if isinstance(manifest, dict) else "") or ""))
        selected_session_labels.discard("")
        selected_session_ids.discard("")
    updated_entries: list[dict[str, Any]] = []
    axis_summaries: list[dict[str, Any]] = []
    for axis in axes:
        axis_dir = maps_root / axis
        entries_dir = axis_dir / "entries"
        entries_dir.mkdir(parents=True, exist_ok=True)
        gitkeep = entries_dir / ".gitkeep"
        if not gitkeep.exists():
            gitkeep.write_text("", encoding="utf-8")
        axis_entries = sorted(by_axis.get(axis, []), key=lambda item: (str(item.get("route_key")), str(item.get("session"))))
        preserved_entries: list[dict[str, Any]] = []
        if not clean:
            for previous in previous_axis_entries.get(axis, []):
                if atlas_entry_matches_session(previous, session_labels=selected_session_labels, session_ids=selected_session_ids):
                    removed_entry_artifact_count += remove_atlas_compact_entry_artifacts(previous)
                else:
                    preserved_entries.append(previous)
        compact_axis_entries: list[dict[str, Any]] = []
        for entry in axis_entries:
            json_name = atlas_entry_filename(str(entry["route_key"]), str(entry["session"]), ".json")
            md_name = atlas_entry_filename(str(entry["route_key"]), str(entry["session"]), ".md")
            json_path = entries_dir / json_name
            md_path = entries_dir / md_name
            write_json(json_path, entry)
            write_markdown(md_path, atlas_entry_markdown(entry))
            compact = {
                "axis": axis,
                "route_key": entry.get("route_key"),
                "session": entry.get("session"),
                "session_id": entry.get("session_id"),
                "session_date": entry.get("session_date"),
                "confidence": entry.get("confidence"),
                "json": str(json_path),
                "markdown": str(md_path),
                "evidence": entry.get("evidence"),
            }
            compact_axis_entries.append(compact)
            updated_entries.append(compact)
        if not clean:
            compact_axis_entries = sorted(
                [*preserved_entries, *compact_axis_entries],
                key=lambda item: (str(item.get("route_key")), str(item.get("session"))),
            )
        axis_index = write_atlas_axis_index(axis_dir, axis, compact_axis_entries)
        axis_summaries.append({"axis": axis, "entry_count": axis_index["entry_count"], "index": str(axis_dir / "index.json")})
    root_payload = {
        "schema_version": ATLAS_SCHEMA_VERSION,
        "artifact_type": "agent_atlas_index",
        "generated_at": now,
        "axis_count": len(axes),
        "entry_count": sum(int_value(axis.get("entry_count")) for axis in axis_summaries),
        "axes": axis_summaries,
    }
    write_json(maps_root / "index.json", root_payload)
    lines = [
        "# Agent Atlas",
        "",
        "Generated route index. Use it to choose a first route, then follow evidence refs.",
        "",
        "| axis | entries | index |",
        "| --- | ---: | --- |",
    ]
    for axis in axis_summaries:
        lines.append(f"| `{axis['axis']}` | {axis['entry_count']} | `{axis['index']}` |")
    write_markdown(maps_root / "INDEX.md", "\n".join(lines) + "\n")
    projection_records = processed_records if budget_exhausted else records
    atlas_projection = update_atlas_projection_state(aoa_root, records=projection_records, generated_at=now, clean=clean)
    payload = {
        "schema_version": ATLAS_SCHEMA_VERSION,
        "artifact_type": "agent_atlas",
        "generated_at": now,
        "ok": not diagnostics and not budget_exhausted,
        "target": target,
        "clean": clean,
        "selected_count": len(records),
        "processed_count": len(processed_records),
        "remaining_count": len(remaining_records),
        "budget_seconds": budget_seconds,
        "elapsed_ms": int((time.monotonic() - started) * 1000),
        "budget_exhausted": budget_exhausted,
        "axis_count": len(axes),
        "entry_count": root_payload["entry_count"],
        "updated_entry_count": len(updated_entries),
        "removed_entry_artifact_count": removed_entry_artifact_count,
        "root_index": str(maps_root / "index.json"),
        "root_markdown": str(maps_root / "INDEX.md"),
        "projection_state": str(atlas_projection_state_path(aoa_root)),
        "projection_session_count": atlas_projection.get("session_count"),
        "diagnostics": diagnostics,
        "axes": axis_summaries,
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__agent-atlas"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, atlas_build_report_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def atlas_build_report_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Agent Atlas Build",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- target: `{payload.get('target')}`",
        f"- selected_count: `{payload.get('selected_count')}`",
        f"- processed_count: `{payload.get('processed_count')}`",
        f"- remaining_count: `{payload.get('remaining_count')}`",
        f"- budget_seconds: `{payload.get('budget_seconds')}`",
        f"- budget_exhausted: `{payload.get('budget_exhausted')}`",
        f"- entry_count: `{payload.get('entry_count')}`",
        "",
        "## Axes",
        "",
        "| axis | entries |",
        "| --- | ---: |",
    ]
    for axis in payload.get("axes", []) if isinstance(payload.get("axes"), list) else []:
        if isinstance(axis, dict):
            lines.append(f"| `{axis.get('axis')}` | {axis.get('entry_count')} |")
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        for item in diagnostics:
            lines.append(f"- {item}")
    return "\n".join(lines) + "\n"


def atlas_axis_states(aoa_root: Path) -> dict[str, dict[str, Any]]:
    states: dict[str, dict[str, Any]] = {}
    maps_root = aoa_root / ATLAS_ROOT
    for axis in atlas_policy_axes(aoa_root):
        axis_dir = maps_root / axis
        index_path = axis_dir / "index.json"
        index_payload = read_json(index_path, {})
        entry_count = int_value(index_payload.get("entry_count")) if isinstance(index_payload, dict) else 0
        states[axis] = {
            "axis": axis,
            "source_readme_exists": (axis_dir / "README.md").exists(),
            "entries_dir_exists": (axis_dir / "entries").is_dir(),
            "generated_index_exists": index_path.exists(),
            "entry_count": entry_count,
            "index": str(index_path),
        }
    return states


def route_readiness_layer_sample(
    session_dir: Path,
    manifest: dict[str, Any],
    layer: str,
    key_counts: Counter[str],
    evidence_cache: dict[str, dict[str, dict[str, str]]] | None = None,
) -> dict[str, Any] | None:
    cache = evidence_cache if evidence_cache is not None else session_axis_evidence_cache(session_dir, manifest)
    for key, count in sorted(key_counts.items(), key=lambda item: (int_value(item[1]), str(item[0])), reverse=True):
        evidence = cache.get("route", {}).get(route_signal_token(layer, str(key)))
        if evidence:
            return {
                "key": str(key),
                "count": int_value(count),
                "session": str(manifest.get("session_label") or session_dir.name),
                "session_id": str(manifest.get("session_id") or ""),
                "evidence": evidence,
            }
    return None


def route_layer_readiness(
    *,
    aoa_root: Path,
    target: str = "all",
    since: str | None = None,
    until: str | None = None,
    limit: int | None = None,
    sample_limit: int = 2,
    write_report: bool = False,
    selected_records: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    now = utc_now()
    try:
        records = selected_records if selected_records is not None else ([resolve_session_record(aoa_root, target)] if target != "all" else chronological_session_records(aoa_root, since=since, until=until, limit=limit))
    except ValueError as exc:
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "route_layer_readiness",
            "generated_at": now,
            "ok": False,
            "target": target,
            "selected_count": 0,
            "diagnostics": [str(exc)],
            "requirements": [],
            "remaining": [],
        }

    layer_counts: Counter[str] = Counter()
    layer_session_counts: Counter[str] = Counter()
    layer_key_counts: dict[str, Counter[str]] = defaultdict(Counter)
    layer_samples: dict[str, list[dict[str, Any]]] = defaultdict(list)
    diagnostics: list[str] = []
    missing_session_index = 0
    non_indexable_session_count = 0
    non_indexable_samples: list[dict[str, str]] = []
    stale_route_schema = 0
    stale_route_classifier = 0
    indexed_session_count = 0
    current_route_signal_index_count = 0

    required_layers = {
        str(layer)
        for item in ROUTE_READINESS_REQUIREMENTS
        for layer in item.get("required_layers", [])
    }

    for record in records:
        session_dir = session_dir_from_record(record)
        manifest = read_json(session_dir / "session.manifest.json", {})
        archive_status = (
            str(manifest.get("archive_status") or record.get("archive_status") or "")
            if isinstance(manifest, dict)
            else str(record.get("archive_status") or "")
        )
        session_index = read_json(session_dir / SESSION_INDEX_JSON, {})
        if not isinstance(session_index, dict) or not session_index:
            if archive_status and archive_status != "indexed":
                non_indexable_session_count += 1
                if len(non_indexable_samples) < 8:
                    non_indexable_samples.append(
                        {
                            "session": str(record.get("session_label") or record.get("session_id") or session_dir.name),
                            "archive_status": archive_status,
                        }
                    )
            else:
                missing_session_index += 1
                diagnostics.append(f"{record.get('session_label') or record.get('session_id')}:missing_session_index")
            continue
        indexed_session_count += 1
        stale_reasons = route_signal_index_stale_reasons(session_index)
        if "route_signal_schema_mismatch" in stale_reasons:
            stale_route_schema += 1
            diagnostics.append(f"{record.get('session_label') or record.get('session_id')}:route_signal_schema_mismatch")
        if "route_signal_classifier_mismatch" in stale_reasons:
            stale_route_classifier += 1
            diagnostics.append(f"{record.get('session_label') or record.get('session_id')}:route_signal_classifier_mismatch")
        if stale_reasons:
            continue
        current_route_signal_index_count += 1
        route_counts = session_index.get("route_signal_counts") if isinstance(session_index.get("route_signal_counts"), dict) else {}
        session_layers: set[str] = set()
        for layer, key_map in route_counts.items():
            layer_name = str(layer)
            if not isinstance(key_map, dict):
                continue
            total = sum(int_value(count) for count in key_map.values())
            if total <= 0:
                continue
            layer_counts[layer_name] += total
            session_layers.add(layer_name)
            for key, count in key_map.items():
                layer_key_counts[layer_name][str(key)] += int_value(count)
        for layer_name in session_layers:
            layer_session_counts[layer_name] += 1
        if sample_limit > 0 and isinstance(manifest, dict) and required_layers:
            sample_layers = sorted(required_layers & set(route_counts.keys()))
            evidence_cache = session_axis_evidence_cache(session_dir, manifest) if sample_layers else None
            for layer_name in sample_layers:
                if len(layer_samples[layer_name]) >= sample_limit:
                    continue
                sample = route_readiness_layer_sample(
                    session_dir,
                    manifest,
                    layer_name,
                    layer_key_counts[layer_name],
                    evidence_cache=evidence_cache,
                )
                if sample:
                    layer_samples[layer_name].append(sample)

    axis_states = atlas_axis_states(aoa_root)
    root_atlas_index = read_json(aoa_root / ATLAS_ROOT / "index.json", {})
    root_atlas_entry_count = int_value(root_atlas_index.get("entry_count")) if isinstance(root_atlas_index, dict) else 0
    provider_status = search_provider_status(
        aoa_root=aoa_root,
        provider_name="portable_sqlite",
        freshness_records=records,
    )
    provider_ready = bool(provider_status.get("ok"))

    requirements: list[dict[str, Any]] = []
    for item in ROUTE_READINESS_REQUIREMENTS:
        req_layers = [str(layer) for layer in item.get("required_layers", [])]
        optional_signal_layers = {
            str(layer)
            for layer in item.get("optional_signal_layers", [])
            if str(layer) in req_layers
        }
        missing_layers = [
            layer
            for layer in req_layers
            if layer not in optional_signal_layers and layer_counts.get(layer, 0) <= 0
        ]
        optional_absent_layers = [
            layer
            for layer in req_layers
            if layer in optional_signal_layers and layer_counts.get(layer, 0) <= 0
        ]
        layer_payloads: list[dict[str, Any]] = []
        missing_axes: list[str] = []
        missing_generated_axes: list[str] = []
        for layer in req_layers:
            axis = ROUTE_SIGNAL_LAYER_TO_AXIS.get(layer, "")
            axis_state = axis_states.get(axis, {}) if axis else {}
            if axis and not axis_state.get("source_readme_exists"):
                missing_axes.append(axis)
            if axis and layer_counts.get(layer, 0) > 0 and int_value(axis_state.get("entry_count")) <= 0:
                missing_generated_axes.append(axis)
            layer_payloads.append(
                {
                    "layer": layer,
                    "axis": axis,
                    "signal_count": layer_counts.get(layer, 0),
                    "session_count": layer_session_counts.get(layer, 0),
                    "top_keys": [
                        {"key": str(key), "count": int_value(count)}
                        for key, count in sorted(
                            layer_key_counts.get(layer, Counter()).items(),
                            key=lambda pair: (int_value(pair[1]), str(pair[0])),
                            reverse=True,
                        )[:8]
                    ],
                    "samples": layer_samples.get(layer, [])[:sample_limit],
                    "axis_state": axis_state,
                }
            )
        status = "covered"
        if missing_layers or missing_axes or missing_generated_axes:
            status = "remaining"
        requirements.append(
            {
                "id": item.get("id"),
                "title": item.get("title"),
                "status": status,
                "required_layers": req_layers,
                "optional_signal_layers": sorted(optional_signal_layers),
                "missing_layers": missing_layers,
                "optional_absent_layers": optional_absent_layers,
                "missing_axes": sorted(set(missing_axes)),
                "missing_generated_axes": sorted(set(missing_generated_axes)),
                "layers": layer_payloads,
            }
        )

    required_axes = sorted({ROUTE_SIGNAL_LAYER_TO_AXIS.get(layer, "") for layer in required_layers if ROUTE_SIGNAL_LAYER_TO_AXIS.get(layer)})
    missing_source_axes = [axis for axis in required_axes if not axis_states.get(axis, {}).get("source_readme_exists")]
    empty_generated_axes = [
        axis
        for axis in required_axes
        if axis_states.get(axis, {}).get("generated_index_exists") and int_value(axis_states.get(axis, {}).get("entry_count")) <= 0
    ]
    global_gates = [
        {
            "name": "session_route_signal_indexes",
            "status": "covered"
            if current_route_signal_index_count > 0
            and missing_session_index == 0
            and stale_route_schema == 0
            and stale_route_classifier == 0
            else "remaining",
            "evidence": {
                "indexed_session_count": indexed_session_count,
                "current_route_signal_index_count": current_route_signal_index_count,
                "missing_session_index": missing_session_index,
                "non_indexable_session_count": non_indexable_session_count,
                "non_indexable_samples": non_indexable_samples,
                "stale_route_schema": stale_route_schema,
                "stale_route_classifier": stale_route_classifier,
                "route_signal_schema_version": ROUTE_SIGNAL_SCHEMA_VERSION,
                "route_signal_classifier_version": ROUTE_SIGNAL_CLASSIFIER_VERSION,
            },
        },
        {
            "name": "source_atlas_axes",
            "status": "covered" if not missing_source_axes else "remaining",
            "evidence": {
                "required_axis_count": len(required_axes),
                "missing_source_axes": missing_source_axes,
            },
        },
        {
            "name": "generated_atlas_index",
            "status": "covered" if root_atlas_entry_count > 0 else "remaining",
            "evidence": {
                "root_index": str(aoa_root / ATLAS_ROOT / "index.json"),
                "root_index_exists": (aoa_root / ATLAS_ROOT / "index.json").exists(),
                "entry_count": root_atlas_entry_count,
                "empty_generated_axes": empty_generated_axes,
            },
        },
        {
            "name": "portable_sqlite_search_index",
            "status": "covered" if provider_ready else "remaining",
            "evidence": provider_status,
        },
    ]
    remaining = [req for req in requirements if req["status"] != "covered"]
    remaining.extend(gate for gate in global_gates if gate["status"] != "covered")
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "route_layer_readiness",
        "generated_at": now,
        "ok": not remaining and not diagnostics,
        "target": target,
        "since": since,
        "until": until,
        "limit": limit,
        "sample_limit": sample_limit,
        "selected_count": len(records),
        "route_signal_schema_version": ROUTE_SIGNAL_SCHEMA_VERSION,
        "route_signal_classifier_version": ROUTE_SIGNAL_CLASSIFIER_VERSION,
        "required_requirement_count": len(ROUTE_READINESS_REQUIREMENTS),
        "covered_requirement_count": sum(1 for req in requirements if req["status"] == "covered"),
        "global_gates": global_gates,
        "requirements": requirements,
        "diagnostics": diagnostics,
        "remaining": remaining,
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__route-layer-readiness"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, route_layer_readiness_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def route_layer_readiness_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Route Layer Readiness",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- target: `{payload.get('target')}`",
        f"- selected_count: `{payload.get('selected_count')}`",
        f"- covered_requirements: `{payload.get('covered_requirement_count')}/{payload.get('required_requirement_count')}`",
        "",
        "## Global Gates",
        "",
        "| gate | status | evidence |",
        "| --- | --- | --- |",
    ]
    for gate in payload.get("global_gates", []) if isinstance(payload.get("global_gates"), list) else []:
        if not isinstance(gate, dict):
            continue
        evidence = gate.get("evidence") if isinstance(gate.get("evidence"), dict) else {}
        lines.append(f"| `{gate.get('name')}` | `{gate.get('status')}` | `{short_text(json.dumps(evidence, ensure_ascii=False, sort_keys=True), max_chars=180)}` |")
    lines.extend(["", "## Requirements", "", "| id | title | status | layers | missing |", "| --- | --- | --- | --- | --- |"])
    for req in payload.get("requirements", []) if isinstance(payload.get("requirements"), list) else []:
        if not isinstance(req, dict):
            continue
        layer_summary = ", ".join(
            f"{layer.get('layer')}:{layer.get('signal_count')}"
            for layer in req.get("layers", [])
            if isinstance(layer, dict)
        )
        missing_parts: list[str] = []
        missing_layers = [str(item) for item in req.get("missing_layers", []) if item]
        optional_absent = [str(item) for item in req.get("optional_absent_layers", []) if item]
        if missing_layers:
            missing_parts.append(", ".join(missing_layers))
        if optional_absent:
            missing_parts.append("optional absent: " + ", ".join(optional_absent))
        missing = "; ".join(missing_parts)
        lines.append(f"| `{req.get('id')}` | {req.get('title')} | `{req.get('status')}` | `{layer_summary}` | `{missing}` |")
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        for item in diagnostics:
            lines.append(f"- `{item}`")
    stale_route_indexes = payload.get("stale_route_indexes") if isinstance(payload.get("stale_route_indexes"), list) else []
    if stale_route_indexes:
        lines.extend(["", "## Stale Route Indexes", ""])
        for item in stale_route_indexes:
            if not isinstance(item, dict):
                continue
            reasons = ", ".join(str(reason) for reason in item.get("reasons", []) if reason)
            lines.append(f"- `{item.get('session')}`: `{reasons}`")
    return "\n".join(lines) + "\n"


def route_readiness_required_layers() -> list[str]:
    layers: list[str] = []
    seen: set[str] = set()
    for item in ROUTE_READINESS_REQUIREMENTS:
        for layer in item.get("required_layers", []):
            layer_name = str(layer)
            if layer_name and layer_name not in seen:
                seen.add(layer_name)
                layers.append(layer_name)
    return layers


def manifest_raw_path(session_dir: Path, manifest: dict[str, Any]) -> Path:
    raw = manifest.get("raw") if isinstance(manifest.get("raw"), dict) else {}
    raw_value = raw.get("path") if isinstance(raw, dict) else ""
    return Path(str(raw_value)) if raw_value else session_dir / "raw" / "session.raw.jsonl"


def raw_line_preview(raw_path: Path, raw_ref: Any, *, max_chars: int = 360) -> dict[str, Any]:
    line_no = line_from_raw_ref(raw_ref)
    if not line_no:
        return {"status": "missing_raw_ref", "line": None, "text": ""}
    if not raw_path.is_file():
        return {"status": "raw_unavailable", "line": line_no, "text": ""}
    with raw_path.open("r", encoding="utf-8", errors="replace") as handle:
        for current_line, line in enumerate(handle, start=1):
            if current_line == line_no:
                return {
                    "status": "available",
                    "line": line_no,
                    "text": short_text(line.rstrip("\n"), max_chars=max_chars),
                }
            if current_line > line_no:
                break
    return {"status": "raw_line_not_found", "line": line_no, "text": ""}


def text_line_packet(path: Path, line_no: int | None, *, max_chars: int = 360, compressed: bool = False) -> dict[str, Any]:
    line_no = int_value(line_no)
    if not line_no:
        return {"status": "missing_line", "line": None, "text": "", "sha256": ""}
    if not path.is_file():
        return {"status": "file_unavailable", "line": line_no, "text": "", "sha256": ""}
    try:
        if compressed:
            handle_context = gzip.open(path, "rt", encoding="utf-8", errors="replace")
        else:
            handle_context = path.open("r", encoding="utf-8", errors="replace")
        with handle_context as handle:
            for current_line, line in enumerate(handle, start=1):
                if current_line != line_no:
                    if current_line > line_no:
                        break
                    continue
                text = line.rstrip("\n")
                return {
                    "status": "available",
                    "line": line_no,
                    "text": bounded_storage_text(text, max_chars=max_chars),
                    "sha256": hashlib.sha256(text.encode("utf-8", errors="replace")).hexdigest(),
                    "byte_count": len(text.encode("utf-8", errors="replace")),
                }
    except OSError as exc:
        return {"status": f"io_error:{exc}", "line": line_no, "text": "", "sha256": ""}
    return {"status": "line_not_found", "line": line_no, "text": "", "sha256": ""}


def session_relative_path(session_dir: Path, value: Any) -> Path:
    text = str(value or "")
    if not text:
        return Path("")
    path = Path(text)
    return path if path.is_absolute() else session_dir / path


def raw_block_plain_path(session_dir: Path, record: dict[str, Any]) -> Path:
    value = record.get("plain_path") or record.get("path") or ""
    if value:
        return session_relative_path(session_dir, value)
    rel = record.get("plain_rel") or record.get("rel") or ""
    if rel:
        return session_relative_path(session_dir, rel)
    block_id = str(record.get("block_id") or record.get("segment_id") or "")
    role = str(record.get("role") or "segment")
    return session_dir / "raw" / RAW_BLOCKS_DIR / f"{block_id}__{role}.raw.jsonl" if block_id else Path("")


def raw_block_compressed_rel(record: dict[str, Any]) -> str:
    rel = str(record.get("compressed_rel") or "")
    if rel:
        return rel
    plain_rel = str(record.get("plain_rel") or record.get("rel") or "")
    if plain_rel:
        return f"{plain_rel}.gz"
    path = Path(str(record.get("plain_path") or record.get("path") or "")).name
    return f"raw/{RAW_BLOCKS_DIR}/{path}.gz" if path else ""


def raw_block_compressed_path(session_dir: Path, record: dict[str, Any]) -> Path:
    value = record.get("compressed_path") or ""
    if value:
        return session_relative_path(session_dir, value)
    rel = raw_block_compressed_rel(record)
    return session_relative_path(session_dir, rel) if rel else Path("")


def raw_block_payload_path(session_dir: Path, record: dict[str, Any]) -> tuple[Path, bool, str]:
    plain_path = raw_block_plain_path(session_dir, record)
    compressed_path = raw_block_compressed_path(session_dir, record)
    storage_mode = str(record.get("storage_mode") or RAW_BLOCK_STORAGE_MODE_PLAIN)
    if storage_mode == RAW_BLOCK_STORAGE_MODE_GZIP and compressed_path.is_file():
        return compressed_path, True, storage_mode
    if plain_path.is_file():
        return plain_path, False, RAW_BLOCK_STORAGE_MODE_PLAIN
    if compressed_path.is_file():
        return compressed_path, True, RAW_BLOCK_STORAGE_MODE_GZIP
    return plain_path, False, storage_mode


def raw_block_payload_available(session_dir: Path, record: dict[str, Any]) -> bool:
    path, _compressed, _storage_mode = raw_block_payload_path(session_dir, record)
    return bool(str(path)) and path.is_file()


def raw_block_records_for_session(session_dir: Path, manifest: dict[str, Any]) -> list[dict[str, Any]]:
    raw_blocks = manifest.get("raw_blocks") if isinstance(manifest.get("raw_blocks"), dict) else {}
    records = raw_blocks.get("blocks") if isinstance(raw_blocks.get("blocks"), list) else []
    if not records:
        blocks_index = session_dir / "raw" / RAW_BLOCK_INDEX_JSON
        index_payload = read_json(blocks_index, {})
        records = index_payload.get("blocks") if isinstance(index_payload.get("blocks"), list) else []
    normalized: list[dict[str, Any]] = []
    for item in records:
        if not isinstance(item, dict):
            continue
        record = dict(item)
        if record.get("path"):
            record["path"] = str(Path(str(record["path"])))
        elif record.get("rel"):
            record["path"] = str(session_dir / str(record["rel"]))
        if record.get("compressed_path"):
            record["compressed_path"] = str(Path(str(record["compressed_path"])))
        if record.get("plain_path"):
            record["plain_path"] = str(Path(str(record["plain_path"])))
        else:
            block_id = str(record.get("block_id") or record.get("segment_id") or "")
            role = str(record.get("role") or "segment")
            if block_id:
                record["path"] = str(session_dir / "raw" / RAW_BLOCKS_DIR / f"{block_id}__{role}.raw.jsonl")
        normalized.append(record)
    return normalized


def raw_block_record_for_ref(
    session_dir: Path,
    manifest: dict[str, Any],
    raw_ref: Any,
    *,
    raw_block_ref: Any = "",
) -> tuple[dict[str, Any] | None, list[str]]:
    diagnostics: list[str] = []
    line_no = line_from_raw_ref(raw_ref)
    if not line_no:
        return None, ["missing_raw_ref"]
    records = raw_block_records_for_session(session_dir, manifest)
    raw_block_ref_text = str(raw_block_ref or "")
    if raw_block_ref_text:
        wanted = Path(raw_block_ref_text.split("#", 1)[0]).name
        for record in records:
            candidates = {
                Path(str(record.get("path") or "")).name,
                Path(str(record.get("plain_path") or "")).name,
                Path(str(record.get("compressed_path") or "")).name,
                Path(str(record.get("rel") or "")).name,
                Path(str(record.get("plain_rel") or "")).name,
                Path(str(record.get("compressed_rel") or "")).name,
                str(record.get("rel") or ""),
                str(record.get("plain_rel") or ""),
                str(record.get("compressed_rel") or ""),
                str(record.get("path") or ""),
                str(record.get("plain_path") or ""),
                str(record.get("compressed_path") or ""),
            }
            if raw_block_ref_text in candidates or wanted in candidates:
                return record, diagnostics
        diagnostics.append("raw_block_ref_not_found")
    for record in records:
        source_range = record.get("source_range") if isinstance(record.get("source_range"), dict) else {}
        from_line = int_value(source_range.get("from_line"))
        to_line = int_value(source_range.get("to_line"))
        if from_line and to_line and from_line <= line_no <= to_line:
            return record, diagnostics
    diagnostics.append("raw_ref_not_covered_by_raw_blocks")
    return None, diagnostics


def raw_block_line_preview(
    session_dir: Path,
    manifest: dict[str, Any],
    raw_ref: Any,
    *,
    raw_block_ref: Any = "",
    max_chars: int = 0,
) -> dict[str, Any]:
    line_no = line_from_raw_ref(raw_ref)
    record, diagnostics = raw_block_record_for_ref(session_dir, manifest, raw_ref, raw_block_ref=raw_block_ref)
    if not line_no:
        return {"status": "missing_raw_ref", "line": None, "text": "", "diagnostics": diagnostics}
    if not record:
        return {"status": "raw_block_unresolved", "line": line_no, "text": "", "diagnostics": diagnostics}
    source_range = record.get("source_range") if isinstance(record.get("source_range"), dict) else {}
    from_line = int_value(source_range.get("from_line"))
    to_line = int_value(source_range.get("to_line"))
    if not from_line or not to_line:
        diagnostics.append("raw_block_source_range_missing")
        return {"status": "raw_block_range_missing", "line": line_no, "text": "", "diagnostics": diagnostics}
    if not (from_line <= line_no <= to_line):
        diagnostics.append("raw_ref_outside_raw_block_range")
        return {"status": "raw_ref_outside_raw_block_range", "line": line_no, "text": "", "diagnostics": diagnostics}
    block_path, compressed, storage_mode = raw_block_payload_path(session_dir, record)
    plain_path = raw_block_plain_path(session_dir, record)
    compressed_path = raw_block_compressed_path(session_dir, record)
    block_line = line_no - from_line + 1
    packet = text_line_packet(block_path, block_line, max_chars=max_chars, compressed=compressed)
    status = "available" if packet.get("status") == "available" else str(packet.get("status") or "unavailable")
    return {
        "status": status,
        "line": line_no,
        "block_line": block_line,
        "text": packet.get("text", ""),
        "sha256": packet.get("sha256", ""),
        "byte_count": packet.get("byte_count", 0),
        "block_id": record.get("block_id"),
        "segment_id": record.get("segment_id"),
        "role": record.get("role"),
        "raw_block_ref": record.get("rel") or record.get("path"),
        "raw_block_path": str(block_path),
        "plain_raw_block_path": str(plain_path),
        "compressed_raw_block_path": str(compressed_path),
        "storage_mode": storage_mode,
        "compressed": compressed,
        "source_range": source_range,
        "diagnostics": diagnostics,
    }


def raw_block_ref_audit_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Raw Block Ref Audit",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- status: `{payload.get('status')}`",
        f"- selected_count: `{payload.get('selected_count')}`",
        f"- checked_count: `{payload.get('checked_count')}`",
        f"- mismatch_count: `{payload.get('mismatch_count')}`",
        f"- missing_count: `{payload.get('missing_count')}`",
        f"- raw_block_duplication_candidate: `{payload.get('raw_block_duplication_candidate_human')}`",
        f"- stop_line: `{payload.get('stop_line')}`",
        "",
        "## Samples",
        "",
        "| session | raw_ref | status | raw_block | raw_equals_block |",
        "| --- | --- | --- | --- | --- |",
    ]
    for item in payload.get("samples", []) if isinstance(payload.get("samples"), list) else []:
        if isinstance(item, dict):
            lines.append(
                f"| `{item.get('session_label')}` | `{item.get('raw_ref')}` | `{item.get('status')}` | `{item.get('raw_block_ref')}` | `{item.get('raw_equals_block')}` |"
            )
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        lines.extend(f"- `{item}`" for item in diagnostics)
    lines.extend(["", "## Next Route", "", str(payload.get("next_route") or "")])
    return "\n".join(lines) + "\n"


def raw_block_ref_audit(
    *,
    aoa_root: Path,
    target: str = "latest",
    limit: int | None = None,
    sample_limit: int = 80,
    max_chars: int = 0,
    write_report: bool = False,
    selected_records_override: list[dict[str, Any]] | None = None,
) -> dict[str, Any]:
    diagnostics: list[str] = []
    records = registry_sessions(aoa_root)
    if selected_records_override is not None:
        selected_records = selected_records_override
    elif target != "all":
        try:
            selected_records = [resolve_session_record(aoa_root, target)]
        except (SystemExit, ValueError):
            selected_records = []
            diagnostics.append("session_not_found")
    else:
        selected_records = sorted(records, key=lambda item: str(item.get("updated_at") or ""), reverse=True)
        if limit is not None:
            selected_records = selected_records[: max(0, int_value(limit))]
    checked = 0
    missing = 0
    mismatch = 0
    available = 0
    samples: list[dict[str, Any]] = []
    for record in selected_records:
        if checked >= max(1, int_value(sample_limit, 80)):
            break
        session_dir = Path(str(record.get("path") or record.get("navigation_path") or ""))
        manifest_path = session_dir / "session.manifest.json"
        manifest = read_json(manifest_path, {})
        if not isinstance(manifest, dict) or not manifest:
            diagnostics.append(f"manifest_missing:{session_dir.name}")
            continue
        raw_path = manifest_raw_path(session_dir, manifest)
        for block in raw_block_records_for_session(session_dir, manifest):
            if checked >= max(1, int_value(sample_limit, 80)):
                break
            source_range = block.get("source_range") if isinstance(block.get("source_range"), dict) else {}
            from_line = int_value(source_range.get("from_line"))
            to_line = int_value(source_range.get("to_line"))
            candidate_lines = [line for line in unique_preserving_order([from_line, to_line]) if line]
            for line_no in candidate_lines:
                if checked >= max(1, int_value(sample_limit, 80)):
                    break
                raw_ref = f"raw:line:{line_no}"
                block_preview = raw_block_line_preview(
                    session_dir,
                    manifest,
                    raw_ref,
                    raw_block_ref=block.get("rel") or block.get("path"),
                    max_chars=max_chars,
                )
                raw_packet = text_line_packet(raw_path, line_no, max_chars=max_chars)
                raw_ok = raw_packet.get("status") == "available"
                block_ok = block_preview.get("status") == "available"
                raw_equals_block = bool(raw_ok and block_ok and raw_packet.get("sha256") == block_preview.get("sha256"))
                status = "available" if raw_equals_block else "mismatch_or_missing"
                if raw_equals_block:
                    available += 1
                else:
                    if not raw_ok or not block_ok:
                        missing += 1
                    else:
                        mismatch += 1
                checked += 1
                samples.append(
                    {
                        "session_id": record.get("session_id"),
                        "session_label": record.get("session_label") or session_dir.name,
                        "raw_ref": raw_ref,
                        "status": status,
                        "raw_status": raw_packet.get("status"),
                        "raw_block_status": block_preview.get("status"),
                        "raw_equals_block": raw_equals_block,
                        "raw_block_ref": block_preview.get("raw_block_ref") or block.get("rel"),
                        "block_line": block_preview.get("block_line"),
                        "raw_sha256": raw_packet.get("sha256"),
                        "block_sha256": block_preview.get("sha256"),
                        "preview": block_preview.get("text", ""),
                        "diagnostics": block_preview.get("diagnostics", []),
                    }
                )
    sessions = session_storage_breakdown(aoa_root)
    status = "reader_ready" if checked and not missing and not mismatch else "needs_repair"
    if not selected_records:
        status = "no_sessions_selected"
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_raw_block_ref_audit",
        "generated_at": utc_now(),
        "ok": bool(checked and not missing and not mismatch),
        "mutates": False,
        "target": target,
        "selected_count": len(selected_records),
        "checked_count": checked,
        "available_count": available,
        "missing_count": missing,
        "mismatch_count": mismatch,
        "status": status,
        "reader": "raw_block_source_range_line_offset_v1",
        "raw_block_duplication_candidate_bytes": sessions.get("raw_block_duplication_candidate_bytes", 0),
        "raw_block_duplication_candidate_human": sessions.get("raw_block_duplication_candidate_human", "0 B"),
        "samples": samples[: max(1, min(int_value(sample_limit, 80), 200))],
        "diagnostics": diagnostics,
        "stop_line": "This audit only reads raw/session and raw-block evidence. It does not delete raw blocks or replace raw transcript authority.",
        "next_route": "after this passes broadly, add compressed/offset raw-block storage and a dry-run cleanup plan before any deletion",
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__raw-block-ref-audit"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, raw_block_ref_audit_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def select_session_records(aoa_root: Path, target: str, *, limit: int | None = None) -> tuple[list[dict[str, Any]], list[str]]:
    diagnostics: list[str] = []
    if target != "all":
        try:
            return [resolve_session_record(aoa_root, target)], diagnostics
        except (SystemExit, ValueError):
            return [], ["session_not_found"]
    records = sorted(registry_sessions(aoa_root), key=lambda item: str(item.get("updated_at") or ""), reverse=True)
    if limit is not None:
        records = records[: max(0, int_value(limit))]
    return records, diagnostics


def session_has_plain_raw_blocks(record: dict[str, Any]) -> bool:
    session_dir = Path(str(record.get("path") or record.get("navigation_path") or ""))
    manifest = read_json(session_dir / "session.manifest.json", {})
    if not isinstance(manifest, dict) or not manifest:
        return False
    return any(raw_block_plain_path(session_dir, block).is_file() for block in raw_block_records_for_session(session_dir, manifest))


def raw_block_compaction_deferred_live_lookup(aoa_root: Path) -> tuple[dict[str, dict[str, Any]], list[str]]:
    db_path = search_db_path(aoa_root)
    if not db_path.exists():
        return {}, []
    try:
        conn = connect_existing_search_db(db_path, timeout=0.5)
    except sqlite3.Error as exc:
        return {}, [f"search_freshness_state_probe_failed:{sqlite_error_status(exc)}"]
    try:
        if not sqlite_table_exists(conn, "search_freshness_state"):
            return {}, []
        rows = conn.execute(
            """
            SELECT session_id, session_label, session_dir, status, reason,
                   deferred_live_reason, live_transcript_path, updated_at
            FROM search_freshness_state
            WHERE status = 'deferred_live'
            """
        ).fetchall()
    except sqlite3.Error as exc:
        return {}, [f"search_freshness_state_probe_failed:{sqlite_error_status(exc)}"]
    finally:
        conn.close()
    lookup: dict[str, dict[str, Any]] = {}
    for row in rows:
        packet = {
            "session_id": row["session_id"],
            "session_label": row["session_label"],
            "session_dir": row["session_dir"],
            "status": row["status"],
            "reason": row["reason"],
            "deferred_live_reason": row["deferred_live_reason"],
            "live_transcript_path": row["live_transcript_path"],
            "updated_at": row["updated_at"],
        }
        session_dir = Path(str(row["session_dir"] or ""))
        keys = unique_preserving_order(
            [
                str(row["session_id"] or ""),
                str(row["session_label"] or ""),
                str(row["session_dir"] or ""),
                session_dir.name if str(session_dir) else "",
            ]
        )
        for key in keys:
            if key:
                lookup[key] = packet
    return lookup, []


def raw_block_compaction_deferred_live_info(record: dict[str, Any], lookup: dict[str, dict[str, Any]]) -> dict[str, Any]:
    session_dir = Path(str(record.get("path") or record.get("navigation_path") or ""))
    keys = unique_preserving_order(
        [
            str(record.get("session_id") or ""),
            str(record.get("session_label") or ""),
            str(record.get("path") or ""),
            str(record.get("navigation_path") or ""),
            session_dir.name if str(session_dir) else "",
        ]
    )
    for key in keys:
        if key and key in lookup:
            return lookup[key]
    return {}


def raw_block_record_key(record: dict[str, Any]) -> str:
    return str(record.get("block_id") or record.get("segment_id") or record.get("rel") or record.get("path") or "")


def compressed_raw_block_record(
    session_dir: Path,
    record: dict[str, Any],
    *,
    compressed_path: Path,
    compressed_bytes: int,
    compressed_sha256: str,
    original_bytes: int,
    original_sha256: str,
    now: str,
    plain_removed: bool = False,
) -> dict[str, Any]:
    updated = dict(record)
    plain_path = raw_block_plain_path(session_dir, record)
    plain_rel = str(record.get("plain_rel") or record.get("rel") or "")
    compressed_rel = raw_block_compressed_rel(record)
    updated.update(
        {
            "storage_mode": RAW_BLOCK_STORAGE_MODE_GZIP,
            "path": str(plain_path),
            "rel": plain_rel or str(record.get("rel") or ""),
            "plain_path": str(plain_path),
            "plain_rel": plain_rel or str(record.get("rel") or ""),
            "compressed_path": str(compressed_path),
            "compressed_rel": compressed_rel,
            "compressed_bytes": compressed_bytes,
            "compressed_sha256": compressed_sha256,
            "uncompressed_bytes": original_bytes,
            "uncompressed_sha256": original_sha256,
            "sha256": original_sha256,
            "storage_updated_at": now,
            "plain_removed": plain_removed,
        }
    )
    if plain_removed:
        updated["plain_removed_at"] = now
        updated["plain_removed_bytes"] = original_bytes
    return updated


def sync_raw_block_storage_records(session_dir: Path, manifest: dict[str, Any], updated_records: dict[str, dict[str, Any]]) -> None:
    raw_blocks = manifest.get("raw_blocks") if isinstance(manifest.get("raw_blocks"), dict) else {}
    blocks = raw_blocks.get("blocks") if isinstance(raw_blocks.get("blocks"), list) else []
    for idx, block in enumerate(blocks):
        if not isinstance(block, dict):
            continue
        key = raw_block_record_key(block)
        if key in updated_records:
            blocks[idx] = dict(updated_records[key])
    raw_blocks["blocks"] = blocks
    manifest["raw_blocks"] = raw_blocks
    for segment in manifest.get("segments", []) if isinstance(manifest.get("segments"), list) else []:
        if not isinstance(segment, dict):
            continue
        raw_block = segment.get("raw_block") if isinstance(segment.get("raw_block"), dict) else {}
        key = raw_block_record_key(raw_block)
        if key not in updated_records:
            continue
        updated = dict(updated_records[key])
        segment["raw_block"] = updated
        index_path = Path(str(segment.get("index") or ""))
        if index_path.exists():
            segment_index = read_json(index_path, {})
            if isinstance(segment_index, dict):
                segment_index["source_block"] = updated
                write_json(index_path, segment_index)
    raw_blocks_index = session_dir / "raw" / RAW_BLOCK_INDEX_JSON
    write_json(
        raw_blocks_index,
        {
            "schema_version": SCHEMA_VERSION,
            "source_raw": raw_blocks.get("source_raw") or "raw/session.raw.jsonl",
            "blocks": blocks,
        },
    )


def gzip_bytes(data: bytes, *, compression_level: int) -> bytes:
    return gzip.compress(data, compresslevel=max(1, min(int_value(compression_level, 6), 9)), mtime=0)


def raw_block_storage_compact_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Raw Block Storage Compact",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- status: `{payload.get('status')}`",
        f"- apply: `{payload.get('apply')}`",
        f"- confirm_remove_plain: `{payload.get('confirm_remove_plain')}`",
        f"- selected_count: `{payload.get('selected_count')}`",
        f"- planned_count: `{payload.get('planned_count')}`",
        f"- compressed_count: `{payload.get('compressed_count')}`",
        f"- removed_plain_count: `{payload.get('removed_plain_count')}`",
        f"- plain_bytes: `{payload.get('plain_bytes_human')}`",
        f"- compressed_bytes: `{payload.get('compressed_bytes_human')}`",
        f"- net_reclaim: `{payload.get('net_reclaim_human')}`",
        f"- stop_line: `{payload.get('stop_line')}`",
        "",
        "## Results",
        "",
        "| session | status | planned | compressed | removed | bytes | compressed |",
        "| --- | --- | --- | --- | --- | --- | --- |",
    ]
    for item in payload.get("results", []) if isinstance(payload.get("results"), list) else []:
        if isinstance(item, dict):
            lines.append(
                f"| `{item.get('session_label')}` | `{item.get('status')}` | `{item.get('planned_count')}` | `{item.get('compressed_count')}` | `{item.get('removed_plain_count')}` | `{item.get('plain_bytes_human')}` | `{item.get('compressed_bytes_human')}` |"
            )
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        lines.extend(f"- `{item}`" for item in diagnostics)
    return "\n".join(lines) + "\n"


def raw_block_storage_compact(
    *,
    aoa_root: Path,
    target: str = "latest",
    limit: int | None = None,
    skip_no_plain: bool = False,
    apply: bool = False,
    confirm_remove_plain: bool = False,
    estimate_compression: bool = False,
    compression_level: int = 6,
    sample_limit: int = 80,
    write_report: bool = False,
) -> dict[str, Any]:
    diagnostics: list[str] = []
    selection_limit = None if target == "all" and skip_no_plain else limit
    selected_records, selection_diagnostics = select_session_records(aoa_root, target, limit=selection_limit)
    diagnostics.extend(selection_diagnostics)
    if skip_no_plain:
        selected_records = [record for record in selected_records if session_has_plain_raw_blocks(record)]
        if limit is not None:
            selected_records = selected_records[: max(0, int_value(limit))]
    deferred_live_lookup, deferred_live_diagnostics = raw_block_compaction_deferred_live_lookup(aoa_root)
    diagnostics.extend(deferred_live_diagnostics)
    skipped_live_deferred_sessions: list[dict[str, Any]] = []
    if deferred_live_lookup:
        guarded_records: list[dict[str, Any]] = []
        for record in selected_records:
            deferred_info = raw_block_compaction_deferred_live_info(record, deferred_live_lookup)
            if deferred_info:
                session_dir = Path(str(record.get("path") or record.get("navigation_path") or deferred_info.get("session_dir") or ""))
                skipped_live_deferred_sessions.append(
                    {
                        "session_id": record.get("session_id") or deferred_info.get("session_id"),
                        "session_label": record.get("session_label") or deferred_info.get("session_label") or session_dir.name,
                        "session_dir": str(session_dir) if str(session_dir) else str(deferred_info.get("session_dir") or ""),
                        "status": "skipped_live_deferred",
                        "reason": deferred_info.get("reason") or "deferred_live",
                        "deferred_live_reason": deferred_info.get("deferred_live_reason") or "",
                        "live_transcript_path": deferred_info.get("live_transcript_path") or "",
                        "next_route": "wait for live quiet-window catch-up before raw-block physical cleanup",
                    }
                )
                continue
            guarded_records.append(record)
        selected_records = guarded_records
    live_deferred_only = bool(skipped_live_deferred_sessions and not selected_records and not selection_diagnostics)
    no_plain_candidates = bool(skip_no_plain and not selected_records and not selection_diagnostics and not skipped_live_deferred_sessions)
    if confirm_remove_plain and not apply:
        diagnostics.append("confirm_remove_plain_requires_apply")
    preflight = raw_block_ref_audit(
        aoa_root=aoa_root,
        target=target,
        limit=limit,
        sample_limit=sample_limit,
        max_chars=0,
        selected_records_override=selected_records,
    )
    if apply and not preflight.get("ok") and not no_plain_candidates and not live_deferred_only:
        diagnostics.append("raw_block_ref_audit_preflight_failed")
    can_apply = bool(apply and selected_records) and not any(item in diagnostics for item in ("confirm_remove_plain_requires_apply", "raw_block_ref_audit_preflight_failed"))
    now = utc_now()
    results: list[dict[str, Any]] = []
    planned_count = 0
    compressed_count = 0
    removed_plain_count = 0
    plain_bytes_total = 0
    compressed_bytes_total = 0
    removed_plain_bytes_total = 0
    created_compressed_bytes_total = 0
    for skipped in skipped_live_deferred_sessions:
        results.append(
            {
                "session_id": skipped.get("session_id"),
                "session_label": skipped.get("session_label"),
                "session_dir": skipped.get("session_dir"),
                "status": "skipped_live_deferred",
                "planned_count": 0,
                "compressed_count": 0,
                "removed_plain_count": 0,
                "plain_bytes": 0,
                "plain_bytes_human": "0 B",
                "compressed_bytes": 0,
                "compressed_bytes_human": "0 B",
                "created_compressed_bytes": 0,
                "removed_plain_bytes": 0,
                "reason": skipped.get("reason"),
                "deferred_live_reason": skipped.get("deferred_live_reason"),
                "next_route": skipped.get("next_route"),
            }
        )
    for record in selected_records:
        session_dir = Path(str(record.get("path") or record.get("navigation_path") or ""))
        manifest_path = session_dir / "session.manifest.json"
        manifest = read_json(manifest_path, {})
        if not isinstance(manifest, dict) or not manifest:
            diagnostics.append(f"manifest_missing:{session_dir.name}")
            continue
        session_results: list[dict[str, Any]] = []
        updated_records: dict[str, dict[str, Any]] = {}
        session_plain_bytes = 0
        session_compressed_bytes = 0
        session_removed_bytes = 0
        session_created_compressed_bytes = 0
        session_planned = 0
        session_compressed = 0
        session_removed = 0
        for block in raw_block_records_for_session(session_dir, manifest):
            key = raw_block_record_key(block)
            plain_path = raw_block_plain_path(session_dir, block)
            compressed_path = raw_block_compressed_path(session_dir, block)
            compressed_rel = raw_block_compressed_rel(block)
            plain_exists = plain_path.is_file()
            compressed_exists = compressed_path.is_file()
            storage_mode = str(block.get("storage_mode") or RAW_BLOCK_STORAGE_MODE_PLAIN)
            if not plain_exists and compressed_exists and storage_mode == RAW_BLOCK_STORAGE_MODE_GZIP:
                known_compressed_bytes = compressed_path.stat().st_size
                session_compressed_bytes += known_compressed_bytes
                session_results.append(
                    {
                        "block_id": block.get("block_id"),
                        "status": "already_compressed",
                        "storage_mode": storage_mode,
                        "compressed_rel": compressed_rel,
                        "compressed_bytes": known_compressed_bytes,
                    }
                )
                continue
            if not plain_exists:
                session_results.append(
                    {
                        "block_id": block.get("block_id"),
                        "status": "plain_unavailable",
                        "storage_mode": storage_mode,
                        "plain_path": str(plain_path),
                        "compressed_rel": compressed_rel,
                    }
                )
                continue
            original_bytes = plain_path.stat().st_size
            session_plain_bytes += original_bytes
            plain_bytes_total += original_bytes
            session_planned += 1
            planned_count += 1
            compressed_size = compressed_path.stat().st_size if compressed_exists else 0
            compressed_sha = sha256_file(compressed_path) if compressed_exists else ""
            if estimate_compression and not compressed_exists:
                data = plain_path.read_bytes()
                compressed_size = len(gzip_bytes(data, compression_level=compression_level))
            if can_apply:
                data = plain_path.read_bytes()
                original_sha = hashlib.sha256(data).hexdigest()
                compressed_path.parent.mkdir(parents=True, exist_ok=True)
                created_now = False
                if not compressed_exists:
                    compressed_path.write_bytes(gzip_bytes(data, compression_level=compression_level))
                    compressed_exists = True
                    created_now = True
                compressed_data = compressed_path.read_bytes()
                decompressed = gzip.decompress(compressed_data)
                if decompressed != data:
                    session_results.append(
                        {
                            "block_id": block.get("block_id"),
                            "status": "compressed_verify_failed",
                            "plain_rel": block.get("rel"),
                            "compressed_rel": compressed_rel,
                        }
                    )
                    continue
                compressed_size = len(compressed_data)
                compressed_sha = hashlib.sha256(compressed_data).hexdigest()
                if created_now:
                    session_created_compressed_bytes += compressed_size
                    created_compressed_bytes_total += compressed_size
                updated = compressed_raw_block_record(
                    session_dir,
                    block,
                    compressed_path=compressed_path,
                    compressed_bytes=compressed_size,
                    compressed_sha256=compressed_sha,
                    original_bytes=original_bytes,
                    original_sha256=original_sha,
                    now=now,
                    plain_removed=False,
                )
                updated_records[key] = updated
                session_compressed += 1
                compressed_count += 1
                session_compressed_bytes += compressed_size
                compressed_bytes_total += compressed_size
                session_results.append(
                    {
                        "block_id": block.get("block_id"),
                        "status": "compressed_sidecar_written",
                        "plain_rel": block.get("rel"),
                        "compressed_rel": compressed_rel,
                        "plain_bytes": original_bytes,
                        "compressed_bytes": compressed_size,
                    }
                )
            else:
                session_compressed_bytes += compressed_size
                compressed_bytes_total += compressed_size
                session_results.append(
                    {
                        "block_id": block.get("block_id"),
                        "status": "planned",
                        "plain_rel": block.get("rel"),
                        "compressed_rel": compressed_rel,
                        "plain_bytes": original_bytes,
                        "compressed_bytes": compressed_size,
                        "compression_estimated": bool(estimate_compression and compressed_size),
                    }
                )
        if can_apply and updated_records:
            sync_raw_block_storage_records(session_dir, manifest, updated_records)
            manifest["updated_at"] = now
            write_json(manifest_path, manifest)
            update_registry(aoa_root, manifest, session_dir)
            if confirm_remove_plain:
                removal_updates: dict[str, dict[str, Any]] = {}
                refreshed_manifest = read_json(manifest_path, {})
                for block in raw_block_records_for_session(session_dir, refreshed_manifest):
                    key = raw_block_record_key(block)
                    if key not in updated_records:
                        continue
                    plain_path = raw_block_plain_path(session_dir, block)
                    compressed_path = raw_block_compressed_path(session_dir, block)
                    if not plain_path.is_file() or not compressed_path.is_file():
                        continue
                    before_unlink_bytes = plain_path.stat().st_size
                    plain_path.unlink()
                    removed_plain_count += 1
                    session_removed += 1
                    removed_plain_bytes_total += before_unlink_bytes
                    session_removed_bytes += before_unlink_bytes
                    removed_record = dict(block)
                    removed_record["plain_removed"] = True
                    removed_record["plain_removed_at"] = now
                    removed_record["plain_removed_bytes"] = before_unlink_bytes
                    removal_updates[key] = removed_record
                if removal_updates:
                    sync_raw_block_storage_records(session_dir, refreshed_manifest, removal_updates)
                    refreshed_manifest["updated_at"] = now
                    write_json(manifest_path, refreshed_manifest)
                    update_registry(aoa_root, refreshed_manifest, session_dir)
        results.append(
            {
                "session_id": record.get("session_id"),
                "session_label": record.get("session_label") or session_dir.name,
                "session_dir": str(session_dir),
                "status": "applied" if can_apply and session_compressed else "planned" if session_planned else "no_plain_blocks",
                "planned_count": session_planned,
                "compressed_count": session_compressed,
                "removed_plain_count": session_removed,
                "plain_bytes": session_plain_bytes,
                "plain_bytes_human": human_size(session_plain_bytes),
                "compressed_bytes": session_compressed_bytes,
                "compressed_bytes_human": human_size(session_compressed_bytes),
                "created_compressed_bytes": session_created_compressed_bytes,
                "removed_plain_bytes": session_removed_bytes,
                "details": session_results[:50],
            }
        )
    post_audit = (
        raw_block_ref_audit(
            aoa_root=aoa_root,
            target=target,
            limit=limit,
            sample_limit=sample_limit,
            max_chars=0,
            selected_records_override=selected_records,
        )
        if can_apply
        else {}
    )
    if can_apply and not post_audit.get("ok"):
        diagnostics.append("raw_block_ref_audit_post_apply_failed")
    net_reclaim_bytes = removed_plain_bytes_total - created_compressed_bytes_total
    status = "current_no_plain_candidates" if no_plain_candidates else "skipped_live_deferred" if live_deferred_only else "applied" if can_apply else "planned"
    if diagnostics and not can_apply:
        status = "blocked"
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "session_memory_raw_block_storage_compact",
        "generated_at": now,
        "ok": (no_plain_candidates or bool(selected_records) or live_deferred_only) and not any(item.endswith("_failed") or item == "confirm_remove_plain_requires_apply" for item in diagnostics),
        "mutates": bool(can_apply),
        "target": target,
        "apply": bool(apply),
        "confirm_remove_plain": bool(confirm_remove_plain),
        "skip_no_plain": bool(skip_no_plain),
        "estimate_compression": bool(estimate_compression),
        "compression": "gzip",
        "compression_level": max(1, min(int_value(compression_level, 6), 9)),
        "storage_mode": RAW_BLOCK_STORAGE_MODE_GZIP,
        "status": status,
        "selected_count": len(selected_records),
        "skipped_live_deferred_count": len(skipped_live_deferred_sessions),
        "skipped_live_deferred_sessions": skipped_live_deferred_sessions,
        "planned_count": planned_count,
        "compressed_count": compressed_count,
        "removed_plain_count": removed_plain_count,
        "plain_bytes": plain_bytes_total,
        "plain_bytes_human": human_size(plain_bytes_total),
        "compressed_bytes": compressed_bytes_total,
        "compressed_bytes_human": human_size(compressed_bytes_total),
        "created_compressed_bytes": created_compressed_bytes_total,
        "created_compressed_bytes_human": human_size(created_compressed_bytes_total),
        "removed_plain_bytes": removed_plain_bytes_total,
        "removed_plain_bytes_human": human_size(removed_plain_bytes_total),
        "net_reclaim_bytes": net_reclaim_bytes,
        "net_reclaim_human": human_size(max(0, net_reclaim_bytes)),
        "preflight_raw_block_ref_audit": {
            "ok": preflight.get("ok"),
            "status": preflight.get("status"),
            "checked_count": preflight.get("checked_count"),
            "missing_count": preflight.get("missing_count"),
            "mismatch_count": preflight.get("mismatch_count"),
        },
        "post_apply_raw_block_ref_audit": {
            "ok": post_audit.get("ok"),
            "status": post_audit.get("status"),
            "checked_count": post_audit.get("checked_count"),
            "missing_count": post_audit.get("missing_count"),
            "mismatch_count": post_audit.get("mismatch_count"),
        }
        if post_audit
        else {},
        "results": results,
        "diagnostics": diagnostics,
        "stop_line": "raw/session.raw.jsonl remains authority; this route only changes generated raw-block storage after ref-audit preflight.",
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__raw-block-storage-compact"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, raw_block_storage_compact_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def raw_semantic_preview(raw_path: Path, raw_ref: Any, *, max_chars: int = 420) -> dict[str, Any]:
    line_no = line_from_raw_ref(raw_ref)
    if not line_no:
        return {"status": "missing_raw_ref", "line": None, "text": ""}
    if not raw_path.is_file():
        return {"status": "raw_unavailable", "line": line_no, "text": ""}
    with raw_path.open("r", encoding="utf-8", errors="replace") as handle:
        for current_line, line in enumerate(handle, start=1):
            if current_line != line_no:
                if current_line > line_no:
                    break
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                return {"status": "invalid_json", "line": line_no, "text": ""}
            if not isinstance(row, dict):
                return {"status": "non_object_json", "line": line_no, "text": ""}
            payload = row.get("payload") if isinstance(row.get("payload"), dict) else {}
            text = semantic_text_for_classification(str(row.get("type") or ""), payload, max_chars=max_chars)
            if not text and str(row.get("type") or "") == "response_item" and str(payload.get("type") or "") == "reasoning" and payload.get("encrypted_content"):
                return {
                    "status": "encrypted_reasoning_boundary",
                    "line": line_no,
                    "text": "Reasoning boundary: encrypted content present; summary empty.",
                }
            return {
                "status": "raw_semantic_text" if text else "semantic_text_empty",
                "line": line_no,
                "text": short_text(text, max_chars=max_chars),
            }
    return {"status": "raw_line_not_found", "line": line_no, "text": ""}


def route_raw_semantic_preview(row: sqlite3.Row, refs: dict[str, Any], *, max_chars: int = 420) -> dict[str, Any]:
    raw_ref = str(refs.get("raw") or "")
    raw_path = search_row_raw_path(row)
    if not raw_path or not raw_ref:
        return {"status": "missing_raw_path_or_ref", "line": line_from_raw_ref(raw_ref), "text": ""}
    return raw_semantic_preview(raw_path, raw_ref, max_chars=max_chars)


def route_refs_raw_semantic_preview(refs: dict[str, Any], *, max_chars: int = 420) -> dict[str, Any]:
    raw_ref = str(refs.get("raw") or "")
    manifest_ref = str(refs.get("session") or "")
    if not raw_ref or not manifest_ref:
        return {"status": "missing_session_ref_or_raw_ref", "line": line_from_raw_ref(raw_ref), "text": ""}
    manifest_path = Path(manifest_ref)
    if not manifest_path.exists():
        return {"status": "session_manifest_unavailable", "line": line_from_raw_ref(raw_ref), "text": ""}
    manifest = read_json(manifest_path, {})
    if not isinstance(manifest, dict):
        return {"status": "session_manifest_invalid", "line": line_from_raw_ref(raw_ref), "text": ""}
    return raw_semantic_preview(manifest_raw_path(manifest_path.parent, manifest), raw_ref, max_chars=max_chars)


def raw_event_shape(raw_path: Path, raw_ref: Any) -> dict[str, Any]:
    line_no = line_from_raw_ref(raw_ref)
    if not line_no:
        return {"status": "missing_raw_ref", "line": None, "shape_key": "missing_raw_ref"}
    if not raw_path.is_file():
        return {"status": "raw_unavailable", "line": line_no, "shape_key": "raw_unavailable"}
    with raw_path.open("r", encoding="utf-8", errors="replace") as handle:
        for current_line, line in enumerate(handle, start=1):
            if current_line != line_no:
                if current_line > line_no:
                    break
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError:
                return {"status": "invalid_json", "line": line_no, "shape_key": "invalid_json"}
            if not isinstance(row, dict):
                return {"status": "non_object_json", "line": line_no, "shape_key": "non_object_json"}
            payload = row.get("payload") if isinstance(row.get("payload"), dict) else {}
            raw_type = str(row.get("type") or "")
            payload_type = str(payload.get("type") or "") if isinstance(payload, dict) else ""
            role = str(payload.get("role") or "") if isinstance(payload, dict) else ""
            name = str(payload.get("name") or "") if isinstance(payload, dict) else ""
            content = payload.get("content") if isinstance(payload, dict) else None
            summary = payload.get("summary") if isinstance(payload, dict) else None
            content_types = [
                str(item.get("type") or "")
                for item in content
                if isinstance(item, dict) and item.get("type")
            ] if isinstance(content, list) else []
            summary_types = [
                str(item.get("type") or "")
                for item in summary
                if isinstance(item, dict) and item.get("type")
            ] if isinstance(summary, list) else []
            output_value = payload.get("output") if isinstance(payload, dict) else None
            message_value = payload.get("message") if isinstance(payload, dict) else None
            shape_parts = [raw_type or "unknown"]
            if payload_type:
                shape_parts.append(payload_type)
            if role:
                shape_parts.append(f"role={role}")
            if name:
                shape_parts.append(f"name={name}")
            if content_types:
                shape_parts.append("content=" + ",".join(sorted(set(content_types))))
            if isinstance(summary, list):
                shape_parts.append(f"summary_count={len(summary)}")
            return {
                "status": "available",
                "line": line_no,
                "shape_key": "|".join(shape_parts),
                "raw_type": raw_type,
                "payload_type": payload_type,
                "role": role,
                "name": name,
                "content_types": sorted(set(content_types)),
                "content_count": len(content) if isinstance(content, list) else 0,
                "summary_types": sorted(set(summary_types)),
                "summary_count": len(summary) if isinstance(summary, list) else 0,
                "has_encrypted_content": bool(payload.get("encrypted_content")) if isinstance(payload, dict) else False,
                "has_usage": isinstance(row.get("usage"), dict) or isinstance(payload.get("usage") if isinstance(payload, dict) else None, dict),
                "message_chars": len(message_value) if isinstance(message_value, str) else 0,
                "output_chars": len(output_value) if isinstance(output_value, str) else 0,
                "payload_keys": sorted(str(key) for key in payload.keys()) if isinstance(payload, dict) else [],
            }
    return {"status": "raw_line_not_found", "line": line_no, "shape_key": "raw_line_not_found"}


def route_signal_for_event_record(event: dict[str, Any], layer: str, key: str) -> dict[str, Any]:
    facets = event.get("facets") if isinstance(event.get("facets"), dict) else {}
    route_signals = facets.get("route_signals") if isinstance(facets.get("route_signals"), list) else []
    for signal in route_signals:
        if not isinstance(signal, dict):
            continue
        if str(signal.get("layer") or "") == layer and str(signal.get("key") or "") == key:
            return signal
    return {}


def route_sample_from_event(
    *,
    session_dir: Path,
    manifest: dict[str, Any],
    record: dict[str, Any],
    segment_index: dict[str, Any],
    event: dict[str, Any],
    layer: str,
    key: str,
    requirement: dict[str, Any],
    max_raw_chars: int,
) -> dict[str, Any]:
    display = manifest.get("display") if isinstance(manifest.get("display"), dict) else {}
    work_context = manifest.get("work_context") if isinstance(manifest.get("work_context"), dict) else {}
    signal = route_signal_for_event_record(event, layer, key)
    raw_ref = str(event.get("raw_ref") or "")
    raw_preview = raw_line_preview(manifest_raw_path(session_dir, manifest), raw_ref, max_chars=max_raw_chars)
    evidence = {
        "session_ref": str(session_dir / SESSION_INDEX_MARKDOWN),
        "segment_ref": str(event.get("md_anchor") or segment_index.get("markdown") or ""),
        "raw_ref": raw_ref,
        "generated_index_ref": str(segment_index.get("_index_path") or ""),
    }
    return {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "route_sample",
        "requirement_id": str(requirement.get("id") or ""),
        "requirement_title": str(requirement.get("title") or ""),
        "layer": layer,
        "axis": ROUTE_SIGNAL_LAYER_TO_AXIS.get(layer, ""),
        "key": key,
        "session": str(display.get("label") or record.get("session_label") or session_dir.name),
        "session_id": str(manifest.get("session_id") or record.get("session_id") or ""),
        "work_context": {
            "work_name": str(work_context.get("work_name") or ""),
            "work_family": str(work_context.get("work_family") or ""),
            "confidence": str(work_context.get("confidence") or ""),
        },
        "event": {
            "event_id": str(event.get("event_id") or ""),
            "type": str(event.get("type") or ""),
            "title": str(event.get("title") or ""),
            "outcome": str(event.get("outcome") or ""),
            "confidence": str(event.get("confidence") or ""),
            "timestamp": str(event.get("timestamp") or ""),
            "tags": event.get("tags", []) if isinstance(event.get("tags"), list) else [],
        },
        "signal": {
            "confidence": str(signal.get("confidence") or ""),
            "source": str(signal.get("source") or ""),
            "detail": str(signal.get("detail") or ""),
        },
        "evidence": evidence,
        "raw_preview": raw_preview,
        "review": {
            "status": "unreviewed",
            "verdict": "",
            "reviewer_action": "accept | reject | weaken | split | add_rule",
            "checklist": [
                "Does the raw preview support this layer/key?",
                "Is the classifier confidence appropriate?",
                "Should this signal be split, weakened, or promoted into a rule change?",
                "Does the evidence ref route to stronger raw or segment material?",
            ],
        },
    }


def route_sample_audit(
    *,
    aoa_root: Path,
    target: str = "all",
    since: str | None = None,
    until: str | None = None,
    limit: int | None = None,
    sample_limit: int = DEFAULT_ROUTE_SAMPLE_LIMIT,
    max_raw_chars: int = 360,
    write_report: bool = False,
) -> dict[str, Any]:
    now = utc_now()
    try:
        records = [resolve_session_record(aoa_root, target)] if target != "all" else chronological_session_records(aoa_root, since=since, until=until, limit=limit)
    except ValueError as exc:
        return {
            "schema_version": SCHEMA_VERSION,
            "artifact_type": "route_sample_audit",
            "generated_at": now,
            "ok": False,
            "target": target,
            "selected_count": 0,
            "diagnostics": [str(exc)],
            "requirements": [],
            "samples": [],
            "remaining": [],
        }

    required_layers = route_readiness_required_layers()
    requirement_by_layer = {
        str(layer): item
        for item in ROUTE_READINESS_REQUIREMENTS
        for layer in item.get("required_layers", [])
    }
    layer_key_counts: dict[str, Counter[str]] = {layer: Counter() for layer in required_layers}
    diagnostics: list[str] = []
    indexed_records: list[tuple[dict[str, Any], Path, dict[str, Any]]] = []
    stale_route_indexes: list[dict[str, Any]] = []
    stale_route_schema = 0
    stale_route_classifier = 0

    for record in records:
        session_dir = session_dir_from_record(record)
        manifest = read_json(session_dir / "session.manifest.json", {})
        session_index = read_json(session_dir / SESSION_INDEX_JSON, {})
        if not isinstance(manifest, dict) or not manifest:
            diagnostics.append(f"{record.get('session_label') or record.get('session_id')}:missing_manifest")
            continue
        if not isinstance(session_index, dict) or not session_index:
            archive_status = str(manifest.get("archive_status") or record.get("archive_status") or "")
            if archive_status and archive_status != "indexed":
                continue
            diagnostics.append(f"{record.get('session_label') or record.get('session_id')}:missing_session_index")
            continue
        stale_reasons = route_signal_index_stale_reasons(session_index)
        if "route_signal_schema_mismatch" in stale_reasons:
            stale_route_schema += 1
        if "route_signal_classifier_mismatch" in stale_reasons:
            stale_route_classifier += 1
        if stale_reasons:
            stale_route_indexes.append(
                {
                    "session": str(record.get("session_label") or record.get("session_id") or session_dir.name),
                    "path": str(session_dir),
                    "reasons": stale_reasons,
                }
            )
            continue
        indexed_records.append((record, session_dir, manifest))
        route_counts = session_index.get("route_signal_counts") if isinstance(session_index.get("route_signal_counts"), dict) else {}
        for layer in required_layers:
            key_counts = route_counts.get(layer) if isinstance(route_counts.get(layer), dict) else {}
            for key, count in key_counts.items():
                layer_key_counts[layer][str(key)] += int_value(count)

    samples_by_layer: dict[str, list[dict[str, Any]]] = {layer: [] for layer in required_layers}
    sampled_tokens_by_layer: dict[str, set[str]] = {layer: set() for layer in required_layers}
    sample_limit = max(0, int_value(sample_limit, DEFAULT_ROUTE_SAMPLE_LIMIT))
    max_raw_chars = max(40, int_value(max_raw_chars, 360))

    for record, session_dir, manifest in indexed_records:
        if sample_limit and all(len(samples_by_layer[layer]) >= sample_limit for layer in required_layers):
            break
        for segment in manifest.get("segments", []) if isinstance(manifest.get("segments"), list) else []:
            if not isinstance(segment, dict):
                continue
            index_path = Path(str(segment.get("index") or ""))
            if not index_path.exists():
                diagnostics.append(f"{session_dir.name}:{segment.get('segment_id') or ''}:missing_segment_index")
                continue
            segment_index = read_json(index_path, {})
            if not isinstance(segment_index, dict):
                diagnostics.append(f"{session_dir.name}:{segment.get('segment_id') or ''}:invalid_segment_index")
                continue
            stale_reasons = route_signal_index_stale_reasons(segment_index)
            if stale_reasons:
                diagnostics.append(f"{session_dir.name}:{segment.get('segment_id') or ''}:{','.join(stale_reasons)}")
                continue
            segment_index["_index_path"] = str(index_path)
            events = segment_index.get("events") if isinstance(segment_index.get("events"), list) else []
            event_by_id = {
                str(event.get("event_id") or ""): event
                for event in events
                if isinstance(event, dict) and event.get("event_id")
            }
            by_route_layer = segment_index.get("by_route_layer") if isinstance(segment_index.get("by_route_layer"), dict) else {}
            for layer in required_layers:
                if sample_limit and len(samples_by_layer[layer]) >= sample_limit:
                    continue
                key_map = by_route_layer.get(layer) if isinstance(by_route_layer.get(layer), dict) else {}
                if not key_map:
                    continue
                ranked_keys = sorted(
                    key_map.keys(),
                    key=lambda key: (
                        str(key) in sampled_tokens_by_layer[layer],
                        -layer_key_counts.get(layer, Counter()).get(str(key), 0),
                        str(key),
                    ),
                )
                for key in ranked_keys:
                    if sample_limit and len(samples_by_layer[layer]) >= sample_limit:
                        break
                    ids = key_map.get(key)
                    if not isinstance(ids, list):
                        continue
                    for event_id in ids:
                        token = f"{session_dir.name}:{index_path.name}:{event_id}:{key}"
                        if token in sampled_tokens_by_layer[layer]:
                            continue
                        event = event_by_id.get(str(event_id))
                        if not event:
                            continue
                        sample = route_sample_from_event(
                            session_dir=session_dir,
                            manifest=manifest,
                            record=record,
                            segment_index=segment_index,
                            event=event,
                            layer=layer,
                            key=str(key),
                            requirement=requirement_by_layer.get(layer, {}),
                            max_raw_chars=max_raw_chars,
                        )
                        samples_by_layer[layer].append(sample)
                        sampled_tokens_by_layer[layer].add(token)
                        break

    requirements: list[dict[str, Any]] = []
    for item in ROUTE_READINESS_REQUIREMENTS:
        layers = [str(layer) for layer in item.get("required_layers", [])]
        layer_payloads = []
        missing_layers = []
        under_sampled_layers = []
        for layer in layers:
            layer_samples = samples_by_layer.get(layer, [])
            if not layer_samples:
                missing_layers.append(layer)
            if sample_limit and len(layer_samples) < sample_limit:
                under_sampled_layers.append(layer)
            layer_payloads.append(
                {
                    "layer": layer,
                    "axis": ROUTE_SIGNAL_LAYER_TO_AXIS.get(layer, ""),
                    "available_signal_count": sum(layer_key_counts.get(layer, Counter()).values()),
                    "sample_count": len(layer_samples),
                    "sample_keys": [sample.get("key") for sample in layer_samples],
                    "samples": layer_samples,
                }
            )
        status = "covered" if not missing_layers else "remaining"
        requirements.append(
            {
                "id": item.get("id"),
                "title": item.get("title"),
                "status": status,
                "required_layers": layers,
                "missing_layers": missing_layers,
                "under_sampled_layers": under_sampled_layers,
                "layers": layer_payloads,
            }
        )

    samples = [sample for layer in required_layers for sample in samples_by_layer.get(layer, [])]
    remaining = [req for req in requirements if req["status"] != "covered"]
    payload = {
        "schema_version": SCHEMA_VERSION,
        "artifact_type": "route_sample_audit",
        "generated_at": now,
        "ok": not remaining and not diagnostics,
        "target": target,
        "since": since,
        "until": until,
        "limit": limit,
        "sample_limit": sample_limit,
        "max_raw_chars": max_raw_chars,
        "selected_count": len(records),
        "indexed_session_count": len(indexed_records),
        "stale_route_schema": stale_route_schema,
        "stale_route_classifier": stale_route_classifier,
        "stale_route_index_count": len(stale_route_indexes),
        "stale_route_indexes": stale_route_indexes,
        "route_signal_schema_version": ROUTE_SIGNAL_SCHEMA_VERSION,
        "route_signal_classifier_version": ROUTE_SIGNAL_CLASSIFIER_VERSION,
        "required_layer_count": len(required_layers),
        "sampled_layer_count": sum(1 for layer in required_layers if samples_by_layer.get(layer)),
        "total_sample_count": len(samples),
        "review_status": "unreviewed",
        "requirements": requirements,
        "samples": samples,
        "diagnostics": diagnostics,
        "remaining": remaining,
    }
    if write_report:
        diagnostics_dir = aoa_root / DIAGNOSTICS_ROOT
        diagnostics_dir.mkdir(parents=True, exist_ok=True)
        stem = f"{compact_stamp()}__route-sample-audit"
        report_json = diagnostics_dir / f"{stem}.json"
        report_md = diagnostics_dir / f"{stem}.md"
        write_json(report_json, payload)
        write_markdown(report_md, route_sample_audit_markdown(payload))
        payload["report_json"] = str(report_json)
        payload["report_markdown"] = str(report_md)
    return payload


def route_sample_audit_markdown(payload: dict[str, Any]) -> str:
    lines = [
        "# Route Sample Audit",
        "",
        f"- generated_at: `{payload.get('generated_at')}`",
        f"- ok: `{payload.get('ok')}`",
        f"- target: `{payload.get('target')}`",
        f"- selected_count: `{payload.get('selected_count')}`",
        f"- indexed_session_count: `{payload.get('indexed_session_count')}`",
        f"- sampled_layers: `{payload.get('sampled_layer_count')}/{payload.get('required_layer_count')}`",
        f"- total_sample_count: `{payload.get('total_sample_count')}`",
        f"- review_status: `{payload.get('review_status')}`",
        "",
        "Samples are classifier calibration packets. They are unreviewed until a reviewer records a verdict.",
        "",
        "## Requirements",
        "",
        "| id | status | layers | samples | missing |",
        "| --- | --- | --- | ---: | --- |",
    ]
    for req in payload.get("requirements", []) if isinstance(payload.get("requirements"), list) else []:
        if not isinstance(req, dict):
            continue
        layers = req.get("layers") if isinstance(req.get("layers"), list) else []
        layer_names = ", ".join(str(layer.get("layer")) for layer in layers if isinstance(layer, dict))
        sample_count = sum(int_value(layer.get("sample_count")) for layer in layers if isinstance(layer, dict))
        missing = ", ".join(str(item) for item in req.get("missing_layers", []) if item)
        lines.append(f"| `{req.get('id')}` | `{req.get('status')}` | `{layer_names}` | {sample_count} | `{missing}` |")
    lines.extend(["", "## Samples", ""])
    for sample in payload.get("samples", []) if isinstance(payload.get("samples"), list) else []:
        if not isinstance(sample, dict):
            continue
        evidence = sample.get("evidence") if isinstance(sample.get("evidence"), dict) else {}
        raw_preview = sample.get("raw_preview") if isinstance(sample.get("raw_preview"), dict) else {}
        signal = sample.get("signal") if isinstance(sample.get("signal"), dict) else {}
        event = sample.get("event") if isinstance(sample.get("event"), dict) else {}
        lines.extend(
            [
                f"### {sample.get('layer')} / {sample.get('key')}",
                "",
                f"- requirement: `{sample.get('requirement_id')}`",
                f"- session: `{sample.get('session')}`",
                f"- event: `{event.get('event_id')}` `{event.get('type')}` `{event.get('outcome')}`",
                f"- signal: confidence=`{signal.get('confidence')}` source=`{signal.get('source')}`",
                f"- raw_ref: `{evidence.get('raw_ref')}`",
                f"- segment_ref: `{evidence.get('segment_ref')}`",
                f"- generated_index_ref: `{evidence.get('generated_index_ref')}`",
                f"- review_status: `{sample.get('review', {}).get('status') if isinstance(sample.get('review'), dict) else 'unreviewed'}`",
                "",
                "```text",
                str(raw_preview.get("text") or ""),
                "```",
                "",
            ]
        )
    diagnostics = payload.get("diagnostics") if isinstance(payload.get("diagnostics"), list) else []
    if diagnostics:
        lines.extend(["", "## Diagnostics", ""])
        for item in diagnostics:
            lines.append(f"- `{item}`")
    return "\n".join(lines) + "\n"


